{
  "name": "Library Legend: The Great Dependency Clicker",
  "description": "An addictive clicker and tower defense hybrid where you collect open-source libraries to defend your mainframe against production bugs. Scale from a junior developer to a Silicon Valley God with a deep skill tree and high-performance canvas rendering."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Point {
  x: number;
  y: number;
}

export interface Particle extends Point {
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

export interface ClickRipple extends Point {
  radius: number;
  maxRadius: number;
  life: number;
}

export interface Enemy extends Point {
  id: string;
  hp: number;
  maxHp: number;
  speed: number;
  value: number;
  type: 'bug' | 'memory-leak' | 'merge-conflict';
  size: number;
  angle: number;
}

export interface Tower extends Point {
  id: string;
  type: string;
  level: number;
  range: number;
  damage: number;
  fireRate: number;
  lastFired: number;
  color: string;
}

export interface LibraryDrop extends Point {
  id: string;
  name: string;
  rarity: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
  effect: string;
  life: number;
}

export interface Skill {
  id: string;
  name: string;
  description: string;
  cost: number;
  icon: string;
  unlocked: boolean;
  onUnlock: (state: GameState) => void;
  dependencies: string[];
}

export interface GameState {
  code: number; // The main currency
  experience: number;
  level: number;
  skillPoints: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  isGameOver: boolean;
}

export const COLORS = {
  PRIMARY: '#38bdf8', // sky-400
  SECONDARY: '#f472b6', // pink-400
  ACCENT: '#fbbf24', // amber-400
  BG: '#020617', // slate-950
  ENEMY: '#ef4444', // red-500
  PARTICLE: '#94a3b8', // slate-400
};

export const LIBRARIES = [
  { name: 'lodash', rarity: 'common', effect: 'Speed +5%' },
  { name: 'react', rarity: 'uncommon', effect: 'Click Power +10%' },
  { name: 'd3', rarity: 'rare', effect: 'Tower Range +20%' },
  { name: 'tensorflow', rarity: 'epic', effect: 'Auto-targeting' },
  { name: 'kubernetes', rarity: 'legendary', effect: 'System Overload' },
  { name: 'is-even', rarity: 'common', effect: 'Code +1' },
  { name: 'left-pad', rarity: 'uncommon', effect: 'Padding +100%' },
  { name: 'three.js', rarity: 'rare', effect: 'Visual Clarity' },
  { name: 'express', rarity: 'common', effect: 'Enemy Delay' },
  { name: 'next.js', rarity: 'epic', effect: 'Production Grade Performance' },
] as const;

export const TOWER_TYPES = {
  BASIC: {
    name: 'Logic Gate',
    cost: 50,
    damage: 10,
    range: 150,
    fireRate: 800, // ms
    color: '#38bdf8',
  },
  SNIPER: {
    name: 'Regex Matcher',
    cost: 200,
    damage: 50,
    range: 300,
    fireRate: 2000,
    color: '#f472b6',
  },
  RAPID: {
    name: 'Loop Unroller',
    cost: 500,
    damage: 5,
    range: 120,
    fireRate: 150,
    color: '#fbbf24',
  }
};

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, Point } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES } from '../constants';

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = {
      code: 100,
      experience: 0,
      level: 1,
      skillPoints: 0,
      clickPower: 5,
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      isGameOver: false,
    };

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public getState() {
    return this.state;
  }

  public handleClick(x: number, y: number) {
    // Check if clicked an enemy
    let hit = false;
    this.state.enemies = this.state.enemies.filter(enemy => {
      const dx = enemy.x - x;
      const dy = enemy.y - y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < enemy.size + 10) {
        enemy.hp -= this.state.clickPower;
        this.createParticles(enemy.x, enemy.y, 5, COLORS.PRIMARY);
        if (enemy.hp <= 0) {
          this.state.code += enemy.value;
          this.state.experience += enemy.value / 2;
          this.checkLevelUp();
          this.spawnDrop(enemy.x, enemy.y);
          return false;
        }
        hit = true;
      }
      return true;
    });

    if (!hit) {
      this.state.code += 1;
    }

    this.state.ripples.push({
      x,
      y,
      radius: 0,
      maxRadius: 50,
      life: 1.0,
    });
  }

  private checkLevelUp() {
    const nextLevelExp = this.state.level * 100;
    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.skillPoints++;
    }
  }

  private spawnDrop(x: number, y: number) {
    if (Math.random() > 0.8) {
      const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
      this.state.drops.push({
        id: Math.random().toString(36),
        name: lib.name,
        rarity: lib.rarity,
        effect: lib.effect,
        x,
        y,
        life: 1.0,
      });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, x: number, y: number) {
    const config = TOWER_TYPES[type];
    if (this.state.code >= config.cost) {
      this.state.code -= config.cost;
      this.state.towers.push({
        id: Math.random().toString(36),
        type,
        level: 1,
        x,
        y,
        range: config.range,
        damage: config.damage,
        fireRate: config.fireRate,
        lastFired: 0,
        color: config.color,
      });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x,
        y,
        vx: (Math.random() - 0.5) * 4,
        vy: (Math.random() - 0.5) * 4,
        size: Math.random() * 3 + 1,
        life: 1.0,
        color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = time - this.lastTime;
    this.lastTime = time;

    this.update(dt);
    this.draw();

    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver) return;

    // Spawn enemies
    this.enemySpawnTimer += dt;
    if (this.enemySpawnTimer > Math.max(500, 2000 - this.state.level * 50)) {
      this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    // Update particles
    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.life -= 0.02;
      return p.life > 0;
    });

    // Update ripples
    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 2;
      r.life -= 0.02;
      return r.life > 0;
    });

    // Update drops
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.005;
      // Magnet to center
      const dx = this.canvas.width / 2 - d.x;
      const dy = this.canvas.height / 2 - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 30) return false;
      d.x += (dx / dist) * 1;
      d.y += (dy / dist) * 1;
      return d.life > 0;
    });

    // Update enemies
    const centerX = this.canvas.width / 2;
    const centerY = this.canvas.height / 2;

    this.state.enemies.forEach(enemy => {
      const dx = centerX - enemy.x;
      const dy = centerY - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 40) {
        this.state.isGameOver = true;
      }

      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Tower logic
    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        // Find nearest enemy in range
        let nearest: Enemy | null = null;
        let minDist = tower.range;

        this.state.enemies.forEach(enemy => {
          const dx = enemy.x - tower.x;
          const dy = enemy.y - tower.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < minDist) {
            minDist = dist;
            nearest = enemy;
          }
        });

        if (nearest) {
          (nearest as Enemy).hp -= tower.damage;
          tower.lastFired = now;
          this.createParticles((nearest as Enemy).x, (nearest as Enemy).y, 3, tower.color);
        }
      }
    });

    // Clean up dead enemies
    this.state.enemies = this.state.enemies.filter(enemy => {
      if (enemy.hp <= 0) {
        this.state.code += enemy.value;
        this.state.experience += enemy.value / 4;
        this.checkLevelUp();
        this.spawnDrop(enemy.x, enemy.y);
        return false;
      }
      return true;
    });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.max(this.canvas.width, this.canvas.height);
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;

    const hp = 20 + this.state.level * 10;
    this.state.enemies.push({
      id: Math.random().toString(36),
      x,
      y,
      hp,
      maxHp: hp,
      speed: 1 + Math.random() * 0.5 + (this.state.level * 0.05),
      value: 10 + this.state.level * 2,
      type: 'bug',
      size: 15,
      angle: 0,
    });
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    // Draw grid
    this.ctx.strokeStyle = '#0f172a';
    this.ctx.lineWidth = 1;
    const gridSize = 50;
    for (let x = 0; x < this.canvas.width; x += gridSize) {
      this.ctx.beginPath();
      this.ctx.moveTo(x, 0);
      this.ctx.lineTo(x, this.canvas.height);
      this.ctx.stroke();
    }
    for (let y = 0; y < this.canvas.height; y += gridSize) {
      this.ctx.beginPath();
      this.ctx.moveTo(0, y);
      this.ctx.lineTo(this.canvas.width, y);
      this.ctx.stroke();
    }

    // Draw Mainframe (Center)
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.ctx.fillStyle = COLORS.PRIMARY;
    this.ctx.beginPath();
    this.ctx.arc(cx, cy, 30, 0, Math.PI * 2);
    this.ctx.fill();
    this.ctx.strokeStyle = COLORS.SECONDARY;
    this.ctx.lineWidth = 2;
    this.ctx.stroke();

    // Draw Ripples
    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`;
      this.ctx.lineWidth = 2;
      this.ctx.beginPath();
      this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2);
      this.ctx.stroke();
    });

    // Draw Particles
    this.state.particles.forEach(p => {
      this.ctx.fillStyle = p.color;
      this.ctx.globalAlpha = p.life;
      this.ctx.fillRect(p.x, p.y, p.size, p.size);
    });
    this.ctx.globalAlpha = 1.0;

    // Draw Drops
    this.state.drops.forEach(d => {
      this.ctx.fillStyle = COLORS.ACCENT;
      this.ctx.beginPath();
      this.ctx.arc(d.x, d.y, 5, 0, Math.PI * 2);
      this.ctx.fill();
      this.ctx.fillStyle = '#fff';
      this.ctx.font = '10px monospace';
      this.ctx.fillText(d.name, d.x + 8, d.y + 4);
    });

    // Draw Towers
    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      this.ctx.fillRect(t.x - 10, t.y - 10, 20, 20);
      this.ctx.strokeStyle = t.color;
      this.ctx.lineWidth = 1;
      this.ctx.globalAlpha = 0.1;
      this.ctx.beginPath();
      this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2);
      this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // Draw Enemies
    this.state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);
      this.ctx.fillStyle = COLORS.ENEMY;

      // Draw a "Bug" shape
      this.ctx.beginPath();
      this.ctx.moveTo(10, 0);
      this.ctx.lineTo(-5, 8);
      this.ctx.lineTo(-5, -8);
      this.ctx.closePath();
      this.ctx.fill();

      // HP bar
      this.ctx.restore();
      const hpWidth = 20;
      this.ctx.fillStyle = '#334155';
      this.ctx.fillRect(e.x - hpWidth/2, e.y - 15, hpWidth, 3);
      this.ctx.fillStyle = '#ef4444';
      this.ctx.fillRect(e.x - hpWidth/2, e.y - 15, hpWidth * (e.hp / e.maxHp), 3);
    });

    if (this.state.isGameOver) {
      this.ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
      this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
      this.ctx.fillStyle = '#fff';
      this.ctx.font = 'bold 48px Space Grotesk';
      this.ctx.textAlign = 'center';
      this.ctx.fillText('PRODUCTION DOWN', cx, cy - 20);
      this.ctx.font = '24px Space Grotesk';
      this.ctx.fillText('The bugs have overwhelmed the system.', cx, cy + 20);
    }
  }

  public applySkill(skill: any) {
    if (this.state.skillPoints > 0) {
      this.state.skillPoints--;
      skill.onUnlock(this.state);
      return true;
    }
    return false;
  }
}

import React from 'react';
import { GameState } from '../types';
import { TOWER_TYPES } from '../constants';
import { Terminal, Cpu, Zap, Code, Shield, Layers } from 'lucide-react';

interface Props {
  state: GameState;
  onBuildTower: (type: keyof typeof TOWER_TYPES) => void;
  onOpenSkills: () => void;
  onRestart: () => void;
}

const UIOverlay: React.FC<Props> = ({ state, onBuildTower, onOpenSkills, onRestart }) => {
  const expProgress = (state.experience / (state.level * 100)) * 100;

  return (
    <div className="fixed inset-0 pointer-events-none flex flex-col justify-between p-6">
      {/* Top Stats Bar */}
      <div className="flex justify-between items-start pointer-events-auto">
        <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700 p-4 rounded-xl shadow-2xl min-w-[200px]">
          <div className="flex items-center gap-2 mb-1">
            <Code className="text-sky-400 w-4 h-4" />
            <span className="text-slate-400 text-xs font-bold uppercase tracking-wider">Lines of Code</span>
          </div>
          <div className="text-3xl font-bold text-white mb-2 tabular-nums">
            {Math.floor(state.code).toLocaleString()}
          </div>
          <div className="flex items-center gap-2 mb-1">
            <Zap className="text-amber-400 w-4 h-4" />
            <span className="text-slate-400 text-xs font-bold uppercase tracking-wider">Level {state.level}</span>
          </div>
          <div className="w-full bg-slate-800 h-2 rounded-full overflow-hidden">
            <div 
              className="bg-amber-400 h-full transition-all duration-300"
              style={{ width: `${expProgress}%` }}
            />
          </div>
        </div>

        <button 
          onClick={onOpenSkills}
          className="bg-slate-900/80 hover:bg-slate-800 transition-colors backdrop-blur-md border border-slate-700 p-4 rounded-xl shadow-2xl flex items-center gap-3"
        >
          <div className="relative">
            <Cpu className="text-pink-400 w-6 h-6" />
            {state.skillPoints > 0 && (
              <span className="absolute -top-2 -right-2 bg-pink-500 text-white text-[10px] w-5 h-5 flex items-center justify-center rounded-full animate-pulse border-2 border-slate-900">
                {state.skillPoints}
              </span>
            )}
          </div>
          <div className="text-left">
            <div className="text-xs text-slate-400 font-bold uppercase">Tech Tree</div>
            <div className="text-sm text-white font-medium">Upgrade Stack</div>
          </div>
        </button>
      </div>

      {/* Center Prompt */}
      {!state.towers.length && !state.isGameOver && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center">
          <div className="animate-bounce mb-4 text-sky-400">
            <Zap size={48} className="mx-auto" />
          </div>
          <h2 className="text-2xl font-bold text-white mb-2">CLICK TO COMPILE</h2>
          <p className="text-slate-400">Destroy the bugs before they reach the Mainframe</p>
        </div>
      )}

      {/* Bottom Build Menu */}
      <div className="flex justify-center gap-4 pointer-events-auto">
        {(Object.entries(TOWER_TYPES) as [keyof typeof TOWER_TYPES, any][]).map(([key, config]) => (
          <button
            key={key}
            onClick={() => onBuildTower(key)}
            disabled={state.code < config.cost}
            className={`
              group relative bg-slate-900/80 backdrop-blur-md border p-4 rounded-xl flex flex-col items-center gap-2 transition-all
              ${state.code >= config.cost 
                ? 'border-slate-700 hover:border-sky-400 hover:-translate-y-1' 
                : 'border-transparent opacity-50 cursor-not-allowed'}
            `}
          >
            <div className="w-10 h-10 rounded-lg flex items-center justify-center" style={{ backgroundColor: config.color + '22' }}>
              {key === 'BASIC' && <Shield className="text-sky-400" />}
              {key === 'SNIPER' && <Terminal className="text-pink-400" />}
              {key === 'RAPID' && <Layers className="text-amber-400" />}
            </div>
            <div className="text-center">
              <div className="text-xs font-bold text-white">{config.name}</div>
              <div className="text-[10px] text-slate-400 uppercase font-bold tracking-tighter">{config.cost} LOC</div>
            </div>

            {/* Tooltip */}
            <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-4 w-48 bg-slate-900 border border-slate-700 p-3 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none text-xs">
              <div className="font-bold text-white mb-1">{config.name}</div>
              <div className="text-slate-400">Dmg: {config.damage} | Rate: {config.fireRate}ms</div>
            </div>
          </button>
        ))}
      </div>

      {/* Game Over Overlay */}
      {state.isGameOver && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-xl flex items-center justify-center pointer-events-auto">
          <div className="bg-slate-900 border border-slate-700 p-12 rounded-3xl shadow-2xl text-center max-w-md">
            <div className="w-20 h-20 bg-red-500/20 rounded-full flex items-center justify-center mx-auto mb-6">
              <Shield className="text-red-500 w-10 h-10" />
            </div>
            <h1 className="text-4xl font-bold text-white mb-4">SEGFAULT</h1>
            <p className="text-slate-400 mb-8 leading-relaxed">
              Your infrastructure failed to scale. You reached Level {state.level} with {Math.floor(state.code)} lines of legacy code.
            </p>
            <button
              onClick={onRestart}
              className="w-full bg-sky-500 hover:bg-sky-400 text-slate-900 font-bold py-4 rounded-xl transition-colors text-lg"
            >
              Hotfix & Restart
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default UIOverlay;

import React from 'react';
import { GameState } from '../types';
import { Cpu, X, Zap, Target, MousePointer2, Shield } from 'lucide-react';

interface Props {
  state: GameState;
  isOpen: boolean;
  onClose: () => void;
  onUpgrade: (skillId: string) => void;
}

const SKILLS = [
  {
    id: 'click_1',
    name: 'Mechanical Keyboard',
    description: '+100% Click Damage',
    cost: 1,
    icon: <MousePointer2 className="w-5 h-5" />,
    onUnlock: (s: GameState) => { s.clickPower *= 2; },
    unlocked: false,
  },
  {
    id: 'tower_range_1',
    name: 'Fiber Optics',
    description: '+20% Tower Range',
    cost: 1,
    icon: <Target className="w-5 h-5" />,
    onUnlock: (s: GameState) => { s.towers.forEach(t => t.range *= 1.2); },
    unlocked: false,
  },
  {
    id: 'tower_dmg_1',
    name: 'Overclocking',
    description: '+30% Tower Damage',
    cost: 2,
    icon: <Zap className="w-5 h-5" />,
    onUnlock: (s: GameState) => { s.towers.forEach(t => t.damage *= 1.3); },
    unlocked: false,
  },
  {
    id: 'auto_collect',
    name: 'Garbage Collection',
    description: 'Auto-collect drops',
    cost: 3,
    icon: <Cpu className="w-5 h-5" />,
    onUnlock: (s: GameState) => { /* Logic in engine handles this usually */ },
    unlocked: false,
  },
  {
    id: 'shield_max',
    name: 'Firewall',
    description: 'Bugs take 10% more damage',
    cost: 5,
    icon: <Shield className="w-5 h-5" />,
    onUnlock: (s: GameState) => { /* Engine level logic */ },
    unlocked: false,
  }
];

const SkillTree: React.FC<Props> = ({ state, isOpen, onClose, onUpgrade }) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-950/90 backdrop-blur-md">
      <div className="bg-slate-900 border border-slate-700 rounded-3xl w-full max-w-2xl overflow-hidden shadow-2xl">
        <div className="p-6 border-b border-slate-700 flex justify-between items-center bg-slate-800/50">
          <div className="flex items-center gap-3">
            <Cpu className="text-sky-400" />
            <div>
              <h2 className="text-xl font-bold text-white">Technology Tree</h2>
              <p className="text-xs text-slate-400">Available Skill Points: <span className="text-amber-400">{state.skillPoints}</span></p>
            </div>
