export interface GameState {
  code: number;
  experience: number;
  level: number;
  skillPoints: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  isGameOver: boolean;
}

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, Point } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES } from '../constants';

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = {
      code: 100,
      experience: 0,
      level: 1,
      skillPoints: 0,
      clickPower: 10, // Buffed starting power
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      isGameOver: false,
    };

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public getState() {
    return this.state;
  }

  public handleClick(x: number, y: number) {
    if (this.state.isGameOver) return;

    let hit = false;
    const now = Date.now();

    this.state.enemies = this.state.enemies.filter(enemy => {
      const dx = enemy.x - x;
      const dy = enemy.y - y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Increased hit area (45px radius) for better mobile/fast-clicking feel
      if (dist < 45) {
        enemy.hp -= this.state.clickPower;
        enemy.lastHit = now;
        this.createParticles(enemy.x, enemy.y, 8, COLORS.PRIMARY);

        if (enemy.hp <= 0) {
          this.state.code += enemy.value;
          this.state.experience += enemy.value / 2;
          this.createFloatingText(enemy.x, enemy.y, `+${enemy.value}`, COLORS.ACCENT);
          this.checkLevelUp();
          this.spawnDrop(enemy.x, enemy.y);
          hit = true;
          return false;
        }
        hit = true;
      }
      return true;
    });

    if (!hit) {
      this.state.code += 1;
      this.createFloatingText(x, y, "+1", COLORS.PRIMARY);
    }

    this.state.ripples.push({
      x,
      y,
      radius: 0,
      maxRadius: 60,
      life: 1.0,
    });

    // Force immediate UI update on click
    this.onUpdate({ ...this.state });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x,
      y,
      vx: (Math.random() - 0.5) * 2,
      vy: -2 - Math.random() * 2,
      size: 14,
      life: 1.0,
      color,
      text
    });
  }

  private checkLevelUp() {
    const nextLevelExp = this.state.level * 100;
    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.skillPoints++;
      this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2, "LEVEL UP!", COLORS.ACCENT);
    }
  }

  private spawnDrop(x: number, y: number) {
    if (Math.random() > 0.7) {
      const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
      this.state.drops.push({
        id: Math.random().toString(36),
        name: lib.name,
        rarity: lib.rarity,
        effect: lib.effect,
        x,
        y,
        life: 1.0,
      });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, x: number, y: number) {
    const config = TOWER_TYPES[type];
    if (this.state.code >= config.cost) {
      this.state.code -= config.cost;
      this.state.towers.push({
        id: Math.random().toString(36),
        type,
        level: 1,
        x,
        y,
        range: config.range,
        damage: config.damage,
        fireRate: config.fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x,
        y,
        vx: (Math.random() - 0.5) * 6,
        vy: (Math.random() - 0.5) * 6,
        size: Math.random() * 4 + 2,
        life: 1.0,
        color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = time - this.lastTime;
    this.lastTime = time;

    this.update(dt);
    this.draw();

    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver) return;

    // Spawn enemies more frequently at higher levels
    this.enemySpawnTimer += dt;
    const spawnRate = Math.max(400, 1800 - this.state.level * 100);
    if (this.enemySpawnTimer > spawnRate) {
      this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    // Update particles
    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.life -= p.text ? 0.015 : 0.03;
      return p.life > 0;
    });

    // Update ripples
    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 4;
      r.life -= 0.04;
      return r.life > 0;
    });

    // Update drops
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.003;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 30) {
        // Collect drop logic
        this.createFloatingText(cx, cy, "LIB INSTALLED", COLORS.SECONDARY);
        this.state.code += 50;
        return false;
      }
      d.x += (dx / dist) * 2;
      d.y += (dy / dist) * 2;
      return d.life > 0;
    });

    // Update enemies
    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 35) {
        this.state.isGameOver = true;
      }

      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Tower logic
    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let nearest: Enemy | null = null;
        let minDist = tower.range;

        this.state.enemies.forEach(enemy => {
          const dx = enemy.x - tower.x;
          const dy = enemy.y - tower.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < minDist) {
            minDist = dist;
            nearest = enemy;
          }
        });

        if (nearest) {
          (nearest as Enemy).hp -= tower.damage;
          (nearest as Enemy).lastHit = now;
          tower.lastFired = now;
          this.createParticles((nearest as Enemy).x, (nearest as Enemy).y, 3, tower.color);
        }
      }
    });

    // Clean up dead enemies (same logic as handleClick but for towers)
    this.state.enemies = this.state.enemies.filter(enemy => {
      if (enemy.hp <= 0) {
        this.state.code += enemy.value;
        this.state.experience += enemy.value / 4;
        this.checkLevelUp();
        this.spawnDrop(enemy.x, enemy.y);
        return false;
      }
      return true;
    });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    // Spawn just outside the viewport radius
    const dist = Math.sqrt(this.canvas.width ** 2 + this.canvas.height ** 2) / 2 + 50;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;

    const hp = 15 + this.state.level * 8;
    this.state.enemies.push({
      id: Math.random().toString(36),
      x,
      y,
      hp,
      maxHp: hp,
      speed: 1.2 + Math.random() * 0.8 + (this.state.level * 0.1),
      value: 10 + this.state.level * 2,
      type: 'bug',
      size: 18,
      angle: 0,
    });
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    // Draw grid
    this.ctx.strokeStyle = '#0f172a';
    this.ctx.lineWidth = 1;
    const gridSize = 80;
    for (let x = 0; x < this.canvas.width; x += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(x, 0); this.ctx.lineTo(x, this.canvas.height); this.ctx.stroke();
    }
    for (let y = 0; y < this.canvas.height; y += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(0, y); this.ctx.lineTo(this.canvas.width, y); this.ctx.stroke();
    }

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;

    // Pulse effect for mainframe
    const pulse = Math.sin(Date.now() / 200) * 5;
    this.ctx.shadowBlur = 20 + pulse;
    this.ctx.shadowColor = COLORS.PRIMARY;
    this.ctx.fillStyle = COLORS.PRIMARY;
    this.ctx.beginPath();
    this.ctx.arc(cx, cy, 30, 0, Math.PI * 2);
    this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // Draw Ripples
    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`;
      this.ctx.lineWidth = 3;
      this.ctx.beginPath();
      this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2);
      this.ctx.stroke();
    });

    // Draw Particles & Floating Text
    this.state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      if (p.text) {
        this.ctx.fillStyle = p.color;
        this.ctx.font = `bold ${p.size}px Space Grotesk`;
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.fillStyle = p.color;
        this.ctx.fillRect(p.x, p.y, p.size, p.size);
      }
    });
    this.ctx.globalAlpha = 1.0;

    // Draw Drops
    this.state.drops.forEach(d => {
      this.ctx.fillStyle = COLORS.ACCENT;
      this.ctx.beginPath(); this.ctx.arc(d.x, d.y, 6, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.fillStyle = '#fff';
      this.ctx.font = '12px monospace';
      this.ctx.fillText(d.name, d.x + 10, d.y + 4);
    });

    // Draw Towers
    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      this.ctx.fillRect(t.x - 12, t.y - 12, 24, 24);
      this.ctx.strokeStyle = t.color;
      this.ctx.globalAlpha = 0.05;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // Draw Enemies
    const now = Date.now();
    this.state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      // Flash white if recently hit
      if (e.lastHit && now - e.lastHit < 100) {
        this.ctx.fillStyle = '#ffffff';
      } else {
        this.ctx.fillStyle = COLORS.ENEMY;
      }

      this.ctx.beginPath();
      this.ctx.moveTo(12, 0);
      this.ctx.lineTo(-8, 10);
      this.ctx.lineTo(-8, -10);
      this.ctx.closePath();
      this.ctx.fill();

      this.ctx.restore();

      // HP bar
      const hpWidth = 30;
      this.ctx.fillStyle = '#1e293b';
      this.ctx.fillRect(e.x - hpWidth/2, e.y - 20, hpWidth, 4);
      this.ctx.fillStyle = COLORS.ENEMY;
      this.ctx.fillRect(e.x - hpWidth/2, e.y - 20, hpWidth * (e.hp / e.maxHp), 4);
    });

    if (this.state.isGameOver) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.85)';
      this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
      this.ctx.fillStyle = '#fff';
      this.ctx.font = 'bold 64px Space Grotesk';
      this.ctx.textAlign = 'center';
      this.ctx.fillText('CRITICAL ERROR', cx, cy - 40);
      this.ctx.font = '24px Space Grotesk';
      this.ctx.fillText('Mainframe compromised by production bugs.', cx, cy + 20);
    }
  }

  public applySkill(skill: any) {
    if (this.state.skillPoints > 0) {
      this.state.skillPoints--;
      skill.onUnlock(this.state);
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }
}

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, Point } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES } from '../constants';

export class GameEngine {
