  life: number;
}

export interface PermanentUpgrades {
  startingCode: number;
  damageMultiplier: number;
  xpMultiplier: number;
  legacyPoints: number;
}

export interface SkillDefinition {
  id: string;
  name: string;
  description: string;
  cost: number;
  rarity: 'common' | 'rare' | 'epic';
}

export interface GameState {
  code: number;
  experience: number;
  level: number;
  skillPoints: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  isGameOver: boolean;
  isVictory: boolean;
  permanentUpgrades: PermanentUpgrades;
  lastRunCode: number;
  availableSkills: string[]; // IDs of currently offered shop skills
  rerollCost: number;
}

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS } from '../constants';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 100;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private hasSaaS: boolean = false;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 100 + this.state.permanentUpgrades.startingCode;
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 100,
      experience: 0,
      level: 1,
      skillPoints: 0,
      clickPower: 12,
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      isGameOver: false,
      isVictory: false,
      lastRunCode: 0,
      availableSkills: [],
      rerollCost: BASE_REROLL_COST,
      permanentUpgrades: {
        startingCode: 0,
        damageMultiplier: 1.0,
        xpMultiplier: 1.0,
        legacyPoints: 0,
      }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 5 : 1;
    const earnedLegacy = Math.floor(this.state.code / 200) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 100 + perms.startingCode;
    this.state.clickPower = 12 * perms.damageMultiplier;

    this.enemySpawnTimer = 0;
    this.hasAutoCollect = false;
    this.hasSaaS = false;
    this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 15;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 250;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.25;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 0.3;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    const shuffled = [...ALL_SKILLS].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.75); // Increase cost
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(x: number, y: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    let hit = false;
    const now = Date.now();

    this.state.enemies = this.state.enemies.filter(enemy => {
      const dx = enemy.x - x;
      const dy = enemy.y - y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 50) {
        enemy.hp -= this.state.clickPower;
        enemy.lastHit = now;
        this.createParticles(enemy.x, enemy.y, 6, COLORS.PRIMARY);

        if (enemy.hp <= 0) {
          this.state.code += enemy.value;
          this.state.experience += (enemy.value / 2) * this.state.permanentUpgrades.xpMultiplier;
          this.createFloatingText(enemy.x, enemy.y, `+${enemy.value}`, COLORS.ACCENT);
          this.checkLevelUp();
          this.spawnDrop(enemy.x, enemy.y);
          hit = true;
          return false;
        }
        hit = true;
      }
      return true;
    });

    if (!hit) {
      this.state.code += 1;
      this.createFloatingText(x, y, "+1", COLORS.PRIMARY);
    }

    this.state.ripples.push({ x, y, radius: 0, maxRadius: 60, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x, y, vx: (Math.random() - 0.5) * 2, vy: -2.5, size: 16, life: 1.0, color, text
    });
  }

  private checkLevelUp() {
    const nextLevelExp = this.state.level * 100;
    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.skillPoints++;
      this.refreshSkillShop();
      this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2, "NEW UPGRADES!", COLORS.ACCENT);

      if (this.state.level >= 100) {
        this.state.isVictory = true;
      }
    }
  }

  private spawnDrop(x: number, y: number) {
    if (Math.random() > 0.75) {
      const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
      this.state.drops.push({
        id: Math.random().toString(36),
        name: lib.name, rarity: lib.rarity, effect: lib.effect, x, y, life: 1.0,
      });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, x: number, y: number) {
    const config = TOWER_TYPES[type];
    if (this.state.code >= config.cost) {
      this.state.code -= config.cost;
      this.state.towers.push({
        id: Math.random().toString(36),
        type, level: 1, x, y,
        range: config.range,
        damage: config.damage * this.state.permanentUpgrades.damageMultiplier,
        fireRate: config.fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x, y, vx: (Math.random() - 0.5) * 8, vy: (Math.random() - 0.5) * 8,
        size: Math.random() * 4 + 2, life: 1.0, color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = time - this.lastTime;
    this.lastTime = time;
    this.update(dt);
    this.draw();
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    // Passive Code timer
    if (this.hasSaaS) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) {
        this.state.code += 10 + (this.state.level * 2);
        this.passiveCodeTimer = 0;
      }
    }

    this.enemySpawnTimer += dt;
    // Faster spawning as level increases
    const spawnRate = Math.max(300, 2000 - (this.state.level * 25));
    if (this.enemySpawnTimer > spawnRate) {
      this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx; p.y += p.vy;
      p.life -= p.text ? 0.01 : 0.04;
      return p.life > 0;
    });

    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 5; r.life -= 0.05;
      return r.life > 0;
    });

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.003;
      const dx = cx - d.x; const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const pullSpeed = this.hasAutoCollect ? 8 : 2;
      const collectRadius = this.hasAutoCollect ? 120 : 40;
      if (dist < collectRadius) {
        this.createFloatingText(cx, cy, "LIB OK", COLORS.SECONDARY);
        this.state.code += 75 + (this.state.level * 5);
        return false;
      }
      d.x += (dx / dist) * pullSpeed; d.y += (dy / dist) * pullSpeed;
      return d.life > 0;
    });

    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x; const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 40) this.state.isGameOver = true;
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let nearest: Enemy | null = null;
        let minDist = tower.range;
        this.state.enemies.forEach(enemy => {
          const dx = enemy.x - tower.x; const dy = enemy.y - tower.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < minDist) { minDist = dist; nearest = enemy; }
        });
        if (nearest) {
          (nearest as Enemy).hp -= tower.damage;
          (nearest as Enemy).lastHit = now;
          tower.lastFired = now;
          this.createParticles((nearest as Enemy).x, (nearest as Enemy).y, 3, tower.color);
        }
      }
    });

    this.state.enemies = this.state.enemies.filter(enemy => {
      if (enemy.hp <= 0) {
        this.state.code += enemy.value;
        this.state.experience += (enemy.value / 4) * this.state.permanentUpgrades.xpMultiplier;
        this.checkLevelUp();
        this.spawnDrop(enemy.x, enemy.y);
        return false;
      }
      return true;
    });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.sqrt(this.canvas.width ** 2 + this.canvas.height ** 2) / 2 + 100;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;

    // Scaling Difficulty: HP increases exponentially
    const isBoss = this.state.level % 10 === 0 && this.state.enemies.filter(e => e.type === 'boss').length === 0;
    const levelMult = Math.pow(1.1, this.state.level);
    const hp = (isBoss ? 200 : 20) * levelMult;

    this.state.enemies.push({
      id: Math.random().toString(36),
      x, y, hp, maxHp: hp,
      speed: (isBoss ? 0.8 : 1.5) + (this.state.level * 0.02),
      value: (isBoss ? 500 : 15) + this.state.level * 5,
      type: isBoss ? 'boss' : 'bug', 
      size: isBoss ? 40 : 20, 
      angle: 0,
    });
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    this.ctx.strokeStyle = '#0f172a';
    this.ctx.lineWidth = 1;
    const gridSize = 100;
    for (let x = 0; x < this.canvas.width; x += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(x, 0); this.ctx.lineTo(x, this.canvas.height); this.ctx.stroke();
    }
    for (let y = 0; y < this.canvas.height; y += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(0, y); this.ctx.lineTo(this.canvas.width, y); this.ctx.stroke();
    }

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;

    // Mainframe scaling visual
    const mfSize = 30 + (this.state.level * 0.5);
    const pulse = Math.sin(Date.now() / 200) * 10;
    this.ctx.shadowBlur = 25 + pulse; 
    this.ctx.shadowColor = this.state.level > 90 ? COLORS.SECONDARY : COLORS.PRIMARY;
    this.ctx.fillStyle = this.state.level > 90 ? COLORS.SECONDARY : COLORS.PRIMARY; 
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 4;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    this.state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      if (p.text) {
        this.ctx.fillStyle = p.color; this.ctx.font = `bold ${p.size}px Space Grotesk`; this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.fillStyle = p.color; this.ctx.fillRect(p.x, p.y, p.size, p.size);
      }
    });
    this.ctx.globalAlpha = 1.0;

    this.state.drops.forEach(d => {
      this.ctx.fillStyle = COLORS.ACCENT; this.ctx.beginPath(); this.ctx.arc(d.x, d.y, 8, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.fillStyle = '#fff'; this.ctx.font = '14px monospace'; this.ctx.fillText(d.name, d.x + 12, d.y + 4);
    });

    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      // Slight fire-kick animation
      const kick = Date.now() - t.lastFired < 100 ? 4 : 0;
      this.ctx.fillRect(t.x - 12 - kick/2, t.y - 12 - kick/2, 24 + kick, 24 + kick);
      this.ctx.strokeStyle = t.color; this.ctx.globalAlpha = 0.08;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    const now = Date.now();
    this.state.enemies.forEach(e => {
      this.ctx.save(); this.ctx.translate(e.x, e.y); this.ctx.rotate(e.angle);
      if (e.lastHit && now - e.lastHit < 100) this.ctx.fillStyle = '#ffffff'; 
      else this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;

      this.ctx.beginPath();
      const s = e.size / 2;
      this.ctx.moveTo(s*1.5, 0); this.ctx.lineTo(-s, s); this.ctx.lineTo(-s, -s); this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();

      const hpWidth = e.size * 1.5;
      this.ctx.fillStyle = '#1e293b'; this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 5, hpWidth, 5);
      this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 5, hpWidth * (e.hp / e.maxHp), 5);
    });

    if (this.state.isGameOver || this.state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.95)'; this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    }
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      this.state.skillPoints--;
      this.state.rerollCost = BASE_REROLL_COST; // Reset cost on purchase
      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      if (skillId === 'code_gen') this.hasSaaS = true;
      onUnlock(this.state);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }
}

import React from 'react';
import { GameState } from '../types';
import { ALL_SKILLS } from '../constants';
import { Cpu, X, Zap, Target, MousePointer2, Shield, Code, Award, Sparkles, RefreshCcw } from 'lucide-react';

interface Props {
  state: GameState;
  isOpen: boolean;
  onClose: () => void;
  onUpgrade: (skillId: string) => void;
  onReroll: () => void;
}

const SkillTree: React.FC<Props> = ({ state, isOpen, onClose, onUpgrade, onReroll }) => {
  if (!isOpen) return null;

  const currentShopSkills = ALL_SKILLS.filter(s => state.availableSkills.includes(s.id));

  const getIcon = (id: string) => {
    if (id.includes('click')) return <MousePointer2 className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('range')) return <Target className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('dmg')) return <Zap className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('collect')) return <Cpu className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('code_gen')) return <Code className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('shield')) return <Shield className="w-5 h-5 sm:w-6 sm:h-6" />;
    return <Award className="w-5 h-5 sm:w-6 sm:h-6" />;
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-3 sm:p-6 bg-slate-950/90 backdrop-blur-xl pointer-events-auto">
      <div className="bg-slate-900 border border-slate-700 rounded-3xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden shadow-2xl">
        {/* Header */}
        <div className="p-4 sm:p-8 border-b border-slate-700 flex justify-between items-center bg-slate-800/30 flex-shrink-0">
          <div className="flex items-center gap-3 sm:gap-4">
            <div className="p-2 sm:p-3 bg-sky-500/10 rounded-xl sm:rounded-2xl">
              <Sparkles className="text-sky-400 w-6 h-6 sm:w-8 sm:h-8" />
            </div>
            <div>
              <h2 className="text-xl sm:text-2xl font-black text-white tracking-tight uppercase italic">Upgrade Stack</h2>
              <p className="text-[10px] sm:text-sm text-slate-400 font-bold uppercase tracking-widest opacity-60">Random Selection Available</p>
            </div>
          </div>
          <div className="flex items-center gap-4 sm:gap-6">
             <div className="text-right hidden xs:block">
                <div className="text-[8px] sm:text-[10px] text-slate-400 uppercase font-black tracking-widest">Points</div>
                <div className="text-lg sm:text-2xl font-black text-amber-400">{state.skillPoints} SP</div>
             </div>
            <button 
              onClick={onClose} 
              className="p-2 hover:bg-slate-700 active:scale-90 rounded-full text-slate-400 transition-all border border-transparent hover:border-slate-600"
            >
              <X size={24} />
            </button>
          </div>
        </div>

        {/* Scrollable Content */}
        <div className="flex-grow overflow-y-auto p-4 sm:p-10 no-scrollbar">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
            {currentShopSkills.map((skill) => (
              <button
                key={skill.id}
                onClick={() => onUpgrade(skill.id)}
                disabled={state.skillPoints < skill.cost}
                className={`
                  text-left p-5 sm:p-6 rounded-2xl sm:rounded-3xl border transition-all relative group flex flex-col justify-between
                  ${state.skillPoints >= skill.cost 
                    ? 'border-slate-700 bg-slate-800/40 hover:border-sky-400 hover:-translate-y-2 active:scale-95 hover:shadow-2xl hover:shadow-sky-500/10' 
                    : 'border-slate-800 bg-slate-900/50 opacity-40 cursor-not-allowed'}
                `}
              >
                <div>
                  <div className={`w-12 h-12 sm:w-14 sm:h-14 rounded-xl sm:rounded-2xl flex items-center justify-center mb-4 sm:mb-6 
                    ${skill.rarity === 'epic' ? 'bg-purple-500/20 text-purple-400' : 
                      skill.rarity === 'rare' ? 'bg-amber-500/20 text-amber-400' : 'bg-sky-500/20 text-sky-400'}`}>
                    {getIcon(skill.id)}
                  </div>
                  <h3 className="text-base sm:text-lg font-black text-white leading-tight mb-2 uppercase italic tracking-tight">{skill.name}</h3>
                  <p className="text-xs sm:text-sm text-slate-400 leading-relaxed mb-4 font-medium">{skill.description}</p>
                </div>

                <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-700/50">
                  <span className={`text-[8px] sm:text-[10px] font-black px-2 py-1 rounded uppercase tracking-tighter
                    ${skill.rarity === 'epic' ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30' : 
                      skill.rarity === 'rare' ? 'bg-amber-500/20 text-amber-400 border border-amber-500/30' : 
                      'bg-sky-500/20 text-sky-400 border border-sky-500/30'}`}>
                    {skill.rarity}
                  </span>
                  <div className="font-black text-white text-[10px] sm:text-sm uppercase tracking-widest">
                    {skill.cost} SP
                  </div>
                </div>
              </button>
            ))}
          </div>

          {/* Reroll Button Section */}
          <div className="mt-8 flex flex-col sm:flex-row items-center justify-center gap-4 border-t border-slate-800 pt-8">
            <button
              onClick={onReroll}
              disabled={state.code < state.rerollCost}
              className={`
                flex items-center gap-3 px-8 py-4 rounded-2xl font-black uppercase italic tracking-wider transition-all
                ${state.code >= state.rerollCost
                  ? 'bg-slate-800 hover:bg-slate-700 border border-slate-700 text-sky-400 hover:border-sky-400 active:scale-95'
                  : 'bg-slate-900/50 border border-transparent text-slate-600 cursor-not-allowed opacity-50'}
              `}
            >
              <RefreshCcw className={`w-5 h-5 ${state.code >= state.rerollCost ? 'animate-spin-slow' : ''}`} />
              <span>Reroll Shop</span>
              <span className="ml-2 text-slate-400 opacity-60">({state.rerollCost} LOC)</span>
            </button>

            <div className="text-[10px] text-slate-500 font-bold text-center sm:text-left max-w-[200px]">
              COST INCREASES UNTIL A PURCHASE IS MADE.
            </div>
          </div>

          {/* Mobile indicator for more SP */}
          <div className="xs:hidden flex justify-center mt-6">
            <div className="bg-slate-800 border border-slate-700 px-4 py-2 rounded-full flex items-center gap-2">
              <Zap className="text-amber-400 w-4 h-4" />
              <span className="text-white text-xs font-black uppercase">{state.skillPoints} SP Available</span>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-4 sm:p-6 bg-slate-950/50 text-center text-[9px] sm:text-xs text-slate-500 font-bold uppercase tracking-[0.2em] border-t border-slate-800 flex-shrink-0">
          The stack refreshes on every level-up. Select your dependencies wisely.
        </div>
      </div>
    </div>
  );
};

export default SkillTree;

import React, { useEffect, useRef, useState } from 'react';
import { GameEngine } from './engine/GameEngine';
import { GameState, PermanentUpgrades } from './types';
import UIOverlay from './components/UIOverlay';
import SkillTree from './components/SkillTree';
import { TOWER_TYPES } from './constants';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<GameEngine | null>(null);
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [isSkillTreeOpen, setIsSkillTreeOpen] = useState(false);
  const [buildingType, setBuildingType] = useState<keyof typeof TOWER_TYPES | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;

    const engine = new GameEngine(canvasRef.current, (state) => {
      setGameState(state);
    });
    engineRef.current = engine;

    return () => {
      // Cleanup
    };
  }, []);

  const handleClick = (e: React.MouseEvent) => {
    if (!engineRef.current || isSkillTreeOpen || (gameState && gameState.isGameOver)) return;

    const rect = canvasRef.current!.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    if (buildingType) {
      const success = engineRef.current.buyTower(buildingType, x, y);
      if (success) setBuildingType(null);
    } else {
      engineRef.current.handleClick(x, y);
    }
  };

  const handleBuildTower = (type: keyof typeof TOWER_TYPES) => {
    setBuildingType(type);
  };

  const handleUpgrade = (skillId: string) => {
    if (engineRef.current) {
      const onUnlock = (s: GameState) => {
        if (skillId === 'click_1') s.clickPower *= 2;
        if (skillId === 'tower_range_1') s.towers.forEach((t: any) => t.range *= 1.2);
        if (skillId === 'tower_dmg_1') s.towers.forEach((t: any) => t.damage *= 1.3);
      };
      engineRef.current.applySkill(skillId, onUnlock);
    }
  };

  const handleReroll = () => {
    if (engineRef.current) {
      engineRef.current.rerollSkills();
    }
  };

  const handleRestart = () => {
    if (engineRef.current) {
      engineRef.current.reset();
    }
  };

  const handleBuyPermanent = (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => {
    if (engineRef.current) {
      engineRef.current.buyPermanentUpgrade(type);
    }
  };

  return (
    <div className="relative w-screen h-screen bg-slate-950 overflow-hidden select-none cursor-crosshair">
      <canvas
        ref={canvasRef}
        onClick={handleClick}
        className="block w-full h-full"
      />

      {gameState && (
        <>
          <UIOverlay 
            state={gameState} 
            onBuildTower={handleBuildTower}
            onOpenSkills={() => setIsSkillTreeOpen(true)}
            onRestart={handleRestart}
            onBuyPermanent={handleBuyPermanent}
          />
          <SkillTree 
            state={gameState}
            isOpen={isSkillTreeOpen}
            onClose={() => setIsSkillTreeOpen(false)}
            onUpgrade={handleUpgrade}
            onReroll={handleReroll}
          />
        </>
      )}

      {buildingType && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-sky-500 text-slate-900 px-6 py-2 rounded-full font-bold shadow-2xl animate-pulse pointer-events-none">
          PLACING {TOWER_TYPES[buildingType].name} - CLICK ANYWHERE
        </div>
      )}

      <div className="fixed inset-0 pointer-events-none opacity-20 bg-[radial-gradient(circle_at_center,_transparent_0%,_#020617_100%)]" />
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export interface Particle extends Point {
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
  text?: string;
}

export interface ClickRipple extends Point {
  radius: number;
  maxRadius: number;
  life: number;
}

export interface Enemy extends Point {
  id: string;
  hp: number;
  maxHp: number;
  speed: number;
  value: number;
  type: 'bug' | 'boss' | 'glitch';
  size: number;
  angle: number;
  lastHit?: number;
}

export interface Tower extends Point {
  id: string;
  type: string;
  level: number;
  range: number;
  damage: number;
  fireRate: number;
  lastFired: number;
  color: string;
}

export interface LibraryDrop extends Point {
  id: string;
  name: string;
  rarity: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
  effect: string;
  life: number;
}

export interface PermanentUpgrades {
  startingCode: number;
  damageMultiplier: number;
  xpMultiplier: number;
  legacyPoints: number;
}

export interface SkillDefinition {
  id: string;
  name: string;
  description: string;
  cost: number;
  rarity: 'common' | 'rare' | 'epic';
}

export interface TechNode {
  id: string;
  name: string;
  description: string;
  cost: number;
  dependsOn?: string;
  position: { x: number, y: number };
}

export interface GameState {
  code: number;
  experience: number;
  level: number;
  skillPoints: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  isGameOver: boolean;
  isVictory: boolean;
  permanentUpgrades: PermanentUpgrades;
  lastRunCode: number;
  availableSkills: string[];
  unlockedTech: string[];
  rerollCost: number;
}

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS } from '../constants';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 100;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private hasSaaS: boolean = false;
  private hasPassiveIncome: boolean = false;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 100 + this.state.permanentUpgrades.startingCode;
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 100,
      experience: 0,
      level: 1,
      skillPoints: 0,
      clickPower: 12,
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      isGameOver: false,
      isVictory: false,
      lastRunCode: 0,
      availableSkills: [],
      unlockedTech: ['root'],
      rerollCost: BASE_REROLL_COST,
      permanentUpgrades: {
        startingCode: 0,
        damageMultiplier: 1.0,
        xpMultiplier: 1.0,
        legacyPoints: 0,
      }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 5 : 1;
    const earnedLegacy = Math.floor(this.state.code / 200) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 100 + perms.startingCode;
    this.state.clickPower = 12 * perms.damageMultiplier;

    this.enemySpawnTimer = 0;
    this.hasAutoCollect = false;
    this.hasSaaS = false;
    this.hasPassiveIncome = false;
    this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 15;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 250;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.25;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 0.3;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    const shuffled = [...ALL_SKILLS].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.75);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(x: number, y: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    let hit = false;
    const now = Date.now();

    this.state.enemies = this.state.enemies.filter(enemy => {
      const dx = enemy.x - x;
      const dy = enemy.y - y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 55) {
        enemy.hp -= this.state.clickPower;
        enemy.lastHit = now;
        this.createParticles(enemy.x, enemy.y, 6, COLORS.PRIMARY);

        if (enemy.hp <= 0) {
          this.state.code += enemy.value;
          this.state.experience += (enemy.value / 2) * this.state.permanentUpgrades.xpMultiplier;
          this.createFloatingText(enemy.x, enemy.y, `+${enemy.value}`, COLORS.ACCENT);
          this.checkLevelUp();
          this.spawnDrop(enemy.x, enemy.y);
          hit = true;
          return false;
        }
        hit = true;
      }
      return true;
    });

    if (!hit) {
      this.state.code += 1;
      this.createFloatingText(x, y, "+1", COLORS.PRIMARY);
    }

    this.state.ripples.push({ x, y, radius: 0, maxRadius: 60, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x, y, vx: (Math.random() - 0.5) * 2, vy: -2.5, size: 16, life: 1.0, color, text
    });
  }

  private checkLevelUp() {
    const nextLevelExp = this.state.level * 100;
    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.skillPoints++;
      this.refreshSkillShop();
      this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2, "NEW UPGRADES!", COLORS.ACCENT);

      if (this.state.level >= 100) {
        this.state.isVictory = true;
      }
    }
  }

  private spawnDrop(x: number, y: number) {
    if (Math.random() > 0.75) {
      const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
      this.state.drops.push({
        id: Math.random().toString(36),
        name: lib.name, rarity: lib.rarity, effect: lib.effect, x, y, life: 1.0,
      });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, x: number, y: number) {
    const config = TOWER_TYPES[type];

    // Check if technology is unlocked
    if (config.requires && !this.state.unlockedTech.includes(config.requires)) {
      this.createFloatingText(x, y, "TECH REQUIRED", COLORS.ENEMY);
      return false;
    }

    if (this.state.code >= config.cost) {
      this.state.code -= config.cost;
      this.state.towers.push({
        id: Math.random().toString(36),
        type, level: 1, x, y,
        range: config.range,
        damage: config.damage * this.state.permanentUpgrades.damageMultiplier,
        fireRate: config.fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x, y, vx: (Math.random() - 0.5) * 8, vy: (Math.random() - 0.5) * 8,
        size: Math.random() * 4 + 2, life: 1.0, color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = time - this.lastTime;
    this.lastTime = time;
    this.update(dt);
    this.draw();
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    // Passive Code timer
    if (this.hasSaaS || this.hasPassiveIncome) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) {
        let gain = 0;
        if (this.hasSaaS) gain += 10 + (this.state.level * 2);
        if (this.hasPassiveIncome) gain += (this.state.level * 5);
        this.state.code += gain;
        this.passiveCodeTimer = 0;
      }
    }

    this.enemySpawnTimer += dt;
    const spawnRate = Math.max(300, 2000 - (this.state.level * 25));
    if (this.enemySpawnTimer > spawnRate) {
      this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx; p.y += p.vy;
      p.life -= p.text ? 0.01 : 0.04;
      return p.life > 0;
    });

    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 5; r.life -= 0.05;
      return r.life > 0;
    });

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.003;
      const dx = cx - d.x; const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const pullSpeed = this.hasAutoCollect ? 8 : 2;
      const collectRadius = this.hasAutoCollect ? 120 : 40;
      if (dist < collectRadius) {
        this.createFloatingText(cx, cy, "LIB OK", COLORS.SECONDARY);
        this.state.code += 75 + (this.state.level * 5);
        return false;
      }
      d.x += (dx / dist) * pullSpeed; d.y += (dy / dist) * pullSpeed;
      return d.life > 0;
    });

    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x; const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 40) this.state.isGameOver = true;
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let nearest: Enemy | null = null;
        let minDist = tower.range;
        this.state.enemies.forEach(enemy => {
          const dx = enemy.x - tower.x; const dy = enemy.y - tower.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < minDist) { minDist = dist; nearest = enemy; }
        });
        if (nearest) {
          (nearest as Enemy).hp -= tower.damage;
          (nearest as Enemy).lastHit = now;
          tower.lastFired = now;
          this.createParticles((nearest as Enemy).x, (nearest as Enemy).y, 3, tower.color);
        }
      }
    });

    this.state.enemies = this.state.enemies.filter(enemy => {
      if (enemy.hp <= 0) {
        this.state.code += enemy.value;
        this.state.experience += (enemy.value / 4) * this.state.permanentUpgrades.xpMultiplier;
        this.checkLevelUp();
        this.spawnDrop(enemy.x, enemy.y);
        return false;
      }
      return true;
    });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.sqrt(this.canvas.width ** 2 + this.canvas.height ** 2) / 2 + 100;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;

    const isBoss = this.state.level % 10 === 0 && this.state.enemies.filter(e => e.type === 'boss').length === 0;
    const levelMult = Math.pow(1.12, this.state.level);
    const hp = (isBoss ? 250 : 25) * levelMult;

    this.state.enemies.push({
      id: Math.random().toString(36),
      x, y, hp, maxHp: hp,
      speed: (isBoss ? 0.8 : 1.6) + (this.state.level * 0.02),
      value: (isBoss ? 600 : 20) + this.state.level * 5,
      type: isBoss ? 'boss' : 'bug', 
      size: isBoss ? 45 : 22, 
      angle: 0,
    });
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    this.ctx.strokeStyle = '#0f172a';
    this.ctx.lineWidth = 1;
    const gridSize = 100;
    for (let x = 0; x < this.canvas.width; x += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(x, 0); this.ctx.lineTo(x, this.canvas.height); this.ctx.stroke();
    }
    for (let y = 0; y < this.canvas.height; y += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(0, y); this.ctx.lineTo(this.canvas.width, y); this.ctx.stroke();
    }

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const mfSize = 35 + (this.state.level * 0.4);
    const pulse = Math.sin(Date.now() / 200) * 10;
    this.ctx.shadowBlur = 25 + pulse; 
    this.ctx.shadowColor = this.state.level > 90 ? COLORS.SECONDARY : COLORS.PRIMARY;
    this.ctx.fillStyle = this.state.level > 90 ? COLORS.SECONDARY : COLORS.PRIMARY; 
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 4;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    this.state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      if (p.text) {
        this.ctx.fillStyle = p.color; this.ctx.font = `bold ${p.size}px Space Grotesk`; this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.fillStyle = p.color; this.ctx.fillRect(p.x, p.y, p.size, p.size);
      }
    });
    this.ctx.globalAlpha = 1.0;

    this.state.drops.forEach(d => {
      this.ctx.fillStyle = COLORS.ACCENT; this.ctx.beginPath(); this.ctx.arc(d.x, d.y, 8, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.fillStyle = '#fff'; this.ctx.font = '14px monospace'; this.ctx.fillText(d.name, d.x + 12, d.y + 4);
    });

    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const kick = Date.now() - t.lastFired < 100 ? 5 : 0;
      this.ctx.fillRect(t.x - 12 - kick/2, t.y - 12 - kick/2, 24 + kick, 24 + kick);
      this.ctx.strokeStyle = t.color; this.ctx.globalAlpha = 0.08;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    const now = Date.now();
    this.state.enemies.forEach(e => {
      this.ctx.save(); this.ctx.translate(e.x, e.y); this.ctx.rotate(e.angle);
      if (e.lastHit && now - e.lastHit < 100) this.ctx.fillStyle = '#ffffff'; 
      else this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.beginPath();
      const s = e.size / 2;
      this.ctx.moveTo(s*1.5, 0); this.ctx.lineTo(-s, s); this.ctx.lineTo(-s, -s); this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();
      const hpWidth = e.size * 1.5;
      this.ctx.fillStyle = '#1e293b'; this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 5, hpWidth, 5);
      this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 5, hpWidth * (e.hp / e.maxHp), 5);
    });

    if (this.state.isGameOver || this.state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.95)'; this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    }
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints >= 0) {
      // Check if it's a tech node
      const isTech = skillId.startsWith('tech_') || skillId === 'root';

      this.state.skillPoints--;
      this.state.rerollCost = BASE_REROLL_COST; // Reset reroll on any purchase

      if (isTech) {
        if (!this.state.unlockedTech.includes(skillId)) {
          this.state.unlockedTech.push(skillId);
        }
        if (skillId === 'tech_passive') this.hasPassiveIncome = true;
        if (skillId === 'tech_god') {
          this.state.clickPower *= 2;
          this.state.towers.forEach(t => t.damage *= 2);
        }
      }

      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      if (skillId === 'code_gen') this.hasSaaS = true;

      onUnlock(this.state);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }
}

import React, { useState } from 'react';
import { GameState, TechNode } from '../types';
import { ALL_SKILLS, TECH_TREE } from '../constants';
import { Cpu, X, Zap, Target, MousePointer2, Shield, Code, Award, Sparkles, RefreshCcw, LayoutGrid, Share2 } from 'lucide-react';

interface Props {
  state: GameState;
  isOpen: boolean;
  onClose: () => void;
  onUpgrade: (skillId: string) => void;
  onReroll: () => void;
}

const SkillTree: React.FC<Props> = ({ state, isOpen, onClose, onUpgrade, onReroll }) => {
  const [activeTab, setActiveTab] = useState<'shop' | 'tree'>('tree');

  if (!isOpen) return null;

  const currentShopSkills = ALL_SKILLS.filter(s => state.availableSkills.includes(s.id));

  const getIcon = (id: string) => {
    if (id.includes('click')) return <MousePointer2 className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('range')) return <Target className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('dmg')) return <Zap className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('collect')) return <Cpu className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('code_gen')) return <Code className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('shield')) return <Shield className="w-5 h-5 sm:w-6 sm:h-6" />;
    return <Award className="w-5 h-5 sm:w-6 sm:h-6" />;
  };

  const isTechUnlocked = (id: string) => state.unlockedTech.includes(id);
  const canUnlockTech = (tech: typeof TECH_TREE[0]) => {
    if (isTechUnlocked(tech.id)) return false;
    if (tech.dependsOn && !isTechUnlocked(tech.dependsOn)) return false;
    return state.skillPoints >= tech.cost;
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-2 sm:p-6 bg-slate-950/90 backdrop-blur-xl pointer-events-auto">
      <div className="bg-slate-900 border border-slate-700 rounded-3xl w-full max-w-5xl max-h-[90vh] flex flex-col overflow-hidden shadow-2xl relative">

        {/* Tabs */}
        <div className="flex bg-slate-800/50 p-1 rounded-t-3xl border-b border-slate-700">
          <button 
            onClick={() => setActiveTab('tree')}
            className={`flex-1 py-3 px-4 flex items-center justify-center gap-2 font-black uppercase text-xs sm:text-sm tracking-widest transition-all rounded-t-2xl
              ${activeTab === 'tree' ? 'bg-slate-900 text-sky-400 shadow-[0_-4px_0_0_#38bdf8]' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <Share2 size={16} /> Tech Stack
          </button>
          <button 
            onClick={() => setActiveTab('shop')}
            className={`flex-1 py-3 px-4 flex items-center justify-center gap-2 font-black uppercase text-xs sm:text-sm tracking-widest transition-all rounded-t-2xl
              ${activeTab === 'shop' ? 'bg-slate-900 text-pink-400 shadow-[0_-4px_0_0_#f472b6]' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <LayoutGrid size={16} /> Dependencies
          </button>
        </div>

        {/* Header (Stats) */}
        <div className="p-4 sm:p-6 flex justify-between items-center bg-slate-900/50 flex-shrink-0">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-white italic leading-tight">
              {activeTab === 'tree' ? 'INFRASTRUCTURE' : 'LIBRARY SHOP'}
            </h2>
            <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
              {state.skillPoints} Skill Points Available
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 transition-all border border-slate-700">
            <X size={20} />
          </button>
        </div>

        {/* Content Area */}
        <div className="flex-grow overflow-y-auto overflow-x-hidden p-4 sm:p-8 no-scrollbar bg-slate-950/30">

          {/* TAB: TECH TREE */}
          {activeTab === 'tree' && (
            <div className="relative min-h-[500px] w-full flex justify-center">
              {/* SVG Lines */}
              <svg className="absolute inset-0 w-full h-full pointer-events-none z-0">
                {TECH_TREE.map(node => {
                  if (!node.dependsOn) return null;
                  const parent = TECH_TREE.find(p => p.id === node.dependsOn);
                  if (!parent) return null;

                  const isLinkActive = isTechUnlocked(node.id);
                  const isLinkAvailable = isTechUnlocked(parent.id);

                  return (
                    <line
                      key={`${parent.id}-${node.id}`}
                      x1={`${parent.position.x}%`}
                      y1={`${parent.position.y}px`}
                      x2={`${node.position.x}%`}
                      y2={`${node.position.y}px`}
                      stroke={isLinkActive ? '#38bdf8' : isLinkAvailable ? '#1e293b' : '#0f172a'}
                      strokeWidth={isLinkActive ? "3" : "2"}
                      strokeDasharray={isLinkActive ? "0" : "5,5"}
                      className="transition-all duration-500"
                    />
                  );
                })}
              </svg>

              {/* Nodes */}
              {TECH_TREE.map(node => {
                const unlocked = isTechUnlocked(node.id);
                const available = canUnlockTech(node);
                const parentUnlocked = !node.dependsOn || isTechUnlocked(node.dependsOn);

                return (
                  <div
                    key={node.id}
                    className="absolute z-10 -translate-x-1/2 -translate-y-1/2"
                    style={{ left: `${node.position.x}%`, top: `${node.position.y}px` }}
                  >
                    <button
                      disabled={!available || unlocked}
                      onClick={() => onUpgrade(node.id)}
                      className={`
                        w-12 h-12 sm:w-16 sm:h-16 rounded-full border-2 flex flex-col items-center justify-center transition-all group relative
                        ${unlocked ? 'bg-sky-500 border-sky-400 shadow-[0_0_20px_rgba(56,189,248,0.5)]' : 
                          available ? 'bg-slate-800 border-slate-600 hover:border-sky-400 hover:scale-110' : 
                          'bg-slate-900 border-slate-800 opacity-50 cursor-not-allowed'}
                      `}
                    >
                      <Cpu size={unlocked ? 24 : 20} className={unlocked ? 'text-white' : 'text-slate-400'} />

                      {/* Tooltip-like popup */}
                      <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 w-40 sm:w-48 bg-slate-800 border border-slate-700 p-2 rounded-xl pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity z-20 shadow-2xl">
                        <div className="text-[10px] font-black text-sky-400 uppercase mb-1">{node.name}</div>
                        <div className="text-[9px] text-slate-300 leading-tight">{node.description}</div>
                        {!unlocked && <div className="mt-1 text-[8px] font-bold text-amber-500">COST: {node.cost} SP</div>}
                        {unlocked && <div className="mt-1 text-[8px] font-bold text-green-400">ACTIVATED</div>}
                      </div>

                      {!unlocked && node.cost > 0 && (
                        <span className="absolute -top-2 -right-2 bg-amber-500 text-slate-900 text-[8px] font-black w-5 h-5 flex items-center justify-center rounded-full border-2 border-slate-900">
                          {node.cost}
                        </span>
                      )}
                    </button>
                  </div>
                );
              })}
            </div>
          )}

          {/* TAB: RANDOM SHOP */}
          {activeTab === 'shop' && (
            <div className="flex flex-col gap-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {currentShopSkills.map((skill) => (
                  <button
                    key={skill.id}
                    onClick={() => onUpgrade(skill.id)}
                    disabled={state.skillPoints < skill.cost}
                    className={`
                      text-left p-5 sm:p-6 rounded-2xl border transition-all relative group flex flex-col justify-between h-48
                      ${state.skillPoints >= skill.cost 
                        ? 'border-slate-700 bg-slate-800/40 hover:border-pink-400 hover:-translate-y-2 active:scale-95' 
                        : 'border-slate-800 bg-slate-900/50 opacity-40 cursor-not-allowed'}
                    `}
                  >
                    <div>
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center mb-4 
                        ${skill.rarity === 'epic' ? 'bg-purple-500/20 text-purple-400' : 
                          skill.rarity === 'rare' ? 'bg-amber-500/20 text-amber-400' : 'bg-pink-500/20 text-pink-400'}`}>
                        {getIcon(skill.id)}
                      </div>
                      <h3 className="text-sm font-black text-white leading-tight mb-1 uppercase tracking-tight">{skill.name}</h3>
                      <p className="text-[10px] sm:text-xs text-slate-400 leading-relaxed font-medium">{skill.description}</p>
                    </div>

                    <div className="flex items-center justify-between mt-auto pt-3 border-t border-slate-700/50">
                      <span className="text-[8px] font-black px-2 py-0.5 rounded uppercase tracking-tighter bg-slate-700 text-slate-300">
                        {skill.rarity}
                      </span>
                      <div className="font-black text-white text-[10px] uppercase">
                        {skill.cost} SP
                      </div>
                    </div>
                  </button>
                ))}
              </div>

              <div className="mt-4 flex flex-col sm:flex-row items-center justify-center gap-4">
                <button
                  onClick={onReroll}
                  disabled={state.code < state.rerollCost}
                  className={`
                    flex items-center gap-3 px-6 py-3 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all
                    ${state.code >= state.rerollCost
                      ? 'bg-slate-800 hover:bg-slate-700 border border-slate-700 text-pink-400 hover:border-pink-400'
                      : 'bg-slate-900/50 text-slate-600 cursor-not-allowed opacity-50'}
                  `}
                >
                  <RefreshCcw className="w-4 h-4" />
                  <span>Reroll Selection</span>
                  <span className="opacity-60">({state.rerollCost} LOC)</span>
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-4 bg-slate-950/80 text-center text-[8px] sm:text-[10px] text-slate-500 font-bold uppercase tracking-[0.3em] border-t border-slate-800 flex-shrink-0">
          The stack is the foundation. The dependencies are the flavor.
        </div>
      </div>
    </div>
  );
};

export default SkillTree;

import React from 'react';
import { GameState, PermanentUpgrades } from '../types';
