            <div className="flex items-center gap-2 mb-1">
              <Code className="text-sky-400 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">LOC</span>
            </div>
            <div className="text-xl sm:text-2xl font-black text-white mb-1 tabular-nums">
              {Math.floor(state.code).toLocaleString()}
