          </div>

          <div className="bg-slate-900/90 backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex items-center gap-2 sm:gap-3 flex-shrink-0">
            <Award className="text-purple-400 w-5 h-5 sm:w-6 sm:h-6" />
            <div>
              <div className="text-[8px] sm:text-[10px] text-slate-400 font-black uppercase tracking-widest">Legacy</div>
              <div className="text-lg sm:text-xl font-black text-white leading-none">{state.permanentUpgrades.legacyPoints}</div>
