      {/* Game Over Screen */}
      {state.isGameOver && !state.isVictory && (
        <div className="fixed inset-0 bg-red-950/90 backdrop-blur-2xl flex items-center justify-center pointer-events-auto p-4 z-50 overflow-y-auto">
          <div className="bg-slate-900 border border-slate-700 p-6 sm:p-10 rounded-2xl sm:rounded-3xl shadow-2xl max-w-4xl w-full my-auto">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 sm:gap-12">
              <div className="flex flex-col justify-center text-center md:text-left md:border-r border-slate-800 md:pr-12">
                <div className="w-16 h-16 sm:w-20 sm:h-20 bg-red-500/20 rounded-2xl flex items-center justify-center mb-4 sm:mb-6 mx-auto md:mx-0">
