                <div className="bg-purple-500/10 border border-purple-500/30 p-4 sm:p-6 rounded-xl mb-6 sm:mb-8">
                  <div className="text-purple-400 font-black text-[10px] sm:text-xs uppercase tracking-widest mb-1 italic">Earnings</div>
                  <div className="text-2xl sm:text-4xl font-black text-white">+{legacyEarned} LP</div>
                </div>

                <button 
                  onClick={onRestart} 
                  className="w-full bg-sky-500 hover:bg-sky-400 active:scale-95 text-slate-900 font-black py-4 rounded-xl transition-all text-lg sm:text-xl shadow-lg shadow-sky-500/10"
