                <div className="space-y-3 sm:space-y-4">
                  {[
                    { id: 'startingCode', name: 'Angel Funding', desc: '+250 Start LOC', icon: <Award className="text-sky-400" /> },
                    { id: 'damageMultiplier', name: 'Better Tools', desc: '+25% Damage', icon: <Zap className="text-amber-400" /> },
                    { id: 'xpMultiplier', name: 'Knowledge', desc: '+30% XP Gain', icon: <Code className="text-purple-400" /> },
                  ].map(upg => (
                    <button 
                      key={upg.id}
                      onClick={() => onBuyPermanent(upg.id as any)}
                      disabled={state.permanentUpgrades.legacyPoints < 15}
                      className="w-full p-3.5 sm:p-5 bg-slate-800/40 border border-slate-700 rounded-xl sm:rounded-2xl hover:border-sky-400 active:bg-slate-700 transition-all flex justify-between items-center group disabled:opacity-30"
