                      <div className="flex items-center gap-3 sm:gap-4">
                        <div className="p-2 bg-slate-700 rounded-lg group-hover:scale-110 transition-transform">{upg.icon}</div>
                        <div className="text-left">
                          <div className="text-white font-bold text-xs sm:text-sm">{upg.name}</div>
                          <div className="text-slate-400 text-[10px] sm:text-xs">{upg.desc}</div>
