                      </div>
                      <div className="bg-purple-600 text-white text-[9px] sm:text-[10px] px-2.5 sm:px-3 py-1 sm:py-1.5 rounded-full font-black">15 LP</div>
                    </button>
                  ))}
                </div>
                <div className="mt-4 sm:mt-6 text-center md:text-left text-[10px] text-slate-500 font-black uppercase tracking-widest">
                  BANKED: {state.permanentUpgrades.legacyPoints} LP
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UIOverlay;

export interface Point {
  x: number;
  y: number;
}

export interface Particle extends Point {
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
  text?: string;
}

export interface ClickRipple extends Point {
  radius: number;
  maxRadius: number;
  life: number;
}

export interface Enemy extends Point {
  id: string;
  hp: number;
  maxHp: number;
  speed: number;
  value: number;
  type: 'bug' | 'boss' | 'glitch';
  size: number;
  angle: number;
  lastHit?: number;
}

export interface Tower extends Point {
  id: string;
  type: string;
  level: number;
  range: number;
  damage: number;
  fireRate: number;
  lastFired: number;
  color: string;
}

export interface LibraryDrop extends Point {
  id: string;
  name: string;
  rarity: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
  effect: string;
  life: number;
}

export interface PermanentUpgrades {
  startingCode: number;
  damageMultiplier: number;
  xpMultiplier: number;
  legacyPoints: number;
}

export interface SkillDefinition {
  id: string;
  name: string;
  description: string;
  cost: number;
  rarity: 'common' | 'rare' | 'epic';
}

export interface TechNode {
  id: string;
  name: string;
  description: string;
  cost: number;
  dependsOn?: string;
  position: { x: number, y: number };
}

export interface GameState {
  code: number;
  experience: number;
  level: number;
  skillPoints: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  isGameOver: boolean;
  isVictory: boolean;
  permanentUpgrades: PermanentUpgrades;
  lastRunCode: number;
  availableSkills: string[];
  unlockedTech: string[];
  rerollCost: number;
  combo: number;
  threatLevel: number;
}

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS } from '../constants';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 100;
const COMBO_TIMEOUT = 2000;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private hasSaaS: boolean = false;
  private hasPassiveIncome: boolean = false;
  private comboTimer: number = 0;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 100 + this.state.permanentUpgrades.startingCode;
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 100,
      experience: 0,
      level: 1,
      skillPoints: 0,
      clickPower: 12,
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      isGameOver: false,
      isVictory: false,
      lastRunCode: 0,
      availableSkills: [],
      unlockedTech: ['root'],
      rerollCost: BASE_REROLL_COST,
      combo: 0,
      threatLevel: 0,
      permanentUpgrades: {
        startingCode: 0,
        damageMultiplier: 1.0,
        xpMultiplier: 1.0,
        legacyPoints: 0,
      }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 5 : 1;
    const earnedLegacy = Math.floor(this.state.code / 500) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 100 + perms.startingCode;
    this.state.clickPower = 12 * perms.damageMultiplier;

    this.enemySpawnTimer = 0;
    this.hasAutoCollect = false;
    this.hasSaaS = false;
    this.hasPassiveIncome = false;
    this.comboTimer = 0;
    this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 25;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 250;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.2;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 0.2;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    const shuffled = [...ALL_SKILLS].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.85);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(x: number, y: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    let hit = false;
    const now = Date.now();

    this.state.enemies = this.state.enemies.filter(enemy => {
      const dx = enemy.x - x;
      const dy = enemy.y - y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 60) {
        enemy.hp -= this.state.clickPower;
        enemy.lastHit = now;
        this.createParticles(enemy.x, enemy.y, 6, COLORS.PRIMARY);

        if (enemy.hp <= 0) {
          this.state.combo++;
          this.comboTimer = COMBO_TIMEOUT;

          const comboBonus = Math.min(1 + this.state.combo * 0.1, 5);
          const reward = Math.floor(enemy.value * comboBonus);
          const xpReward = (enemy.value / 2) * comboBonus * this.state.permanentUpgrades.xpMultiplier;

          this.state.code += reward;
          this.state.experience += xpReward;
          this.state.threatLevel += 0.02; // Skill increases threat

          this.createFloatingText(enemy.x, enemy.y, `+${reward} LOC`, COLORS.ACCENT);
          if (this.state.combo > 1) {
            this.createFloatingText(enemy.x, enemy.y - 20, `COMBO x${this.state.combo}`, COLORS.SECONDARY);
          }

          this.checkLevelUp();
          this.spawnDrop(enemy.x, enemy.y);
          hit = true;
          return false;
        }
        hit = true;
      }
      return true;
    });

    if (!hit) {
      this.state.code += 1;
      this.createFloatingText(x, y, "+1", COLORS.PRIMARY);
    }

    this.state.ripples.push({ x, y, radius: 0, maxRadius: 60, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x, y, vx: (Math.random() - 0.5) * 2, vy: -2.5, size: 14, life: 1.0, color, text
    });
  }

  private checkLevelUp() {
    const nextLevelExp = 150 * Math.pow(this.state.level, 1.4);
    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.skillPoints++;
      this.refreshSkillShop();
      this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2, `LEVEL ${this.state.level} UP!`, COLORS.ACCENT);

      if (this.state.level >= 100) {
        this.state.isVictory = true;
      }
    }
  }

  private spawnDrop(x: number, y: number) {
    if (Math.random() > 0.8) {
      const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
      this.state.drops.push({
        id: Math.random().toString(36),
        name: lib.name, rarity: lib.rarity, effect: lib.effect, x, y, life: 1.0,
      });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, x: number, y: number) {
    const config = TOWER_TYPES[type];

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) {
      this.createFloatingText(x, y, "TECH REQUIRED", COLORS.ENEMY);
      return false;
    }

    if (this.state.code >= config.cost) {
      this.state.code -= config.cost;
      this.state.towers.push({
        id: Math.random().toString(36),
        type, level: 1, x, y,
        range: config.range,
        damage: config.damage * this.state.permanentUpgrades.damageMultiplier,
        fireRate: config.fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x, y, vx: (Math.random() - 0.5) * 8, vy: (Math.random() - 0.5) * 8,
        size: Math.random() * 4 + 2, life: 1.0, color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = time - this.lastTime;
    this.lastTime = time;
    this.update(dt);
    this.draw();
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    if (this.comboTimer > 0) {
      this.comboTimer -= dt;
      if (this.comboTimer <= 0) {
        this.state.combo = 0;
      }
    }

    if (this.hasSaaS || this.hasPassiveIncome) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) {
        let gain = 0;
        if (this.hasSaaS) gain += 5 + (this.state.level * 2);
        if (this.hasPassiveIncome) gain += (this.state.level * 4);
        this.state.code += gain;
        this.passiveCodeTimer = 0;
      }
    }

    this.enemySpawnTimer += dt;
    // Base spawn rate significantly faster and scales with threat level
    const baseSpawn = Math.max(250, 1800 - (this.state.level * 30));
    const threatMod = 1 + (this.state.threatLevel * 0.1);
    const spawnRate = baseSpawn / threatMod;

    if (this.enemySpawnTimer > spawnRate) {
      this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx; p.y += p.vy;
      p.life -= p.text ? 0.015 : 0.05;
      return p.life > 0;
    });

    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 5; r.life -= 0.05;
      return r.life > 0;
    });

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.003;
      const dx = cx - d.x; const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const pullSpeed = this.hasAutoCollect ? 10 : 3;
      const collectRadius = this.hasAutoCollect ? 140 : 50;
      if (dist < collectRadius) {
        this.createFloatingText(cx, cy, "LIB PATCH", COLORS.SECONDARY);
        this.state.code += 50 + (this.state.level * 10);
        return false;
      }
      d.x += (dx / dist) * pullSpeed; d.y += (dy / dist) * pullSpeed;
      return d.life > 0;
    });

    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x; const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 45) this.state.isGameOver = true;
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let nearest: Enemy | null = null;
        let minDist = tower.range;
        this.state.enemies.forEach(enemy => {
          const dx = enemy.x - tower.x; const dy = enemy.y - tower.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < minDist) { minDist = dist; nearest = enemy; }
        });
        if (nearest) {
          (nearest as Enemy).hp -= tower.damage;
          (nearest as Enemy).lastHit = now;
          tower.lastFired = now;
          this.createParticles((nearest as Enemy).x, (nearest as Enemy).y, 3, tower.color);
        }
      }
    });

    this.state.enemies = this.state.enemies.filter(enemy => {
      if (enemy.hp <= 0) {
        this.state.code += enemy.value;
        this.state.experience += (enemy.value / 4) * this.state.permanentUpgrades.xpMultiplier;
        this.state.threatLevel += 0.005; // Each kill makes the server hotter
        this.checkLevelUp();
        this.spawnDrop(enemy.x, enemy.y);
        return false;
      }
      return true;
    });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.sqrt(this.canvas.width ** 2 + this.canvas.height ** 2) / 2 + 100;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;

    const isBoss = this.state.level % 10 === 0 && this.state.enemies.filter(e => e.type === 'boss').length === 0;
    // Aggressive exponential scaling: 1.18x per level + threat level multiplier
    const scalingFactor = Math.pow(1.18, this.state.level) * (1 + this.state.threatLevel * 0.2);
    const hp = (isBoss ? 350 : 35) * scalingFactor;

    this.state.enemies.push({
      id: Math.random().toString(36),
      x, y, hp, maxHp: hp,
      speed: (isBoss ? 0.9 : 1.8) + (this.state.level * 0.04) + (this.state.threatLevel * 0.05),
      value: (isBoss ? 800 : 25) + this.state.level * 8,
      type: isBoss ? 'boss' : 'bug', 
      size: isBoss ? 55 : 24, 
      angle: 0,
    });
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    this.ctx.strokeStyle = '#0f172a';
    this.ctx.lineWidth = 1;
    const gridSize = 100;
    for (let x = 0; x < this.canvas.width; x += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(x, 0); this.ctx.lineTo(x, this.canvas.height); this.ctx.stroke();
    }
    for (let y = 0; y < this.canvas.height; y += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(0, y); this.ctx.lineTo(this.canvas.width, y); this.ctx.stroke();
    }

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const mfSize = 40 + (this.state.level * 0.3);
    const pulse = Math.sin(Date.now() / 200) * 12;

    // Core visual change based on threat level
    const coreColor = this.state.threatLevel > 10 ? COLORS.ENEMY : this.state.level > 80 ? COLORS.SECONDARY : COLORS.PRIMARY;

    this.ctx.shadowBlur = 30 + pulse; 
    this.ctx.shadowColor = coreColor;
    this.ctx.fillStyle = coreColor; 
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 4;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    this.state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      if (p.text) {
        this.ctx.fillStyle = p.color; this.ctx.font = `bold ${p.size}px Space Grotesk`; this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.fillStyle = p.color; this.ctx.fillRect(p.x, p.y, p.size, p.size);
      }
    });
    this.ctx.globalAlpha = 1.0;

    this.state.drops.forEach(d => {
      this.ctx.fillStyle = COLORS.ACCENT; this.ctx.beginPath(); this.ctx.arc(d.x, d.y, 8, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 12px monospace'; this.ctx.fillText(d.name.toUpperCase(), d.x + 12, d.y + 4);
    });

    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const kick = Date.now() - t.lastFired < 100 ? 6 : 0;
      this.ctx.fillRect(t.x - 14 - kick/2, t.y - 14 - kick/2, 28 + kick, 28 + kick);
      this.ctx.strokeStyle = t.color; this.ctx.globalAlpha = 0.05;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    const now = Date.now();
    this.state.enemies.forEach(e => {
      this.ctx.save(); this.ctx.translate(e.x, e.y); this.ctx.rotate(e.angle);
      if (e.lastHit && now - e.lastHit < 100) this.ctx.fillStyle = '#ffffff'; 
      else this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.beginPath();
      const s = e.size / 2;
      this.ctx.moveTo(s*1.6, 0); this.ctx.lineTo(-s, s); this.ctx.lineTo(-s, -s); this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();
      const hpWidth = e.size * 1.5;
      this.ctx.fillStyle = '#1e293b'; this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 8, hpWidth, 6);
      this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 8, hpWidth * (e.hp / e.maxHp), 6);
    });

    if (this.state.isGameOver || this.state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.98)'; this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    }
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints >= 0) {
      const isTech = skillId.startsWith('tech_') || skillId === 'root';

      this.state.skillPoints--;
      this.state.rerollCost = BASE_REROLL_COST; // Reset reroll on ANY purchase

      if (isTech) {
        if (!this.state.unlockedTech.includes(skillId)) {
          this.state.unlockedTech.push(skillId);
        }
        if (skillId === 'tech_passive') this.hasPassiveIncome = true;
        if (skillId === 'tech_god') {
          this.state.clickPower *= 2.5;
          this.state.towers.forEach(t => t.damage *= 2.5);
        }
      }

      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      if (skillId === 'code_gen') this.hasSaaS = true;
      if (skillId === 'click_1') this.state.clickPower *= 2;

      onUnlock(this.state);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }
}

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS } from '../constants';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 100;
const COMBO_TIMEOUT = 1500;
const THREAT_DECAY = 0.08; // Per second

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private hasSaaS: boolean = false;
  private hasPassiveIncome: boolean = false;
  private comboTimer: number = 0;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 100 + this.state.permanentUpgrades.startingCode;
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 100,
      experience: 0,
      level: 1,
      skillPoints: 0,
      clickPower: 15, // Buffed base power
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      isGameOver: false,
      isVictory: false,
      lastRunCode: 0,
      availableSkills: [],
      unlockedTech: ['root'],
      rerollCost: BASE_REROLL_COST,
      combo: 0,
      threatLevel: 1.0, // Start with some heat
      permanentUpgrades: {
        startingCode: 0,
        damageMultiplier: 1.0,
        xpMultiplier: 1.0,
        legacyPoints: 0,
      }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 5 : 1;
    const earnedLegacy = Math.floor(this.state.code / 1000) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 100 + perms.startingCode;
    this.state.clickPower = 15 * perms.damageMultiplier;

    this.enemySpawnTimer = 0;
    this.hasAutoCollect = false;
    this.hasSaaS = false;
    this.hasPassiveIncome = false;
    this.comboTimer = 0;
    this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 25;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.25;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 0.3;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    const shuffled = [...ALL_SKILLS].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.5);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(x: number, y: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    let hit = false;
    const now = Date.now();
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;

    // Check Mainframe click (Overclock)
    const distToCore = Math.sqrt((x - cx) ** 2 + (y - cy) ** 2);
    if (distToCore < 80) {
      this.state.threatLevel += 0.5; // Manually boost heat
      this.createParticles(cx, cy, 4, COLORS.ACCENT);
      this.createFloatingText(cx, cy, "OVERCLOCKING...", COLORS.ACCENT);
      hit = true;
    }

    this.state.enemies = this.state.enemies.filter(enemy => {
      const dx = enemy.x - x;
      const dy = enemy.y - y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 65) {
        enemy.hp -= this.state.clickPower;
        enemy.lastHit = now;
        this.createParticles(enemy.x, enemy.y, 8, COLORS.PRIMARY);

        if (enemy.hp <= 0) {
          this.state.combo++;
          this.comboTimer = COMBO_TIMEOUT;
          this.state.threatLevel += 0.2; // Every kill increases heat

          const comboBonus = 1 + (this.state.combo * 0.05);
          const threatBonus = Math.max(1, this.state.threatLevel * 0.5);
          const reward = Math.floor(enemy.value * comboBonus * (1 + this.state.threatLevel * 0.1));
          const xpReward = (enemy.value / 1.5) * comboBonus * threatBonus * this.state.permanentUpgrades.xpMultiplier;

          this.state.code += reward;
          this.state.experience += xpReward;

          this.createFloatingText(enemy.x, enemy.y, `+${reward}`, COLORS.ACCENT);
          if (this.state.combo % 5 === 0) {
            this.createFloatingText(enemy.x, enemy.y - 25, `${this.state.combo} STREAK!`, COLORS.SECONDARY);
          }

          this.checkLevelUp();
          this.spawnDrop(enemy.x, enemy.y);
          hit = true;
          return false;
        }
        hit = true;
      }
      return true;
    });

    if (!hit) {
      this.state.code += 1;
      this.createFloatingText(x, y, "+1", COLORS.PRIMARY);
    }

    this.state.ripples.push({ x, y, radius: 0, maxRadius: 70, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x, y, vx: (Math.random() - 0.5) * 2, vy: -3, size: 14, life: 1.0, color, text
    });
  }

  private checkLevelUp() {
    // Faster early progression, steeper later
    const nextLevelExp = this.state.level < 5 
      ? 100 * Math.pow(this.state.level, 1.1)
      : 200 * Math.pow(this.state.level, 1.5);

    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.skillPoints++;
      this.refreshSkillShop();
      this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2, `STACK LEVEL ${this.state.level}`, COLORS.ACCENT);

      if (this.state.level >= 100) {
        this.state.isVictory = true;
      }
    }
  }

  private spawnDrop(x: number, y: number) {
    if (Math.random() > 0.85) {
      const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
      this.state.drops.push({
        id: Math.random().toString(36),
        name: lib.name, rarity: lib.rarity, effect: lib.effect, x, y, life: 1.0,
      });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, x: number, y: number) {
    const config = TOWER_TYPES[type];
    const towerCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.5, towerCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) {
      this.createFloatingText(x, y, "LOCKED IN TECH TREE", COLORS.ENEMY);
      return false;
    }

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36),
        type, level: 1, x, y,
        range: config.range,
        damage: config.damage * this.state.permanentUpgrades.damageMultiplier,
        fireRate: config.fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    } else {
      this.createFloatingText(x, y, `NEED ${currentCost} LOC`, COLORS.ENEMY);
      return false;
    }
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x, y, vx: (Math.random() - 0.5) * 10, vy: (Math.random() - 0.5) * 10,
        size: Math.random() * 5 + 2, life: 1.0, color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 100);
    this.lastTime = time;
    this.update(dt);
    this.draw();
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    // Heat decay
    this.state.threatLevel = Math.max(0.5, this.state.threatLevel - (THREAT_DECAY * dt / 1000));

    if (this.comboTimer > 0) {
      this.comboTimer -= dt;
      if (this.comboTimer <= 0) this.state.combo = 0;
    }

    if (this.hasSaaS || this.hasPassiveIncome) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) {
        let gain = 0;
        if (this.hasSaaS) gain += 5 + (this.state.level * 2);
        if (this.hasPassiveIncome) gain += (this.state.level * 5);
        this.state.code += gain;
        this.passiveCodeTimer = 0;
      }
    }

    this.enemySpawnTimer += dt;

    // SCALING SPAWN RATE
    // Base frequency increases with level, multiplied by current threat
    const baseFreq = Math.max(200, 2000 - (this.state.level * 50));
    const threatMult = 1 + (this.state.threatLevel * 0.4);
    const spawnRate = baseFreq / threatMult;

    if (this.enemySpawnTimer > spawnRate) {
      this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx; p.y += p.vy;
      p.life -= p.text ? 0.012 : 0.04;
      return p.life > 0;
    });

    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 6; r.life -= 0.04;
      return r.life > 0;
    });

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.003;
      const dx = cx - d.x; const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const pullSpeed = (this.hasAutoCollect ? 12 : 4) * (1 + this.state.threatLevel * 0.1);
      const collectRadius = this.hasAutoCollect ? 150 : 60;

      if (dist < collectRadius) {
        this.state.code += 50 + (this.state.level * 10);
        this.createParticles(cx, cy, 3, COLORS.SECONDARY);
        return false;
      }
      d.x += (dx / dist) * pullSpeed; d.y += (dy / dist) * pullSpeed;
      return d.life > 0;
    });

    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x; const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 50) this.state.isGameOver = true;
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let nearest: Enemy | null = null;
        let minDist = tower.range;
        this.state.enemies.forEach(enemy => {
          const dx = enemy.x - tower.x; const dy = enemy.y - tower.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < minDist) { minDist = dist; nearest = enemy; }
        });
        if (nearest) {
          (nearest as Enemy).hp -= tower.damage;
          (nearest as Enemy).lastHit = now;
          tower.lastFired = now;
          this.createParticles((nearest as Enemy).x, (nearest as Enemy).y, 3, tower.color);
        }
      }
    });

    this.state.enemies = this.state.enemies.filter(enemy => {
      if (enemy.hp <= 0) return false;
      return true;
    });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.sqrt(this.canvas.width ** 2 + this.canvas.height ** 2) / 2 + 100;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;

    const isBoss = this.state.level % 10 === 0 && this.state.enemies.filter(e => e.type === 'boss').length === 0;
    const scalingFactor = Math.pow(1.15, this.state.level) * (1 + this.state.threatLevel * 0.1);
    const hp = (isBoss ? 400 : 40) * scalingFactor;

    this.state.enemies.push({
      id: Math.random().toString(36),
      x, y, hp, maxHp: hp,
      speed: (isBoss ? 0.8 : 2.0) + (this.state.level * 0.05) + (this.state.threatLevel * 0.05),
      value: (isBoss ? 1000 : 30) + this.state.level * 10,
      type: isBoss ? 'boss' : 'bug', 
      size: isBoss ? 60 : 26, 
      angle: 0,
    });
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    this.ctx.strokeStyle = '#0f172a';
    this.ctx.lineWidth = 1;
    const gridSize = 100;
    for (let x = 0; x < this.canvas.width; x += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(x, 0); this.ctx.lineTo(x, this.canvas.height); this.ctx.stroke();
    }
    for (let y = 0; y < this.canvas.height; y += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(0, y); this.ctx.lineTo(this.canvas.width, y); this.ctx.stroke();
    }

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const mfSize = 45 + (this.state.level * 0.2);
    const pulse = Math.sin(Date.now() / 150) * (15 + this.state.threatLevel * 2);

    const coreColor = this.state.threatLevel > 15 ? COLORS.ENEMY : this.state.threatLevel > 8 ? COLORS.ACCENT : COLORS.PRIMARY;

    this.ctx.shadowBlur = 35 + pulse; 
    this.ctx.shadowColor = coreColor;
    this.ctx.fillStyle = coreColor; 
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize, 0, Math.PI * 2); this.ctx.fill();

    // Core detail
    this.ctx.strokeStyle = '#fff';
    this.ctx.lineWidth = 4;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize * 0.7, 0, Math.PI * 2); this.ctx.stroke();
    this.ctx.shadowBlur = 0;

    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 4;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    this.state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      if (p.text) {
        this.ctx.fillStyle = p.color; this.ctx.font = `black ${p.size}px Space Grotesk`; this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.fillStyle = p.color; this.ctx.fillRect(p.x, p.y, p.size, p.size);
      }
    });
    this.ctx.globalAlpha = 1.0;

    this.state.drops.forEach(d => {
      this.ctx.fillStyle = COLORS.ACCENT; this.ctx.beginPath(); this.ctx.arc(d.x, d.y, 10, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 10px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(d.name.toUpperCase(), d.x, d.y - 15);
    });

    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const kick = Date.now() - t.lastFired < 100 ? 8 : 0;
      this.ctx.fillRect(t.x - 15 - kick/2, t.y - 15 - kick/2, 30 + kick, 30 + kick);
      this.ctx.strokeStyle = t.color; this.ctx.globalAlpha = 0.05;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    const now = Date.now();
    this.state.enemies.forEach(e => {
      this.ctx.save(); this.ctx.translate(e.x, e.y); this.ctx.rotate(e.angle);
      if (e.lastHit && now - e.lastHit < 100) this.ctx.fillStyle = '#ffffff'; 
      else this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.beginPath();
      const s = e.size / 2;
      this.ctx.moveTo(s*1.8, 0); this.ctx.lineTo(-s, s); this.ctx.lineTo(-s, -s); this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();
      const hpWidth = e.size * 1.5;
      this.ctx.fillStyle = '#1e293b'; this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 10, hpWidth, 8);
      this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 10, hpWidth * (e.hp / e.maxHp), 8);
    });

    if (this.state.isGameOver || this.state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.98)'; this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    }
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints >= 0) {
      const isTech = skillId.startsWith('tech_') || skillId === 'root';
      this.state.skillPoints--;
      this.state.rerollCost = BASE_REROLL_COST;

      if (isTech) {
        if (!this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
        if (skillId === 'tech_passive') this.hasPassiveIncome = true;
        if (skillId === 'tech_god') {
          this.state.clickPower *= 3;
          this.state.towers.forEach(t => t.damage *= 3);
        }
      }

      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      if (skillId === 'code_gen') this.hasSaaS = true;
      if (skillId === 'click_1') this.state.clickPower *= 2;

      onUnlock(this.state);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }
}

import React from 'react';
import { GameState, PermanentUpgrades } from '../types';
import { TOWER_TYPES } from '../constants';
import { Terminal, Cpu, Zap, Code, Shield, Layers, Award, Star, Trophy, Rocket, Lock, Flame } from 'lucide-react';

interface Props {
  state: GameState;
  onBuildTower: (type: keyof typeof TOWER_TYPES) => void;
  onOpenSkills: () => void;
  onRestart: () => void;
  onBuyPermanent: (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => void;
}

const UIOverlay: React.FC<Props> = ({ state, onBuildTower, onOpenSkills, onRestart, onBuyPermanent }) => {
  const expProgress = (state.experience / (state.level < 5 ? 100 * Math.pow(state.level, 1.1) : 200 * Math.pow(state.level, 1.5))) * 100;
  const legacyEarned = Math.floor(state.code / 1000) * (state.isVictory ? 5 : 1);

  return (
    <div className="fixed inset-0 pointer-events-none flex flex-col justify-between p-3 sm:p-6">
      {/* Top Stats Bar */}
      <div className="flex flex-col sm:flex-row justify-between items-stretch sm:items-start gap-3 pointer-events-auto">
        <div className="flex gap-2 sm:gap-4 overflow-x-auto no-scrollbar">
          <div className="bg-slate-900/95 backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex-shrink-0 min-w-[140px] sm:min-w-[200px]">
            <div className="flex items-center gap-2 mb-1">
              <Code className="text-sky-400 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">LOC</span>
            </div>
            <div className="text-xl sm:text-2xl font-black text-white mb-1 tabular-nums">
              {Math.floor(state.code).toLocaleString()}
            </div>
            <div className="flex items-center gap-2 mb-1">
              <Zap className="text-amber-400 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">LVL {state.level}</span>
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="bg-gradient-to-r from-amber-600 to-amber-400 h-full transition-all duration-300" style={{ width: `${expProgress}%` }} />
            </div>
          </div>

          <div className={`bg-slate-900/95 backdrop-blur-md border p-3 sm:p-4 rounded-xl shadow-2xl flex items-center gap-3 transition-colors duration-500 ${state.threatLevel > 10 ? 'border-red-500' : 'border-slate-700'}`}>
            <Flame className={`w-5 h-5 sm:w-6 sm:h-6 ${state.threatLevel > 10 ? 'text-red-500 animate-pulse' : 'text-amber-500'}`} />
            <div>
              <div className="text-[8px] sm:text-[10px] text-slate-400 font-black uppercase tracking-widest">Heat Level</div>
              <div className={`text-lg sm:text-xl font-black tabular-nums ${state.threatLevel > 10 ? 'text-red-400' : 'text-white'}`}>
                {state.threatLevel.toFixed(1)}x
              </div>
            </div>
          </div>
        </div>

        <button 
          onClick={onOpenSkills} 
          className="group bg-slate-900/95 hover:bg-slate-800 transition-all backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex items-center justify-between sm:justify-start gap-4"
        >
          <div className="flex items-center gap-3">
            <div className="relative">
              <div className="bg-pink-500/20 p-2 rounded-lg group-hover:scale-110 transition-transform">
                <Cpu className="text-pink-400 w-5 h-5 sm:w-6 sm:h-6" />
              </div>
              {state.skillPoints > 0 && (
                <span className="absolute -top-1.5 -right-1.5 bg-pink-500 text-white text-[9px] w-5 h-5 flex items-center justify-center rounded-full animate-pulse border-2 border-slate-900 font-black">
                  {state.skillPoints}
                </span>
              )}
            </div>
            <div className="text-left">
              <div className="text-[8px] sm:text-[10px] text-slate-400 font-black uppercase tracking-widest">Infrastructure</div>
              <div className="text-xs sm:text-sm text-white font-bold italic">R&D SHOP</div>
            </div>
          </div>
        </button>
      </div>

      {/* Center Prompt */}
      {state.level === 1 && state.code < 150 && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 translate-y-20 pointer-events-none text-center animate-bounce">
          <div className="text-sky-400 font-black text-sm uppercase tracking-[0.3em]">Click the Core to Overclock</div>
          <div className="text-slate-500 text-[10px] font-bold uppercase tracking-widest">Summon Bugs for XP</div>
        </div>
      )}

      {/* Bottom Build Menu */}
      <div className="flex justify-center gap-2 sm:gap-4 pointer-events-auto mb-2 overflow-x-auto no-scrollbar pb-2 px-2">
        {(Object.entries(TOWER_TYPES) as [keyof typeof TOWER_TYPES, any][]).map(([key, config]) => {
          const towerCount = state.towers.filter(t => t.type === key).length;
          const currentCost = Math.floor(config.cost * Math.pow(1.5, towerCount));
          const isUnlocked = !config.requires || state.unlockedTech.includes(config.requires);
          const canAfford = state.code >= currentCost;

          return (
            <button
              key={key}
              onClick={() => isUnlocked && onBuildTower(key)}
              disabled={!isUnlocked || !canAfford}
              className={`
                group relative bg-slate-900/95 backdrop-blur-lg border p-3 sm:p-4 rounded-2xl flex flex-col items-center gap-1.5 transition-all flex-shrink-0 min-w-[100px] sm:min-w-[140px]
                ${isUnlocked && canAfford 
                  ? 'border-slate-700 hover:border-sky-400 hover:-translate-y-2 shadow-xl' 
                  : !isUnlocked ? 'border-slate-800 opacity-60 grayscale cursor-not-allowed' : 'border-transparent opacity-40 cursor-not-allowed'}
              `}
            >
              <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl flex items-center justify-center relative" style={{ backgroundColor: config.color + '15' }}>
                {key === 'BASIC' && <Shield className="text-sky-400 w-5 h-5 sm:w-6 sm:h-6" />}
                {key === 'SNIPER' && <Terminal className="text-pink-400 w-5 h-5 sm:w-6 sm:h-6" />}
                {key === 'RAPID' && <Layers className="text-amber-400 w-5 h-5 sm:w-6 sm:h-6" />}
                {!isUnlocked && (
                  <div className="absolute inset-0 flex items-center justify-center bg-black/60 rounded-xl">
                    <Lock className="text-white w-4 h-4" />
                  </div>
                )}
              </div>
              <div className="text-center">
                <div className="text-[10px] sm:text-xs font-black text-white uppercase tracking-tighter">{isUnlocked ? config.name : 'LOCKED'}</div>
                <div className={`text-[9px] sm:text-[10px] font-black tracking-widest ${canAfford ? 'text-sky-400' : 'text-red-500'}`}>
                  {isUnlocked ? `${currentCost.toLocaleString()} LOC` : 'R&D REQUIRED'}
                </div>
              </div>
            </button>
          );
        })}
      </div>

      {/* Victory Screen */}
      {state.isVictory && (
        <div className="fixed inset-0 bg-sky-950/90 backdrop-blur-2xl flex items-center justify-center pointer-events-auto p-4 z-50">
          <div className="bg-slate-900 border-4 border-sky-400 p-12 rounded-[3rem] shadow-[0_0_100px_rgba(56,189,248,0.3)] text-center max-w-2xl w-full">
            <Trophy className="w-24 h-24 text-sky-400 mx-auto mb-8 animate-bounce" />
            <h1 className="text-6xl font-black text-white mb-4 italic tracking-tighter">SILICON GOD</h1>
            <p className="text-xl text-sky-200 mb-8 font-medium">Infrastructure peak stability achieved.</p>
            <div className="bg-sky-500/10 border border-sky-400/30 p-8 rounded-3xl mb-10">
              <div className="text-3xl font-black text-white">+{legacyEarned} LEGACY POINTS</div>
            </div>
            <button onClick={onRestart} className="w-full bg-sky-400 hover:bg-white text-slate-900 font-black py-6 rounded-2xl transition-all text-2xl flex items-center justify-center gap-4 group">
              <Rocket className="group-hover:translate-x-2 transition-transform w-8 h-8" />
              ASCEND VERSION
            </button>
          </div>
        </div>
      )}

      {/* Game Over Screen */}
      {state.isGameOver && !state.isVictory && (
        <div className="fixed inset-0 bg-red-950/95 backdrop-blur-2xl flex items-center justify-center pointer-events-auto p-4 z-50">
          <div className="bg-slate-900 border border-slate-700 p-10 rounded-3xl shadow-2xl max-w-4xl w-full">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
