                    >
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-700 rounded-lg group-hover:scale-110 transition-transform">{upg.icon}</div>
                        <div className="text-left">
                          <div className="text-white font-bold text-sm">{upg.name}</div>
                          <div className="text-slate-400 text-xs">{upg.desc}</div>
                        </div>
                      </div>
                      <div className="bg-purple-600 text-white text-[10px] px-3 py-1.5 rounded-full font-black">25 LP</div>
                    </button>
                  ))}
