import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS } from '../constants';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const COMBO_TIMEOUT = 2500; 
const THREAT_DECAY = 0.05; 

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private hasSaaS: boolean = false;
  private hasPassiveIncome: boolean = false;
  private comboTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 250 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 250,
      experience: 0,
      level: 1,
      skillPoints: 0,
      clickPower: 20,
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      isGameOver: false,
      isVictory: false,
      lastRunCode: 0,
      availableSkills: [],
      unlockedTech: ['root'],
      rerollCost: BASE_REROLL_COST,
      combo: 0,
      threatLevel: 0.5,
      coreHp: 100,
      maxCoreHp: 100,
      permanentUpgrades: {
        startingCode: 0,
        damageMultiplier: 1.0,
        xpMultiplier: 1.0,
        legacyPoints: 0,
      }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 10 : 1;
    const codeLegacy = Math.floor(this.state.code / 250); 
    const levelLegacy = this.state.level * 5;
    const earnedLegacy = (codeLegacy + levelLegacy) * legacyFactor;

    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 250 + (perms.startingCode || 0);
    this.state.clickPower = 20 * perms.damageMultiplier;

    this.enemySpawnTimer = 0;
    this.hasAutoCollect = false;
    this.hasSaaS = false;
    this.hasPassiveIncome = false;
    this.comboTimer = 0;
    this.cameraScale = 1.0;
    this.targetCameraScale = 1.0;
    this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 50;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 1000;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.5;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 0.5;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    const shuffled = [...ALL_SKILLS].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.3);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    // Convert raw click to world coordinates
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const x = (rawX - cx) / this.cameraScale + cx;
    const y = (rawY - cy) / this.cameraScale + cy;

    let hit = false;
    const now = Date.now();

    const distToCore = Math.sqrt((x - cx) ** 2 + (y - cy) ** 2);
    if (distToCore < 100) {
      this.state.threatLevel += 1.0; 
      this.createParticles(cx, cy, 10, COLORS.ACCENT);
      this.createFloatingText(cx, cy, "SYSTEM OVERCLOCK!", COLORS.ACCENT);
      hit = true;
    }

    this.state.enemies = this.state.enemies.filter(enemy => {
      const dx = enemy.x - x;
      const dy = enemy.y - y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 75) {
        enemy.hp -= this.state.clickPower;
        enemy.lastHit = now;
        this.createParticles(enemy.x, enemy.y, 8, COLORS.PRIMARY);

        if (enemy.hp <= 0) {
          this.state.combo++;
          this.comboTimer = COMBO_TIMEOUT;
          this.state.threatLevel += 0.2; 

          const comboBonus = 1 + (this.state.combo * 0.1);
          const threatBonus = 1 + (this.state.threatLevel * 0.5);
          const levelBonus = 1 + (this.state.level * 0.1);

          const reward = Math.floor(enemy.value * comboBonus * threatBonus * levelBonus);
          const xpReward = (enemy.value / 1.2) * comboBonus * threatBonus * this.state.permanentUpgrades.xpMultiplier;

          this.state.code += reward;
          this.state.experience += xpReward;

          this.createFloatingText(enemy.x, enemy.y, `+${reward}`, COLORS.ACCENT);
          this.checkLevelUp();
          this.spawnDrop(enemy.x, enemy.y);
          hit = true;
          return false;
        }
        hit = true;
      }
      return true;
    });

    if (!hit) {
      this.state.code += 5;
      this.createFloatingText(x, y, "+5", COLORS.PRIMARY);
    }

    this.state.ripples.push({ x, y, radius: 0, maxRadius: 80, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x, y, vx: (Math.random() - 0.5) * 2, vy: -4, size: 16, life: 1.0, color, text
    });
  }

  private checkLevelUp() {
    const nextLevelExp = 60 + (this.state.level * 80);

    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.skillPoints += 1;

      if (this.state.level % 10 === 0) this.state.skillPoints += 1;

      // Handle Morph and Zoom every 5 levels
      if (this.state.level % 5 === 0) {
        this.targetCameraScale *= 0.85;
        this.state.maxCoreHp += 50;
        this.state.coreHp = Math.min(this.state.maxCoreHp, this.state.coreHp + 50);
        this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2, "SYSTEM EVOLVED", COLORS.PRIMARY);
      }

      this.refreshSkillShop();
      this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2, `LVL ${this.state.level} UP!`, COLORS.ACCENT);

      if (this.state.level >= 100) this.state.isVictory = true;
    }
  }

  private spawnDrop(x: number, y: number) {
    if (Math.random() > 0.8) {
      const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
      this.state.drops.push({
        id: Math.random().toString(36),
        name: lib.name, rarity: lib.rarity, effect: lib.effect, x, y, life: 1.0,
      });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const x = (rawX - cx) / this.cameraScale + cx;
    const y = (rawY - cy) / this.cameraScale + cy;

    const config = TOWER_TYPES[type];
    const towerCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.35, towerCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36),
        type, level: 1, x, y,
        range: config.range,
        damage: config.damage * this.state.permanentUpgrades.damageMultiplier,
        fireRate: config.fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x, y, vx: (Math.random() - 0.5) * 12, vy: (Math.random() - 0.5) * 12,
        size: Math.random() * 6 + 2, life: 1.0, color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 50);
    this.lastTime = time;
    this.update(dt);
    this.draw();
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    // Smoother Camera Transition
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    this.state.threatLevel = Math.max(0.5, this.state.threatLevel - (THREAT_DECAY * dt / 1000));

    if (this.comboTimer > 0) {
      this.comboTimer -= dt;
      if (this.comboTimer <= 0) this.state.combo = 0;
    }

    if (this.hasSaaS || this.hasPassiveIncome) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) {
        let gain = 0;
        if (this.hasSaaS) gain += 50 + (this.state.level * 20);
        if (this.hasPassiveIncome) gain += (this.state.level * 50);
        this.state.code += gain;
        this.passiveCodeTimer = 0;
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(80, 1500 - (this.state.level * 60));
    const threatMult = 1 + (this.state.threatLevel * 0.8);
    const spawnRate = baseFreq / threatMult;

    if (this.enemySpawnTimer > spawnRate) {
      const count = Math.min(10, Math.floor(1 + this.state.threatLevel / 5));
      for(let i=0; i<count; i++) this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx; p.y += p.vy;
      p.life -= p.text ? 0.015 : 0.05;
      return p.life > 0;
    });

    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 8; r.life -= 0.05;
      return r.life > 0;
    });

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.005;
      const dx = cx - d.x; const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const pullSpeed = (this.hasAutoCollect ? 15 : 5) * (1 + this.state.threatLevel * 0.1);
      const collectRadius = (this.hasAutoCollect ? 200 : 70) / this.cameraScale;

      if (dist < collectRadius) {
        this.state.code += 200 + (this.state.level * 50);
        this.createParticles(cx, cy, 5, COLORS.SECONDARY);
        return false;
      }
      d.x += (dx / dist) * pullSpeed; d.y += (dy / dist) * pullSpeed;
      return d.life > 0;
    });

    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x; const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Damage core on contact
      if (dist < 60) {
        this.state.coreHp -= 10 + (this.state.level * 0.5);
        this.createParticles(enemy.x, enemy.y, 5, COLORS.ENEMY);
        enemy.hp = 0; // Destroy enemy on contact
        if (this.state.coreHp <= 0) this.state.isGameOver = true;
      }

      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let nearest: Enemy | null = null;
        let minDist = tower.range;
        this.state.enemies.forEach(enemy => {
          const dx = enemy.x - tower.x; const dy = enemy.y - tower.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < minDist) { minDist = dist; nearest = enemy; }
        });
        if (nearest) {
          (nearest as Enemy).hp -= tower.damage;
          (nearest as Enemy).lastHit = now;
          tower.lastFired = now;
          this.createParticles((nearest as Enemy).x, (nearest as Enemy).y, 3, tower.color);
        }
      }
    });

    this.state.enemies = this.state.enemies.filter(enemy => enemy.hp > 0);

    this.onUpdate({ ...this.state });
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = (Math.sqrt(this.canvas.width ** 2 + this.canvas.height ** 2) / 2 + 300) / this.cameraScale;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;

    const isBoss = this.state.level % 10 === 0 && this.state.enemies.filter(e => e.type === 'boss').length === 0;
    const scalingFactor = Math.pow(1.12, this.state.level) * (1 + this.state.threatLevel * 0.1);
    const hp = (isBoss ? 200 : 20) * scalingFactor;

    this.state.enemies.push({
      id: Math.random().toString(36),
      x, y, hp, maxHp: hp,
      speed: (isBoss ? 0.7 : 1.8) + (this.state.level * 0.04) + (this.state.threatLevel * 0.06),
      value: (isBoss ? 2000 : 50) + this.state.level * 25,
      type: isBoss ? 'boss' : 'bug', 
      size: isBoss ? 65 : 28, 
      angle: 0,
    });
  }

  private drawPlanets(cx: number, cy: number) {
    const planetDist = 1500;
    const angles = [0, Math.PI / 2, Math.PI, Math.PI * 1.5];
    angles.forEach((a, i) => {
      const px = cx + Math.cos(a) * planetDist;
      const py = cy + Math.sin(a) * planetDist;

      // Draw Planet
      const grad = this.ctx.createRadialGradient(px, py, 0, px, py, 250);
      grad.addColorStop(0, '#1e293b');
      grad.addColorStop(1, '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath();
      this.ctx.arc(px, py, 250, 0, Math.PI * 2);
      this.ctx.fill();

      // Planet Aura
      this.ctx.strokeStyle = COLORS.ENEMY;
      this.ctx.lineWidth = 2;
      this.ctx.globalAlpha = 0.2 + Math.sin(Date.now() / 1000 + i) * 0.1;
      this.ctx.beginPath();
      this.ctx.arc(px, py, 260 + Math.sin(Date.now() / 500) * 10, 0, Math.PI * 2);
      this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });
  }

  private drawMainframe(cx: number, cy: number) {
    const mfSize = 60 + (this.state.level * 0.3);
    const pulse = Math.sin(Date.now() / 120) * (20 + this.state.threatLevel * 3);
    const coreColor = this.state.threatLevel > 20 ? COLORS.ENEMY : this.state.threatLevel > 10 ? COLORS.ACCENT : COLORS.PRIMARY;

    const morphStage = Math.floor(this.state.level / 5);

    this.ctx.save();
    this.ctx.shadowBlur = 40 + pulse; 
    this.ctx.shadowColor = coreColor;
    this.ctx.fillStyle = coreColor; 

    // Morphing logic
    if (morphStage < 1) {
      // Junior Core
      this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize, 0, Math.PI * 2); this.ctx.fill();
    } else if (morphStage < 2) {
      // Armored Core
      this.ctx.beginPath(); this.ctx.rect(cx - mfSize, cy - mfSize, mfSize * 2, mfSize * 2); this.ctx.fill();
      this.ctx.strokeStyle = '#fff'; this.ctx.lineWidth = 4; this.ctx.stroke();
    } else if (morphStage < 4) {
      // Hexagonal Core
      this.ctx.beginPath();
      for (let i = 0; i < 6; i++) {
        const a = (i / 6) * Math.PI * 2;
        const x = cx + Math.cos(a) * mfSize * 1.2;
        const y = cy + Math.sin(a) * mfSize * 1.2;
        if (i === 0) this.ctx.moveTo(x, y); else this.ctx.lineTo(x, y);
      }
      this.ctx.closePath(); this.ctx.fill();
      this.ctx.strokeStyle = '#fff'; this.ctx.lineWidth = 6; this.ctx.stroke();
    } else {
      // God Core
      this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize * 1.5, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = COLORS.SECONDARY; this.ctx.lineWidth = 8; this.ctx.stroke();
      // Orbitals
      for(let i=0; i<3; i++) {
        const a = (Date.now() / 1000) + (i * Math.PI * 2 / 3);
        const ox = cx + Math.cos(a) * mfSize * 2.5;
        const oy = cy + Math.sin(a) * mfSize * 2.5;
        this.ctx.fillStyle = COLORS.ACCENT;
        this.ctx.beginPath(); this.ctx.arc(ox, oy, 15, 0, Math.PI * 2); this.ctx.fill();
      }
    }

    this.ctx.restore();

    // Core Detail
    this.ctx.strokeStyle = '#fff';
    this.ctx.lineWidth = 4;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize * 0.6, 0, Math.PI * 2); this.ctx.stroke();
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;

    this.ctx.save();
    this.ctx.translate(cx, cy);
    this.ctx.scale(this.cameraScale, this.cameraScale);
    this.ctx.translate(-cx, -cy);

    // Grid
    this.ctx.strokeStyle = '#0f172a';
    this.ctx.lineWidth = 1;
    const gridSize = 100;
    const worldSize = 4000;
    for (let x = cx - worldSize; x < cx + worldSize; x += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(x, cy - worldSize); this.ctx.lineTo(x, cy + worldSize); this.ctx.stroke();
    }
    for (let y = cy - worldSize; y < cy + worldSize; y += gridSize) {
      this.ctx.beginPath(); this.ctx.moveTo(cx - worldSize, y); this.ctx.lineTo(cx + worldSize, y); this.ctx.stroke();
    }

    this.drawPlanets(cx, cy);
    this.drawMainframe(cx, cy);

    // Entities
    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 5;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    this.state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      if (p.text) {
        this.ctx.fillStyle = p.color; 
        this.ctx.font = `black ${p.size}px Space Grotesk`; 
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.fillStyle = p.color; this.ctx.fillRect(p.x, p.y, p.size, p.size);
      }
    });
    this.ctx.globalAlpha = 1.0;

    this.state.drops.forEach(d => {
      this.ctx.fillStyle = COLORS.ACCENT; this.ctx.beginPath(); this.ctx.arc(d.x, d.y, 12, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 12px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(d.name.toUpperCase(), d.x, d.y - 18);
    });

    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const kick = Date.now() - t.lastFired < 100 ? 10 : 0;
      this.ctx.fillRect(t.x - 18 - kick/2, t.y - 18 - kick/2, 36 + kick, 36 + kick);
      this.ctx.strokeStyle = t.color; this.ctx.globalAlpha = 0.08;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    const now = Date.now();
    this.state.enemies.forEach(e => {
      this.ctx.save(); this.ctx.translate(e.x, e.y); this.ctx.rotate(e.angle);
      if (e.lastHit && now - e.lastHit < 100) this.ctx.fillStyle = '#ffffff'; 
      else this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.beginPath();
      const s = e.size / 2;
      this.ctx.moveTo(s*2, 0); this.ctx.lineTo(-s, s); this.ctx.lineTo(-s, -s); this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();
      const hpWidth = e.size * 1.5;
      this.ctx.fillStyle = '#1e293b'; this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 12, hpWidth, 10);
      this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 12, hpWidth * (e.hp / e.maxHp), 10);
    });

    this.ctx.restore();

    if (this.state.isGameOver || this.state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.99)'; this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    }
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints >= 0) {
      const isTech = skillId.startsWith('tech_') || skillId === 'root';
      this.state.skillPoints--;
      this.state.rerollCost = BASE_REROLL_COST;

      if (isTech) {
        if (!this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
        if (skillId === 'tech_passive') this.hasPassiveIncome = true;
        if (skillId === 'tech_god') {
          this.state.clickPower *= 5;
          this.state.towers.forEach(t => t.damage *= 5);
        }
      }

      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      if (skillId === 'code_gen') this.hasSaaS = true;
      if (skillId === 'click_1') this.state.clickPower *= 3;

      onUnlock(this.state);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }
}

