              <Zap className="text-amber-400 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">LVL {state.level}</span>
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="bg-gradient-to-r from-amber-600 to-amber-400 h-full transition-all duration-300" style={{ width: `${expProgress}%` }} />
            </div>
          </div>

          <div className={`bg-slate-900/95 backdrop-blur-md border p-3 sm:p-4 rounded-xl shadow-2xl flex items-center gap-3 transition-colors duration-500 ${state.threatLevel > 15 ? 'border-red-500' : 'border-slate-700'}`}>
            <Flame className={`w-5 h-5 sm:w-6 sm:h-6 ${state.threatLevel > 15 ? 'text-red-500 animate-pulse' : 'text-amber-500'}`} />
            <div>
              <div className="text-[8px] sm:text-[10px] text-slate-400 font-black uppercase tracking-widest">Heat Level</div>
              <div className={`text-lg sm:text-xl font-black tabular-nums ${state.threatLevel > 15 ? 'text-red-400' : 'text-white'}`}>
                {state.threatLevel.toFixed(1)}x
              </div>
            </div>
          </div>

          <div className="bg-slate-900/95 backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex-shrink-0 min-w-[140px] sm:min-w-[200px]">
            <div className="flex items-center gap-2 mb-1">
              <Heart className="text-red-500 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">CORE STABILITY</span>
            </div>
            <div className="text-xl sm:text-2xl font-black text-white mb-1 tabular-nums">
              {Math.ceil(state.coreHp)}
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="bg-gradient-to-r from-red-600 to-red-400 h-full transition-all duration-300" style={{ width: `${coreHpPercent}%` }} />
            </div>
          </div>
        </div>

        <button 
          onClick={onOpenSkills} 
          className="group bg-slate-900/95 hover:bg-slate-800 transition-all backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex items-center justify-between sm:justify-start gap-4"
        >
          <div className="flex items-center gap-3">
            <div className="relative">
              <div className="bg-pink-500/20 p-2 rounded-lg group-hover:scale-110 transition-transform">
                <Cpu className="text-pink-400 w-5 h-5 sm:w-6 sm:h-6" />
              </div>
              {state.skillPoints > 0 && (
                <span className="absolute -top-1.5 -right-1.5 bg-pink-500 text-white text-[9px] w-5 h-5 flex items-center justify-center rounded-full animate-pulse border-2 border-slate-900 font-black">
                  {state.skillPoints}
                </span>
              )}
            </div>
            <div className="text-left">
              <div className="text-[8px] sm:text-[10px] text-slate-400 font-black uppercase tracking-widest">Infrastructure</div>
              <div className="text-xs sm:text-sm text-white font-bold italic uppercase">Research & Dev</div>
            </div>
          </div>
        </button>
      </div>

      {/* Center Prompt */}
      {state.level === 1 && state.code < 500 && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 translate-y-24 pointer-events-none text-center animate-bounce">
          <div className="text-sky-400 font-black text-xs uppercase tracking-[0.4em]">Spam click core for Heat</div>
          <div className="text-slate-500 text-[9px] font-bold uppercase tracking-widest">Higher Heat = Massive XP</div>
        </div>
      )}

      {/* Bottom Build Menu */}
      <div className="flex justify-center gap-2 sm:gap-4 pointer-events-auto mb-2 overflow-x-auto no-scrollbar pb-2 px-2">
        {(Object.entries(TOWER_TYPES) as [keyof typeof TOWER_TYPES, any][]).map(([key, config]) => {
          const towerCount = state.towers.filter(t => t.type === key).length;
          const currentCost = Math.floor(config.cost * Math.pow(1.35, towerCount));
          const isUnlocked = !config.requires || state.unlockedTech.includes(config.requires);
          const canAfford = state.code >= currentCost;

          return (
            <button
              key={key}
              onClick={() => isUnlocked && onBuildTower(key)}
              disabled={!isUnlocked || !canAfford}
              className={`
                group relative bg-slate-900/95 backdrop-blur-lg border p-3 sm:p-4 rounded-2xl flex flex-col items-center gap-1.5 transition-all flex-shrink-0 min-w-[100px] sm:min-w-[140px]
                ${isUnlocked && canAfford 
                  ? 'border-slate-700 hover:border-sky-400 hover:-translate-y-2 shadow-xl' 
                  : !isUnlocked ? 'border-slate-800 opacity-60 grayscale cursor-not-allowed' : 'border-transparent opacity-40 cursor-not-allowed'}
              `}
            >
              <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl flex items-center justify-center relative" style={{ backgroundColor: config.color + '15' }}>
                {key === 'BASIC' && <Shield className="text-sky-400 w-5 h-5 sm:w-6 sm:h-6" />}
                {key === 'SNIPER' && <Terminal className="text-pink-400 w-5 h-5 sm:w-6 sm:h-6" />}
                {key === 'RAPID' && <Layers className="text-amber-400 w-5 h-5 sm:w-6 sm:h-6" />}
                {!isUnlocked && <Lock className="absolute inset-0 m-auto text-white w-4 h-4" />}
              </div>
              <div className="text-center">
                <div className="text-[10px] sm:text-xs font-black text-white uppercase tracking-tighter">{isUnlocked ? config.name : 'LOCKED'}</div>
                <div className={`text-[9px] sm:text-[10px] font-black tracking-widest ${canAfford ? 'text-sky-400' : 'text-red-500'}`}>
                  {isUnlocked ? `${currentCost.toLocaleString()} LOC` : 'UPGRADE TREE'}
                </div>
              </div>
            </button>
          );
        })}
      </div>

      {/* Victory Screen */}
      {state.isVictory && (
        <div className="fixed inset-0 bg-sky-950/95 backdrop-blur-3xl flex items-center justify-center pointer-events-auto p-4 z-50">
          <div className="bg-slate-900 border-4 border-sky-400 p-12 rounded-[3rem] shadow-[0_0_150px_rgba(56,189,248,0.4)] text-center max-w-2xl w-full">
            <Trophy className="w-24 h-24 text-sky-400 mx-auto mb-8 animate-bounce" />
            <h1 className="text-6xl font-black text-white mb-4 italic tracking-tighter">SILICON GOD</h1>
            <p className="text-xl text-sky-200 mb-8 font-medium">Peak technical stability achieved.</p>
            <div className="bg-sky-500/10 border border-sky-400/30 p-8 rounded-3xl mb-10">
              <div className="text-4xl font-black text-white">+{legacyEarned} LEGACY POINTS</div>
              <div className="text-xs text-sky-400 font-bold mt-2 tracking-widest uppercase">10x Victory Multiplier Applied</div>
            </div>
            <button onClick={onRestart} className="w-full bg-sky-400 hover:bg-white text-slate-900 font-black py-6 rounded-2xl transition-all text-2xl flex items-center justify-center gap-4 group">
              <Rocket className="group-hover:translate-x-2 transition-transform w-8 h-8" />
              ASCEND TO v2.0
            </button>
          </div>
        </div>
      )}

      {/* Game Over Screen */}
      {state.isGameOver && !state.isVictory && (
        <div className="fixed inset-0 bg-red-950/95 backdrop-blur-3xl flex items-center justify-center pointer-events-auto p-4 z-50">
          <div className="bg-slate-900 border border-slate-700 p-10 rounded-3xl shadow-2xl max-w-4xl w-full">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="flex flex-col justify-center text-center md:text-left md:border-r border-slate-800 md:pr-12">
                <Shield className="text-red-500 w-20 h-20 mb-6 mx-auto md:mx-0" />
                <h1 className="text-5xl font-black text-white mb-2 italic tracking-tight uppercase">Segment Fault</h1>
                <p className="text-slate-400 mb-6 text-sm">System killed by overwhelming technical debt.</p>
                <div className="bg-purple-500/10 border border-purple-500/30 p-6 rounded-xl mb-8">
                  <div className="text-[10px] text-purple-400 font-black uppercase mb-1">Total Legacy Gain</div>
                  <div className="text-4xl font-black text-white">+{legacyEarned} LP</div>
                  <div className="text-[9px] text-slate-500 mt-2">({codeLP} from LOC + {levelLP} from Levels)</div>
                </div>
                <button onClick={onRestart} className="w-full bg-sky-500 hover:bg-sky-400 text-slate-900 font-black py-4 rounded-xl transition-all text-xl shadow-lg">
                  REWRITE & REBOOT
                </button>
              </div>
              <div>
                <h3 className="text-xl font-black text-white mb-6 flex items-center gap-2">
                  <Star className="text-amber-400 w-6 h-6 fill-amber-400" />
                  PERMANENT REFACTOR
                </h3>
                <div className="space-y-4">
                  {[
                    { id: 'startingCode', name: 'Series A Funding', desc: '+1000 Start LOC', icon: <Award className="text-sky-400" /> },
                    { id: 'damageMultiplier', name: 'Better Specs', desc: '+50% All Damage', icon: <Zap className="text-amber-400" /> },
                    { id: 'xpMultiplier', name: 'Knowledge Graph', desc: '+50% XP Bonus', icon: <Code className="text-purple-400" /> },
                  ].map(upg => (
                    <button 
                      key={upg.id}
                      onClick={() => onBuyPermanent(upg.id as any)}
                      disabled={state.permanentUpgrades.legacyPoints < 50}
                      className="w-full p-5 bg-slate-800/40 border border-slate-700 rounded-2xl hover:border-sky-400 transition-all flex justify-between items-center group disabled:opacity-30"
                    >
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-700 rounded-lg group-hover:scale-110 transition-transform">{upg.icon}</div>
                        <div className="text-left">
                          <div className="text-white font-bold text-sm">{upg.name}</div>
                          <div className="text-slate-400 text-xs">{upg.desc}</div>
                        </div>
                      </div>
                      <div className="bg-purple-600 text-white text-[10px] px-3 py-1.5 rounded-full font-black">50 LP</div>
                    </button>
                  ))}
                </div>
                <div className="mt-6 text-center text-xs text-slate-500 font-black uppercase tracking-[0.2em]">
                  Banked Legacy: {state.permanentUpgrades.legacyPoints}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UIOverlay;

export interface Point {
  x: number;
  y: number;
}

export interface Particle extends Point {
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
  text?: string;
}

export interface Projectile extends Point {
  id: string;
  targetId: string;
  speed: number;
  damage: number;
  color: string;
  type: 'allied' | 'enemy';
}

export interface Planet extends Point {
  id: string;
  hp: number;
  maxHp: number;
  isCaptured: boolean;
  size: number;
  color: string;
  name: string;
}

export interface ClickRipple extends Point {
  radius: number;
  maxRadius: number;
  life: number;
}

export interface Enemy extends Point {
  id: string;
  hp: number;
  maxHp: number;
  speed: number;
  value: number;
  type: 'bug' | 'boss' | 'glitch';
  size: number;
  angle: number;
  lastHit?: number;
  sourcePlanetId?: string;
}

export interface Tower extends Point {
  id: string;
  type: string;
  level: number;
  range: number;
  damage: number;
  fireRate: number;
  lastFired: number;
  color: string;
}

export interface LibraryDrop extends Point {
  id: string;
  name: string;
  rarity: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
  effect: string;
  life: number;
}

export interface PermanentUpgrades {
  startingCode: number;
  damageMultiplier: number;
  xpMultiplier: number;
  legacyPoints: number;
}

export interface SkillDefinition {
  id: string;
  name: string;
  description: string;
  cost: number;
  rarity: 'common' | 'rare' | 'epic';
}

export interface TechNode {
  id: string;
  name: string;
  description: string;
  cost: number;
  dependsOn?: string;
  position: { x: number, y: number };
}

export interface GameState {
  code: number;
  experience: number;
  level: number;
  skillPoints: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  planets: Planet[];
  projectiles: Projectile[];
  isGameOver: boolean;
  isVictory: boolean;
  permanentUpgrades: PermanentUpgrades;
  lastRunCode: number;
  availableSkills: string[];
  unlockedTech: string[];
  rerollCost: number;
  combo: number;
  threatLevel: number;
  coreHp: number;
  maxCoreHp: number;
}

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades, Planet, Projectile } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS } from '../constants';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const COMBO_TIMEOUT = 2500; 
const THREAT_DECAY = 0.05; 
const PLANET_COUNT = 4;
const ALLIED_ARROW_SPEED = 12;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private planetAttackTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private hasSaaS: boolean = false;
  private hasPassiveIncome: boolean = false;
  private comboTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 1800;
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`,
        name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 1000,
        maxHp: 1000,
        isCaptured: false,
        size: 250,
        color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 250 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 250,
      experience: 0,
      level: 1,
      skillPoints: 0,
      clickPower: 20,
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      planets: [],
      projectiles: [],
      isGameOver: false,
      isVictory: false,
      lastRunCode: 0,
      availableSkills: [],
      unlockedTech: ['root'],
      rerollCost: BASE_REROLL_COST,
      combo: 0,
      threatLevel: 0.5,
      coreHp: 100,
      maxCoreHp: 100,
      permanentUpgrades: {
        startingCode: 0,
        damageMultiplier: 1.0,
        xpMultiplier: 1.0,
        legacyPoints: 0,
      }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 10 : 1;
    const codeLegacy = Math.floor(this.state.code / 250); 
    const levelLegacy = this.state.level * 5;
    const earnedLegacy = (codeLegacy + levelLegacy) * legacyFactor;

    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 250 + (perms.startingCode || 0);
    this.state.clickPower = 20 * perms.damageMultiplier;

    this.enemySpawnTimer = 0;
    this.hasAutoCollect = false;
    this.hasSaaS = false;
    this.hasPassiveIncome = false;
    this.comboTimer = 0;
    this.cameraScale = 1.0;
    this.targetCameraScale = 1.0;
    this.generatePlanets();
    this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 50;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 1000;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.5;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 0.5;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    const shuffled = [...ALL_SKILLS].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.3);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const x = (rawX - cx) / this.cameraScale + cx;
    const y = (rawY - cy) / this.cameraScale + cy;

    let hit = false;
    const now = Date.now();

    // Core Overclock
    const distToCore = Math.sqrt((x - cx) ** 2 + (y - cy) ** 2);
    if (distToCore < 100) {
      this.state.threatLevel += 1.0; 
      this.createParticles(cx, cy, 10, COLORS.ACCENT);
      this.createFloatingText(cx, cy, "SYSTEM OVERCLOCK!", COLORS.ACCENT);
      hit = true;
    }

    // Check Planets
    this.state.planets.forEach(planet => {
      if (!planet.isCaptured) {
        const pdx = x - planet.x;
        const pdy = y - planet.y;
        const pdist = Math.sqrt(pdx * pdx + pdy * pdy);
        if (pdist < planet.size) {
          planet.hp -= this.state.clickPower;
          this.createParticles(x, y, 5, COLORS.ENEMY);
          if (planet.hp <= 0) {
            planet.hp = 0;
            planet.isCaptured = true;
            planet.color = COLORS.PRIMARY;
            this.state.experience += 500;
            this.checkLevelUp();
            this.createFloatingText(planet.x, planet.y, "PLANET CAPTURED!", COLORS.PRIMARY);
          }
          hit = true;
        }
      }
    });

    // Check Enemies
    this.state.enemies = this.state.enemies.filter(enemy => {
      const dx = enemy.x - x;
      const dy = enemy.y - y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 75) {
        enemy.hp -= this.state.clickPower;
        enemy.lastHit = now;
        this.createParticles(enemy.x, enemy.y, 8, COLORS.PRIMARY);

        if (enemy.hp <= 0) {
          this.state.combo++;
          this.comboTimer = COMBO_TIMEOUT;
          this.state.threatLevel += 0.2; 

          const comboBonus = 1 + (this.state.combo * 0.1);
          const threatBonus = 1 + (this.state.threatLevel * 0.5);
          const levelBonus = 1 + (this.state.level * 0.1);

          const reward = Math.floor(enemy.value * comboBonus * threatBonus * levelBonus);
          const xpReward = (enemy.value / 1.2) * comboBonus * threatBonus * this.state.permanentUpgrades.xpMultiplier;

          this.state.code += reward;
          this.state.experience += xpReward;

          this.createFloatingText(enemy.x, enemy.y, `+${reward}`, COLORS.ACCENT);
          this.checkLevelUp();
          this.spawnDrop(enemy.x, enemy.y);
          hit = true;
          return false;
        }
        hit = true;
      }
      return true;
    });

    if (!hit) {
      this.state.code += 5;
      this.createFloatingText(x, y, "+5", COLORS.PRIMARY);
    }

    this.state.ripples.push({ x, y, radius: 0, maxRadius: 80, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x, y, vx: (Math.random() - 0.5) * 2, vy: -4, size: 16, life: 1.0, color, text
    });
  }

  private checkLevelUp() {
    const nextLevelExp = 60 + (this.state.level * 80);

    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.skillPoints += 1;

      if (this.state.level % 10 === 0) this.state.skillPoints += 1;

      if (this.state.level % 5 === 0) {
        this.targetCameraScale = Math.max(0.2, this.targetCameraScale - 0.1);
        this.state.maxCoreHp += 100;
        this.state.coreHp = this.state.maxCoreHp;
        this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2, "SYSTEM EVOLVED", COLORS.PRIMARY);
      }

      this.refreshSkillShop();
      this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2, `LVL ${this.state.level} UP!`, COLORS.ACCENT);

      if (this.state.level >= 100) this.state.isVictory = true;
    }
  }

  private spawnDrop(x: number, y: number) {
    if (Math.random() > 0.8) {
      const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
      this.state.drops.push({
        id: Math.random().toString(36),
        name: lib.name, rarity: lib.rarity, effect: lib.effect, x, y, life: 1.0,
      });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const x = (rawX - cx) / this.cameraScale + cx;
    const y = (rawY - cy) / this.cameraScale + cy;

    const config = TOWER_TYPES[type];
    const towerCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.35, towerCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36),
        type, level: 1, x, y,
        range: config.range,
        damage: config.damage * this.state.permanentUpgrades.damageMultiplier,
        fireRate: config.fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x, y, vx: (Math.random() - 0.5) * 12, vy: (Math.random() - 0.5) * 12,
        size: Math.random() * 6 + 2, life: 1.0, color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 50);
    this.lastTime = time;
    this.update(dt);
    this.draw();
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;
    this.state.threatLevel = Math.max(0.5, this.state.threatLevel - (THREAT_DECAY * dt / 1000));

    if (this.comboTimer > 0) {
      this.comboTimer -= dt;
      if (this.comboTimer <= 0) this.state.combo = 0;
    }

    if (this.hasSaaS || this.hasPassiveIncome) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) {
        let gain = 0;
        if (this.hasSaaS) gain += 50 + (this.state.level * 20);
        if (this.hasPassiveIncome) gain += (this.state.level * 50);
        this.state.code += gain;
        this.passiveCodeTimer = 0;
      }
    }

    // Spawn Allied Arrows from captured planets
    this.planetAttackTimer += dt;
    if (this.planetAttackTimer > 2000) {
      this.state.planets.filter(p => p.isCaptured).forEach(planet => {
        const target = this.state.planets.find(p => !p.isCaptured);
        if (target) {
          this.state.projectiles.push({
            id: Math.random().toString(36),
            targetId: target.id,
            x: planet.x,
            y: planet.y,
            speed: ALLIED_ARROW_SPEED,
            damage: 50 + (this.state.level * 5),
            color: COLORS.PRIMARY,
            type: 'allied'
          });
        }
      });
      this.planetAttackTimer = 0;
    }

    // Projectile Movement
    this.state.projectiles = this.state.projectiles.filter(proj => {
      const target = this.state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;

      const dx = target.x - proj.x;
      const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 30) {
        target.hp -= proj.damage;
        this.createParticles(proj.x, proj.y, 10, proj.color);
        if (target.hp <= 0 && !target.isCaptured) {
          target.isCaptured = true;
          target.color = COLORS.PRIMARY;
          target.hp = 0;
          this.createFloatingText(target.x, target.y, "PLANET SECURED", COLORS.PRIMARY);
        }
        return false;
      }

      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // Enemy Spawning - Spawn from specific enemy planets
    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(80, 1500 - (this.state.level * 60));
    const threatMult = 1 + (this.state.threatLevel * 0.8);
    const spawnRate = baseFreq / threatMult;

    if (this.enemySpawnTimer > spawnRate) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      if (activePlanets.length > 0) {
        const source = activePlanets[Math.floor(Math.random() * activePlanets.length)];
        this.spawnEnemyFromPlanet(source);
      } else {
        // All planets captured - generate enemies from the void
        this.spawnEnemy();
      }
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx; p.y += p.vy;
      p.life -= p.text ? 0.015 : 0.05;
      return p.life > 0;
    });

    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 8; r.life -= 0.05;
      return r.life > 0;
    });

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.005;
      const dx = cx - d.x; const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const pullSpeed = (this.hasAutoCollect ? 15 : 5) * (1 + this.state.threatLevel * 0.1);
      const collectRadius = (this.hasAutoCollect ? 200 : 70) / this.cameraScale;

      if (dist < collectRadius) {
        this.state.code += 200 + (this.state.level * 50);
        this.createParticles(cx, cy, 5, COLORS.SECONDARY);
        return false;
      }
      d.x += (dx / dist) * pullSpeed; d.y += (dy / dist) * pullSpeed;
      return d.life > 0;
    });

    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x; const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 60) {
        this.state.coreHp -= 10 + (this.state.level * 0.5);
        this.createParticles(enemy.x, enemy.y, 5, COLORS.ENEMY);
        enemy.hp = 0;
        if (this.state.coreHp <= 0) this.state.isGameOver = true;
      }

      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let nearest: (Enemy | Planet) | null = null;
        let minDist = tower.range;

        // Target nearest Enemy
        this.state.enemies.forEach(enemy => {
          const dx = enemy.x - tower.x; const dy = enemy.y - tower.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < minDist) { minDist = dist; nearest = enemy; }
        });

        // Target nearest Enemy Planet if no enemies close
        if (!nearest) {
          this.state.planets.filter(p => !p.isCaptured).forEach(planet => {
             const dx = planet.x - tower.x; const dy = planet.y - tower.y;
             const dist = Math.sqrt(dx * dx + dy * dy);
             if (dist < minDist) { minDist = dist; nearest = planet; }
          });
        }

        if (nearest) {
          nearest.hp -= tower.damage;
          if ('lastHit' in nearest) (nearest as Enemy).lastHit = now;
          tower.lastFired = now;
          this.createParticles(nearest.x, nearest.y, 3, tower.color);
        }
      }
    });

    this.state.enemies = this.state.enemies.filter(enemy => enemy.hp > 0);
    this.state.planets.forEach(p => { if (p.hp <= 0 && !p.isCaptured) { p.isCaptured = true; p.color = COLORS.PRIMARY; } });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemyFromPlanet(source: Planet) {
    const angle = Math.random() * Math.PI * 2;
    const x = source.x + Math.cos(angle) * source.size * 0.8;
    const y = source.y + Math.sin(angle) * source.size * 0.8;
    this.createEnemyAt(x, y);
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = (Math.sqrt(this.canvas.width ** 2 + this.canvas.height ** 2) / 2 + 500) / this.cameraScale;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;
    this.createEnemyAt(x, y);
  }

  private createEnemyAt(x: number, y: number) {
    const isBoss = this.state.level % 10 === 0 && this.state.enemies.filter(e => e.type === 'boss').length === 0;
    const scalingFactor = Math.pow(1.12, this.state.level) * (1 + this.state.threatLevel * 0.1);
    const hp = (isBoss ? 200 : 20) * scalingFactor;

    this.state.enemies.push({
      id: Math.random().toString(36),
      x, y, hp, maxHp: hp,
      speed: (isBoss ? 0.7 : 1.8) + (this.state.level * 0.04) + (this.state.threatLevel * 0.06),
      value: (isBoss ? 2000 : 50) + this.state.level * 25,
      type: isBoss ? 'boss' : 'bug', 
      size: isBoss ? 65 : 28, 
      angle: 0,
    });
  }

  private drawMainframe(cx: number, cy: number) {
    const mfSize = 60 + (this.state.level * 0.3);
    const pulse = Math.sin(Date.now() / 120) * (20 + this.state.threatLevel * 3);
    const coreColor = this.state.threatLevel > 20 ? COLORS.ENEMY : this.state.threatLevel > 10 ? COLORS.ACCENT : COLORS.PRIMARY;

    const morphStage = Math.floor(this.state.level / 5);

    this.ctx.save();
    this.ctx.shadowBlur = 40 + pulse; 
    this.ctx.shadowColor = coreColor;
    this.ctx.fillStyle = coreColor; 

    if (morphStage < 1) {
      this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize, 0, Math.PI * 2); this.ctx.fill();
    } else if (morphStage < 2) {
      this.ctx.beginPath(); this.ctx.rect(cx - mfSize, cy - mfSize, mfSize * 2, mfSize * 2); this.ctx.fill();
      this.ctx.strokeStyle = '#fff'; this.ctx.lineWidth = 4; this.ctx.stroke();
    } else if (morphStage < 4) {
      this.ctx.beginPath();
      for (let i = 0; i < 6; i++) {
        const a = (i / 6) * Math.PI * 2;
        const x = cx + Math.cos(a) * mfSize * 1.2;
        const y = cy + Math.sin(a) * mfSize * 1.2;
        if (i === 0) this.ctx.moveTo(x, y); else this.ctx.lineTo(x, y);
      }
      this.ctx.closePath(); this.ctx.fill();
      this.ctx.strokeStyle = '#fff'; this.ctx.lineWidth = 6; this.ctx.stroke();
    } else {
      this.ctx.beginPath();
      for (let i = 0; i < 12; i++) {
        const r = i % 2 === 0 ? mfSize * 2.0 : mfSize * 1.0;
        const a = (i / 12) * Math.PI * 2;
        const x = cx + Math.cos(a) * r;
        const y = cy + Math.sin(a) * r;
        if (i === 0) this.ctx.moveTo(x, y); else this.ctx.lineTo(x, y);
      }
      this.ctx.closePath(); this.ctx.fill();
      this.ctx.strokeStyle = COLORS.SECONDARY; this.ctx.lineWidth = 8; this.ctx.stroke();
      for(let i=0; i<3; i++) {
        const a = (Date.now() / 1000) + (i * Math.PI * 2 / 3);
        const ox = cx + Math.cos(a) * mfSize * 3.5;
        const oy = cy + Math.sin(a) * mfSize * 3.5;
        this.ctx.fillStyle = COLORS.ACCENT;
        this.ctx.beginPath(); this.ctx.arc(ox, oy, 20, 0, Math.PI * 2); this.ctx.fill();
      }
    }
    this.ctx.restore();
    this.ctx.strokeStyle = '#fff';
    this.ctx.lineWidth = 4;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize * 0.6, 0, Math.PI * 2); this.ctx.stroke();
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;

    this.ctx.save();
    this.ctx.translate(cx, cy);
    this.ctx.scale(this.cameraScale, this.cameraScale);
    this.ctx.translate(-cx, -cy);

    // Planet Rendering
    this.state.planets.forEach(planet => {
      this.ctx.save();
      const grad = this.ctx.createRadialGradient(planet.x, planet.y, 0, planet.x, planet.y, planet.size);
      grad.addColorStop(0, planet.isCaptured ? '#0c4a6e' : '#450a0a');
      grad.addColorStop(1, planet.isCaptured ? '#020617' : '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath();
      this.ctx.arc(planet.x, planet.y, planet.size, 0, Math.PI * 2);
      this.ctx.fill();

      this.ctx.strokeStyle = planet.color;
      this.ctx.lineWidth = 10;
      this.ctx.globalAlpha = 0.3 + Math.sin(Date.now() / 300) * 0.1;
      this.ctx.beginPath();
      this.ctx.arc(planet.x, planet.y, planet.size + 15, 0, Math.PI * 2);
      this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;

      // HP Bar for planet
      const hpW = planet.size;
      this.ctx.fillStyle = '#1e293b';
      this.ctx.fillRect(planet.x - hpW / 2, planet.y - planet.size - 40, hpW, 20);
      this.ctx.fillStyle = planet.color;
      this.ctx.fillRect(planet.x - hpW / 2, planet.y - planet.size - 40, hpW * (planet.hp / planet.maxHp), 20);

      this.ctx.fillStyle = '#fff';
      this.ctx.font = 'bold 30px Space Grotesk';
      this.ctx.textAlign = 'center';
      this.ctx.fillText(planet.name.toUpperCase(), planet.x, planet.y + 10);
      this.ctx.restore();
    });

    this.drawMainframe(cx, cy);

    // Allied Arrows / Projectiles
    this.state.projectiles.forEach(p => {
      this.ctx.save();
      const target = this.state.planets.find(plan => plan.id === p.targetId);
      if (target) {
        const angle = Math.atan2(target.y - p.y, target.x - p.x);
        this.ctx.translate(p.x, p.y);
        this.ctx.rotate(angle);
        this.ctx.fillStyle = p.color;
        this.ctx.beginPath();
        this.ctx.moveTo(25, 0);
        this.ctx.lineTo(-15, 12);
        this.ctx.lineTo(-15, -12);
        this.ctx.closePath();
        this.ctx.fill();
        // Glow trail
        this.ctx.shadowBlur = 15;
        this.ctx.shadowColor = p.color;
        this.ctx.fillRect(-30, -3, 30, 6);
      }
      this.ctx.restore();
    });

    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 5;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    this.state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      if (p.text) {
        this.ctx.fillStyle = p.color; 
        this.ctx.font = `black ${p.size}px Space Grotesk`; 
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.fillStyle = p.color; this.ctx.fillRect(p.x, p.y, p.size, p.size);
      }
    });
    this.ctx.globalAlpha = 1.0;

    this.state.drops.forEach(d => {
      this.ctx.fillStyle = COLORS.ACCENT; this.ctx.beginPath(); this.ctx.arc(d.x, d.y, 12, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 12px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(d.name.toUpperCase(), d.x, d.y - 18);
    });

    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const kick = Date.now() - t.lastFired < 100 ? 10 : 0;
      this.ctx.fillRect(t.x - 18 - kick/2, t.y - 18 - kick/2, 36 + kick, 36 + kick);
      this.ctx.strokeStyle = t.color; this.ctx.globalAlpha = 0.08;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    const now = Date.now();
    this.state.enemies.forEach(e => {
      this.ctx.save(); this.ctx.translate(e.x, e.y); this.ctx.rotate(e.angle);
      if (e.lastHit && now - e.lastHit < 100) this.ctx.fillStyle = '#ffffff'; 
      else this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.beginPath();
      const s = e.size / 2;
      this.ctx.moveTo(s*2, 0); this.ctx.lineTo(-s, s); this.ctx.lineTo(-s, -s); this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();
      const hpWidth = e.size * 1.5;
      this.ctx.fillStyle = '#1e293b'; this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 12, hpWidth, 10);
      this.ctx.fillStyle = e.type === 'boss' ? COLORS.BOSS : COLORS.ENEMY;
      this.ctx.fillRect(e.x - hpWidth/2, e.y - e.size - 12, hpWidth * (e.hp / e.maxHp), 10);
    });

    this.ctx.restore();

    if (this.state.isGameOver || this.state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.99)'; this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    }
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints >= 0) {
      const isTech = skillId.startsWith('tech_') || skillId === 'root';
      this.state.skillPoints--;
      this.state.rerollCost = BASE_REROLL_COST;

      if (isTech) {
        if (!this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
        if (skillId === 'tech_passive') this.hasPassiveIncome = true;
        if (skillId === 'tech_god') {
          this.state.clickPower *= 5;
          this.state.towers.forEach(t => t.damage *= 5);
        }
      }

      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      if (skillId === 'code_gen') this.hasSaaS = true;
      if (skillId === 'click_1') this.state.clickPower *= 3;

      onUnlock(this.state);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }
}

