              <Zap className="text-amber-400 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">LVL {state.level}</span>
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="bg-gradient-to-r from-amber-600 to-amber-400 h-full transition-all duration-300" style={{ width: `${expProgress}%` }} />
            </div>
          </div>

          {/* SYNC STAT (Manual SP) */}
          <div className={`bg-slate-900/95 backdrop-blur-md border p-3 sm:p-4 rounded-xl shadow-2xl flex-shrink-0 min-w-[140px] sm:min-w-[180px] transition-colors ${state.towers.length > 0 ? 'border-pink-500/50' : 'border-slate-800 opacity-50'}`}>
            <div className="flex items-center gap-2 mb-1">
              <MousePointer2 className="text-pink-400 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">NETWORK SYNC</span>
            </div>
            <div className="text-xl sm:text-2xl font-black text-white mb-1 tabular-nums">
              {state.towers.length > 0 ? `${state.spProgress}/${state.spGoal}` : "OFFLINE"}
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="bg-gradient-to-r from-pink-600 to-pink-400 h-full transition-all duration-300" style={{ width: `${syncProgress}%` }} />
            </div>
            {state.towers.length === 0 && <div className="text-[8px] text-pink-500 font-bold mt-1">BUILD TOWERS TO ENABLE</div>}
          </div>

          {/* UPTIME STAT */}
          <div className="bg-slate-900/95 backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex-shrink-0 min-w-[140px] sm:min-w-[180px]">
            <div className="flex items-center gap-2 mb-1">
              <Heart className="text-red-500 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">UPTIME</span>
            </div>
            <div className="text-xl sm:text-2xl font-black text-white mb-1 tabular-nums">
              {Math.max(0, Math.ceil(state.coreHp))}
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="bg-gradient-to-r from-red-600 to-red-400 h-full transition-all duration-300" style={{ width: `${coreHpPercent}%` }} />
            </div>
          </div>
        </div>

        {/* TECH TREE BUTTON */}
        <button 
          onClick={onOpenSkills} 
          className="group bg-slate-900/95 hover:bg-slate-800 transition-all backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex items-center justify-between sm:justify-start gap-4"
        >
          <div className="flex items-center gap-3">
            <div className="relative">
              <div className="bg-pink-500/20 p-2 rounded-lg group-hover:scale-110 transition-transform">
                <Cpu className="text-pink-400 w-5 h-5 sm:w-6 sm:h-6" />
              </div>
              {state.skillPoints > 0 && (
                <span className="absolute -top-1.5 -right-1.5 bg-pink-500 text-white text-[9px] w-5 h-5 flex items-center justify-center rounded-full animate-pulse border-2 border-slate-900 font-black">
                  {state.skillPoints}
                </span>
              )}
            </div>
            <div className="text-left">
              <div className="text-[8px] sm:text-[10px] text-slate-400 font-black uppercase tracking-widest">R&D HUB</div>
              <div className="text-xs sm:text-sm text-white font-bold italic uppercase">TECH TREE</div>
            </div>
          </div>
        </button>
      </div>

      {/* PLACEMENT HINT */}
      {state.level === 1 && state.towers.length === 0 && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 translate-y-32 pointer-events-none text-center">
          <div className="text-pink-400 font-black text-sm uppercase tracking-[0.4em] animate-pulse">Build your first Logic Gate</div>
          <div className="text-slate-500 text-[9px] font-bold uppercase tracking-widest mt-2">Then tap enemies to harvest Skill Points</div>
        </div>
      )}

      {/* BUILD MENU */}
      <div className="flex justify-center gap-2 sm:gap-4 pointer-events-auto mb-2 overflow-x-auto no-scrollbar pb-2 px-2">
        {(Object.entries(TOWER_TYPES) as [keyof typeof TOWER_TYPES, any][]).map(([key, config]) => {
          const towerCount = state.towers.filter(t => t.type === key).length;
          const currentCost = Math.floor(config.cost * Math.pow(1.25, towerCount));
          const isUnlocked = !config.requires || state.unlockedTech.includes(config.requires);
          const canAfford = state.code >= currentCost;
          return (
            <button
              key={key}
              onClick={() => isUnlocked && onBuildTower(key)}
              disabled={!isUnlocked || !canAfford}
              className={`group relative bg-slate-900/95 backdrop-blur-lg border p-3 sm:p-4 rounded-2xl flex flex-col items-center gap-1.5 transition-all flex-shrink-0 min-w-[100px] sm:min-w-[140px] ${isUnlocked && canAfford ? 'border-slate-700 hover:border-sky-400 hover:-translate-y-2' : 'opacity-40 grayscale cursor-not-allowed'}`}
            >
              <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl flex items-center justify-center relative" style={{ backgroundColor: config.color + '15' }}>
                {key === 'BASIC' && <Shield className="text-sky-400 w-5 h-5 sm:w-6 sm:h-6" />}
                {key === 'SNIPER' && <Terminal className="text-pink-400 w-5 h-5 sm:w-6 sm:h-6" />}
                {key === 'RAPID' && <Layers className="text-amber-400 w-5 h-5 sm:w-6 sm:h-6" />}
                {!isUnlocked && <Lock className="absolute inset-0 m-auto text-white w-4 h-4" />}
              </div>
              <div className="text-center">
                <div className="text-[10px] sm:text-xs font-black text-white uppercase tracking-tight">{isUnlocked ? config.name : 'ENCRYPTED'}</div>
                <div className={`text-[9px] sm:text-[10px] font-black ${canAfford ? 'text-sky-400' : 'text-red-500'}`}>{currentCost.toLocaleString()} LOC</div>
              </div>
            </button>
          );
        })}
      </div>

      {/* GAME OVER SCREEN */}
      {state.isGameOver && (
        <div className="fixed inset-0 bg-red-950/98 backdrop-blur-3xl flex items-center justify-center pointer-events-auto p-4 z-50">
          <div className="bg-slate-900 border border-slate-700 p-10 rounded-3xl shadow-2xl max-w-4xl w-full">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="text-center md:text-left md:border-r border-slate-800 md:pr-12">
                <h1 className="text-5xl font-black text-white mb-2 italic uppercase">Crash Detected</h1>
                <p className="text-slate-400 mb-6 text-sm">System integrity failed at Level {state.level}.</p>
                <div className="bg-purple-500/10 border border-purple-500/30 p-6 rounded-xl mb-8">
                  <div className="text-4xl font-black text-white">+{legacyEarned} LP</div>
                  <div className="text-[9px] text-purple-400 mt-1 uppercase tracking-widest font-bold">Banked Legacy Points</div>
                </div>
                <button onClick={onRestart} className="w-full bg-sky-500 hover:bg-sky-400 text-slate-900 font-black py-4 rounded-xl text-xl shadow-[0_0_30px_rgba(56,189,248,0.3)]">REBOOT CLUSTER</button>
              </div>
              <div>
                <h3 className="text-xl font-black text-white mb-6 flex items-center gap-2"><Star className="text-amber-400 w-6 h-6 fill-amber-400" />PERMANENT UPGRADES</h3>
                <div className="space-y-4">
                  {[
                    { id: 'startingCode', name: 'Angel Funding', desc: '+2k Start LOC', icon: <Award className="text-sky-400" /> },
                    { id: 'damageMultiplier', name: 'Custom Kernels', desc: '+80% Damage', icon: <Zap className="text-amber-400" /> },
                    { id: 'xpMultiplier', name: 'Training Data', desc: '+80% XP Gain', icon: <Code className="text-purple-400" /> },
                  ].map(upg => (
                    <button key={upg.id} onClick={() => onBuyPermanent(upg.id as any)} disabled={state.permanentUpgrades.legacyPoints < 100} className="w-full p-4 bg-slate-800/40 border border-slate-700 rounded-2xl hover:border-sky-400 flex justify-between items-center group disabled:opacity-30">
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-700 rounded-lg group-hover:scale-110 transition-transform">{upg.icon}</div>
                        <div className="text-left"><div className="text-white font-bold text-sm">{upg.name}</div><div className="text-slate-400 text-xs">{upg.desc}</div></div>
                      </div>
                      <div className="bg-purple-600 text-white text-[10px] px-3 py-1 rounded-full font-black">100 LP</div>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

