import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades, Planet, Projectile } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS } from '../constants';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const COMBO_TIMEOUT = 2500; 
const THREAT_DECAY = 0.05; 
const PLANET_COUNT = 4;
const ALLIED_ARROW_SPEED = 20;
const MAX_ENEMIES_ON_SCREEN = 60;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private planetAttackTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private hasSaaS: boolean = false;
  private hasPassiveIncome: boolean = false;
  private comboTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`,
        name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false,
        size: 350,
        color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 1200,
      experience: 0,
      level: 1,
      skillPoints: 2,
      spProgress: 0,
      spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35,
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      planets: [],
      projectiles: [],
      isGameOver: false,
      isVictory: false,
      lastRunCode: 0,
      availableSkills: [],
      unlockedTech: ['root'],
      rerollCost: BASE_REROLL_COST,
      combo: 0,
      threatLevel: 0.5,
      coreHp: 250,
      maxCoreHp: 250,
      permanentUpgrades: {
        startingCode: 0,
        damageMultiplier: 1.0,
        xpMultiplier: 1.0,
        legacyPoints: 0,
      }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 25 : 1;
    const earnedLegacy = (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;

    this.cameraScale = 1.0;
    this.targetCameraScale = 1.0;
    this.generatePlanets();
    this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    const shuffled = [...ALL_SKILLS].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const now = Date.now();
    let hitSomething = false;

    // Direct Clicks generate a small shard progress immediately
    if (this.state.towers.length > 0) {
        this.state.spProgress += 0.1; 
    }

    const splashRadius = 120 + (this.state.level * 4);

    this.state.enemies.forEach(enemy => {
      const dx = enemy.x - worldX;
      const dy = enemy.y - worldY;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= this.state.clickPower * damageMult;
        enemy.lastHit = now;

        if (damageMult > 0.75) {
          hitSomething = true;
          this.createParticles(enemy.x, enemy.y, 4, COLORS.PRIMARY);
        }

        if (enemy.hp <= 0) {
          this.processEnemyDeath(enemy, true);
        }
      }
    });

    if (!hitSomething) {
      this.state.code += 25;
      this.createFloatingText(worldX, worldY, "+25", COLORS.PRIMARY);
    }

    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: splashRadius, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private processEnemyDeath(enemy: Enemy, isManual: boolean) {
    this.state.combo++;
    this.comboTimer = COMBO_TIMEOUT;

    // Scaling rewards
    const rewardMult = (1 + this.state.threatLevel * 0.15) * this.state.permanentUpgrades.xpMultiplier;
    const locValue = Math.floor(enemy.value * rewardMult);
    const xpValue = (enemy.value / 2) * rewardMult;

    this.state.experience += xpValue;
    this.state.code += locValue;

    // Spawn drops instead of direct SP to make it tactile
    this.spawnDrop(enemy.x, enemy.y, isManual);

    this.checkLevelUp();
    enemy.hp = -999;
  }

  private spawnDrop(x: number, y: number, isManual: boolean) {
    const rand = Math.random();
    // Shard drops for SP progress
    if (rand < (isManual ? 0.35 : 0.15)) {
        this.state.drops.push({
            id: Math.random().toString(36),
            name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP Progress', x, y, life: 1.0
        });
    } 
    // Data packets for LOC boost
    else if (rand < 0.5) {
        this.state.drops.push({
            id: Math.random().toString(36),
            name: 'Data', type: 'loc', rarity: 'common', effect: 'LOC Boost', x, y, life: 1.0
        });
    }
    // Rare library drops
    else if (rand > 0.96) {
        const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
        this.state.drops.push({
            id: Math.random().toString(36),
            name: lib.name, type: 'library', rarity: lib.rarity, effect: lib.effect, x, y, life: 1.0
        });
    }
  }

  private checkLevelUp() {
    const nextLevelExp = 200 + (this.state.level * 250);

    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.clickPower *= 1.15;

      if (this.state.level % 5 === 0) {
        this.targetCameraScale = Math.max(0.1, 1.0 / (1 + (this.state.level / 8)));
        this.state.maxCoreHp += 500;
        this.state.coreHp = this.state.maxCoreHp;
      }

      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const config = TOWER_TYPES[type];
    const towerCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, towerCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36),
        type, level: 1, x: worldX, y: worldY,
        range: config.range,
        damage: config.damage * this.state.permanentUpgrades.damageMultiplier,
        fireRate: config.fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x, y, vx: (Math.random() - 0.5) * 10, vy: (Math.random() - 0.5) * 10,
        size: Math.random() * 5 + 2, life: 1.0, color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.update(dt);
    this.draw();
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;
    this.state.threatLevel = Math.max(0.5, this.state.threatLevel - (THREAT_DECAY * dt / 1000));

    if (this.comboTimer > 0) {
      this.comboTimer -= dt;
      if (this.comboTimer <= 0) this.state.combo = 0;
    }

    // Allied planet logic
    this.planetAttackTimer += dt;
    if (this.planetAttackTimer > 1000) {
      this.state.planets.filter(p => p.isCaptured).forEach(planet => {
        const target = this.state.planets.find(p => !p.isCaptured);
        if (target) {
          this.state.projectiles.push({
            id: Math.random().toString(36), targetId: target.id, x: planet.x, y: planet.y,
            speed: ALLIED_ARROW_SPEED, damage: 300 + (this.state.level * 30),
            color: COLORS.PRIMARY, type: 'allied'
          });
        }
      });
      this.planetAttackTimer = 0;
    }

    this.state.projectiles = this.state.projectiles.filter(proj => {
      const target = this.state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x; const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        this.createParticles(proj.x, proj.y, 8, proj.color);
        if (target.hp <= 0 && !target.isCaptured) {
           target.isCaptured = true; target.color = COLORS.PRIMARY; target.hp = 0;
           this.state.experience += 1000;
           this.checkLevelUp();
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed; proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // Swarm logic: merge enemies
    if (this.state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = this.state.enemies[Math.floor(Math.random() * this.state.enemies.length)];
      const e2 = this.state.enemies[Math.floor(Math.random() * this.state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id) {
          e1.hp += e2.hp; e1.maxHp += e2.maxHp; e1.size = Math.min(150, e1.size + 15);
          e1.value += e2.value; e2.hp = -999;
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(200, 3000 - (this.state.level * 80));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      if (source) this.spawnEnemyFromPlanet(source);
      else this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    // Update particles and ripples
    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx; p.y += p.vy;
      p.life -= p.text ? 0.02 : 0.07;
      return p.life > 0;
    });
    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 15; r.life -= 0.1;
      return r.life > 0;
    });

    // Handle Drops Collection (Auto Collect logic)
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.002;
      const dx = cx - d.x; const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const vacuumRadius = (this.hasAutoCollect ? 1200 : 80) / this.cameraScale;
      const vacuumSpeed = this.hasAutoCollect ? 25 : 4;

      if (dist < 80 / this.cameraScale) {
        // Collect!
        if (d.type === 'shard') {
          this.state.spProgress += 1;
          if (this.state.spProgress >= this.state.spGoal) {
            this.state.skillPoints += 1;
            this.state.spProgress = 0;
            this.state.spGoal = Math.floor(this.state.spGoal * 1.1) + 2;
            this.createFloatingText(cx, cy, "+1 SKILL POINT", COLORS.SECONDARY);
          }
        } else if (d.type === 'loc') {
          this.state.code += 500 + (this.state.level * 100);
        }
        this.createParticles(cx, cy, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        return false;
      }

      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // Enemy movement
    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x; const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        this.state.coreHp -= 25 + (this.state.level * 2);
        this.createParticles(enemy.x, enemy.y, 10, COLORS.ENEMY);
        enemy.hp = -1;
        if (this.state.coreHp <= 0) this.state.isGameOver = true;
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Tower firing logic
    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let nearest: (Enemy | Planet) | null = null;
        let minDist = tower.range;
        this.state.enemies.forEach(e => {
          const dist = Math.sqrt((e.x - tower.x)**2 + (e.y - tower.y)**2);
          if (dist < minDist) { minDist = dist; nearest = e; }
        });
        if (!nearest) {
          this.state.planets.filter(p => !p.isCaptured).forEach(p => {
             const dist = Math.sqrt((p.x - tower.x)**2 + (p.y - tower.y)**2);
             if (dist < minDist) { minDist = dist; nearest = p; }
          });
        }
        if (nearest) {
          nearest.hp -= tower.damage;
          // TOWERS ALWAYS GENERATE XP ON HIT
          this.state.experience += tower.damage * 0.1 * this.state.permanentUpgrades.xpMultiplier;
          if ('lastHit' in nearest) (nearest as Enemy).lastHit = now;
          tower.lastFired = now;
          if ('id' in nearest && nearest.hp <= 0 && nearest.hp > -100) this.processEnemyDeath(nearest as Enemy, false);
        }
      }
    });

    this.state.enemies = this.state.enemies.filter(e => e.hp > 0);
    this.onUpdate({ ...this.state });
  }

  private spawnEnemyFromPlanet(source: Planet) {
    const angle = Math.random() * Math.PI * 2;
    const x = source.x + Math.cos(angle) * source.size * 0.4;
    const y = source.y + Math.sin(angle) * source.size * 0.4;
    this.createEnemyAt(x, y);
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3600 / this.cameraScale;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;
    this.createEnemyAt(x, y);
  }

  private createEnemyAt(x: number, y: number) {
    const scalingFactor = Math.pow(1.1, this.state.level);
    const hp = 80 * scalingFactor;
    this.state.enemies.push({
      id: Math.random().toString(36), x, y, hp, maxHp: hp,
      speed: 1.6 + (this.state.level * 0.05), value: 150 + this.state.level * 60,
      type: 'bug', size: 40 + (this.state.level * 0.7), angle: 0,
    });
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;

    this.ctx.save();
    this.ctx.translate(cx, cy);
    this.ctx.scale(this.cameraScale, this.cameraScale);
    this.ctx.translate(-cx, -cy);

    // Render Planets
    this.state.planets.forEach(p => {
      const grad = this.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size);
      grad.addColorStop(0, p.isCaptured ? '#0c4a6e' : '#450a0a');
      grad.addColorStop(0.9, '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = p.isCaptured ? COLORS.PRIMARY : COLORS.ENEMY; this.ctx.lineWidth = 15; this.ctx.globalAlpha = 0.2;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 25, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 50px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // Core
    const mfSize = 90 + (this.state.level * 0.6);
    const coreColor = this.state.threatLevel > 15 ? COLORS.ENEMY : COLORS.PRIMARY;
    this.ctx.fillStyle = coreColor; this.ctx.shadowBlur = 80; this.ctx.shadowColor = coreColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // Drops (Tactile visuals)
    this.state.drops.forEach(d => {
        this.ctx.save();
        this.ctx.shadowBlur = 15;
        this.ctx.shadowColor = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
        this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : d.type === 'loc' ? COLORS.PRIMARY : COLORS.ACCENT;
        if (d.type === 'shard') {
            this.ctx.beginPath();
            this.ctx.moveTo(d.x, d.y - 12);
            this.ctx.lineTo(d.x + 12, d.y);
            this.ctx.lineTo(d.x, d.y + 12);
            this.ctx.lineTo(d.x - 12, d.y);
            this.ctx.closePath();
            this.ctx.fill();
        } else {
            this.ctx.fillRect(d.x - 10, d.y - 10, 20, 20);
        }
        this.ctx.restore();
    });

    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 8;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    this.state.enemies.forEach(e => {
      this.ctx.save(); this.ctx.translate(e.x, e.y); this.ctx.rotate(e.angle);
      this.ctx.fillStyle = Date.now() - (e.lastHit || 0) < 100 ? '#fff' : COLORS.ENEMY;
      this.ctx.beginPath(); this.ctx.moveTo(e.size, 0); this.ctx.lineTo(-e.size/2, e.size/2); this.ctx.lineTo(-e.size/2, -e.size/2); this.ctx.closePath();
      this.ctx.fill(); this.ctx.restore();
    });

    this.state.projectiles.forEach(p => {
        this.ctx.fillStyle = p.color;
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, 10, 0, Math.PI * 2); this.ctx.fill();
    });

    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color; this.ctx.fillRect(t.x-30, t.y-30, 60, 60);
    });

    this.ctx.restore();

    if (this.state.isGameOver || this.state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.99)'; this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    }
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      this.state.skillPoints--;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      if (skillId === 'code_gen') this.hasSaaS = true;
      if (skillId === 'click_1') this.state.clickPower *= 3;
      onUnlock(this.state);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x, y, vx: (Math.random() - 0.5) * 2, vy: -5, size: 30, life: 1.0, color, text
    });
  }
}

import React from 'react';
import { GameState, PermanentUpgrades } from '../types';
import { TOWER_TYPES, COLORS } from '../constants';
import { Terminal, Cpu, Zap, Code, Shield, Layers, Award, Star, Trophy, Rocket, Lock, Flame, Heart, Globe, MousePointer2, Database } from 'lucide-react';

interface Props {
  state: GameState;
  onBuildTower: (type: keyof typeof TOWER_TYPES) => void;
  onOpenSkills: () => void;
  onRestart: () => void;
  onBuyPermanent: (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => void;
}

const UIOverlay: React.FC<Props> = ({ state, onBuildTower, onOpenSkills, onRestart, onBuyPermanent }) => {
  const nextLevelExp = 200 + (state.level * 250);
  const expProgress = (state.experience / nextLevelExp) * 100;
  const coreHpPercent = (state.coreHp / state.maxCoreHp) * 100;
  const syncProgress = (state.spProgress / state.spGoal) * 100;

  const legacyEarned = (Math.floor(state.code / 100) + state.level * 15) * (state.isVictory ? 25 : 1);
  const capturedPlanets = state.planets.filter(p => p.isCaptured).length;

  return (
    <div className="fixed inset-0 pointer-events-none flex flex-col justify-between p-3 sm:p-6">
      {/* TOP STATS */}
      <div className="flex flex-col sm:flex-row justify-between items-stretch sm:items-start gap-3 pointer-events-auto">
        <div className="flex gap-2 sm:gap-4 overflow-x-auto no-scrollbar">
          {/* LOC */}
          <div className="bg-slate-900/95 backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex-shrink-0 min-w-[140px] sm:min-w-[180px]">
            <div className="flex items-center gap-2 mb-1">
              <Code className="text-sky-400 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">LOCAL CODE</span>
            </div>
            <div className="text-xl sm:text-2xl font-black text-white mb-1 tabular-nums">
              {Math.floor(state.code).toLocaleString()}
            </div>
            <div className="flex items-center gap-2 mb-1">
              <Zap className="text-amber-400 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">LEVEL {state.level}</span>
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="bg-gradient-to-r from-amber-600 to-amber-400 h-full transition-all duration-300" style={{ width: `${expProgress}%` }} />
            </div>
          </div>

          {/* NETWORK SYNC (SP Progress) */}
          <div className={`bg-slate-900/95 backdrop-blur-md border p-3 sm:p-4 rounded-xl shadow-2xl flex-shrink-0 min-w-[140px] sm:min-w-[180px] transition-colors ${state.towers.length > 0 ? 'border-pink-500/50' : 'border-slate-800 opacity-50'}`}>
            <div className="flex items-center gap-2 mb-1">
              <Database className="text-pink-400 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">SKILL FRAGMENTS</span>
            </div>
            <div className="text-xl sm:text-2xl font-black text-white mb-1 tabular-nums">
              {state.spProgress.toFixed(0)}/{state.spGoal}
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="bg-gradient-to-r from-pink-600 to-pink-400 h-full transition-all duration-300" style={{ width: `${syncProgress}%` }} />
            </div>
            <div className="text-[7px] text-pink-500/80 font-bold mt-1 uppercase">Pick up pink shards from enemies</div>
          </div>

          {/* SYSTEM UPTIME */}
          <div className="bg-slate-900/95 backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex-shrink-0 min-w-[140px] sm:min-w-[180px]">
            <div className="flex items-center gap-2 mb-1">
              <Heart className="text-red-500 w-3 h-3 sm:w-4 sm:h-4" />
              <span className="text-slate-400 text-[8px] sm:text-[10px] font-black uppercase tracking-widest">SYSTEM UPTIME</span>
            </div>
            <div className="text-xl sm:text-2xl font-black text-white mb-1 tabular-nums">
              {Math.max(0, Math.ceil(state.coreHp))}
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="bg-gradient-to-r from-red-600 to-red-400 h-full transition-all duration-300" style={{ width: `${coreHpPercent}%` }} />
            </div>
          </div>
        </div>

        {/* TECH TREE */}
        <button 
          onClick={onOpenSkills} 
          className="group bg-slate-900/95 hover:bg-slate-800 transition-all backdrop-blur-md border border-slate-700 p-3 sm:p-4 rounded-xl shadow-2xl flex items-center justify-between sm:justify-start gap-4"
        >
          <div className="flex items-center gap-3">
            <div className="relative">
              <div className="bg-pink-500/20 p-2 rounded-lg group-hover:scale-110 transition-transform">
                <Cpu className="text-pink-400 w-5 h-5 sm:w-6 sm:h-6" />
              </div>
              {state.skillPoints > 0 && (
                <span className="absolute -top-2 -right-2 bg-pink-500 text-white text-[10px] w-6 h-6 flex items-center justify-center rounded-full animate-pulse border-2 border-slate-900 font-black">
                  {state.skillPoints}
                </span>
              )}
            </div>
            <div className="text-left">
              <div className="text-[8px] sm:text-[10px] text-slate-400 font-black uppercase tracking-widest">RESEARCH HUB</div>
              <div className="text-xs sm:text-sm text-white font-bold uppercase italic">TECH STACK</div>
            </div>
          </div>
        </button>
      </div>

      {/* CENTER HINT */}
      {state.level === 1 && state.towers.length === 0 && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 translate-y-36 pointer-events-none text-center">
          <div className="text-sky-400 font-black text-xs uppercase tracking-[0.4em] animate-pulse">Defend the Mainframe</div>
          <div className="text-slate-500 text-[9px] font-bold uppercase tracking-widest mt-2">Build towers to generate XP & Click enemies for SP shards</div>
        </div>
      )}

      {/* BUILDER */}
      <div className="flex justify-center gap-2 sm:gap-4 pointer-events-auto mb-2 overflow-x-auto no-scrollbar pb-2 px-2">
        {(Object.entries(TOWER_TYPES) as [keyof typeof TOWER_TYPES, any][]).map(([key, config]) => {
          const towerCount = state.towers.filter(t => t.type === key).length;
          const currentCost = Math.floor(config.cost * Math.pow(1.2, towerCount));
          const isUnlocked = !config.requires || state.unlockedTech.includes(config.requires);
          const canAfford = state.code >= currentCost;
          return (
            <button
              key={key}
              onClick={() => isUnlocked && onBuildTower(key)}
              disabled={!isUnlocked || !canAfford}
              className={`group relative bg-slate-900/95 backdrop-blur-lg border p-3 sm:p-4 rounded-2xl flex flex-col items-center gap-1.5 transition-all flex-shrink-0 min-w-[110px] sm:min-w-[150px] ${isUnlocked && canAfford ? 'border-slate-700 hover:border-sky-400 hover:-translate-y-2' : 'opacity-30 grayscale cursor-not-allowed'}`}
            >
              <div className="w-12 h-12 sm:w-14 sm:h-14 rounded-xl flex items-center justify-center relative" style={{ backgroundColor: config.color + '20' }}>
                {key === 'BASIC' && <Shield className="text-sky-400 w-6 h-6 sm:w-7 sm:h-7" />}
                {key === 'SNIPER' && <Terminal className="text-pink-400 w-6 h-6 sm:w-7 sm:h-7" />}
                {key === 'RAPID' && <Layers className="text-amber-400 w-6 h-6 sm:w-7 sm:h-7" />}
                {!isUnlocked && <Lock className="absolute inset-0 m-auto text-white w-5 h-5" />}
              </div>
              <div className="text-center">
                <div className="text-[10px] sm:text-xs font-black text-white uppercase">{isUnlocked ? config.name : 'LOCKED'}</div>
                <div className={`text-[10px] font-black ${canAfford ? 'text-sky-400' : 'text-red-500'}`}>{currentCost.toLocaleString()} LOC</div>
              </div>
            </button>
          );
        })}
      </div>

      {/* GAME OVER */}
      {state.isGameOver && (
        <div className="fixed inset-0 bg-red-950/98 backdrop-blur-3xl flex items-center justify-center pointer-events-auto p-4 z-50">
          <div className="bg-slate-900 border border-slate-700 p-12 rounded-[2.5rem] shadow-2xl max-w-4xl w-full">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="text-center md:text-left md:border-r border-slate-800 md:pr-12">
                <h1 className="text-6xl font-black text-white mb-2 italic uppercase">System Exit</h1>
                <p className="text-slate-400 mb-8 text-sm">Cluster failed at Level {state.level}. Technical debt too high.</p>
                <div className="bg-purple-500/10 border border-purple-500/30 p-8 rounded-2xl mb-8 text-center">
                  <div className="text-5xl font-black text-white">+{legacyEarned} LP</div>
                  <div className="text-[10px] text-purple-400 mt-2 uppercase font-black tracking-widest">Venture Capital Earned</div>
                </div>
                <button onClick={onRestart} className="w-full bg-sky-500 hover:bg-sky-400 text-slate-900 font-black py-5 rounded-2xl text-2xl">HARD REBOOT</button>
              </div>
              <div className="flex flex-col justify-center">
                <h3 className="text-xl font-black text-white mb-6 flex items-center gap-2"><Star className="text-amber-400 w-6 h-6 fill-amber-400" />ANGEL INVESTMENTS</h3>
                <div className="space-y-4">
                  {[
                    { id: 'startingCode', name: 'Seed Round', desc: '+2.5k Start LOC', icon: <Award className="text-sky-400" /> },
                    { id: 'damageMultiplier', name: 'Optimized Kernels', desc: '+80% Total Power', icon: <Zap className="text-amber-400" /> },
                    { id: 'xpMultiplier', name: 'Neural Training', desc: '+100% XP Learning', icon: <Code className="text-purple-400" /> },
                  ].map(upg => (
                    <button key={upg.id} onClick={() => onBuyPermanent(upg.id as any)} disabled={state.permanentUpgrades.legacyPoints < 100} className="w-full p-4 bg-slate-800/40 border border-slate-700 rounded-2xl hover:border-sky-400 flex justify-between items-center group disabled:opacity-30">
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-700 rounded-lg group-hover:scale-110 transition-transform">{upg.icon}</div>
                        <div className="text-left"><div className="text-white font-bold text-sm">{upg.name}</div><div className="text-slate-400 text-xs">{upg.desc}</div></div>
                      </div>
                      <div className="bg-purple-600 text-white text-[11px] px-3 py-1.5 rounded-full font-black">100 LP</div>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UIOverlay;

export interface Point {
  x: number;
  y: number;
}

export interface Particle extends Point {
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
  text?: string;
}

export interface Projectile extends Point {
  id: string;
  targetId: string;
  speed: number;
  damage: number;
  color: string;
  type: 'allied' | 'enemy';
}

export interface Planet extends Point {
  id: string;
  hp: number;
  maxHp: number;
  isCaptured: boolean;
  size: number;
  color: string;
  name: string;
}

export interface ClickRipple extends Point {
  radius: number;
  maxRadius: number;
  life: number;
}

export interface Enemy extends Point {
  id: string;
  hp: number;
  maxHp: number;
  speed: number;
  value: number;
  type: 'bug' | 'boss' | 'glitch';
  size: number;
  angle: number;
  lastHit?: number;
  sourcePlanetId?: string;
}

export interface Tower extends Point {
  id: string;
  type: string;
  level: number;
  range: number;
  damage: number;
  fireRate: number;
  lastFired: number;
  color: string;
}

export interface LibraryDrop extends Point {
  id: string;
  name: string;
  type: 'loc' | 'shard' | 'library';
  rarity: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
  effect: string;
  life: number;
}

export interface PermanentUpgrades {
  startingCode: number;
  damageMultiplier: number;
  xpMultiplier: number;
  legacyPoints: number;
}

export interface TechNode {
  id: string;
  name: string;
  description: string;
  cost: number;
  position: { x: number; y: number };
  dependsOn?: string;
}

export interface GameState {
  code: number;
  experience: number;
  level: number;
  skillPoints: number;
  spProgress: number;
  spGoal: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  planets: Planet[];
  projectiles: Projectile[];
  isGameOver: boolean;
  isVictory: boolean;
  permanentUpgrades: PermanentUpgrades;
  lastRunCode: number;
  availableSkills: string[];
  unlockedTech: string[];
  unlockedSkills: string[]; // Track one-time skill purchases
  rerollCost: number;
  combo: number;
  threatLevel: number;
  coreHp: number;
  maxCoreHp: number;
}

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades, Planet, Projectile } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const COMBO_TIMEOUT = 2500; 
const THREAT_DECAY = 0.05; 
const PLANET_COUNT = 4;
const ALLIED_ARROW_SPEED = 20;
const MAX_ENEMIES_ON_SCREEN = 60;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private planetAttackTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private hasSaaS: boolean = false;
  private hasPassiveIncome: boolean = false;
  private comboTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`,
        name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false,
        size: 350,
        color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 1200,
      experience: 0,
      level: 1,
      skillPoints: 2,
      spProgress: 0,
      spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35,
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      planets: [],
      projectiles: [],
      isGameOver: false,
      isVictory: false,
      lastRunCode: 0,
      availableSkills: [],
      unlockedTech: ['root'],
      unlockedSkills: [],
      rerollCost: BASE_REROLL_COST,
      combo: 0,
      threatLevel: 0.5,
      coreHp: 250,
      maxCoreHp: 250,
      permanentUpgrades: {
        startingCode: 0,
        damageMultiplier: 1.0,
        xpMultiplier: 1.0,
        legacyPoints: 0,
      }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 25 : 1;
    const earnedLegacy = (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;

    this.cameraScale = 1.0;
    this.targetCameraScale = 1.0;
    this.generatePlanets();
    this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    // Filter out skills that are one-time and already unlocked
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const now = Date.now();
    let hitSomething = false;

    // 1. Check for item collection by clicking
    const dropCollectionRadius = 50 / this.cameraScale;
    let itemsCollected = 0;
    this.state.drops = this.state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX)**2 + (d.y - worldY)**2);
      if (dist < dropCollectionRadius) {
        this.collectDropItem(d);
        itemsCollected++;
        hitSomething = true;
        return false;
      }
      return true;
    });

    if (itemsCollected > 0) {
      this.onUpdate({ ...this.state });
      // If we clicked items, we don't also fire a splash damage click usually, 
      // but let's allow it for better feel.
    }

    // 2. Click damage
    const splashRadius = 120 + (this.state.level * 4);
    this.state.enemies.forEach(enemy => {
      const dx = enemy.x - worldX;
      const dy = enemy.y - worldY;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= this.state.clickPower * damageMult;
        enemy.lastHit = now;

        if (damageMult > 0.75) {
          hitSomething = true;
          this.createParticles(enemy.x, enemy.y, 4, COLORS.PRIMARY);
        }

        if (enemy.hp <= 0) {
          this.processEnemyDeath(enemy, true);
        }
      }
    });

    if (!hitSomething) {
      this.state.code += 25;
      this.createFloatingText(worldX, worldY, "+25", COLORS.PRIMARY);
    }

    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: splashRadius, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private collectDropItem(d: LibraryDrop) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    if (d.type === 'shard') {
      this.state.spProgress += 1;
      if (this.state.spProgress >= this.state.spGoal) {
        this.state.skillPoints += 1;
        this.state.spProgress = 0;
        this.state.spGoal = Math.floor(this.state.spGoal * 1.1) + 2;
        this.createFloatingText(cx, cy, "+1 SKILL POINT", COLORS.SECONDARY);
      }
    } else if (d.type === 'loc') {
      const gain = 500 + (this.state.level * 100);
      this.state.code += gain;
      this.createFloatingText(d.x, d.y, `+${gain}`, COLORS.PRIMARY);
    }
    this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
  }

  private processEnemyDeath(enemy: Enemy, isManual: boolean) {
    this.state.combo++;
    this.comboTimer = COMBO_TIMEOUT;

    // Scaling rewards
    let rewardMult = (1 + this.state.threatLevel * 0.15) * this.state.permanentUpgrades.xpMultiplier;
    if (this.state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (this.state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    const locValue = Math.floor(enemy.value * rewardMult);
    const xpValue = (enemy.value / 2) * rewardMult;

    this.state.experience += xpValue;
    this.state.code += locValue;

    this.spawnDrop(enemy.x, enemy.y, isManual);
    this.checkLevelUp();
    enemy.hp = -999;
  }

  private spawnDrop(x: number, y: number, isManual: boolean) {
    const rand = Math.random();
    let shardChance = isManual ? 0.4 : 0.2;
    if (this.state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    if (rand < shardChance) {
        this.state.drops.push({
            id: Math.random().toString(36),
            name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP Progress', x, y, life: 1.0
        });
    } 
    else if (rand < 0.5) {
        this.state.drops.push({
            id: Math.random().toString(36),
            name: 'Data', type: 'loc', rarity: 'common', effect: 'LOC Boost', x, y, life: 1.0
        });
    }
    else if (rand > 0.96) {
        const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
        this.state.drops.push({
            id: Math.random().toString(36),
            name: lib.name, type: 'library', rarity: lib.rarity, effect: lib.effect, x, y, life: 1.0
        });
    }
  }

  private checkLevelUp() {
    const nextLevelExp = 200 + (this.state.level * 250);

    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.clickPower *= 1.15;

      if (this.state.level % 5 === 0) {
        this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
        this.state.maxCoreHp += 500;
        this.state.coreHp = this.state.maxCoreHp;
      }

      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const config = TOWER_TYPES[type];
    const towerCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, towerCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let damage = config.damage * this.state.permanentUpgrades.damageMultiplier;
      let range = config.range;
      let fireRate = config.fireRate;

      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36),
        type, level: 1, x: worldX, y: worldY,
        range: range,
        damage: damage,
        fireRate: fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x, y, vx: (Math.random() - 0.5) * 10, vy: (Math.random() - 0.5) * 10,
        size: Math.random() * 5 + 2, life: 1.0, color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.update(dt);
    this.draw();
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;
    this.state.threatLevel = Math.max(0.5, this.state.threatLevel - (THREAT_DECAY * dt / 1000));

    if (this.comboTimer > 0) {
      this.comboTimer -= dt;
      if (this.comboTimer <= 0) this.state.combo = 0;
    }

    // Tech Passive
    if (this.state.unlockedTech.includes('tech_passive')) {
        this.passiveCodeTimer += dt;
        if (this.passiveCodeTimer > 1000) {
            this.state.code += this.state.level * 250;
            this.passiveCodeTimer = 0;
        }
    }

    this.planetAttackTimer += dt;
    if (this.planetAttackTimer > 1000) {
      this.state.planets.filter(p => p.isCaptured).forEach(planet => {
        const target = this.state.planets.find(p => !p.isCaptured);
        if (target) {
          this.state.projectiles.push({
            id: Math.random().toString(36), targetId: target.id, x: planet.x, y: planet.y,
            speed: ALLIED_ARROW_SPEED, damage: 300 + (this.state.level * 30),
            color: COLORS.PRIMARY, type: 'allied'
          });
        }
      });
      this.planetAttackTimer = 0;
    }

    this.state.projectiles = this.state.projectiles.filter(proj => {
      const target = this.state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x; const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        this.createParticles(proj.x, proj.y, 8, proj.color);
        if (target.hp <= 0 && !target.isCaptured) {
           target.isCaptured = true; target.color = COLORS.PRIMARY; target.hp = 0;
           this.state.experience += 2500;
           this.checkLevelUp();
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed; proj.y += (dy / dist) * proj.speed;
      return true;
    });

    if (this.state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = this.state.enemies[Math.floor(Math.random() * this.state.enemies.length)];
      const e2 = this.state.enemies[Math.floor(Math.random() * this.state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id) {
          e1.hp += e2.hp; e1.maxHp += e2.maxHp; e1.size = Math.min(150, e1.size + 15);
          e1.value += e2.value; e2.hp = -999;
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      if (source) this.spawnEnemyFromPlanet(source);
      else this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx; p.y += p.vy;
      p.life -= p.text ? 0.02 : 0.07;
      return p.life > 0;
    });
    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 15; r.life -= 0.1;
      return r.life > 0;
    });

    // Handle Drops Collection
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x; const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const vacuumRadius = (this.hasAutoCollect ? 1500 : 0) / this.cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / this.cameraScale) {
        this.collectDropItem(d);
        return false;
      }

      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x; const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        this.state.coreHp -= 25 + (this.state.level * 2);
        this.createParticles(enemy.x, enemy.y, 10, COLORS.ENEMY);
        enemy.hp = -1;
        if (this.state.coreHp <= 0) this.state.isGameOver = true;
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        let minDist = tower.range;

        if (tower.type === 'AOE') {
           this.state.enemies.forEach(e => {
               const d = Math.sqrt((e.x - tower.x)**2 + (e.y - tower.y)**2);
               if (d < tower.range) targets.push(e);
           });
        } else {
            let nearest: (Enemy | Planet) | null = null;
            this.state.enemies.forEach(e => {
                const dist = Math.sqrt((e.x - tower.x)**2 + (e.y - tower.y)**2);
                if (dist < minDist) { minDist = dist; nearest = e; }
            });
            if (!nearest) {
                this.state.planets.filter(p => !p.isCaptured).forEach(p => {
                    const dist = Math.sqrt((p.x - tower.x)**2 + (p.y - tower.y)**2);
                    if (dist < minDist) { minDist = dist; nearest = p; }
                });
            }
            if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            target.hp -= tower.damage;
            this.state.experience += tower.damage * 0.15 * this.state.permanentUpgrades.xpMultiplier;
            if ('lastHit' in target) (target as Enemy).lastHit = now;
            if ('id' in target && target.hp <= 0 && target.hp > -100) this.processEnemyDeath(target as Enemy, false);
          });
          tower.lastFired = now;
        }
      }
    });

    this.state.enemies = this.state.enemies.filter(e => e.hp > 0);
    this.onUpdate({ ...this.state });
  }

  private spawnEnemyFromPlanet(source: Planet) {
    const angle = Math.random() * Math.PI * 2;
    const x = source.x + Math.cos(angle) * source.size * 0.4;
    const y = source.y + Math.sin(angle) * source.size * 0.4;
    this.createEnemyAt(x, y);
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3600 / this.cameraScale;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;
    this.createEnemyAt(x, y);
  }

  private createEnemyAt(x: number, y: number) {
    const scalingFactor = Math.pow(1.12, this.state.level);
    const hp = 100 * scalingFactor;
    this.state.enemies.push({
      id: Math.random().toString(36), x, y, hp, maxHp: hp,
      speed: 1.7 + (this.state.level * 0.05), value: 200 + this.state.level * 80,
      type: 'bug', size: 45 + (this.state.level * 0.8), angle: 0,
    });
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;

    this.ctx.save();
    this.ctx.translate(cx, cy);
    this.ctx.scale(this.cameraScale, this.cameraScale);
    this.ctx.translate(-cx, -cy);

    // Render Planets
    this.state.planets.forEach(p => {
      const grad = this.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size);
      grad.addColorStop(0, p.isCaptured ? '#0c4a6e' : '#450a0a');
      grad.addColorStop(0.9, '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = p.isCaptured ? COLORS.PRIMARY : COLORS.ENEMY; this.ctx.lineWidth = 15; this.ctx.globalAlpha = 0.2;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 25, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 50px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // Core
    const mfSize = 90 + (this.state.level * 0.6);
    const coreColor = this.state.threatLevel > 15 ? COLORS.ENEMY : COLORS.PRIMARY;
    this.ctx.fillStyle = coreColor; this.ctx.shadowBlur = 80; this.ctx.shadowColor = coreColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // Drops
    this.state.drops.forEach(d => {
        this.ctx.save();
        this.ctx.shadowBlur = 15;
        this.ctx.shadowColor = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
        this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : d.type === 'loc' ? COLORS.PRIMARY : COLORS.ACCENT;
        if (d.type === 'shard') {
            this.ctx.beginPath();
            this.ctx.moveTo(d.x, d.y - 12);
            this.ctx.lineTo(d.x + 12, d.y);
            this.ctx.lineTo(d.x, d.y + 12);
            this.ctx.lineTo(d.x - 12, d.y);
            this.ctx.closePath();
            this.ctx.fill();
        } else {
            this.ctx.fillRect(d.x - 10, d.y - 10, 20, 20);
        }
        this.ctx.restore();
    });

    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 8;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    this.state.enemies.forEach(e => {
      this.ctx.save(); this.ctx.translate(e.x, e.y); this.ctx.rotate(e.angle);
      this.ctx.fillStyle = Date.now() - (e.lastHit || 0) < 100 ? '#fff' : COLORS.ENEMY;
      this.ctx.beginPath(); this.ctx.moveTo(e.size, 0); this.ctx.lineTo(-e.size/2, e.size/2); this.ctx.lineTo(-e.size/2, -e.size/2); this.ctx.closePath();
      this.ctx.fill(); this.ctx.restore();
    });

    this.state.projectiles.forEach(p => {
        this.ctx.fillStyle = p.color;
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, 10, 0, Math.PI * 2); this.ctx.fill();
    });

    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color; this.ctx.fillRect(t.x-30, t.y-30, 60, 60);
      this.ctx.strokeStyle = t.color; this.ctx.lineWidth = 1; this.ctx.globalAlpha = 0.1;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    this.ctx.restore();

    if (this.state.isGameOver || this.state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.99)'; this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    }
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId) || TECH_TREE.find(s => s.id === skillId);
      if (!skillDef) return false;

      this.state.skillPoints -= skillDef.cost;

      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) {
          this.state.unlockedTech.push(skillId);
      } else {
          this.state.unlockedSkills.push(skillId);
      }

      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      if (skillId === 'code_gen') this.hasSaaS = true;

      onUnlock(this.state);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x, y, vx: (Math.random() - 0.5) * 2, vy: -5, size: 30, life: 1.0, color, text
    });
  }
}

import React, { useState, useRef } from 'react';
import { GameState, TechNode } from '../types';
import { ALL_SKILLS, TECH_TREE } from '../constants';
import { Cpu, X, Zap, Target, MousePointer2, Shield, Code, Award, Sparkles, RefreshCcw, LayoutGrid, Share2, ZoomIn, ZoomOut } from 'lucide-react';

interface Props {
  state: GameState;
  isOpen: boolean;
  onClose: () => void;
  onUpgrade: (skillId: string) => void;
  onReroll: () => void;
}

const SkillTree: React.FC<Props> = ({ state, isOpen, onClose, onUpgrade, onReroll }) => {
  const [activeTab, setActiveTab] = useState<'shop' | 'tree'>('tree');
  const scrollRef = useRef<HTMLDivElement>(null);

  if (!isOpen) return null;

  // Filter skills: only show if not oneTime or not already unlocked
  const currentShopSkills = ALL_SKILLS.filter(s => 
    state.availableSkills.includes(s.id) && 
    (!s.oneTime || !state.unlockedSkills.includes(s.id))
  );

  const getIcon = (id: string) => {
    if (id.includes('click')) return <MousePointer2 className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('range')) return <Target className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('dmg')) return <Zap className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('collect')) return <Cpu className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('code_gen')) return <Code className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('shield')) return <Shield className="w-5 h-5 sm:w-6 sm:h-6" />;
    return <Award className="w-5 h-5 sm:w-6 sm:h-6" />;
  };

  const isTechUnlocked = (id: string) => state.unlockedTech.includes(id);
  const canUnlockTech = (tech: TechNode) => {
    if (isTechUnlocked(tech.id)) return false;
    if (tech.dependsOn && !isTechUnlocked(tech.dependsOn)) return false;
    return state.skillPoints >= tech.cost;
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-2 sm:p-6 bg-slate-950/90 backdrop-blur-xl pointer-events-auto">
      <div className="bg-slate-900 border border-slate-700 rounded-3xl w-full max-w-5xl max-h-[90vh] flex flex-col overflow-hidden shadow-2xl relative">

        {/* Tabs */}
        <div className="flex bg-slate-800/50 p-1 rounded-t-3xl border-b border-slate-700">
          <button 
            onClick={() => setActiveTab('tree')}
            className={`flex-1 py-3 px-4 flex items-center justify-center gap-2 font-black uppercase text-xs sm:text-sm tracking-widest transition-all rounded-t-2xl
              ${activeTab === 'tree' ? 'bg-slate-900 text-sky-400 shadow-[0_-4px_0_0_#38bdf8]' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <Share2 size={16} /> Tech Stack
          </button>
          <button 
            onClick={() => setActiveTab('shop')}
            className={`flex-1 py-3 px-4 flex items-center justify-center gap-2 font-black uppercase text-xs sm:text-sm tracking-widest transition-all rounded-t-2xl
              ${activeTab === 'shop' ? 'bg-slate-900 text-pink-400 shadow-[0_-4px_0_0_#f472b6]' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <LayoutGrid size={16} /> Dependencies
          </button>
        </div>

        {/* Header */}
        <div className="p-4 sm:p-6 flex justify-between items-center bg-slate-900/50 flex-shrink-0">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-white italic leading-tight uppercase">
              {activeTab === 'tree' ? 'Global Infrastructure' : 'External Modules'}
            </h2>
            <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
              {state.skillPoints} Skill Points Available
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 transition-all border border-slate-700">
            <X size={20} />
          </button>
        </div>

        {/* Content Area */}
        <div ref={scrollRef} className="flex-grow overflow-auto p-4 sm:p-8 no-scrollbar bg-slate-950/30">

          {/* TECH TREE TAB */}
          {activeTab === 'tree' && (
            <div className="relative min-h-[700px] w-full min-w-[600px] flex justify-center">
              <svg className="absolute inset-0 w-full h-full pointer-events-none z-0">
                {TECH_TREE.map(node => {
                  if (!node.dependsOn) return null;
                  const parent = TECH_TREE.find(p => p.id === node.dependsOn);
                  if (!parent) return null;
                  const isLinkActive = isTechUnlocked(node.id);
                  const isLinkAvailable = isTechUnlocked(parent.id);
                  return (
                    <line
                      key={`${parent.id}-${node.id}`}
                      x1={`${parent.position.x}%`}
                      y1={`${parent.position.y}px`}
                      x2={`${node.position.x}%`}
                      y2={`${node.position.y}px`}
                      stroke={isLinkActive ? '#38bdf8' : isLinkAvailable ? '#334155' : '#0f172a'}
                      strokeWidth={isLinkActive ? "4" : "2"}
                      strokeDasharray={isLinkActive ? "0" : "5,5"}
                      className="transition-all duration-500"
                    />
                  );
                })}
              </svg>

              {TECH_TREE.map(node => {
                const unlocked = isTechUnlocked(node.id);
                const available = canUnlockTech(node);
                return (
                  <div
                    key={node.id}
                    className="absolute z-10 -translate-x-1/2 -translate-y-1/2"
                    style={{ left: `${node.position.x}%`, top: `${node.position.y}px` }}
                  >
                    <button
                      disabled={!available || unlocked}
                      onClick={() => onUpgrade(node.id)}
                      className={`
                        w-14 h-14 sm:w-20 sm:h-20 rounded-full border-2 flex flex-col items-center justify-center transition-all group relative
                        ${unlocked ? 'bg-sky-500 border-sky-300 shadow-[0_0_30px_rgba(56,189,248,0.4)]' : 
                          available ? 'bg-slate-800 border-slate-600 hover:border-sky-400 hover:scale-110' : 
                          'bg-slate-900 border-slate-800 opacity-40 cursor-not-allowed'}
                      `}
                    >
                      <Cpu size={unlocked ? 28 : 24} className={unlocked ? 'text-white' : 'text-slate-400'} />
                      <div className="absolute top-full mt-3 left-1/2 -translate-x-1/2 w-48 bg-slate-800 border border-slate-700 p-3 rounded-xl pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity z-20 shadow-2xl">
                        <div className="text-[11px] font-black text-sky-400 uppercase mb-1">{node.name}</div>
                        <div className="text-[10px] text-slate-300 leading-tight font-medium">{node.description}</div>
                        {!unlocked && <div className="mt-2 text-[9px] font-black text-amber-500">REQUIREMENT: {node.cost} SP</div>}
                        {unlocked && <div className="mt-2 text-[9px] font-black text-green-400">STATUS: DEPLOYED</div>}
                      </div>
                      {!unlocked && node.cost > 0 && (
                        <span className="absolute -top-1 -right-1 bg-amber-500 text-slate-900 text-[10px] font-black w-6 h-6 flex items-center justify-center rounded-full border-2 border-slate-900 shadow-lg">
                          {node.cost}
                        </span>
                      )}
                    </button>
                  </div>
                );
              })}
            </div>
          )}

          {/* SHOP TAB */}
          {activeTab === 'shop' && (
            <div className="flex flex-col gap-6">
              {currentShopSkills.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-slate-500">
                  <LayoutGrid size={48} className="mb-4 opacity-20" />
                  <div className="text-sm font-bold uppercase tracking-widest">No dependencies found</div>
                  <div className="text-xs opacity-60">Reroll to fetch new versions</div>
                </div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {currentShopSkills.map((skill) => (
                    <button
                      key={skill.id}
                      onClick={() => onUpgrade(skill.id)}
                      disabled={state.skillPoints < skill.cost}
                      className={`
                        text-left p-6 rounded-2xl border transition-all relative group flex flex-col justify-between h-52
                        ${state.skillPoints >= skill.cost 
                          ? 'border-slate-700 bg-slate-800/40 hover:border-pink-400 hover:-translate-y-2 active:scale-95 shadow-lg hover:shadow-pink-500/10' 
                          : 'border-slate-800 bg-slate-900/50 opacity-40 cursor-not-allowed'}
                      `}
                    >
                      <div>
                        <div className={`w-12 h-12 rounded-xl flex items-center justify-center mb-4 
                          ${skill.rarity === 'epic' ? 'bg-purple-500/20 text-purple-400' : 
                            skill.rarity === 'rare' ? 'bg-amber-500/20 text-amber-400' : 'bg-pink-500/20 text-pink-400'}`}>
                          {getIcon(skill.id)}
                        </div>
                        <h3 className="text-sm font-black text-white leading-tight mb-1 uppercase tracking-tight">{skill.name}</h3>
                        <p className="text-[11px] text-slate-400 leading-relaxed font-medium">{skill.description}</p>
                      </div>
                      <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-700/50">
                        <span className="text-[9px] font-black px-2 py-0.5 rounded uppercase tracking-tighter bg-slate-700 text-slate-300">
                          {skill.rarity}
                        </span>
                        <div className="font-black text-white text-xs uppercase flex items-center gap-1">
                          <Sparkles size={12} className="text-amber-400" /> {skill.cost} SP
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
              )}

              <div className="mt-8 flex flex-col items-center gap-4">
                <button
                  onClick={onReroll}
                  disabled={state.code < state.rerollCost}
                  className={`
                    flex items-center gap-3 px-8 py-4 rounded-2xl font-black uppercase text-[11px] tracking-[0.2em] transition-all shadow-2xl
                    ${state.code >= state.rerollCost
                      ? 'bg-slate-800 hover:bg-slate-700 border-2 border-slate-700 text-pink-400 hover:border-pink-500 shadow-pink-500/5'
                      : 'bg-slate-900/50 text-slate-700 cursor-not-allowed opacity-50 border-2 border-transparent'}
                  `}
                >
                  <RefreshCcw className="w-5 h-5" />
                  <span>Update Dependencies</span>
                  <span className="opacity-60">({state.rerollCost} LOC)</span>
                </button>
              </div>
            </div>
          )}
        </div>

        <div className="p-4 bg-slate-950/80 text-center text-[9px] text-slate-600 font-bold uppercase tracking-[0.4em] border-t border-slate-800 flex-shrink-0">
          Scaling infrastructure is the only path to Godhood.
        </div>
      </div>
    </div>
  );
};

