import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades, Planet, Projectile } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const COMBO_TIMEOUT = 2500; 
const THREAT_DECAY = 0.05; 
const PLANET_COUNT = 4;
const ALLIED_ARROW_SPEED = 20;
const MAX_ENEMIES_ON_SCREEN = 60;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private planetAttackTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private hasSaaS: boolean = false;
  private hasPassiveIncome: boolean = false;
  private comboTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`,
        name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false,
        size: 350,
        color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 1200,
      experience: 0,
      level: 1,
      skillPoints: 2,
      spProgress: 0,
      spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35,
      towers: [],
      enemies: [],
      particles: [],
      ripples: [],
      drops: [],
      planets: [],
      projectiles: [],
      isGameOver: false,
      isVictory: false,
      lastRunCode: 0,
      availableSkills: [],
      unlockedTech: ['root'],
      unlockedSkills: [],
      rerollCost: BASE_REROLL_COST,
      combo: 0,
      threatLevel: 0.5,
      coreHp: 250,
      maxCoreHp: 250,
      permanentUpgrades: {
        startingCode: 0,
        damageMultiplier: 1.0,
        xpMultiplier: 1.0,
        legacyPoints: 0,
      }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 25 : 1;
    const earnedLegacy = (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;

    this.cameraScale = 1.0;
    this.targetCameraScale = 1.0;
    this.generatePlanets();
    this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    // Filter out skills that are one-time and already unlocked
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const now = Date.now();
    let hitSomething = false;

    // 1. Check for item collection by clicking
    const dropCollectionRadius = 50 / this.cameraScale;
    let itemsCollected = 0;
    this.state.drops = this.state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX)**2 + (d.y - worldY)**2);
      if (dist < dropCollectionRadius) {
        this.collectDropItem(d);
        itemsCollected++;
        hitSomething = true;
        return false;
      }
      return true;
    });

    if (itemsCollected > 0) {
      this.onUpdate({ ...this.state });
      // If we clicked items, we don't also fire a splash damage click usually, 
      // but let's allow it for better feel.
    }

    // 2. Click damage
    const splashRadius = 120 + (this.state.level * 4);
    this.state.enemies.forEach(enemy => {
      const dx = enemy.x - worldX;
      const dy = enemy.y - worldY;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= this.state.clickPower * damageMult;
        enemy.lastHit = now;

        if (damageMult > 0.75) {
          hitSomething = true;
          this.createParticles(enemy.x, enemy.y, 4, COLORS.PRIMARY);
        }

        if (enemy.hp <= 0) {
          this.processEnemyDeath(enemy, true);
        }
      }
    });

    if (!hitSomething) {
      this.state.code += 25;
      this.createFloatingText(worldX, worldY, "+25", COLORS.PRIMARY);
    }

    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: splashRadius, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private collectDropItem(d: LibraryDrop) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    if (d.type === 'shard') {
      this.state.spProgress += 1;
      if (this.state.spProgress >= this.state.spGoal) {
        this.state.skillPoints += 1;
        this.state.spProgress = 0;
        this.state.spGoal = Math.floor(this.state.spGoal * 1.1) + 2;
        this.createFloatingText(cx, cy, "+1 SKILL POINT", COLORS.SECONDARY);
      }
    } else if (d.type === 'loc') {
      const gain = 500 + (this.state.level * 100);
      this.state.code += gain;
      this.createFloatingText(d.x, d.y, `+${gain}`, COLORS.PRIMARY);
    }
    this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
  }

  private processEnemyDeath(enemy: Enemy, isManual: boolean) {
    this.state.combo++;
    this.comboTimer = COMBO_TIMEOUT;

    // Scaling rewards
    let rewardMult = (1 + this.state.threatLevel * 0.15) * this.state.permanentUpgrades.xpMultiplier;
    if (this.state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (this.state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    const locValue = Math.floor(enemy.value * rewardMult);
    const xpValue = (enemy.value / 2) * rewardMult;

    this.state.experience += xpValue;
    this.state.code += locValue;

    this.spawnDrop(enemy.x, enemy.y, isManual);
    this.checkLevelUp();
    enemy.hp = -999;
  }

  private spawnDrop(x: number, y: number, isManual: boolean) {
    const rand = Math.random();
    let shardChance = isManual ? 0.4 : 0.2;
    if (this.state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    if (rand < shardChance) {
        this.state.drops.push({
            id: Math.random().toString(36),
            name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP Progress', x, y, life: 1.0
        });
    } 
    else if (rand < 0.5) {
        this.state.drops.push({
            id: Math.random().toString(36),
            name: 'Data', type: 'loc', rarity: 'common', effect: 'LOC Boost', x, y, life: 1.0
        });
    }
    else if (rand > 0.96) {
        const lib = LIBRARIES[Math.floor(Math.random() * LIBRARIES.length)];
        this.state.drops.push({
            id: Math.random().toString(36),
            name: lib.name, type: 'library', rarity: lib.rarity, effect: lib.effect, x, y, life: 1.0
        });
    }
  }

  private checkLevelUp() {
    const nextLevelExp = 200 + (this.state.level * 250);

    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.clickPower *= 1.15;

      // USER REQUEST: Give a full skill point per level
      this.state.skillPoints += 1;
      this.createFloatingText(this.canvas.width / 2, this.canvas.height / 2 - 80, "+1 SKILL POINT (LEVEL UP)", COLORS.SECONDARY);

      if (this.state.level % 5 === 0) {
        this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
        this.state.maxCoreHp += 500;
        this.state.coreHp = this.state.maxCoreHp;
      }

      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const config = TOWER_TYPES[type];
    const towerCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, towerCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let damage = config.damage * this.state.permanentUpgrades.damageMultiplier;
      let range = config.range;
      let fireRate = config.fireRate;

      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36),
        type, level: 1, x: worldX, y: worldY,
        range: range,
        damage: damage,
        fireRate: fireRate,
        lastFired: 0,
        color: config.color,
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({
        x, y, vx: (Math.random() - 0.5) * 10, vy: (Math.random() - 0.5) * 10,
        size: Math.random() * 5 + 2, life: 1.0, color,
      });
    }
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.update(dt);
    this.draw();
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;
    this.state.threatLevel = Math.max(0.5, this.state.threatLevel - (THREAT_DECAY * dt / 1000));

    if (this.comboTimer > 0) {
      this.comboTimer -= dt;
      if (this.comboTimer <= 0) this.state.combo = 0;
    }

    // Tech Passive
    if (this.state.unlockedTech.includes('tech_passive')) {
        this.passiveCodeTimer += dt;
        if (this.passiveCodeTimer > 1000) {
            this.state.code += this.state.level * 250;
            this.passiveCodeTimer = 0;
        }
    }

    this.planetAttackTimer += dt;
    if (this.planetAttackTimer > 1000) {
      this.state.planets.filter(p => p.isCaptured).forEach(planet => {
        const target = this.state.planets.find(p => !p.isCaptured);
        if (target) {
          this.state.projectiles.push({
            id: Math.random().toString(36), targetId: target.id, x: planet.x, y: planet.y,
            speed: ALLIED_ARROW_SPEED, damage: 300 + (this.state.level * 30),
            color: COLORS.PRIMARY, type: 'allied'
          });
        }
      });
      this.planetAttackTimer = 0;
    }

    this.state.projectiles = this.state.projectiles.filter(proj => {
      const target = this.state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x; const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        this.createParticles(proj.x, proj.y, 8, proj.color);
        if (target.hp <= 0 && !target.isCaptured) {
           target.isCaptured = true; target.color = COLORS.PRIMARY; target.hp = 0;
           this.state.experience += 2500;
           this.checkLevelUp();
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed; proj.y += (dy / dist) * proj.speed;
      return true;
    });

    if (this.state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = this.state.enemies[Math.floor(Math.random() * this.state.enemies.length)];
      const e2 = this.state.enemies[Math.floor(Math.random() * this.state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id) {
          e1.hp += e2.hp; e1.maxHp += e2.maxHp; e1.size = Math.min(150, e1.size + 15);
          e1.value += e2.value; e2.hp = -999;
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      if (source) this.spawnEnemyFromPlanet(source);
      else this.spawnEnemy();
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => {
      p.x += p.vx; p.y += p.vy;
      p.life -= p.text ? 0.02 : 0.07;
      return p.life > 0;
    });
    this.state.ripples = this.state.ripples.filter(r => {
      r.radius += 15; r.life -= 0.1;
      return r.life > 0;
    });

    // Handle Drops Collection
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    this.state.drops = this.state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x; const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const vacuumRadius = (this.hasAutoCollect ? 1500 : 0) / this.cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / this.cameraScale) {
        this.collectDropItem(d);
        return false;
      }

      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    this.state.enemies.forEach(enemy => {
      const dx = cx - enemy.x; const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        this.state.coreHp -= 25 + (this.state.level * 2);
        this.createParticles(enemy.x, enemy.y, 10, COLORS.ENEMY);
        enemy.hp = -1;
        if (this.state.coreHp <= 0) this.state.isGameOver = true;
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        let minDist = tower.range;

        if (tower.type === 'AOE') {
           this.state.enemies.forEach(e => {
               const d = Math.sqrt((e.x - tower.x)**2 + (e.y - tower.y)**2);
               if (d < tower.range) targets.push(e);
           });
        } else {
            let nearest: (Enemy | Planet) | null = null;
            this.state.enemies.forEach(e => {
                const dist = Math.sqrt((e.x - tower.x)**2 + (e.y - tower.y)**2);
                if (dist < minDist) { minDist = dist; nearest = e; }
            });
            if (!nearest) {
                this.state.planets.filter(p => !p.isCaptured).forEach(p => {
                    const dist = Math.sqrt((p.x - tower.x)**2 + (p.y - tower.y)**2);
                    if (dist < minDist) { minDist = dist; nearest = p; }
                });
            }
            if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            target.hp -= tower.damage;
            this.state.experience += tower.damage * 0.15 * this.state.permanentUpgrades.xpMultiplier;
            if ('lastHit' in target) (target as Enemy).lastHit = now;
            if ('id' in target && target.hp <= 0 && target.hp > -100) this.processEnemyDeath(target as Enemy, false);
          });
          tower.lastFired = now;
        }
      }
    });

    this.state.enemies = this.state.enemies.filter(e => e.hp > 0);
    this.onUpdate({ ...this.state });
  }

  private spawnEnemyFromPlanet(source: Planet) {
    const angle = Math.random() * Math.PI * 2;
    const x = source.x + Math.cos(angle) * source.size * 0.4;
    const y = source.y + Math.sin(angle) * source.size * 0.4;
    this.createEnemyAt(x, y);
  }

  private spawnEnemy() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3600 / this.cameraScale;
    const x = this.canvas.width / 2 + Math.cos(angle) * dist;
    const y = this.canvas.height / 2 + Math.sin(angle) * dist;
    this.createEnemyAt(x, y);
  }

  private createEnemyAt(x: number, y: number) {
    const scalingFactor = Math.pow(1.12, this.state.level);
    const hp = 100 * scalingFactor;
    this.state.enemies.push({
      id: Math.random().toString(36), x, y, hp, maxHp: hp,
      speed: 1.7 + (this.state.level * 0.05), value: 200 + this.state.level * 80,
      type: 'bug', size: 45 + (this.state.level * 0.8), angle: 0,
    });
  }

  private draw() {
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;

    this.ctx.save();
    this.ctx.translate(cx, cy);
    this.ctx.scale(this.cameraScale, this.cameraScale);
    this.ctx.translate(-cx, -cy);

    // Render Planets
    this.state.planets.forEach(p => {
      const grad = this.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size);
      grad.addColorStop(0, p.isCaptured ? '#0c4a6e' : '#450a0a');
      grad.addColorStop(0.9, '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = p.isCaptured ? COLORS.PRIMARY : COLORS.ENEMY; this.ctx.lineWidth = 15; this.ctx.globalAlpha = 0.2;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 25, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 50px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // Core
    const mfSize = 90 + (this.state.level * 0.6);
    const coreColor = this.state.threatLevel > 15 ? COLORS.ENEMY : COLORS.PRIMARY;
    this.ctx.fillStyle = coreColor; this.ctx.shadowBlur = 80; this.ctx.shadowColor = coreColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, mfSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // Drops
    this.state.drops.forEach(d => {
        this.ctx.save();
        this.ctx.shadowBlur = 15;
        this.ctx.shadowColor = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
        this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : d.type === 'loc' ? COLORS.PRIMARY : COLORS.ACCENT;
        if (d.type === 'shard') {
            this.ctx.beginPath();
            this.ctx.moveTo(d.x, d.y - 12);
            this.ctx.lineTo(d.x + 12, d.y);
            this.ctx.lineTo(d.x, d.y + 12);
            this.ctx.lineTo(d.x - 12, d.y);
            this.ctx.closePath();
            this.ctx.fill();
        } else {
            this.ctx.fillRect(d.x - 10, d.y - 10, 20, 20);
        }
        this.ctx.restore();
    });

    this.state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 8;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    this.state.enemies.forEach(e => {
      this.ctx.save(); this.ctx.translate(e.x, e.y); this.ctx.rotate(e.angle);
      this.ctx.fillStyle = Date.now() - (e.lastHit || 0) < 100 ? '#fff' : COLORS.ENEMY;
      this.ctx.beginPath(); this.ctx.moveTo(e.size, 0); this.ctx.lineTo(-e.size/2, e.size/2); this.ctx.lineTo(-e.size/2, -e.size/2); this.ctx.closePath();
      this.ctx.fill(); this.ctx.restore();
    });

    this.state.projectiles.forEach(p => {
        this.ctx.fillStyle = p.color;
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, 10, 0, Math.PI * 2); this.ctx.fill();
    });

    this.state.towers.forEach(t => {
      this.ctx.fillStyle = t.color; this.ctx.fillRect(t.x-30, t.y-30, 60, 60);
      this.ctx.strokeStyle = t.color; this.ctx.lineWidth = 1; this.ctx.globalAlpha = 0.1;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    this.ctx.restore();

    if (this.state.isGameOver || this.state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.99)'; this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    }
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId) || TECH_TREE.find(s => s.id === skillId);
      if (!skillDef) return false;

      this.state.skillPoints -= skillDef.cost;

      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) {
          this.state.unlockedTech.push(skillId);
      } else {
          this.state.unlockedSkills.push(skillId);
      }

      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      if (skillId === 'code_gen') this.hasSaaS = true;

      onUnlock(this.state);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({
      x, y, vx: (Math.random() - 0.5) * 2, vy: -5, size: 30, life: 1.0, color, text
    });
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';

const COMBO_TIMEOUT = 2500;
const THREAT_DECAY = 0.05;
const ALLIED_ARROW_SPEED = 20;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(state: GameState, dt: number, cameraScale: number, hasAutoCollect: boolean): void {
    if (state.isGameOver || state.isVictory) return;

    // 1. Threat Decay
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 2. Combo Timer
    if (state.combo > 0) {
      // Logic for combo decay could be added here if we had a dedicated timer in state
    }

    // 3. Tech Passives
    if (state.unlockedTech.includes('tech_passive')) {
      // Handled via a timer in the main loop or here if we track time
      // For simplicity, keeping specific high-frequency state updates in GameEngine
    }

    // 4. Planet Combat (Projectiles)
    state.projectiles = state.projectiles.filter(proj => {
      const target = state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x;
      const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        if (target.hp <= 0 && !target.isCaptured) {
          target.isCaptured = true;
          target.color = COLORS.PRIMARY;
          target.hp = 0;
          state.experience += 2500;
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 5. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 6. Drops & Collection
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 1500 : 0) / cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / cameraScale) {
        LogicHandler.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 7. Enemy Movement
    state.enemies.forEach(enemy => {
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        state.coreHp -= 25 + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) state.isGameOver = true;
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // 8. Tower Combat logic is high-frequency and tightly coupled with animations,
    // we'll keep the orchestrator handling the "Firing" event to trigger visuals.
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 2;
      }
    } else if (d.type === 'loc') {
      state.code += 500 + (state.level * 100);
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    state.experience += (enemy.value / 2) * rewardMult;
    state.code += Math.floor(enemy.value * rewardMult);
    enemy.hp = -999;
  }
}

import { GameState, COLORS } from '../types';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
  }

  public draw(state: GameState, cameraScale: number) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();
    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. Planets
    state.planets.forEach(p => {
      const grad = this.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size);
      grad.addColorStop(0, p.isCaptured ? '#0c4a6e' : '#450a0a');
      grad.addColorStop(0.9, '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = p.isCaptured ? COLORS.PRIMARY : COLORS.ENEMY;
      this.ctx.lineWidth = 15; this.ctx.globalAlpha = 0.2;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 25, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 50px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // 2. Firing Effects (Animations)
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.save();
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = ef.type === 'SNIPER' ? 4 * ef.life : 2;

      if (ef.type === 'SNIPER') {
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
      } else if (ef.type === 'RAPID') {
        this.ctx.fillStyle = ef.color;
        this.ctx.beginPath();
        this.ctx.arc(ef.x1 + (ef.x2-ef.x1)*0.1, ef.y1 + (ef.y2-ef.y1)*0.1, 15 * ef.life, 0, Math.PI*2);
        this.ctx.fill();
      } else if (ef.type === 'AOE') {
        this.ctx.beginPath();
        this.ctx.arc(ef.x1, ef.y1, (1-ef.life) * 300, 0, Math.PI*2);
        this.ctx.stroke();
      } else {
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
      }

      this.ctx.restore();
      ef.life -= 0.1;
      return ef.life > 0;
    });

    // 3. Core
    const coreSize = 90 + (state.level * 0.6);
    this.ctx.fillStyle = state.threatLevel > 15 ? COLORS.ENEMY : COLORS.PRIMARY;
    this.ctx.shadowBlur = 80; this.ctx.shadowColor = this.ctx.fillStyle as string;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 4. Drops
    state.drops.forEach(d => {
      this.ctx.save();
      this.ctx.shadowBlur = 15;
      this.ctx.shadowColor = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : d.type === 'loc' ? COLORS.PRIMARY : COLORS.ACCENT;
      if (d.type === 'shard') {
        this.ctx.beginPath();
        this.ctx.moveTo(d.x, d.y - 12); this.ctx.lineTo(d.x + 12, d.y);
        this.ctx.lineTo(d.x, d.y + 12); this.ctx.lineTo(d.x - 12, d.y);
        this.ctx.closePath(); this.ctx.fill();
      } else {
        this.ctx.fillRect(d.x - 10, d.y - 10, 20, 20);
      }
      this.ctx.restore();
    });

    // 5. Ripples
    state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 8;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    // 6. Enemies (with hit animation)
    state.enemies.forEach(e => {
      const isHit = Date.now() - (e.lastHit || 0) < 100;
      const scale = isHit ? 1.2 : 1.0;
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);
      this.ctx.scale(scale, scale);
      this.ctx.fillStyle = isHit ? '#fff' : COLORS.ENEMY;
      this.ctx.beginPath();
      this.ctx.moveTo(e.size, 0);
      this.ctx.lineTo(-e.size / 2, e.size / 2);
      this.ctx.lineTo(-e.size / 2, -e.size / 2);
      this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();
    });

    // 7. Projectiles
    state.projectiles.forEach(p => {
      this.ctx.fillStyle = p.color;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, 10, 0, Math.PI * 2); this.ctx.fill();
    });

    // 8. Towers
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);
      this.ctx.strokeStyle = t.color; this.ctx.lineWidth = 1; this.ctx.globalAlpha = 0.1;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // 9. Particles & Floating Text
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${p.size}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      }
      this.ctx.globalAlpha = 1.0;
    });

    this.ctx.restore();

    if (state.isGameOver || state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.95)';
      this.ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
  }
}

import { GameState, Enemy, Tower, Particle, ClickRipple, LibraryDrop, PermanentUpgrades, Planet, Projectile } from '../types';
import { COLORS, LIBRARIES, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const COMBO_TIMEOUT = 2500; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private planetAttackTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 25 : 1;
    const earnedLegacy = (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const now = Date.now();
    let hitSomething = false;

    // Collection by clicking
    const dropCollectionRadius = 50 / this.cameraScale;
    this.state.drops = this.state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX)**2 + (d.y - worldY)**2);
      if (dist < dropCollectionRadius) {
        LogicHandler.collectDrop(this.state, d);
        hitSomething = true;
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        return false;
      }
      return true;
    });

    // Click damage
    const splashRadius = 120 + (this.state.level * 4);
    this.state.enemies.forEach(enemy => {
      const dist = Math.sqrt((enemy.x - worldX)**2 + (enemy.y - worldY)**2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= this.state.clickPower * damageMult;
        enemy.lastHit = now;
        if (damageMult > 0.75) {
          hitSomething = true;
          this.createParticles(enemy.x, enemy.y, 4, COLORS.PRIMARY);
        }
        if (enemy.hp <= 0) {
          LogicHandler.processEnemyDeath(this.state, enemy, true);
          this.spawnDrop(enemy.x, enemy.y, true);
          this.checkLevelUp();
        }
      }
    });

    if (!hitSomething) {
      this.state.code += 25;
      this.createFloatingText(worldX, worldY, "+25", COLORS.PRIMARY);
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: splashRadius, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private checkLevelUp() {
    const nextLevelExp = 200 + (this.state.level * 250);
    if (this.state.experience >= nextLevelExp) {
      this.state.level++;
      this.state.experience -= nextLevelExp;
      this.state.clickPower *= 1.15;
      this.state.skillPoints += 1;
      this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
      if (this.state.level % 5 === 0) {
        this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
        this.state.maxCoreHp += 500; this.state.coreHp = this.state.maxCoreHp;
      }
      this.refreshSkillShop();
    }
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const towerCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, towerCount));
    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let damage = config.damage * this.state.permanentUpgrades.damageMultiplier;
      let range = config.range; let fireRate = config.fireRate;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private spawnDrop(x: number, y: number, isManual: boolean) {
    const rand = Math.random();
    let shardChance = isManual ? 0.4 : 0.2;
    if (this.state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;
    if (rand < shardChance) {
      this.state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP', x, y, life: 1.0 });
    } else if (rand < 0.5) {
      this.state.drops.push({ id: Math.random().toString(36), name: 'Data', type: 'loc', rarity: 'common', effect: 'LOC', x, y, life: 1.0 });
    }
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.update(dt);
    this.renderer.draw(this.state, this.cameraScale);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    // Logic updates
    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect);

    // Tech Passive
    if (this.state.unlockedTech.includes('tech_passive')) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { this.state.code += this.state.level * 250; this.passiveCodeTimer = 0; }
    }

    // Spawn Logic
    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999);
      this.enemySpawnTimer = 0;
    }

    // High frequency physics & Tower firing (requires triggering renderer effects)
    const now = Date.now();
    this.state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          this.state.enemies.forEach(e => { if (Math.sqrt((e.x-tower.x)**2+(e.y-tower.y)**2) < tower.range) targets.push(e); });
        } else {
          let minDist = tower.range; let nearest: (Enemy | Planet) | null = null;
          this.state.enemies.forEach(e => {
            const dist = Math.sqrt((e.x-tower.x)**2+(e.y-tower.y)**2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            this.state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x-tower.x)**2+(p.y-tower.y)**2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            target.hp -= tower.damage;
            this.state.experience += tower.damage * 0.15 * this.state.permanentUpgrades.xpMultiplier;
            if ('lastHit' in target) (target as Enemy).lastHit = now;
            this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
            if ('id' in target && target.hp <= 0 && target.hp > -100) {
              LogicHandler.processEnemyDeath(this.state, target as Enemy, false);
              this.spawnDrop(target.x, target.y, false);
              this.checkLevelUp();
            }
          });
          tower.lastFired = now;
        }
      }
    });

    // Particle/Ripple life updates (simple)
    this.state.particles = this.state.particles.filter(p => { p.x += p.vx; p.y += p.vy; p.life -= p.text ? 0.02 : 0.07; return p.life > 0; });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });
    this.state.enemies = this.state.enemies.filter(e => e.hp > 0);
    this.onUpdate({ ...this.state });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }
    const hp = 100 * Math.pow(1.12, this.state.level);
    this.state.enemies.push({ id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.7 + (this.state.level * 0.05), value: 200 + this.state.level * 80, type: 'bug', size: 45 + (this.state.level * 0.8), angle: 0 });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId) || TECH_TREE.find(s => s.id === skillId);
      if (!skillDef) return false;
      this.state.skillPoints -= skillDef.cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else this.state.unlockedSkills.push(skillId);
      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      onUnlock(this.state); this.refreshSkillShop(); this.onUpdate({ ...this.state }); return true;
    }
    return false;
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    // 1. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 2. Projectiles (Allied arrows between planets)
    state.projectiles = state.projectiles.filter(proj => {
      const target = state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x;
      const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        if (target.hp <= 0 && !target.isCaptured) {
          target.isCaptured = true;
          target.color = COLORS.PRIMARY;
          target.hp = 0;
          state.experience += 2500;
          this.checkLevelUp(state, onLevelUp);
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 3. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 4. Drops & Collection
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 1500 : 0) / cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 5. Enemy Movement & Core Damage
    state.enemies.forEach(enemy => {
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        state.coreHp -= 25 + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) state.isGameOver = true;
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    let hitSomething = false;
    const now = Date.now();

    // Collect items
    const dropCollectionRadius = 50 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    // Damage enemies
    const splashRadius = 120 + (state.level * 4);
    state.enemies.forEach(enemy => {
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        if (damageMult > 0.75) {
          hitSomething = true;
          onEnemyHit(enemy);
        }
        if (enemy.hp <= 0) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Point) => void,
    onLevelUp: () => void
  ): void {
    const now = Date.now();
    state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            target.hp -= tower.damage;
            state.experience += tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier;
            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);
            if ('id' in target && target.hp <= 0 && target.hp > -100) {
              this.processEnemyDeath(state, target as Enemy, false);
              this.checkLevelUp(state, onLevelUp);
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 2;
      }
    } else if (d.type === 'loc') {
      state.code += 500 + (state.level * 100);
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    state.experience += (enemy.value / 2) * rewardMult;
    state.code += Math.floor(enemy.value * rewardMult);
    enemy.hp = -999; // Flag for deletion
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

import { GameState, COLORS } from '../types';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  public draw(state: GameState, cameraScale: number) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();

    // Screen Shake
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.9;
      if (this.screenShake < 0.1) this.screenShake = 0;
    }

    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. Planets
    state.planets.forEach(p => {
      const grad = this.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size);
      grad.addColorStop(0, p.isCaptured ? '#0c4a6e' : '#450a0a');
      grad.addColorStop(0.9, '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = p.isCaptured ? COLORS.PRIMARY : COLORS.ENEMY;
      this.ctx.lineWidth = 15; this.ctx.globalAlpha = 0.2;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 25, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 50px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // 2. Firing Effects
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.save();
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.shadowBlur = 15;
      this.ctx.shadowColor = ef.color;

      if (ef.type === 'SNIPER') {
        this.ctx.lineWidth = 6 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
        // Inner white beam
        this.ctx.strokeStyle = '#fff';
        this.ctx.lineWidth = 2 * ef.life;
        this.ctx.stroke();
      } else if (ef.type === 'RAPID') {
        this.ctx.lineWidth = 2;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
        this.ctx.fillStyle = ef.color;
        this.ctx.beginPath();
        this.ctx.arc(ef.x2, ef.y2, 10 * (1 - ef.life), 0, Math.PI * 2);
        this.ctx.fill();
      } else if (ef.type === 'AOE') {
        this.ctx.lineWidth = 8 * ef.life;
        this.ctx.beginPath();
        this.ctx.arc(ef.x1, ef.y1, (1 - ef.life) * 400, 0, Math.PI * 2);
        this.ctx.stroke();
      } else {
        this.ctx.lineWidth = 3 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
      }

      this.ctx.restore();
      ef.life -= 0.12;
      return ef.life > 0;
    });

    // 3. Core
    const coreSize = 90 + (state.level * 0.6);
    this.ctx.fillStyle = state.threatLevel > 15 ? COLORS.ENEMY : COLORS.PRIMARY;
    this.ctx.shadowBlur = 80; this.ctx.shadowColor = this.ctx.fillStyle as string;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 4. Drops
    state.drops.forEach(d => {
      this.ctx.save();
      this.ctx.shadowBlur = 15;
      this.ctx.shadowColor = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : d.type === 'loc' ? COLORS.PRIMARY : COLORS.ACCENT;
      if (d.type === 'shard') {
        this.ctx.beginPath();
        this.ctx.moveTo(d.x, d.y - 12); this.ctx.lineTo(d.x + 12, d.y);
        this.ctx.lineTo(d.x, d.y + 12); this.ctx.lineTo(d.x - 12, d.y);
        this.ctx.closePath(); this.ctx.fill();
      } else {
        this.ctx.fillRect(d.x - 10, d.y - 10, 20, 20);
      }
      this.ctx.restore();
    });

    // 5. Ripples
    state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 8;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    // 6. Enemies (with hit animation)
    state.enemies.forEach(e => {
      const isHit = Date.now() - (e.lastHit || 0) < 100;
      const scale = isHit ? 1.3 : 1.0;
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);
      this.ctx.scale(scale, scale);
      this.ctx.fillStyle = isHit ? '#fff' : COLORS.ENEMY;
      this.ctx.beginPath();
      this.ctx.moveTo(e.size, 0);
      this.ctx.lineTo(-e.size / 2, e.size / 2);
      this.ctx.lineTo(-e.size / 2, -e.size / 2);
      this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();
    });

    // 7. Projectiles
    state.projectiles.forEach(p => {
      this.ctx.fillStyle = p.color;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, 10, 0, Math.PI * 2); this.ctx.fill();
    });

    // 8. Towers
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);
      this.ctx.strokeStyle = t.color; this.ctx.lineWidth = 1; this.ctx.globalAlpha = 0.1;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // 9. Particles & Floating Text
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${p.size}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      }
      this.ctx.globalAlpha = 1.0;
    });

    this.ctx.restore();

    if (state.isGameOver || state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.95)';
      this.ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 25 : 1;
    const earnedLegacy = (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY),
      (e) => this.createParticles(e.x, e.y, 4, COLORS.PRIMARY),
      () => this.onLevelUp()
    );

    if (!hit) {
      this.state.code += 25;
      this.createFloatingText(worldX, worldY, "+25", COLORS.PRIMARY);
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const towerCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, towerCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.update(dt);
    this.renderer.draw(this.state, this.cameraScale);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    // Logic updates
    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
      },
      () => this.onLevelUp()
    );

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    // Passives
    if (this.state.unlockedTech.includes('tech_passive')) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { this.state.code += this.state.level * 250; this.passiveCodeTimer = 0; }
    }

    // Spawn Enemies
    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999);
      this.enemySpawnTimer = 0;
    }

    // Particles life
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }
    const hp = 100 * Math.pow(1.12, this.state.level);
    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 1.7 + (this.state.level * 0.05), value: 200 + this.state.level * 80, 
      type: 'bug', size: 45 + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId) || [];
      // Simplified: usually would fetch from constants, assuming passed handler does specific work
      this.state.skillPoints -= 1; // Basic cost
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else this.state.unlockedSkills.push(skillId);
      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      onUnlock(this.state); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

import { GameState } from '../types';
// Fix: Import COLORS from constants instead of types
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  public draw(state: GameState, cameraScale: number) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();

    // Screen Shake
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.9;
      if (this.screenShake < 0.1) this.screenShake = 0;
    }

    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. Planets
    state.planets.forEach(p => {
      const grad = this.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size);
      grad.addColorStop(0, p.isCaptured ? '#0c4a6e' : '#450a0a');
      grad.addColorStop(0.9, '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = p.isCaptured ? COLORS.PRIMARY : COLORS.ENEMY;
      this.ctx.lineWidth = 15; this.ctx.globalAlpha = 0.2;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 25, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 50px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // 2. Firing Effects
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.save();
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.shadowBlur = 15;
      this.ctx.shadowColor = ef.color;

      if (ef.type === 'SNIPER') {
        this.ctx.lineWidth = 6 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
        // Inner white beam
        this.ctx.strokeStyle = '#fff';
        this.ctx.lineWidth = 2 * ef.life;
        this.ctx.stroke();
      } else if (ef.type === 'RAPID') {
        this.ctx.lineWidth = 2;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
        this.ctx.fillStyle = ef.color;
        this.ctx.beginPath();
        this.ctx.arc(ef.x2, ef.y2, 10 * (1 - ef.life), 0, Math.PI * 2);
        this.ctx.fill();
      } else if (ef.type === 'AOE') {
        this.ctx.lineWidth = 8 * ef.life;
        this.ctx.beginPath();
        this.ctx.arc(ef.x1, ef.y1, (1 - ef.life) * 400, 0, Math.PI * 2);
        this.ctx.stroke();
      } else {
        this.ctx.lineWidth = 3 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
      }

      this.ctx.restore();
      ef.life -= 0.12;
      return ef.life > 0;
    });

    // 3. Core
    const coreSize = 90 + (state.level * 0.6);
    this.ctx.fillStyle = state.threatLevel > 15 ? COLORS.ENEMY : COLORS.PRIMARY;
    this.ctx.shadowBlur = 80; this.ctx.shadowColor = this.ctx.fillStyle as string;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 4. Drops
    state.drops.forEach(d => {
      this.ctx.save();
      this.ctx.shadowBlur = 15;
      this.ctx.shadowColor = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : d.type === 'loc' ? COLORS.PRIMARY : COLORS.ACCENT;
      if (d.type === 'shard') {
        this.ctx.beginPath();
        this.ctx.moveTo(d.x, d.y - 12); this.ctx.lineTo(d.x + 12, d.y);
        this.ctx.lineTo(d.x, d.y + 12); this.ctx.lineTo(d.x - 12, d.y);
        this.ctx.closePath(); this.ctx.fill();
      } else {
        this.ctx.fillRect(d.x - 10, d.y - 10, 20, 20);
      }
      this.ctx.restore();
    });

    // 5. Ripples
    state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 8;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    // 6. Enemies (with hit animation)
    state.enemies.forEach(e => {
      const isHit = Date.now() - (e.lastHit || 0) < 100;
      const scale = isHit ? 1.3 : 1.0;
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);
      this.ctx.scale(scale, scale);
      this.ctx.fillStyle = isHit ? '#fff' : COLORS.ENEMY;
      this.ctx.beginPath();
      this.ctx.moveTo(e.size, 0);
      this.ctx.lineTo(-e.size / 2, e.size / 2);
      this.ctx.lineTo(-e.size / 2, -e.size / 2);
      this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();
    });

    // 7. Projectiles
    state.projectiles.forEach(p => {
      this.ctx.fillStyle = p.color;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, 10, 0, Math.PI * 2); this.ctx.fill();
    });

    // 8. Towers
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);
      this.ctx.strokeStyle = t.color; this.ctx.lineWidth = 1; this.ctx.globalAlpha = 0.1;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // 9. Particles & Floating Text
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${p.size}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      }
      this.ctx.globalAlpha = 1.0;
    });

    this.ctx.restore();

    if (state.isGameOver || state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.95)';
      this.ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;
const TICK_RATE_MS = 1000;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    // 1. Base Passive Trickle (Prevents total soft-locks)
    state.code += (5 + state.level) * (dt / 1000);

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied arrows between planets)
    state.projectiles = state.projectiles.filter(proj => {
      const target = state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x;
      const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        // Reward LOC for planet damage too
        state.code += proj.damage * 0.05; 

        if (target.hp <= 0 && !target.isCaptured) {
          target.isCaptured = true;
          target.color = COLORS.PRIMARY;
          target.hp = 0;
          state.experience += 2500;
          this.checkLevelUp(state, onLevelUp);
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 1500 : 0) / cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Core Damage
    state.enemies.forEach(enemy => {
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        state.coreHp -= 25 + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) state.isGameOver = true;
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    let hitSomething = false;
    const now = Date.now();

    // Collect items
    const dropCollectionRadius = 50 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    // Damage enemies
    const splashRadius = 120 + (state.level * 4);
    state.enemies.forEach(enemy => {
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;

        // Clicks grant a tiny bit of LOC per hit to help player out of LOC holes
        state.code += 5;

        if (damageMult > 0.75) {
          hitSomething = true;
          onEnemyHit(enemy);
        }
        if (enemy.hp <= 0) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Point) => void,
    onLevelUp: () => void
  ): void {
    const now = Date.now();
    state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            const actualDmg = Math.min(target.hp, tower.damage);
            target.hp -= tower.damage;

            // CRITICAL FIX: Grant LOC reward on every hit (5% of damage dealt)
            // This ensures towers like SNIPER (Regex Matcher) generate income even against high HP targets
            state.code += actualDmg * 0.05;

            state.experience += tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier;
            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);
            if ('id' in target && target.hp <= 0 && target.hp > -100) {
              this.processEnemyDeath(state, target as Enemy, false);
              this.checkLevelUp(state, onLevelUp);
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 2;
      }
    } else if (d.type === 'loc') {
      state.code += 500 + (state.level * 100);
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    state.experience += (enemy.value / 2) * rewardMult;
    state.code += Math.floor(enemy.value * rewardMult);
    enemy.hp = -999; // Flag for deletion
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 25 : 1;
    const earnedLegacy = (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY),
      (e) => this.createParticles(e.x, e.y, 4, COLORS.PRIMARY),
      () => this.onLevelUp()
    );

    if (!hit) {
      // Increased miss-click reward to ensure players can always recover
      const missReward = 50 + (this.state.level * 5);
      this.state.code += missReward;
      this.createFloatingText(worldX, worldY, `+${missReward}`, COLORS.PRIMARY);
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const towerCount = this.state.towers.filter(t => t.type === key).length; // Wait, key should be type
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.update(dt);
    this.renderer.draw(this.state, this.cameraScale);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    // Logic updates
    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
      },
      () => this.onLevelUp()
    );

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    // Passive Income Handlers
    // tech_passive: Senior Dev Level Passive
    // code_gen: SaaS Business skill Passive
    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250;
        if (this.state.unlockedSkills.includes('code_gen')) gain += 1000; // Extra flat bonus for SaaS skill
        this.state.code += gain; 
        this.passiveCodeTimer = 0; 
      }
    }

    // Spawn Enemies
    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999);
      this.enemySpawnTimer = 0;
    }

    // Particles life
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }
    const hp = 100 * Math.pow(1.12, this.state.level);
    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 1.7 + (this.state.level * 0.05), value: 200 + this.state.level * 80, 
      type: 'bug', size: 45 + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}
import { TECH_TREE } from '../constants';

import React, { useEffect, useRef, useState } from 'react';
import { GameEngine } from './engine/GameEngine';
import { GameState, PermanentUpgrades } from './types';
import UIOverlay from './components/UIOverlay';
import SkillTree from './components/SkillTree';
import { TOWER_TYPES } from './constants';
import { Target } from 'lucide-react';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<GameEngine | null>(null);
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [isSkillTreeOpen, setIsSkillTreeOpen] = useState(false);
  const [buildingType, setBuildingType] = useState<keyof typeof TOWER_TYPES | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;

    const engine = new GameEngine(canvasRef.current, (state) => {
      setGameState(state);
    });
    engineRef.current = engine;

    return () => {
      // Cleanup
    };
  }, []);

  const handleClick = (e: React.MouseEvent) => {
    if (!engineRef.current || isSkillTreeOpen || (gameState && gameState.isGameOver)) return;

    const rect = canvasRef.current!.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    if (buildingType) {
      const success = engineRef.current.buyTower(buildingType, x, y);
      if (success) setBuildingType(null);
    } else {
      engineRef.current.handleClick(x, y);
    }
  };

  const handleBuildTower = (type: keyof typeof TOWER_TYPES) => {
    setBuildingType(type);
  };

  const handleUpgrade = (skillId: string) => {
    if (engineRef.current) {
      const onUnlock = (s: GameState) => {
        // Shop Skills
        if (skillId === 'click_1') s.clickPower *= 2;
        if (skillId === 'massive_click') s.clickPower *= 6;
        if (skillId === 'tower_range_1') s.towers.forEach((t: any) => t.range *= 1.2);
        if (skillId === 'tower_dmg_1') s.towers.forEach((t: any) => t.damage *= 1.4);
        if (skillId === 'core_plating') {
           s.maxCoreHp += 1000;
           s.coreHp += 1000;
        }
        // code_gen (SaaS Business) passive is handled in GameEngine.update, 
        // no immediate state change needed here except unlocking.

        // Tech Tree Nodes
        if (skillId === 'tech_range') s.towers.forEach((t: any) => t.range *= 1.35);
        if (skillId === 'tech_speed') s.towers.forEach((t: any) => t.fireRate *= 0.7);
        if (skillId === 'tech_click_god') s.clickPower *= 10;
        if (skillId === 'tech_tower_god') s.towers.forEach((t: any) => t.damage *= 3);
        if (skillId === 'tech_god') {
            s.clickPower *= 5;
            s.towers.forEach((t: any) => t.damage *= 5);
        }
      };
      engineRef.current.applySkill(skillId, onUnlock);
    }
  };

  const handleReroll = () => {
    if (engineRef.current) {
      engineRef.current.rerollSkills();
    }
  };

  const handleRestart = () => {
    if (engineRef.current) {
      engineRef.current.reset();
    }
  };

  const handleBuyPermanent = (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => {
    if (engineRef.current) {
      engineRef.current.buyPermanentUpgrade(type);
    }
  };

  return (
    <div className="relative w-screen h-screen bg-slate-950 overflow-hidden select-none cursor-crosshair">
      <canvas
        ref={canvasRef}
        onClick={handleClick}
        className="block w-full h-full"
      />

      {gameState && (
        <>
          <UIOverlay 
            state={gameState} 
            onBuildTower={handleBuildTower}
            onOpenSkills={() => setIsSkillTreeOpen(true)}
            onRestart={handleRestart}
            onBuyPermanent={handleBuyPermanent}
          />
          <SkillTree 
            state={gameState}
            isOpen={isSkillTreeOpen}
            onClose={() => setIsSkillTreeOpen(false)}
            onUpgrade={handleUpgrade}
            onReroll={handleReroll}
          />
        </>
      )}

      {buildingType && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-sky-500 text-slate-900 px-6 py-2 rounded-full font-bold shadow-[0_0_30px_rgba(56,189,248,0.5)] animate-pulse pointer-events-none z-40 flex items-center gap-2">
          <Target className="w-5 h-5" /> 
          PLACING {TOWER_TYPES[buildingType].name} - CLICK TO DEPLOY
        </div>
      )}

      <div className="fixed inset-0 pointer-events-none opacity-30 bg-[radial-gradient(circle_at_center,_transparent_0%,_#020617_100%)]" />
    </div>
  );
};

export default App;

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point } from '../types';
// Fix: Consolidate constants imports and include TECH_TREE
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    const legacyFactor = this.state.isVictory ? 25 : 1;
    const earnedLegacy = (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor;
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY),
      (e) => this.createParticles(e.x, e.y, 4, COLORS.PRIMARY),
      () => this.onLevelUp()
    );

    if (!hit) {
      // Increased miss-click reward to ensure players can always recover
      const missReward = 50 + (this.state.level * 5);
      this.state.code += missReward;
      this.createFloatingText(worldX, worldY, `+${missReward}`, COLORS.PRIMARY);
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    // Fix: Removed line with undefined variable 'key' and corrected filtering logic
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.update(dt);
    this.renderer.draw(this.state, this.cameraScale);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    // Logic updates
    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
      },
      () => this.onLevelUp()
    );

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    // Passive Income Handlers
    // tech_passive: Senior Dev Level Passive
    // code_gen: SaaS Business skill Passive
    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250;
        if (this.state.unlockedSkills.includes('code_gen')) gain += 1000; // Extra flat bonus for SaaS skill
        this.state.code += gain; 
        this.passiveCodeTimer = 0; 
      }
    }

    // Spawn Enemies
    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999);
      this.enemySpawnTimer = 0;
    }

    // Particles life
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }
    const hp = 100 * Math.pow(1.12, this.state.level);
    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 1.7 + (this.state.level * 0.05), value: 200 + this.state.level * 80, 
      type: 'bug', size: 45 + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    // 1. Base Passive Trickle (Prevents total soft-locks)
    state.code += (5 + state.level) * (dt / 1000);

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied arrows between planets)
    state.projectiles = state.projectiles.filter(proj => {
      const target = state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x;
      const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        state.code += proj.damage * 0.05; 

        if (target.hp <= 0 && !target.isCaptured) {
          target.isCaptured = true;
          target.color = COLORS.PRIMARY;
          target.hp = 0;
          state.experience += 2500;
          this.checkLevelUp(state, onLevelUp);
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 1500 : 0) / cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Core Damage
    state.enemies.forEach(enemy => {
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        state.coreHp -= 25 + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) state.isGameOver = true;
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    let hitSomething = false;
    const now = Date.now();

    const dropCollectionRadius = 50 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    const splashRadius = 120 + (state.level * 4);
    state.enemies.forEach(enemy => {
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        state.code += 5;

        if (damageMult > 0.75) {
          hitSomething = true;
          onEnemyHit(enemy);
        }
        if (enemy.hp <= 0) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Point) => void,
    onLevelUp: () => void
  ): void {
    const now = Date.now();
    state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            const actualDmg = Math.min(target.hp, tower.damage);
            target.hp -= tower.damage;
            state.code += actualDmg * 0.05;
            state.experience += tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier;
            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);
            if ('id' in target && target.hp <= 0 && target.hp > -100) {
              this.processEnemyDeath(state, target as Enemy, false);
              this.checkLevelUp(state, onLevelUp);
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 2;
      }
    } else if (d.type === 'loc') {
      state.code += 500 + (state.level * 100);
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    state.experience += (enemy.value / 2) * rewardMult;
    state.code += Math.floor(enemy.value * rewardMult);

    // RESTORED: Spawn Drop Logic
    const rand = Math.random();
    let shardChance = isManual ? 0.4 : 0.2;
    if (state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    if (rand < shardChance) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Shard', 
        type: 'shard', 
        rarity: 'common', 
        effect: 'SP', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.0 
      });
    } else if (rand < 0.5) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Data', 
        type: 'loc', 
        rarity: 'common', 
        effect: 'LOC', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.0 
      });
    }

    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    // 1. Base Passive Trickle (Prevents total soft-locks)
    // Use Math.max to prevent negative code from any weird edge cases
    state.code = Math.max(0, state.code + (5 + state.level) * (dt / 1000));

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied arrows between planets)
    state.projectiles = state.projectiles.filter(proj => {
      const target = state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x;
      const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        state.code += Math.max(0, proj.damage * 0.05); 

        if (target.hp <= 0 && !target.isCaptured) {
          target.isCaptured = true;
          target.color = COLORS.PRIMARY;
          target.hp = 0;
          state.experience += 2500;
          this.checkLevelUp(state, onLevelUp);
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 1500 : 0) / cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Core Damage
    state.enemies.forEach(enemy => {
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        state.coreHp -= 25 + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) {
          state.coreHp = 0;
          state.isGameOver = true;
        }
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory) return false;
    let hitSomething = false;
    const now = Date.now();

    const dropCollectionRadius = 50 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    const splashRadius = 120 + (state.level * 4);
    state.enemies.forEach(enemy => {
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        state.code += 5;

        if (damageMult > 0.75) {
          hitSomething = true;
          onEnemyHit(enemy);
        }
        if (enemy.hp <= 0) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Point) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;
    const now = Date.now();
    state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            const actualDmg = Math.max(0, Math.min(target.hp, tower.damage));
            target.hp -= tower.damage;
            state.code += actualDmg * 0.05;
            state.experience += Math.max(0, tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier);
            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);
            if ('id' in target && target.hp <= 0 && target.hp > -100) {
              this.processEnemyDeath(state, target as Enemy, false);
              this.checkLevelUp(state, onLevelUp);
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 2;
      }
    } else if (d.type === 'loc') {
