import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    // 1. Base Passive Trickle (Prevents total soft-locks)
    state.code = Math.max(0, state.code + (5 + state.level) * (dt / 1000));

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied arrows between planets)
    state.projectiles = state.projectiles.filter(proj => {
      const target = state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x;
      const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        state.code += Math.max(0, proj.damage * 0.05); 

        if (target.hp <= 0 && !target.isCaptured) {
          this.capturePlanet(state, target, onLevelUp);
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id && e1.hp > 0 && e2.hp > 0) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 1500 : 0) / cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Core Damage
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        state.coreHp -= 25 + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) {
          state.coreHp = 0;
          state.isGameOver = true;
        }
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory) return false;
    let hitSomething = false;
    const now = Date.now();

    const dropCollectionRadius = 50 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    const splashRadius = 120 + (state.level * 4);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        state.code += 5;

        if (damageMult > 0.75) {
          hitSomething = true;
          onEnemyHit(enemy);
        }
        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Point) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;
    const now = Date.now();
    state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (e.hp > 0 && Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            if (e.hp <= 0) return;
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            // Apply Damage
            const actualDmg = Math.max(0, Math.min(target.hp, tower.damage));
            target.hp -= tower.damage;

            // Hit rewards (granted even if not a kill)
            state.code += actualDmg * 0.05;
            state.experience += Math.max(0, tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier);

            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);

            // Handle Death / Capture
            if (target.hp <= 0) {
              const isEnemy = 'type' in target;
              const isPlanet = 'isCaptured' in target;

              if (isEnemy && !(target as any)._processed) {
                this.processEnemyDeath(state, target as Enemy, false);
                this.checkLevelUp(state, onLevelUp);
              } else if (isPlanet && !(target as Planet).isCaptured) {
                this.capturePlanet(state, target as Planet, onLevelUp);
              }
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += 2500 * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 2;
      }
    } else if (d.type === 'loc') {
      state.code += Math.max(0, 500 + (state.level * 100));
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code += Math.max(0, Math.floor(enemy.value * rewardMult));

    const rand = Math.random();
    let shardChance = isManual ? 0.4 : 0.2;
    if (state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    if (rand < shardChance) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Shard', 
        type: 'shard', 
        rarity: 'common', 
        effect: 'SP', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.0 
      });
    } else if (rand < 0.5) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Data', 
        type: 'loc', 
        rarity: 'common', 
        effect: 'LOC', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.0 
      });
    }

    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private bgmOsc: OscillatorNode | null = null;
  private bgmGain: GainNode | null = null;
  private lastPlayTimes: Map<string, number> = new Map();
  private enabled: boolean = false;

  private COOLDOWNS = {
    fire_basic: 80,
    fire_rapid: 40,
    fire_sniper: 150,
    fire_aoe: 200,
    death: 30,
    click: 50,
    shard: 100,
  };

  constructor() {
    // Context is created on first interaction to comply with browser policies
  }

  private init() {
    if (this.ctx) return;
    this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = 0.3;
    this.masterGain.connect(this.ctx.destination);
    this.enabled = true;
    this.startBGM();
  }

  public enable() {
    if (!this.ctx) this.init();
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume();
    }
  }

  private startBGM() {
    if (!this.ctx || !this.masterGain) return;

    this.bgmGain = this.ctx.createGain();
    this.bgmGain.gain.value = 0.05;
    this.bgmGain.connect(this.masterGain);

    // Simple 8-bit style pulsing drone
    const createDrone = (freq: number, type: OscillatorType) => {
      const osc = this.ctx!.createOscillator();
      osc.type = type;
      osc.frequency.setValueAtTime(freq, this.ctx!.currentTime);
      osc.connect(this.bgmGain!);
      osc.start();
      return osc;
    };

    this.bgmOsc = createDrone(55, 'sawtooth'); // A1 Low Drone
    const subOsc = createDrone(110, 'square'); // A2 pulsing harmonic

    // Add a simple LFO to the drone for "tech" feel
    const lfo = this.ctx.createOscillator();
    lfo.frequency.setValueAtTime(0.5, this.ctx.currentTime);
    const lfoGain = this.ctx.createGain();
    lfoGain.gain.setValueAtTime(10, this.ctx.currentTime);
    lfo.connect(lfoGain);
    lfoGain.connect(this.bgmOsc.frequency);
    lfo.start();
  }

  private canPlay(key: string): boolean {
    if (!this.enabled) return false;
    const now = Date.now();
    const last = this.lastPlayTimes.get(key) || 0;
    const cooldown = (this.COOLDOWNS as any)[key] || 0;
    if (now - last > cooldown) {
      this.lastPlayTimes.set(key, now);
      return true;
    }
    return false;
  }

  public playFire(type: string) {
    if (!this.ctx || !this.masterGain) return;
    const key = `fire_${type.toLowerCase()}`;
    if (!this.canPlay(key)) return;

    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.connect(g);
    g.connect(this.masterGain);

    const now = this.ctx.currentTime;

    if (type === 'SNIPER') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(800, now);
      osc.frequency.exponentialRampToValueAtTime(40, now + 0.5);
      g.gain.setValueAtTime(0.3, now);
      g.gain.linearRampToValueAtTime(0, now + 0.5);
      osc.start(now);
      osc.stop(now + 0.5);
    } else if (type === 'RAPID') {
      osc.type = 'square';
      osc.frequency.setValueAtTime(1200, now);
      osc.frequency.linearRampToValueAtTime(400, now + 0.05);
      g.gain.setValueAtTime(0.1, now);
      g.gain.linearRampToValueAtTime(0, now + 0.05);
      osc.start(now);
      osc.stop(now + 0.05);
    } else if (type === 'AOE') {
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(100, now);
      osc.frequency.exponentialRampToValueAtTime(400, now + 0.2);
      g.gain.setValueAtTime(0.4, now);
      g.gain.linearRampToValueAtTime(0, now + 0.2);
      osc.start(now);
      osc.stop(now + 0.2);
    } else {
      osc.type = 'square';
      osc.frequency.setValueAtTime(440, now);
      osc.frequency.exponentialRampToValueAtTime(110, now + 0.1);
      g.gain.setValueAtTime(0.2, now);
      g.gain.linearRampToValueAtTime(0, now + 0.1);
      osc.start(now);
      osc.stop(now + 0.1);
    }
  }

  public playDeath() {
    if (!this.ctx || !this.masterGain || !this.canPlay('death')) return;

    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();

    // Noise-like explosion using rapid frequency randomizing
    osc.type = 'square';
    osc.frequency.setValueAtTime(100, now);
    osc.frequency.linearRampToValueAtTime(20, now + 0.15);

    g.gain.setValueAtTime(0.15, now);
    g.gain.exponentialRampToValueAtTime(0.01, now + 0.15);

    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.15);
  }

  public playClick() {
    if (!this.ctx || !this.masterGain || !this.canPlay('click')) return;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sine';
    const now = this.ctx.currentTime;
    osc.frequency.setValueAtTime(1200, now);
    osc.frequency.exponentialRampToValueAtTime(1500, now + 0.02);
    g.gain.setValueAtTime(0.1, now);
    g.gain.linearRampToValueAtTime(0, now + 0.02);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.02);
  }

  public playLevelUp() {
    if (!this.ctx || !this.masterGain) return;
    const now = this.ctx.currentTime;
    [440, 554, 659, 880].forEach((f, i) => {
      const osc = this.ctx!.createOscillator();
      const g = this.ctx!.createGain();
      osc.type = 'square';
      osc.frequency.setValueAtTime(f, now + i * 0.1);
      g.gain.setValueAtTime(0.1, now + i * 0.1);
      g.gain.exponentialRampToValueAtTime(0.01, now + i * 0.1 + 0.3);
      osc.connect(g);
      g.connect(this.masterGain!);
      osc.start(now + i * 0.1);
      osc.stop(now + i * 0.1 + 0.3);
    });
  }

  public playGameOver() {
    if (!this.ctx || !this.masterGain) return;
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(220, now);
    osc.frequency.linearRampToValueAtTime(55, now + 1.5);
    g.gain.setValueAtTime(0.3, now);
    g.gain.linearRampToValueAtTime(0, now + 1.5);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 1.5);
  }

  public playShard() {
    if (!this.ctx || !this.masterGain || !this.canPlay('shard')) return;
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(2000, now);
    osc.frequency.exponentialRampToValueAtTime(3000, now + 0.05);
    g.gain.setValueAtTime(0.15, now);
    g.gain.linearRampToValueAtTime(0, now + 0.05);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.05);
  }
}

export const audio = new AudioManager();

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    // Ensure audio is enabled on first interaction
    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const missReward = 50 + (this.state.level * 5);
      this.state.code += missReward;
      this.createFloatingText(worldX, worldY, `+${missReward}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.update(dt);
    this.renderer.draw(this.state, this.cameraScale);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    // Logic updates
    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
        if (target.hp <= 0) {
           audio.playDeath();
        }
      },
      () => this.onLevelUp()
    );

    // Finalize LP immediately when transitioning to Game Over / Victory
    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const legacyFactor = this.state.isVictory ? 25 : 1;
      const earnedLegacy = Math.max(0, (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor);
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) {
      return; 
    }

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    // Passive Income Handlers
    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250;
        if (this.state.unlockedSkills.includes('code_gen')) gain += 1000; 
        this.state.code += Math.max(0, gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    // Spawn Enemies
    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999);
      this.enemySpawnTimer = 0;
    }

    // Particles life
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }
    const hp = 100 * Math.pow(1.12, this.state.level);
    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 1.7 + (this.state.level * 0.05), value: 200 + this.state.level * 80, 
      type: 'bug', size: 45 + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); // Skill unlock sound
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

import React, { useEffect, useRef, useState } from 'react';
import { GameEngine } from './engine/GameEngine';
import { GameState, PermanentUpgrades } from './types';
import UIOverlay from './components/UIOverlay';
import SkillTree from './components/SkillTree';
import { TOWER_TYPES } from './constants';
import { Target } from 'lucide-react';
import { audio } from './engine/AudioManager';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<GameEngine | null>(null);
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [isSkillTreeOpen, setIsSkillTreeOpen] = useState(false);
  const [buildingType, setBuildingType] = useState<keyof typeof TOWER_TYPES | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;

    const engine = new GameEngine(canvasRef.current, (state) => {
      setGameState(state);
    });
    engineRef.current = engine;

    return () => {
      // Cleanup
    };
  }, []);

  const handleClick = (e: React.MouseEvent) => {
    // Ensure audio starts on first click
    audio.enable();

    if (!engineRef.current || isSkillTreeOpen || (gameState && gameState.isGameOver)) return;

    const rect = canvasRef.current!.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    if (buildingType) {
      const success = engineRef.current.buyTower(buildingType, x, y);
      if (success) setBuildingType(null);
    } else {
      engineRef.current.handleClick(x, y);
    }
  };

  const handleBuildTower = (type: keyof typeof TOWER_TYPES) => {
    audio.enable();
    setBuildingType(type);
  };

  const handleUpgrade = (skillId: string) => {
    if (engineRef.current) {
      const onUnlock = (s: GameState) => {
        // Shop Skills
        if (skillId === 'click_1') s.clickPower *= 2;
        if (skillId === 'massive_click') s.clickPower *= 6;
        if (skillId === 'tower_range_1') s.towers.forEach((t: any) => t.range *= 1.2);
        if (skillId === 'tower_dmg_1') s.towers.forEach((t: any) => t.damage *= 1.4);
        if (skillId === 'core_plating') {
           s.maxCoreHp += 1000;
           s.coreHp += 1000;
        }

        // Tech Tree Nodes
        if (skillId === 'tech_range') s.towers.forEach((t: any) => t.range *= 1.35);
        if (skillId === 'tech_speed') s.towers.forEach((t: any) => t.fireRate *= 0.7);
        if (skillId === 'tech_click_god') s.clickPower *= 10;
        if (skillId === 'tech_tower_god') s.towers.forEach((t: any) => t.damage *= 3);
        if (skillId === 'tech_god') {
            s.clickPower *= 5;
            s.towers.forEach((t: any) => t.damage *= 5);
        }
      };
      engineRef.current.applySkill(skillId, onUnlock);
    }
  };

  const handleReroll = () => {
    if (engineRef.current) {
      engineRef.current.rerollSkills();
    }
  };

  const handleRestart = () => {
    if (engineRef.current) {
      engineRef.current.reset();
    }
  };

  const handleBuyPermanent = (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => {
    if (engineRef.current) {
      engineRef.current.buyPermanentUpgrade(type);
    }
  };

  return (
    <div className="relative w-screen h-screen bg-slate-950 overflow-hidden select-none cursor-crosshair">
      <canvas
        ref={canvasRef}
        onClick={handleClick}
        className="block w-full h-full"
      />

      {gameState && (
        <>
          <UIOverlay 
            state={gameState} 
            onBuildTower={handleBuildTower}
            onOpenSkills={() => {
              audio.enable();
              setIsSkillTreeOpen(true);
            }}
            onRestart={handleRestart}
            onBuyPermanent={handleBuyPermanent}
          />
          <SkillTree 
            state={gameState}
            isOpen={isSkillTreeOpen}
            onClose={() => setIsSkillTreeOpen(false)}
            onUpgrade={handleUpgrade}
            onReroll={handleReroll}
          />
        </>
      )}

      {buildingType && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-sky-500 text-slate-900 px-6 py-2 rounded-full font-bold shadow-[0_0_30px_rgba(56,189,248,0.5)] animate-pulse pointer-events-none z-40 flex items-center gap-2">
          <Target className="w-5 h-5" /> 
          PLACING {TOWER_TYPES[buildingType].name} - CLICK TO DEPLOY
        </div>
      )}

      <div className="fixed inset-0 pointer-events-none opacity-30 bg-[radial-gradient(circle_at_center,_transparent_0%,_#020617_100%)]" />
    </div>
  );
};

export default App;

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    // 1. Base Passive Trickle (Prevents total soft-locks)
    state.code = Math.max(0, state.code + (5 + state.level) * (dt / 1000));

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied arrows between planets)
    state.projectiles = state.projectiles.filter(proj => {
      const target = state.planets.find(p => p.id === proj.targetId);
      if (!target) return false;
      const dx = target.x - proj.x;
      const dy = target.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 60) {
        target.hp -= proj.damage;
        state.code += Math.max(0, proj.damage * 0.05); 

        if (target.hp <= 0 && !target.isCaptured) {
          this.capturePlanet(state, target, onLevelUp);
        }
        return false;
      }
      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id && e1.hp > 0 && e2.hp > 0) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 1500 : 0) / cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Core Damage
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 85) {
        state.coreHp -= 25 + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) {
          state.coreHp = 0;
          state.isGameOver = true;
        }
      }
      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory) return false;
    let hitSomething = false;
    const now = Date.now();

    const dropCollectionRadius = 50 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    const splashRadius = 120 + (state.level * 4);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        state.code += 5;

        if (damageMult > 0.75) {
          hitSomething = true;
          onEnemyHit(enemy);
        }
        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  // Changed target type from Point to Enemy | Planet to expose hp property to consumers
  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;
    const now = Date.now();
    state.towers.forEach(tower => {
      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (e.hp > 0 && Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            if (e.hp <= 0) return;
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            // Apply Damage
            const actualDmg = Math.max(0, Math.min(target.hp, tower.damage));
            target.hp -= tower.damage;

            // Hit rewards (granted even if not a kill)
            state.code += actualDmg * 0.05;
            state.experience += Math.max(0, tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier);

            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);

            // Handle Death / Capture
            if (target.hp <= 0) {
              const isEnemy = 'type' in target;
              const isPlanet = 'isCaptured' in target;

              if (isEnemy && !(target as any)._processed) {
                this.processEnemyDeath(state, target as Enemy, false);
                this.checkLevelUp(state, onLevelUp);
              } else if (isPlanet && !(target as Planet).isCaptured) {
                this.capturePlanet(state, target as Planet, onLevelUp);
              }
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += 2500 * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 2;
      }
    } else if (d.type === 'loc') {
      state.code += Math.max(0, 500 + (state.level * 100));
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code += Math.max(0, Math.floor(enemy.value * rewardMult));

    const rand = Math.random();
    let shardChance = isManual ? 0.4 : 0.2;
    if (state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    if (rand < shardChance) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Shard', 
        type: 'shard', 
        rarity: 'common', 
        effect: 'SP', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.0 
      });
    } else if (rand < 0.5) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Data', 
        type: 'loc', 
        rarity: 'common', 
        effect: 'LOC', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.0 
      });
    }

    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private bgmGain: GainNode | null = null;
  private lastPlayTimes: Map<string, number> = new Map();
  private enabled: boolean = false;

  // Sequencer state
  private currentBpm: number = 128;
  private nextNoteTime: number = 0;
  private currentStep: number = 0;
  private lookahead: number = 25.0; // ms
  private scheduleAheadTime: number = 0.1; // seconds
  private timerId: number | null = null;

  // Scales & Patterns (8-bit C minor / Pentatonic vibes)
  private bassScale = [65.41, 77.78, 98.00, 116.54]; // C2, Eb2, G2, Bb2
  private leadScale = [261.63, 311.13, 392.00, 466.16, 523.25]; // C4, Eb4, G4, Bb4, C5

  private bassPattern = [0, 0, 2, 2, 3, 3, 1, 1];
  private leadPattern = [0, -1, 1, -1, 2, 4, 3, -1, 0, 2, 1, -1, 3, -1, 2, -1];

  private COOLDOWNS = {
    fire_basic: 80,
    fire_rapid: 40,
    fire_sniper: 150,
    fire_aoe: 200,
    death: 30,
    click: 50,
    shard: 100,
  };

  constructor() {}

  private init() {
    if (this.ctx) return;
    this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = 0.3;
    this.masterGain.connect(this.ctx.destination);

    this.bgmGain = this.ctx.createGain();
    this.bgmGain.gain.value = 0.08;
    this.bgmGain.connect(this.masterGain);

    this.enabled = true;
    this.scheduler();
  }

  public enable() {
    if (!this.ctx) this.init();
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume();
    }
  }

  public updateBPM(level: number) {
    // Increase speed slightly with level
    this.currentBpm = Math.min(220, 128 + (level * 1.5));
  }

  private scheduler = () => {
    if (!this.ctx || !this.enabled) return;

    while (this.nextNoteTime < this.ctx.currentTime + this.scheduleAheadTime) {
      this.scheduleNote(this.currentStep, this.nextNoteTime);
      this.advanceNote();
    }
    this.timerId = window.setTimeout(this.scheduler, this.lookahead);
  }

  private advanceNote() {
    const secondsPerBeat = 60.0 / this.currentBpm;
    this.nextNoteTime += 0.25 * secondsPerBeat; // 16th notes
    this.currentStep = (this.currentStep + 1) % 16;
  }

  private scheduleNote(step: number, time: number) {
    if (!this.ctx || !this.bgmGain) return;

    // Bassline (every 8th note)
    if (step % 2 === 0) {
      const bassIndex = this.bassPattern[(step / 2) % 8];
      if (bassIndex !== -1) {
        this.playPluck(this.bassScale[bassIndex], time, 0.15, 'triangle', 0.4);
      }
    }

    // Lead melody
    const leadIndex = this.leadPattern[step % 16];
    if (leadIndex !== -1) {
      this.playPluck(this.leadScale[leadIndex], time, 0.1, 'square', 0.2);
    }
  }

  private playPluck(freq: number, time: number, duration: number, type: OscillatorType, volume: number) {
    if (!this.ctx || !this.bgmGain) return;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, time);

    g.gain.setValueAtTime(0, time);
    g.gain.linearRampToValueAtTime(volume, time + 0.01);
    g.gain.exponentialRampToValueAtTime(0.001, time + duration);

    osc.connect(g);
    g.connect(this.bgmGain);

    osc.start(time);
    osc.stop(time + duration);
  }

  private canPlay(key: string): boolean {
    if (!this.enabled) return false;
    const now = Date.now();
    const last = this.lastPlayTimes.get(key) || 0;
    const cooldown = (this.COOLDOWNS as any)[key] || 0;
    if (now - last > cooldown) {
      this.lastPlayTimes.set(key, now);
      return true;
    }
    return false;
  }

  public playFire(type: string) {
    if (!this.ctx || !this.masterGain) return;
    const key = `fire_${type.toLowerCase()}`;
    if (!this.canPlay(key)) return;

    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.connect(g);
    g.connect(this.masterGain);

    const now = this.ctx.currentTime;

    if (type === 'SNIPER') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(800, now);
      osc.frequency.exponentialRampToValueAtTime(40, now + 0.5);
      g.gain.setValueAtTime(0.3, now);
      g.gain.linearRampToValueAtTime(0, now + 0.5);
      osc.start(now);
      osc.stop(now + 0.5);
    } else if (type === 'RAPID') {
      osc.type = 'square';
      osc.frequency.setValueAtTime(1200, now);
      osc.frequency.linearRampToValueAtTime(400, now + 0.05);
      g.gain.setValueAtTime(0.1, now);
      g.gain.linearRampToValueAtTime(0, now + 0.05);
      osc.start(now);
      osc.stop(now + 0.05);
    } else if (type === 'AOE') {
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(100, now);
      osc.frequency.exponentialRampToValueAtTime(400, now + 0.2);
      g.gain.setValueAtTime(0.4, now);
      g.gain.linearRampToValueAtTime(0, now + 0.2);
      osc.start(now);
      osc.stop(now + 0.2);
    } else {
      osc.type = 'square';
      osc.frequency.setValueAtTime(440, now);
      osc.frequency.exponentialRampToValueAtTime(110, now + 0.1);
      g.gain.setValueAtTime(0.2, now);
      g.gain.linearRampToValueAtTime(0, now + 0.1);
      osc.start(now);
      osc.stop(now + 0.1);
    }
  }

  public playDeath() {
    if (!this.ctx || !this.masterGain || !this.canPlay('death')) return;

    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();

    osc.type = 'square';
    osc.frequency.setValueAtTime(100, now);
    osc.frequency.linearRampToValueAtTime(20, now + 0.15);

    g.gain.setValueAtTime(0.15, now);
    g.gain.exponentialRampToValueAtTime(0.01, now + 0.15);

    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.15);
  }

  public playClick() {
    if (!this.ctx || !this.masterGain || !this.canPlay('click')) return;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sine';
    const now = this.ctx.currentTime;
    osc.frequency.setValueAtTime(1200, now);
    osc.frequency.exponentialRampToValueAtTime(1500, now + 0.02);
    g.gain.setValueAtTime(0.1, now);
    g.gain.linearRampToValueAtTime(0, now + 0.02);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.02);
  }

  public playLevelUp() {
    if (!this.ctx || !this.masterGain) return;
    const now = this.ctx.currentTime;
    [440, 554, 659, 880].forEach((f, i) => {
      const osc = this.ctx!.createOscillator();
      const g = this.ctx!.createGain();
      osc.type = 'square';
      osc.frequency.setValueAtTime(f, now + i * 0.1);
      g.gain.setValueAtTime(0.1, now + i * 0.1);
      g.gain.exponentialRampToValueAtTime(0.01, now + i * 0.1 + 0.3);
      osc.connect(g);
      g.connect(this.masterGain!);
      osc.start(now + i * 0.1);
      osc.stop(now + i * 0.1 + 0.3);
    });
  }

  public playGameOver() {
    if (!this.ctx || !this.masterGain) return;
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(220, now);
    osc.frequency.linearRampToValueAtTime(55, now + 1.5);
    g.gain.setValueAtTime(0.3, now);
    g.gain.linearRampToValueAtTime(0, now + 1.5);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 1.5);
  }

  public playShard() {
    if (!this.ctx || !this.masterGain || !this.canPlay('shard')) return;
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(2000, now);
    osc.frequency.exponentialRampToValueAtTime(3000, now + 0.05);
    g.gain.setValueAtTime(0.15, now);
    g.gain.linearRampToValueAtTime(0, now + 0.05);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.05);
  }
}

export const audio = new AudioManager();

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory) return;

    // Ensure audio is enabled on first interaction
    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const missReward = 50 + (this.state.level * 5);
      this.state.code += missReward;
      this.createFloatingText(worldX, worldY, `+${missReward}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.update(dt);
    this.renderer.draw(this.state, this.cameraScale);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    // Logic updates
    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
        if (target.hp <= 0) {
           audio.playDeath();
        }
      },
      () => this.onLevelUp()
    );

    // Finalize LP immediately when transitioning to Game Over / Victory
    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const legacyFactor = this.state.isVictory ? 25 : 1;
      const earnedLegacy = Math.max(0, (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor);
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) {
      return; 
    }

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    // Passive Income Handlers
    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250;
        if (this.state.unlockedSkills.includes('code_gen')) gain += 1000; 
        this.state.code += Math.max(0, gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    // Spawn Enemies
    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999);
      this.enemySpawnTimer = 0;
    }

    // Particles life
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    this.onUpdate({ ...this.state });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }
    const hp = 100 * Math.pow(1.12, this.state.level);
    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 1.7 + (this.state.level * 0.05), value: 200 + this.state.level * 80, 
      type: 'bug', size: 45 + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); // Skill unlock sound
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

export interface Point {
  x: number;
  y: number;
}

export interface Particle extends Point {
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
  text?: string;
}

export interface Projectile extends Point {
  id: string;
  targetId: string;
  speed: number;
  damage: number;
  color: string;
  type: 'allied' | 'enemy';
}

export interface Planet extends Point {
  id: string;
  hp: number;
  maxHp: number;
  isCaptured: boolean;
  size: number;
  color: string;
  name: string;
}

export interface ClickRipple extends Point {
  radius: number;
  maxRadius: number;
  life: number;
}

export interface Enemy extends Point {
  id: string;
  hp: number;
  maxHp: number;
  speed: number;
  value: number;
  type: 'bug' | 'boss' | 'glitch';
  size: number;
  angle: number;
  lastHit?: number;
  sourcePlanetId?: string;
  nextAttackTime?: number; // For boss projectiles
}

export interface Tower extends Point {
  id: string;
  type: string;
  level: number;
  range: number;
  damage: number;
  fireRate: number;
  lastFired: number;
  color: string;
  disabledUntil?: number; // For glitch effects
}

export interface LibraryDrop extends Point {
  id: string;
  name: string;
  type: 'loc' | 'shard' | 'library';
  rarity: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
  effect: string;
  life: number;
}

export interface PermanentUpgrades {
  startingCode: number;
  damageMultiplier: number;
  xpMultiplier: number;
  legacyPoints: number;
}

export interface TechNode {
  id: string;
  name: string;
  description: string;
  cost: number;
  position: { x: number; y: number };
  dependsOn?: string;
}

export interface GameState {
  code: number;
  experience: number;
  level: number;
  skillPoints: number;
  spProgress: number;
  spGoal: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  planets: Planet[];
  projectiles: Projectile[];
  isGameOver: boolean;
  isVictory: boolean;
  permanentUpgrades: PermanentUpgrades;
  lastRunCode: number;
  availableSkills: string[];
  unlockedTech: string[];
  unlockedSkills: string[]; 
  rerollCost: number;
  combo: number;
  threatLevel: number;
  coreHp: number;
  maxCoreHp: number;
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;

    // 1. Base Passive Trickle
    state.code = Math.max(0, state.code + (5 + state.level) * (dt / 1000));

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied & Enemy)
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;

      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        // Enemy virus projectiles target the core
        targetPos = { x: cx, y: cy };
      }

      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 60) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code += Math.max(0, proj.damage * 0.05); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          // Virus hit core
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id && e1.hp > 0 && e2.hp > 0 && e1.type === e2.type) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(e1.type === 'boss' ? 400 : 150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 1500 : 0) / cameraScale;
      const vacuumSpeed = 25;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Specialized Behaviors
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Core collision
      if (dist < (enemy.type === 'boss' ? 150 : 85)) {
        state.coreHp -= (enemy.type === 'boss' ? 500 : 25) + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) {
          state.coreHp = 0;
          state.isGameOver = true;
        }
        return;
      }

      // Behavior: Glitch (Disables nearby towers)
      if (enemy.type === 'glitch') {
        const glitchAura = 300;
        state.towers.forEach(t => {
          const tDist = Math.sqrt((t.x - enemy.x) ** 2 + (t.y - enemy.y) ** 2);
          if (tDist < glitchAura) {
            t.disabledUntil = now + 1000; // Disable for 1 second while in aura
          }
        });
      }

      // Behavior: Boss (Fires projectiles)
      if (enemy.type === 'boss') {
        if (!enemy.nextAttackTime) enemy.nextAttackTime = now + 2000;
        if (now > enemy.nextAttackTime) {
          state.projectiles.push({
            id: Math.random().toString(36),
            targetId: 'core',
            x: enemy.x,
            y: enemy.y,
            speed: 5,
            damage: 50 + (state.level * 10),
            color: COLORS.BOSS,
            type: 'enemy'
          });
          enemy.nextAttackTime = now + (3000 - Math.min(2000, state.level * 100));
        }
      }

      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory) return false;
    let hitSomething = false;
    const now = Date.now();

    const dropCollectionRadius = 50 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    const splashRadius = 120 + (state.level * 4);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        state.code += 5;

        if (damageMult > 0.75) {
          hitSomething = true;
          onEnemyHit(enemy);
        }
        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;
    const now = Date.now();
    state.towers.forEach(tower => {
      // Check if tower is disabled by Glitch
      if (tower.disabledUntil && now < tower.disabledUntil) return;

      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (e.hp > 0 && Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            if (e.hp <= 0) return;
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            const actualDmg = Math.max(0, Math.min(target.hp, tower.damage));
            target.hp -= tower.damage;

            state.code += actualDmg * 0.05;
            state.experience += Math.max(0, tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier);

            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);

            if (target.hp <= 0) {
              const isEnemy = 'type' in target;
              const isPlanet = 'isCaptured' in target;

              if (isEnemy && !(target as any)._processed) {
                this.processEnemyDeath(state, target as Enemy, false);
                this.checkLevelUp(state, onLevelUp);
              } else if (isPlanet && !(target as Planet).isCaptured) {
                this.capturePlanet(state, target as Planet, onLevelUp);
              }
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += 2500 * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 2;
      }
    } else if (d.type === 'loc') {
      state.code += Math.max(0, 500 + (state.level * 100));
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    // Boss rewards
    if (enemy.type === 'boss') rewardMult *= 10;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code += Math.max(0, Math.floor(enemy.value * rewardMult));

    const rand = Math.random();
    let shardChance = isManual ? 0.4 : 0.2;
    if (state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    // Bosses always drop several shards
    if (enemy.type === 'boss') {
      for (let i = 0; i < 5; i++) {
        state.drops.push({ 
          id: Math.random().toString(36), 
          name: 'Core Shard', 
          type: 'shard', 
          rarity: 'rare', 
          effect: 'SP', 
          x: enemy.x + (Math.random() - 0.5) * 100, 
          y: enemy.y + (Math.random() - 0.5) * 100, 
          life: 2.0 
        });
      }
    } else if (rand < shardChance) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Shard', 
        type: 'shard', 
        rarity: 'common', 
        effect: 'SP', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.0 
      });
    } else if (rand < 0.5) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Data', 
        type: 'loc', 
        rarity: 'common', 
        effect: 'LOC', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.0 
      });
    }

    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const missReward = 50 + (this.state.level * 5);
      this.state.code += missReward;
      this.createFloatingText(worldX, worldY, `+${missReward}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
      // Spawn a Boss immediately on level up milestones
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;

    if (!this.isPaused) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    // Logic updates
    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
        if (target.hp <= 0) {
           audio.playDeath();
        }
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const legacyFactor = this.state.isVictory ? 25 : 1;
      const earnedLegacy = Math.max(0, (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor);
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) {
      return; 
    }

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    // Passive Income Handlers
    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250;
        if (this.state.unlockedSkills.includes('code_gen')) gain += 1000; 
        this.state.code += Math.max(0, gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    // Spawn Enemies
    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      // Determine enemy type
      let type: 'bug' | 'glitch' = 'bug';
      if (this.state.level >= 3 && Math.random() < 0.15) {
        type = 'glitch';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    // Particles life
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3000 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const hp = 50000 * Math.pow(1.3, this.state.level / 5);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 0.8 + (this.state.level * 0.02), value: 20000 + this.state.level * 5000, 
      type: 'boss', size: 300, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "BOSS DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: 'bug' | 'glitch' = 'bug') {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }
    const hp = (type === 'glitch' ? 500 : 100) * Math.pow(1.12, this.state.level);
    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: (type === 'glitch' ? 2.5 : 1.7) + (this.state.level * 0.05), value: (type === 'glitch' ? 1000 : 200) + this.state.level * 80, 
      type, size: (type === 'glitch' ? 60 : 45) + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

import { GameState } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();

    // Screen Shake
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.9;
      if (this.screenShake < 0.1) this.screenShake = 0;
    }

    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. Planets
    state.planets.forEach(p => {
      const grad = this.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size);
      grad.addColorStop(0, p.isCaptured ? '#0c4a6e' : '#450a0a');
      grad.addColorStop(0.9, '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = p.isCaptured ? COLORS.PRIMARY : COLORS.ENEMY;
      this.ctx.lineWidth = 15; this.ctx.globalAlpha = 0.2;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 25, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 50px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // 2. Firing Effects
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.save();
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.shadowBlur = 15;
      this.ctx.shadowColor = ef.color;

      if (ef.type === 'SNIPER') {
        this.ctx.lineWidth = 6 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
        this.ctx.strokeStyle = '#fff';
        this.ctx.lineWidth = 2 * ef.life;
        this.ctx.stroke();
      } else if (ef.type === 'RAPID') {
        this.ctx.lineWidth = 2;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
        this.ctx.fillStyle = ef.color;
        this.ctx.beginPath();
        this.ctx.arc(ef.x2, ef.y2, 10 * (1 - ef.life), 0, Math.PI * 2);
        this.ctx.fill();
      } else if (ef.type === 'AOE') {
        this.ctx.lineWidth = 8 * ef.life;
        this.ctx.beginPath();
        this.ctx.arc(ef.x1, ef.y1, (1 - ef.life) * 400, 0, Math.PI * 2);
        this.ctx.stroke();
      } else {
        this.ctx.lineWidth = 3 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
      }

      this.ctx.restore();
      ef.life -= 0.12;
      return ef.life > 0;
    });

    // 3. Core
    const coreSize = 90 + (state.level * 0.6);
    this.ctx.fillStyle = state.threatLevel > 15 ? COLORS.ENEMY : COLORS.PRIMARY;
    this.ctx.shadowBlur = 80; this.ctx.shadowColor = this.ctx.fillStyle as string;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 4. Drops
    state.drops.forEach(d => {
      this.ctx.save();
      this.ctx.shadowBlur = 15;
      this.ctx.shadowColor = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : d.type === 'loc' ? COLORS.PRIMARY : COLORS.ACCENT;
      if (d.type === 'shard') {
        this.ctx.beginPath();
        this.ctx.moveTo(d.x, d.y - 12); this.ctx.lineTo(d.x + 12, d.y);
        this.ctx.lineTo(d.x, d.y + 12); this.ctx.lineTo(d.x - 12, d.y);
        this.ctx.closePath(); this.ctx.fill();
      } else {
        this.ctx.fillRect(d.x - 10, d.y - 10, 20, 20);
      }
      this.ctx.restore();
    });

    // 5. Ripples
    state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 8;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    // 6. Enemies
    state.enemies.forEach(e => {
      const isHit = Date.now() - (e.lastHit || 0) < 100;
      const scale = isHit ? 1.3 : 1.0;
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      if (e.type === 'glitch') {
        // Skew and jitter glitch effect
        const jitterX = (Math.random() - 0.5) * 10;
        const jitterY = (Math.random() - 0.5) * 10;
        this.ctx.translate(jitterX, jitterY);
        this.ctx.scale(scale * (0.8 + Math.random() * 0.4), scale);

        // Aura
        this.ctx.strokeStyle = '#00ffcc';
        this.ctx.lineWidth = 2;
        this.ctx.setLineDash([5, 5]);
        this.ctx.beginPath();
        this.ctx.arc(0, 0, 300, 0, Math.PI * 2);
        this.ctx.stroke();
        this.ctx.setLineDash([]);
      } else if (e.type === 'boss') {
        this.ctx.scale(scale, scale);
        // Boss Glow
        this.ctx.shadowBlur = 40;
        this.ctx.shadowColor = COLORS.BOSS;
      } else {
        this.ctx.scale(scale, scale);
      }

      this.ctx.fillStyle = isHit ? '#fff' : (e.type === 'boss' ? COLORS.BOSS : e.type === 'glitch' ? '#00ffcc' : COLORS.ENEMY);

      if (e.type === 'boss') {
        // Draw boss health bar
        const hpPercent = e.hp / e.maxHp;
        this.ctx.save();
        this.ctx.rotate(-e.angle); // Keep bar flat
        this.ctx.fillStyle = '#444';
        this.ctx.fillRect(-200, -250, 400, 20);
        this.ctx.fillStyle = COLORS.BOSS;
        this.ctx.fillRect(-200, -250, 400 * hpPercent, 20);
        this.ctx.restore();

        // Dreadful shape
        this.ctx.beginPath();
        this.ctx.moveTo(e.size, 0);
        this.ctx.lineTo(-e.size / 3, e.size / 2);
        this.ctx.lineTo(-e.size, 0);
        this.ctx.lineTo(-e.size / 3, -e.size / 2);
        this.ctx.closePath();
      } else if (e.type === 'glitch') {
        // Diamond shape
        this.ctx.beginPath();
        this.ctx.moveTo(0, -e.size);
        this.ctx.lineTo(e.size, 0);
        this.ctx.lineTo(0, e.size);
        this.ctx.lineTo(-e.size, 0);
        this.ctx.closePath();
      } else {
        // Standard bug triangle
        this.ctx.beginPath();
        this.ctx.moveTo(e.size, 0);
        this.ctx.lineTo(-e.size / 2, e.size / 2);
        this.ctx.lineTo(-e.size / 2, -e.size / 2);
        this.ctx.closePath();
      }

      this.ctx.fill();
      this.ctx.restore();
    });

    // 7. Projectiles
    state.projectiles.forEach(p => {
      this.ctx.fillStyle = p.color;
      this.ctx.shadowBlur = 10;
      this.ctx.shadowColor = p.color;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.type === 'enemy' ? 15 : 10, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.shadowBlur = 0;
    });

    // 8. Towers
    state.towers.forEach(t => {
      const isDisabled = t.disabledUntil && now < t.disabledUntil;

      if (isDisabled) {
        this.ctx.save();
        this.ctx.fillStyle = '#333';
        this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);
        // Draw static noise
        for (let i = 0; i < 5; i++) {
          this.ctx.fillStyle = Math.random() > 0.5 ? '#fff' : '#000';
          this.ctx.fillRect(t.x - 30 + Math.random() * 60, t.y - 30 + Math.random() * 60, 10, 2);
        }
        this.ctx.restore();
      } else {
        this.ctx.fillStyle = t.color;
        this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);
        this.ctx.strokeStyle = t.color; this.ctx.lineWidth = 1; this.ctx.globalAlpha = 0.1;
        this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
        this.ctx.globalAlpha = 1.0;
      }
    });

    // 9. Particles & Floating Text
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${p.size}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      }
      this.ctx.globalAlpha = 1.0;
    });

    this.ctx.restore();

    // Menu overlay dimming
    if (isPaused || state.isGameOver || state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.7)';
      this.ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
  }
}

import React, { useEffect, useRef, useState } from 'react';
import { GameEngine } from './engine/GameEngine';
import { GameState, PermanentUpgrades } from './types';
import UIOverlay from './components/UIOverlay';
import SkillTree from './components/SkillTree';
import { TOWER_TYPES } from './constants';
import { Target } from 'lucide-react';
import { audio } from './engine/AudioManager';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<GameEngine | null>(null);
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [isSkillTreeOpen, setIsSkillTreeOpen] = useState(false);
  const [buildingType, setBuildingType] = useState<keyof typeof TOWER_TYPES | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;

    const engine = new GameEngine(canvasRef.current, (state) => {
      setGameState(state);
    });
    engineRef.current = engine;

    return () => {
      // Cleanup
    };
  }, []);

  // Update engine pause state when menu toggles
  useEffect(() => {
    if (engineRef.current) {
      engineRef.current.setPaused(isSkillTreeOpen);
    }
  }, [isSkillTreeOpen]);

  const handleClick = (e: React.MouseEvent) => {
    audio.enable();

    if (!engineRef.current || isSkillTreeOpen || (gameState && gameState.isGameOver)) return;

    const rect = canvasRef.current!.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    if (buildingType) {
      const success = engineRef.current.buyTower(buildingType, x, y);
      if (success) setBuildingType(null);
    } else {
      engineRef.current.handleClick(x, y);
    }
  };

  const handleBuildTower = (type: keyof typeof TOWER_TYPES) => {
    audio.enable();
    setBuildingType(type);
  };

  const handleUpgrade = (skillId: string) => {
    if (engineRef.current) {
      const onUnlock = (s: GameState) => {
        if (skillId === 'click_1') s.clickPower *= 2;
        if (skillId === 'massive_click') s.clickPower *= 6;
        if (skillId === 'tower_range_1') s.towers.forEach((t: any) => t.range *= 1.2);
        if (skillId === 'tower_dmg_1') s.towers.forEach((t: any) => t.damage *= 1.4);
        if (skillId === 'core_plating') {
           s.maxCoreHp += 1000;
           s.coreHp += 1000;
        }

        if (skillId === 'tech_range') s.towers.forEach((t: any) => t.range *= 1.35);
        if (skillId === 'tech_speed') s.towers.forEach((t: any) => t.fireRate *= 0.7);
        if (skillId === 'tech_click_god') s.clickPower *= 10;
        if (skillId === 'tech_tower_god') s.towers.forEach((t: any) => t.damage *= 3);
        if (skillId === 'tech_god') {
            s.clickPower *= 5;
            s.towers.forEach((t: any) => t.damage *= 5);
        }
      };
      engineRef.current.applySkill(skillId, onUnlock);
    }
  };

  const handleReroll = () => {
    if (engineRef.current) {
      engineRef.current.rerollSkills();
    }
  };

  const handleRestart = () => {
    if (engineRef.current) {
      engineRef.current.reset();
    }
  };

  const handleBuyPermanent = (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => {
    if (engineRef.current) {
      engineRef.current.buyPermanentUpgrade(type);
    }
  };

  return (
    <div className="relative w-screen h-screen bg-slate-950 overflow-hidden select-none cursor-crosshair">
      <canvas
        ref={canvasRef}
        onClick={handleClick}
        className="block w-full h-full"
      />

      {gameState && (
        <>
          <UIOverlay 
            state={gameState} 
            onBuildTower={handleBuildTower}
            onOpenSkills={() => {
              audio.enable();
              setIsSkillTreeOpen(true);
            }}
            onRestart={handleRestart}
            onBuyPermanent={handleBuyPermanent}
          />
          <SkillTree 
            state={gameState}
            isOpen={isSkillTreeOpen}
            onClose={() => setIsSkillTreeOpen(false)}
            onUpgrade={handleUpgrade}
            onReroll={handleReroll}
          />
        </>
      )}

      {buildingType && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-sky-500 text-slate-900 px-6 py-2 rounded-full font-bold shadow-[0_0_30px_rgba(56,189,248,0.5)] animate-pulse pointer-events-none z-40 flex items-center gap-2">
          <Target className="w-5 h-5" /> 
          PLACING {TOWER_TYPES[buildingType].name} - CLICK TO DEPLOY
        </div>
      )}

      <div className="fixed inset-0 pointer-events-none opacity-30 bg-[radial-gradient(circle_at_center,_transparent_0%,_#020617_100%)]" />
    </div>
  );
};

export default App;

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;

    // 1. Base Passive Trickle
    state.code = Math.max(0, state.code + (5 + state.level) * (dt / 1000));

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied & Enemy)
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;

      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        // Enemy virus projectiles target the core
        targetPos = { x: cx, y: cy };
      }

      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 60) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code += Math.max(0, proj.damage * 0.05); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          // Virus hit core
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id && e1.hp > 0 && e2.hp > 0 && e1.type === e2.type) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(e1.type === 'boss' ? 400 : 150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      // Large vacuum radius for auto-collect
      const vacuumRadius = (hasAutoCollect ? 2500 : 0) / cameraScale;
      const vacuumSpeed = 30;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Specialized Behaviors
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Core collision
      if (dist < (enemy.type === 'boss' ? 150 : 85)) {
        state.coreHp -= (enemy.type === 'boss' ? 500 : 25) + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) {
          state.coreHp = 0;
          state.isGameOver = true;
        }
        return;
      }

      // Behavior: Glitch (Disables nearby towers)
      if (enemy.type === 'glitch') {
        const glitchAura = 300;
        state.towers.forEach(t => {
          const tDist = Math.sqrt((t.x - enemy.x) ** 2 + (t.y - enemy.y) ** 2);
          if (tDist < glitchAura) {
            t.disabledUntil = now + 1000; // Disable for 1 second while in aura
          }
        });
      }

      // Behavior: Boss (Fires projectiles)
      if (enemy.type === 'boss') {
        if (!enemy.nextAttackTime) enemy.nextAttackTime = now + 2000;
        if (now > enemy.nextAttackTime) {
          state.projectiles.push({
            id: Math.random().toString(36),
            targetId: 'core',
            x: enemy.x,
            y: enemy.y,
            speed: 5,
            damage: 50 + (state.level * 10),
            color: COLORS.BOSS,
            type: 'enemy'
          });
          enemy.nextAttackTime = now + (3000 - Math.min(2000, state.level * 100));
        }
      }

      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory) return false;
    let hitSomething = false;
    const now = Date.now();

    const dropCollectionRadius = 50 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    const splashRadius = 120 + (state.level * 4);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        state.code += 5;

        if (damageMult > 0.75) {
          hitSomething = true;
          onEnemyHit(enemy);
        }
        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;
    const now = Date.now();
    state.towers.forEach(tower => {
      // Check if tower is disabled by Glitch
      if (tower.disabledUntil && now < tower.disabledUntil) return;

      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (e.hp > 0 && Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            if (e.hp <= 0) return;
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            const actualDmg = Math.max(0, Math.min(target.hp, tower.damage));
            target.hp -= tower.damage;

            state.code += actualDmg * 0.05;
            state.experience += Math.max(0, tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier);

            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);

            if (target.hp <= 0) {
              const isEnemy = 'type' in target;
              const isPlanet = 'isCaptured' in target;

              if (isEnemy && !(target as any)._processed) {
                this.processEnemyDeath(state, target as Enemy, false);
                this.checkLevelUp(state, onLevelUp);
              } else if (isPlanet && !(target as Planet).isCaptured) {
                this.capturePlanet(state, target as Planet, onLevelUp);
              }
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += 2500 * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        // Make future SP slightly easier to acquire
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
      }
    } else if (d.type === 'loc') {
      state.code += Math.max(0, 500 + (state.level * 100));
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    // Boss rewards
    if (enemy.type === 'boss') rewardMult *= 10;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code += Math.max(0, Math.floor(enemy.value * rewardMult));

    // Towers grant small direct SP progress on every kill
    if (!isManual) {
        state.spProgress += 0.2;
    } else {
        state.spProgress += 0.1;
    }

    // Check if SP goal is reached from direct progress
    if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress -= state.spGoal;
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
    }

    const rand = Math.random();
    // Increased shard chances to make skill points less rare
    let shardChance = isManual ? 0.6 : 0.4;
    if (state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    // Bosses always drop several shards
    if (enemy.type === 'boss') {
      for (let i = 0; i < 8; i++) {
        state.drops.push({ 
          id: Math.random().toString(36), 
          name: 'Core Shard', 
          type: 'shard', 
          rarity: 'rare', 
          effect: 'SP', 
          x: enemy.x + (Math.random() - 0.5) * 150, 
          y: enemy.y + (Math.random() - 0.5) * 150, 
          life: 3.0 
        });
      }
    } else if (rand < shardChance) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Shard', 
        type: 'shard', 
        rarity: 'common', 
        effect: 'SP', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.5 
      });
    } else if (rand < 0.65) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Data', 
        type: 'loc', 
        rarity: 'common', 
        effect: 'LOC', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.5 
      });
    }

    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;

    // 1. Base Passive Trickle
    state.code = Math.max(0, state.code + (5 + state.level) * (dt / 1000));

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied & Enemy)
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;

      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        // Enemy virus projectiles target the core
        targetPos = { x: cx, y: cy };
      }

      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 60) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code += Math.max(0, proj.damage * 0.05); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          // Virus hit core
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id && e1.hp > 0 && e2.hp > 0 && e1.type === e2.type) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(e1.type === 'boss' ? 400 : 150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      // Large vacuum radius for auto-collect
      const vacuumRadius = (hasAutoCollect ? 2500 : 0) / cameraScale;
      const vacuumSpeed = 30;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Specialized Behaviors
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Core collision
      if (dist < (enemy.type === 'boss' ? 150 : 85)) {
        state.coreHp -= (enemy.type === 'boss' ? 500 : 25) + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) {
          state.coreHp = 0;
          state.isGameOver = true;
        }
        return;
      }

      // Behavior: Glitch (Disables nearby towers)
      if (enemy.type === 'glitch') {
        const glitchAura = 300;
        state.towers.forEach(t => {
          const tDist = Math.sqrt((t.x - enemy.x) ** 2 + (t.y - enemy.y) ** 2);
          if (tDist < glitchAura) {
            t.disabledUntil = now + 1000; // Disable for 1 second while in aura
          }
        });
      }

      // Behavior: Boss (Fires projectiles)
      if (enemy.type === 'boss') {
        if (!enemy.nextAttackTime) enemy.nextAttackTime = now + 2000;
        if (now > enemy.nextAttackTime) {
          state.projectiles.push({
            id: Math.random().toString(36),
            targetId: 'core',
            x: enemy.x,
            y: enemy.y,
            speed: 5,
            damage: 25 + (state.level * 5), // Reduced projectile damage
            color: COLORS.BOSS,
            type: 'enemy'
          });
          enemy.nextAttackTime = now + (4000 - Math.min(3000, state.level * 100)); // Slower attack rate
        }
      }

      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory) return false;
    let hitSomething = false;
    const now = Date.now();

    // 1. Intercept Enemy Projectiles (Purple Balls)
    const projInterceptRadius = 40 / cameraScale;
    const initialProjCount = state.projectiles.length;
    state.projectiles = state.projectiles.filter(p => {
      if (p.type !== 'enemy') return true;
      const dist = Math.sqrt((p.x - worldX) ** 2 + (p.y - worldY) ** 2);
      if (dist < projInterceptRadius) {
        state.code += 100; // Reward for intercepting
        hitSomething = true;
        return false;
      }
      return true;
    });

    // 2. Collect Drops
    const dropCollectionRadius = 50 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    // 3. Hit Enemies
    const splashRadius = 120 + (state.level * 4);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 60 ? 1.0 : (1 - (dist / splashRadius)) * 0.8;
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        state.code += 5;

        if (damageMult > 0.75) {
          hitSomething = true;
          onEnemyHit(enemy);
        }
        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;
    const now = Date.now();
    state.towers.forEach(tower => {
      // Check if tower is disabled by Glitch
      if (tower.disabledUntil && now < tower.disabledUntil) return;

      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (e.hp > 0 && Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            if (e.hp <= 0) return;
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            const actualDmg = Math.max(0, Math.min(target.hp, tower.damage));
            target.hp -= tower.damage;

            state.code += actualDmg * 0.05;
            state.experience += Math.max(0, tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier);

            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);

            if (target.hp <= 0) {
              const isEnemy = 'type' in target;
              const isPlanet = 'isCaptured' in target;

              if (isEnemy && !(target as any)._processed) {
                this.processEnemyDeath(state, target as Enemy, false);
                this.checkLevelUp(state, onLevelUp);
              } else if (isPlanet && !(target as Planet).isCaptured) {
                this.capturePlanet(state, target as Planet, onLevelUp);
              }
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += 2500 * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        // Make future SP slightly easier to acquire
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
      }
    } else if (d.type === 'loc') {
      state.code += Math.max(0, 500 + (state.level * 100));
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    // Boss rewards
    if (enemy.type === 'boss') rewardMult *= 10;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code += Math.max(0, Math.floor(enemy.value * rewardMult));

    // Towers grant small direct SP progress on every kill
    if (!isManual) {
        state.spProgress += 0.2;
    } else {
        state.spProgress += 0.1;
    }

    // Check if SP goal is reached from direct progress
    if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress -= state.spGoal;
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
    }

    const rand = Math.random();
    // Increased shard chances to make skill points less rare
    let shardChance = isManual ? 0.6 : 0.4;
    if (state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    // Bosses always drop several shards
    if (enemy.type === 'boss') {
      for (let i = 0; i < 8; i++) {
        state.drops.push({ 
          id: Math.random().toString(36), 
          name: 'Core Shard', 
          type: 'shard', 
          rarity: 'rare', 
          effect: 'SP', 
          x: enemy.x + (Math.random() - 0.5) * 150, 
          y: enemy.y + (Math.random() - 0.5) * 150, 
          life: 3.0 
        });
      }
    } else if (rand < shardChance) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Shard', 
        type: 'shard', 
        rarity: 'common', 
        effect: 'SP', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.5 
      });
    } else if (rand < 0.65) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Data', 
        type: 'loc', 
        rarity: 'common', 
        effect: 'LOC', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.5 
      });
    }

    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 4000 + (this.state.level * 300),
        maxHp: 4000 + (this.state.level * 300),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const missReward = 50 + (this.state.level * 5);
      this.state.code += missReward;
      this.createFloatingText(worldX, worldY, `+${missReward}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
      // Spawn a Boss immediately on level up milestones
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;

    if (!this.isPaused) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    // Logic updates
    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
        if (target.hp <= 0) {
           audio.playDeath();
        }
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const legacyFactor = this.state.isVictory ? 25 : 1;
      const earnedLegacy = Math.max(0, (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor);
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) {
      return; 
    }

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    // Passive Income Handlers
    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250;
        if (this.state.unlockedSkills.includes('code_gen')) gain += 1000; 
        this.state.code += Math.max(0, gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    // Spawn Enemies
    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      // Determine enemy type
      let type: 'bug' | 'glitch' = 'bug';
      if (this.state.level >= 3 && Math.random() < 0.15) {
        type = 'glitch';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    // Particles life
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3000 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    // Lowered initial Boss HP to make first encounter fair
    const hp = 12000 * Math.pow(1.3, this.state.level / 5);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 0.8 + (this.state.level * 0.02), value: 20000 + this.state.level * 5000, 
      type: 'boss', size: 300, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "BOSS DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: 'bug' | 'glitch' = 'bug') {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }
    // Glitch HP also lowered slightly
    const hp = (type === 'glitch' ? 300 : 100) * Math.pow(1.12, this.state.level);
    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: (type === 'glitch' ? 2.5 : 1.7) + (this.state.level * 0.05), value: (type === 'glitch' ? 1000 : 200) + this.state.level * 80, 
      type, size: (type === 'glitch' ? 60 : 45) + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

import { GameState } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();

    // Screen Shake
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.9;
      if (this.screenShake < 0.1) this.screenShake = 0;
    }

    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. Planets
    state.planets.forEach(p => {
      const grad = this.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size);
      grad.addColorStop(0, p.isCaptured ? '#0c4a6e' : '#450a0a');
      grad.addColorStop(0.9, '#020617');
      this.ctx.fillStyle = grad;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = p.isCaptured ? COLORS.PRIMARY : COLORS.ENEMY;
      this.ctx.lineWidth = 15; this.ctx.globalAlpha = 0.2;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 25, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = '#fff'; this.ctx.font = 'bold 50px Space Grotesk'; this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // 2. Firing Effects
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.save();
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.shadowBlur = 15;
      this.ctx.shadowColor = ef.color;

      if (ef.type === 'SNIPER') {
        this.ctx.lineWidth = 6 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
        this.ctx.strokeStyle = '#fff';
        this.ctx.lineWidth = 2 * ef.life;
        this.ctx.stroke();
      } else if (ef.type === 'RAPID') {
        this.ctx.lineWidth = 2;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
        this.ctx.fillStyle = ef.color;
        this.ctx.beginPath();
        this.ctx.arc(ef.x2, ef.y2, 10 * (1 - ef.life), 0, Math.PI * 2);
        this.ctx.fill();
      } else if (ef.type === 'AOE') {
        this.ctx.lineWidth = 8 * ef.life;
        this.ctx.beginPath();
        this.ctx.arc(ef.x1, ef.y1, (1 - ef.life) * 400, 0, Math.PI * 2);
        this.ctx.stroke();
      } else {
        this.ctx.lineWidth = 3 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
      }

      this.ctx.restore();
      ef.life -= 0.12;
      return ef.life > 0;
    });

    // 3. Core
    const coreSize = 90 + (state.level * 0.6);
    this.ctx.fillStyle = state.threatLevel > 15 ? COLORS.ENEMY : COLORS.PRIMARY;
    this.ctx.shadowBlur = 80; this.ctx.shadowColor = this.ctx.fillStyle as string;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 4. Drops
    state.drops.forEach(d => {
      this.ctx.save();
      this.ctx.shadowBlur = 15;
      this.ctx.shadowColor = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : d.type === 'loc' ? COLORS.PRIMARY : COLORS.ACCENT;
      if (d.type === 'shard') {
        this.ctx.beginPath();
        this.ctx.moveTo(d.x, d.y - 12); this.ctx.lineTo(d.x + 12, d.y);
        this.ctx.lineTo(d.x, d.y + 12); this.ctx.lineTo(d.x - 12, d.y);
        this.ctx.closePath(); this.ctx.fill();
      } else {
        this.ctx.fillRect(d.x - 10, d.y - 10, 20, 20);
      }
      this.ctx.restore();
    });

    // 5. Ripples
    state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; this.ctx.lineWidth = 8;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    // 6. Enemies
    state.enemies.forEach(e => {
      const isHit = Date.now() - (e.lastHit || 0) < 100;
      const scale = isHit ? 1.3 : 1.0;
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      if (e.type === 'glitch') {
        const jitterX = (Math.random() - 0.5) * 10;
        const jitterY = (Math.random() - 0.5) * 10;
        this.ctx.translate(jitterX, jitterY);
        this.ctx.scale(scale * (0.8 + Math.random() * 0.4), scale);

        this.ctx.strokeStyle = '#00ffcc';
        this.ctx.lineWidth = 2;
        this.ctx.setLineDash([5, 5]);
        this.ctx.beginPath();
        this.ctx.arc(0, 0, 300, 0, Math.PI * 2);
        this.ctx.stroke();
        this.ctx.setLineDash([]);
      } else if (e.type === 'boss') {
        this.ctx.scale(scale, scale);
        this.ctx.shadowBlur = 40;
        this.ctx.shadowColor = COLORS.BOSS;
      } else {
        this.ctx.scale(scale, scale);
      }

      this.ctx.fillStyle = isHit ? '#fff' : (e.type === 'boss' ? COLORS.BOSS : e.type === 'glitch' ? '#00ffcc' : COLORS.ENEMY);

      if (e.type === 'boss') {
        const hpPercent = e.hp / e.maxHp;
        this.ctx.save();
        this.ctx.rotate(-e.angle);
        this.ctx.fillStyle = '#444';
        this.ctx.fillRect(-200, -250, 400, 20);
        this.ctx.fillStyle = COLORS.BOSS;
        this.ctx.fillRect(-200, -250, 400 * Math.max(0, hpPercent), 20);
        this.ctx.restore();

        this.ctx.beginPath();
        this.ctx.moveTo(e.size, 0);
        this.ctx.lineTo(-e.size / 3, e.size / 2);
        this.ctx.lineTo(-e.size, 0);
        this.ctx.lineTo(-e.size / 3, -e.size / 2);
        this.ctx.closePath();
      } else if (e.type === 'glitch') {
        this.ctx.beginPath();
        this.ctx.moveTo(0, -e.size);
        this.ctx.lineTo(e.size, 0);
        this.ctx.lineTo(0, e.size);
        this.ctx.lineTo(-e.size, 0);
        this.ctx.closePath();
      } else {
        this.ctx.beginPath();
        this.ctx.moveTo(e.size, 0);
        this.ctx.lineTo(-e.size / 2, e.size / 2);
        this.ctx.lineTo(-e.size / 2, -e.size / 2);
        this.ctx.closePath();
      }

      this.ctx.fill();
      this.ctx.restore();
    });

    // 7. Projectiles (Interceptive "Purple Balls")
    state.projectiles.forEach(p => {
      this.ctx.save();
      this.ctx.fillStyle = p.color;
      this.ctx.shadowBlur = 10;
      this.ctx.shadowColor = p.color;

      let radius = p.type === 'enemy' ? 20 : 10;
      if (p.type === 'enemy') {
        // Add a pulsing effect to make them look clickable and dangerous
        radius += Math.sin(now / 100) * 5;
        this.ctx.lineWidth = 3;
        this.ctx.strokeStyle = '#fff';
        this.ctx.beginPath(); 
        this.ctx.arc(p.x, p.y, radius + 5, 0, Math.PI * 2); 
        this.ctx.stroke();
      }

      this.ctx.beginPath(); 
      this.ctx.arc(p.x, p.y, radius, 0, Math.PI * 2); 
      this.ctx.fill();
      this.ctx.restore();
    });

    // 8. Towers
    state.towers.forEach(t => {
      const isDisabled = t.disabledUntil && now < t.disabledUntil;

      if (isDisabled) {
        this.ctx.save();
        this.ctx.fillStyle = '#333';
        this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);
        for (let i = 0; i < 5; i++) {
          this.ctx.fillStyle = Math.random() > 0.5 ? '#fff' : '#000';
          this.ctx.fillRect(t.x - 30 + Math.random() * 60, t.y - 30 + Math.random() * 60, 10, 2);
        }
        this.ctx.restore();
      } else {
        this.ctx.fillStyle = t.color;
        this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);
        this.ctx.strokeStyle = t.color; this.ctx.lineWidth = 1; this.ctx.globalAlpha = 0.1;
        this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
        this.ctx.globalAlpha = 1.0;
      }
    });

    // 9. Particles & Floating Text
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${p.size}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      }
      this.ctx.globalAlpha = 1.0;
    });

    this.ctx.restore();

    if (isPaused || state.isGameOver || state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.7)';
      this.ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;

    // 1. Base Passive Trickle
    state.code = Math.max(0, state.code + (5 + state.level) * (dt / 1000));

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied & Enemy)
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;

      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        // Enemy virus projectiles target the core
        targetPos = { x: cx, y: cy };
      }

      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 60) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code += Math.max(0, proj.damage * 0.05); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          // Virus hit core
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id && e1.hp > 0 && e2.hp > 0 && e1.type === e2.type) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(e1.type === 'boss' ? 400 : 150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 2500 : 0) / cameraScale;
      const vacuumSpeed = 30;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Specialized Behaviors
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Core collision
      if (dist < (enemy.type === 'boss' ? 150 : 85)) {
        state.coreHp -= (enemy.type === 'boss' ? 500 : 25) + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) {
          state.coreHp = 0;
          state.isGameOver = true;
        }
        return;
      }

      // Behavior: Glitch (Disables nearby towers)
      if (enemy.type === 'glitch') {
        const glitchAura = 250; // Reduced radius
        state.towers.forEach(t => {
          const tDist = Math.sqrt((t.x - enemy.x) ** 2 + (t.y - enemy.y) ** 2);
          if (tDist < glitchAura) {
            t.disabledUntil = now + 500; // Shorter disable
          }
        });
      }

      // Behavior: Boss (Fires projectiles)
      if (enemy.type === 'boss') {
        if (!enemy.nextAttackTime) enemy.nextAttackTime = now + 2000;
        if (now > enemy.nextAttackTime) {
          state.projectiles.push({
            id: Math.random().toString(36),
            targetId: 'core',
            x: enemy.x,
            y: enemy.y,
            speed: 3.5, // Even slower for readability
            damage: 20 + (state.level * 3), 
            color: COLORS.BOSS,
            type: 'enemy'
          });
          enemy.nextAttackTime = now + (5000 - Math.min(3000, state.level * 100));
        }
      }

      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory) return false;
    let hitSomething = false;
    const now = Date.now();

    // 1. Intercept Enemy Projectiles (Purple Balls)
    // Generous hitbox for projectiles
    const projInterceptRadius = 80 / cameraScale;
    state.projectiles = state.projectiles.filter(p => {
      if (p.type !== 'enemy') return true;
      const dist = Math.sqrt((p.x - worldX) ** 2 + (p.y - worldY) ** 2);
      if (dist < projInterceptRadius) {
        state.code += 500; // High reward for active defense
        state.experience += 50;
        hitSomething = true;
        return false;
      }
      return true;
    });

    // 2. Collect Drops
    const dropCollectionRadius = 100 / cameraScale; // Larger drop pickup on click
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    // 3. Hit Enemies
    // Massive splash radius to help clear glitch/boss mobs
    const splashRadius = 180 + (state.level * 5);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        // Linear falloff but higher floor (0.5 minimum damage if in splash)
        const damageMult = dist < 80 ? 1.0 : Math.max(0.5, (1 - (dist / splashRadius)));
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        state.code += 5;

        hitSomething = true;
        onEnemyHit(enemy);

        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;
    const now = Date.now();
    state.towers.forEach(tower => {
      if (tower.disabledUntil && now < tower.disabledUntil) return;

      if (now - tower.lastFired > tower.fireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (e.hp > 0 && Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < tower.range) targets.push(e);
          });
        } else {
          let minDist = tower.range;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            if (e.hp <= 0) return;
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            const actualDmg = Math.max(0, Math.min(target.hp, tower.damage));
            target.hp -= tower.damage;

            state.code += actualDmg * 0.05;
            state.experience += Math.max(0, tower.damage * 0.15 * state.permanentUpgrades.xpMultiplier);

            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);

            if (target.hp <= 0) {
              const isEnemy = 'type' in target;
              const isPlanet = 'isCaptured' in target;

              if (isEnemy && !(target as any)._processed) {
                this.processEnemyDeath(state, target as Enemy, false);
                this.checkLevelUp(state, onLevelUp);
              } else if (isPlanet && !(target as Planet).isCaptured) {
                this.capturePlanet(state, target as Planet, onLevelUp);
              }
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += 2500 * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
      }
    } else if (d.type === 'loc') {
      state.code += Math.max(0, 500 + (state.level * 100));
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    if (enemy.type === 'boss') rewardMult *= 10;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code += Math.max(0, Math.floor(enemy.value * rewardMult));

    if (!isManual) {
        state.spProgress += 0.2;
    } else {
        state.spProgress += 0.1;
    }

    if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress -= state.spGoal;
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
    }

    const rand = Math.random();
    let shardChance = isManual ? 0.6 : 0.4;
    if (state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    if (enemy.type === 'boss') {
      for (let i = 0; i < 8; i++) {
        state.drops.push({ 
          id: Math.random().toString(36), 
          name: 'Core Shard', 
          type: 'shard', 
          rarity: 'rare', 
          effect: 'SP', 
          x: enemy.x + (Math.random() - 0.5) * 150, 
          y: enemy.y + (Math.random() - 0.5) * 150, 
          life: 3.0 
        });
      }
    } else if (rand < shardChance) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Shard', 
        type: 'shard', 
        rarity: 'common', 
        effect: 'SP', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.5 
      });
    } else if (rand < 0.65) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Data', 
        type: 'loc', 
        rarity: 'common', 
        effect: 'LOC', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.5 
      });
    }

    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 3000 + (this.state.level * 200),
        maxHp: 3000 + (this.state.level * 200),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const missReward = 50 + (this.state.level * 5);
      this.state.code += missReward;
      this.createFloatingText(worldX, worldY, `+${missReward}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;

    if (!this.isPaused) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
        if (target.hp <= 0) {
           audio.playDeath();
        }
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const legacyFactor = this.state.isVictory ? 25 : 1;
      const earnedLegacy = Math.max(0, (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor);
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) {
      return; 
    }

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250;
        if (this.state.unlockedSkills.includes('code_gen')) gain += 1000; 
        this.state.code += Math.max(0, gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      let type: 'bug' | 'glitch' = 'bug';
      if (this.state.level >= 3 && Math.random() < 0.12) {
        type = 'glitch';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3000 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;

    // SIGNIFICANTLY LOWERED HP FOR PLAYABILITY
    // Was 12000, now 2000 base. Even at level 10 it will be manageable.
    const hp = 2000 * Math.pow(1.2, this.state.level / 5);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 0.6 + (this.state.level * 0.02), value: 20000 + this.state.level * 5000, 
      type: 'boss', size: 300, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "BOSS DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: 'bug' | 'glitch' = 'bug') {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }

    // LOWERED ENEMY HP SCALING
    const hpBase = type === 'glitch' ? 80 : 40;
    const hp = hpBase * Math.pow(1.08, this.state.level);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: (type === 'glitch' ? 1.8 : 1.4) + (this.state.level * 0.04), value: (type === 'glitch' ? 1000 : 200) + this.state.level * 80, 
      type, size: (type === 'glitch' ? 60 : 45) + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

import { GameState } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 50; // Performance cap

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();

    // Fast clear
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();

    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.9;
      if (this.screenShake < 0.1) this.screenShake = 0;
    }

    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. Planets - Simplified Glow
    state.planets.forEach(p => {
      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#450a0a';
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();

      this.ctx.strokeStyle = p.isCaptured ? COLORS.PRIMARY : COLORS.ENEMY;
      this.ctx.lineWidth = 4;
      this.ctx.globalAlpha = 0.3;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 15, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;

      this.ctx.fillStyle = '#fff'; 
      this.ctx.font = 'bold 50px Space Grotesk'; 
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // 2. Firing Effects - Optimized lines
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;

      if (ef.type === 'SNIPER') {
        this.ctx.lineWidth = 4 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
      } else if (ef.type === 'RAPID') {
        this.ctx.lineWidth = 2;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
      } else if (ef.type === 'AOE') {
        this.ctx.lineWidth = 4 * ef.life;
        this.ctx.beginPath();
        this.ctx.arc(ef.x1, ef.y1, (1 - ef.life) * 300, 0, Math.PI * 2);
        this.ctx.stroke();
      } else {
        this.ctx.lineWidth = 2 * ef.life;
        this.ctx.beginPath();
        this.ctx.moveTo(ef.x1, ef.y1);
        this.ctx.lineTo(ef.x2, ef.y2);
        this.ctx.stroke();
      }

      ef.life -= 0.15;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // 3. Core - Keep Core Glow as it's a single object
    const coreSize = 90 + (state.level * 0.6);
    this.ctx.fillStyle = state.threatLevel > 15 ? COLORS.ENEMY : COLORS.PRIMARY;
    this.ctx.shadowBlur = 40; 
    this.ctx.shadowColor = this.ctx.fillStyle as string;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0; // Turn off immediately

    // 4. Drops
    state.drops.forEach(d => {
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : d.type === 'loc' ? COLORS.PRIMARY : COLORS.ACCENT;
      if (d.type === 'shard') {
        this.ctx.beginPath();
        this.ctx.moveTo(d.x, d.y - 12); this.ctx.lineTo(d.x + 12, d.y);
        this.ctx.lineTo(d.x, d.y + 12); this.ctx.lineTo(d.x - 12, d.y);
        this.ctx.closePath(); this.ctx.fill();
      } else {
        this.ctx.fillRect(d.x - 10, d.y - 10, 20, 20);
      }
    });

    // 5. Ripples
    state.ripples.forEach(r => {
      this.ctx.strokeStyle = `rgba(56, 189, 248, ${r.life})`; 
      this.ctx.lineWidth = 4;
      this.ctx.beginPath(); this.ctx.arc(r.x, r.y, r.radius, 0, Math.PI * 2); this.ctx.stroke();
    });

    // 6. Enemies
    state.enemies.forEach(e => {
      const isHit = Date.now() - (e.lastHit || 0) < 100;
      const scale = isHit ? 1.2 : 1.0;
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      if (e.type === 'glitch') {
        const jitterX = (Math.random() - 0.5) * 5;
        this.ctx.translate(jitterX, 0);
        this.ctx.scale(scale, scale);

        this.ctx.strokeStyle = '#00ffcc';
        this.ctx.lineWidth = 1;
        this.ctx.beginPath();
        this.ctx.arc(0, 0, 250, 0, Math.PI * 2);
        this.ctx.stroke();
      } else if (e.type === 'boss') {
        this.ctx.scale(scale, scale);
        this.ctx.shadowBlur = 30; // Bosses get glow
        this.ctx.shadowColor = COLORS.BOSS;
      } else {
        this.ctx.scale(scale, scale);
      }

      this.ctx.fillStyle = isHit ? '#fff' : (e.type === 'boss' ? COLORS.BOSS : e.type === 'glitch' ? '#00ffcc' : COLORS.ENEMY);

      if (e.type === 'boss') {
        const hpPercent = e.hp / e.maxHp;
        this.ctx.save();
        this.ctx.rotate(-e.angle);
        this.ctx.fillStyle = '#1e293b';
        this.ctx.fillRect(-200, -250, 400, 15);
        this.ctx.fillStyle = COLORS.BOSS;
        this.ctx.fillRect(-200, -250, 400 * Math.max(0, hpPercent), 15);
        this.ctx.restore();

        this.ctx.beginPath();
        this.ctx.moveTo(e.size, 0);
        this.ctx.lineTo(-e.size / 3, e.size / 2);
        this.ctx.lineTo(-e.size, 0);
        this.ctx.lineTo(-e.size / 3, -e.size / 2);
        this.ctx.closePath();
      } else if (e.type === 'glitch') {
        this.ctx.beginPath();
        this.ctx.moveTo(0, -e.size);
        this.ctx.lineTo(e.size, 0);
        this.ctx.lineTo(0, e.size);
        this.ctx.lineTo(-e.size, 0);
        this.ctx.closePath();
      } else {
        this.ctx.beginPath();
        this.ctx.moveTo(e.size, 0);
        this.ctx.lineTo(-e.size / 2, e.size / 2);
        this.ctx.lineTo(-e.size / 2, -e.size / 2);
        this.ctx.closePath();
      }

      this.ctx.fill();
      this.ctx.restore();
      this.ctx.shadowBlur = 0;
    });

    // 7. Projectiles
    state.projectiles.forEach(p => {
      this.ctx.fillStyle = p.color;
      let radius = p.type === 'enemy' ? 15 : 8;
      if (p.type === 'enemy') {
        radius += Math.sin(now / 150) * 4;
        this.ctx.strokeStyle = '#fff';
        this.ctx.lineWidth = 2;
        this.ctx.beginPath(); 
        this.ctx.arc(p.x, p.y, radius + 3, 0, Math.PI * 2); 
        this.ctx.stroke();
      }
      this.ctx.beginPath(); 
      this.ctx.arc(p.x, p.y, radius, 0, Math.PI * 2); 
      this.ctx.fill();
    });

    // 8. Towers
    state.towers.forEach(t => {
      const isDisabled = t.disabledUntil && now < t.disabledUntil;

      if (isDisabled) {
        this.ctx.fillStyle = '#1e293b';
        this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);
        this.ctx.fillStyle = '#fff';
        for (let i = 0; i < 3; i++) {
           this.ctx.fillRect(t.x - 20 + Math.random() * 40, t.y - 20 + Math.random() * 40, 5, 2);
        }
      } else {
        this.ctx.fillStyle = t.color;
        this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);
        this.ctx.strokeStyle = t.color; 
        this.ctx.lineWidth = 1; 
        this.ctx.globalAlpha = 0.1;
        this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
        this.ctx.globalAlpha = 1.0;
      }
    });

    // 9. Particles
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${p.size}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      }
    });
    this.ctx.globalAlpha = 1.0;

    this.ctx.restore();

    if (isPaused || state.isGameOver || state.isVictory) {
      this.ctx.fillStyle = 'rgba(2, 6, 23, 0.7)';
      this.ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resize();
    window.addEventListener('resize', () => this.resize());
    this.animate(0);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 3000 + (this.state.level * 200),
        maxHp: 3000 + (this.state.level * 200),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const missReward = 50 + (this.state.level * 5);
      this.state.code += missReward;
      this.createFloatingText(worldX, worldY, `+${missReward}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });

    // Immediate update for clicks to feel responsive
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;

    if (!this.isPaused) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
        if (target.hp <= 0) {
           audio.playDeath();
        }
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const legacyFactor = this.state.isVictory ? 25 : 1;
      const earnedLegacy = Math.max(0, (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor);
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) {
      return; 
    }

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250;
        if (this.state.unlockedSkills.includes('code_gen')) gain += 1000; 
        this.state.code += Math.max(0, gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      let type: 'bug' | 'glitch' = 'bug';
      if (this.state.level >= 3 && Math.random() < 0.12) {
        type = 'glitch';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    // THROTTLE REACT UPDATE: Only notify React every 2nd frame (~30FPS bridge) 
    // This significantly helps performance during intensive late-game bursts.
    if (this.frameCount % 2 === 0) {
      this.onUpdate({ ...this.state });
    }
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3000 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const hp = 2000 * Math.pow(1.2, this.state.level / 5);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 0.6 + (this.state.level * 0.02), value: 20000 + this.state.level * 5000, 
      type: 'boss', size: 300, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "BOSS DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: 'bug' | 'glitch' = 'bug') {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }

    const hpBase = type === 'glitch' ? 80 : 40;
    const hp = hpBase * Math.pow(1.08, this.state.level);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: (type === 'glitch' ? 1.8 : 1.4) + (this.state.level * 0.04), value: (type === 'glitch' ? 1000 : 200) + this.state.level * 80, 
      type, size: (type === 'glitch' ? 60 : 45) + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 200) return; // Slightly tighter cap
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private bgmGain: GainNode | null = null;
  private lastPlayTimes: Map<string, number> = new Map();
  private enabled: boolean = false;

  // Sequencer state
  private currentBpm: number = 128;
  private nextNoteTime: number = 0;
  private currentStep: number = 0;
  private lookahead: number = 25.0; // ms
  private scheduleAheadTime: number = 0.1; // seconds
  private timerId: number | null = null;

  // Scales & Patterns (8-bit C minor / Pentatonic vibes)
  private bassScale = [65.41, 77.78, 98.00, 116.54]; // C2, Eb2, G2, Bb2
  private leadScale = [261.63, 311.13, 392.00, 466.16, 523.25]; // C4, Eb4, G4, Bb4, C5

  private bassPattern = [0, 0, 2, 2, 3, 3, 1, 1];
  private leadPattern = [0, -1, 1, -1, 2, 4, 3, -1, 0, 2, 1, -1, 3, -1, 2, -1];

  private COOLDOWNS = {
    fire_basic: 80,
    fire_rapid: 40,
    fire_sniper: 150,
    fire_aoe: 200,
    death: 30,
    click: 50,
    shard: 100,
  };

  constructor() {}

  private init() {
    if (this.ctx) return;
    this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = 0.3;
    this.masterGain.connect(this.ctx.destination);

    this.bgmGain = this.ctx.createGain();
    this.bgmGain.gain.value = 0.08;
    this.bgmGain.connect(this.masterGain);

    this.enabled = true;
    this.scheduler();
  }

  public enable() {
    if (!this.ctx) this.init();
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume();
    }
  }

  public stop() {
    this.enabled = false;
    if (this.timerId !== null) {
      window.clearTimeout(this.timerId);
      this.timerId = null;
    }
    if (this.ctx) {
      this.ctx.close();
      this.ctx = null;
    }
  }

  public updateBPM(level: number) {
    this.currentBpm = Math.min(220, 128 + (level * 1.5));
  }

  private scheduler = () => {
    if (!this.ctx || !this.enabled) return;

    while (this.nextNoteTime < this.ctx.currentTime + this.scheduleAheadTime) {
      this.scheduleNote(this.currentStep, this.nextNoteTime);
      this.advanceNote();
    }
    this.timerId = window.setTimeout(this.scheduler, this.lookahead);
  }

  private advanceNote() {
    const secondsPerBeat = 60.0 / this.currentBpm;
    this.nextNoteTime += 0.25 * secondsPerBeat; // 16th notes
    this.currentStep = (this.currentStep + 1) % 16;
  }

  private scheduleNote(step: number, time: number) {
    if (!this.ctx || !this.bgmGain) return;

    if (step % 2 === 0) {
      const bassIndex = this.bassPattern[(step / 2) % 8];
      if (bassIndex !== -1) {
        this.playPluck(this.bassScale[bassIndex], time, 0.15, 'triangle', 0.4);
      }
    }

    const leadIndex = this.leadPattern[step % 16];
    if (leadIndex !== -1) {
      this.playPluck(this.leadScale[leadIndex], time, 0.1, 'square', 0.2);
    }
  }

  private playPluck(freq: number, time: number, duration: number, type: OscillatorType, volume: number) {
    if (!this.ctx || !this.bgmGain) return;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, time);

    g.gain.setValueAtTime(0, time);
    g.gain.linearRampToValueAtTime(volume, time + 0.01);
    g.gain.exponentialRampToValueAtTime(0.001, time + duration);

    osc.connect(g);
    g.connect(this.bgmGain);

    osc.start(time);
    osc.stop(time + duration);
  }

  private canPlay(key: string): boolean {
    if (!this.enabled) return false;
    const now = Date.now();
    const last = this.lastPlayTimes.get(key) || 0;
    const cooldown = (this.COOLDOWNS as any)[key] || 0;
    if (now - last > cooldown) {
      this.lastPlayTimes.set(key, now);
      return true;
    }
    return false;
  }

  public playFire(type: string) {
    if (!this.ctx || !this.masterGain) return;
    const key = `fire_${type.toLowerCase()}`;
    if (!this.canPlay(key)) return;

    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.connect(g);
    g.connect(this.masterGain);

    const now = this.ctx.currentTime;

    if (type === 'SNIPER') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(800, now);
      osc.frequency.exponentialRampToValueAtTime(40, now + 0.5);
      g.gain.setValueAtTime(0.3, now);
      g.gain.linearRampToValueAtTime(0, now + 0.5);
      osc.start(now);
      osc.stop(now + 0.5);
    } else if (type === 'RAPID') {
      osc.type = 'square';
      osc.frequency.setValueAtTime(1200, now);
      osc.frequency.linearRampToValueAtTime(400, now + 0.05);
      g.gain.setValueAtTime(0.1, now);
      g.gain.linearRampToValueAtTime(0, now + 0.05);
      osc.start(now);
      osc.stop(now + 0.05);
    } else if (type === 'AOE') {
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(100, now);
      osc.frequency.exponentialRampToValueAtTime(400, now + 0.2);
      g.gain.setValueAtTime(0.4, now);
      g.gain.linearRampToValueAtTime(0, now + 0.2);
      osc.start(now);
      osc.stop(now + 0.2);
    } else {
      osc.type = 'square';
      osc.frequency.setValueAtTime(440, now);
      osc.frequency.exponentialRampToValueAtTime(110, now + 0.1);
      g.gain.setValueAtTime(0.2, now);
      g.gain.linearRampToValueAtTime(0, now + 0.1);
      osc.start(now);
      osc.stop(now + 0.1);
    }
  }

  public playDeath() {
    if (!this.ctx || !this.masterGain || !this.canPlay('death')) return;

    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();

    osc.type = 'square';
    osc.frequency.setValueAtTime(100, now);
    osc.frequency.linearRampToValueAtTime(20, now + 0.15);

    g.gain.setValueAtTime(0.15, now);
    g.gain.exponentialRampToValueAtTime(0.01, now + 0.15);

    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.15);
  }

  public playClick() {
    if (!this.ctx || !this.masterGain || !this.canPlay('click')) return;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sine';
    const now = this.ctx.currentTime;
    osc.frequency.setValueAtTime(1200, now);
    osc.frequency.exponentialRampToValueAtTime(1500, now + 0.02);
    g.gain.setValueAtTime(0.1, now);
    g.gain.linearRampToValueAtTime(0, now + 0.02);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.02);
  }

  public playLevelUp() {
    if (!this.ctx || !this.masterGain) return;
    const now = this.ctx.currentTime;
    [440, 554, 659, 880].forEach((f, i) => {
      const osc = this.ctx!.createOscillator();
      const g = this.ctx!.createGain();
      osc.type = 'square';
      osc.frequency.setValueAtTime(f, now + i * 0.1);
      g.gain.setValueAtTime(0.1, now + i * 0.1);
      g.gain.exponentialRampToValueAtTime(0.01, now + i * 0.1 + 0.3);
      osc.connect(g);
      g.connect(this.masterGain!);
      osc.start(now + i * 0.1);
      osc.stop(now + i * 0.1 + 0.3);
    });
  }

  public playGameOver() {
    if (!this.ctx || !this.masterGain) return;
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(220, now);
    osc.frequency.linearRampToValueAtTime(55, now + 1.5);
    g.gain.setValueAtTime(0.3, now);
    g.gain.linearRampToValueAtTime(0, now + 1.5);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 1.5);
  }

  public playShard() {
    if (!this.ctx || !this.masterGain || !this.canPlay('shard')) return;
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(2000, now);
    osc.frequency.exponentialRampToValueAtTime(3000, now + 0.05);
    g.gain.setValueAtTime(0.15, now);
    g.gain.linearRampToValueAtTime(0, now + 0.05);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.05);
  }
}

export const audio = new AudioManager();

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private resizeHandler: () => void;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets();

    this.resizeHandler = () => this.resize();
    this.resize();
    window.addEventListener('resize', this.resizeHandler);
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  public destroy() {
    this.isDestroyed = true;
    window.removeEventListener('resize', this.resizeHandler);
    audio.stop();
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250,
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0 }
    };
  }

  private generatePlanets() {
    const planets: Planet[] = [];
    const dist = 2600; 
    const names = ["NPM-7", "PYPI-Prime", "Maven-Void", "Cargo-Core"];
    for (let i = 0; i < PLANET_COUNT; i++) {
      const angle = (i / PLANET_COUNT) * Math.PI * 2;
      planets.push({
        id: `planet_${i}`, name: names[i],
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: 3000 + (this.state.level * 200),
        maxHp: 3000 + (this.state.level * 200),
        isCaptured: false, size: 350, color: COLORS.ENEMY
      });
    }
    this.state.planets = planets;
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1200 + (perms.startingCode || 0);
    this.state.clickPower = 35 * perms.damageMultiplier;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused || this.isDestroyed) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const missReward = 50 + (this.state.level * 5);
      this.state.code += missReward;
      this.createFloatingText(worldX, worldY, `+${missReward}`, COLORS.PRIMARY);
      audio.playClick();
    }

    if (this.state.ripples.length < 15) {
      this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    }

    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);
    if (this.state.level % 5 === 0) {
      this.targetCameraScale = Math.max(0.08, 1.0 / (1 + (this.state.level / 6)));
      this.state.maxCoreHp += 500; 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused || this.isDestroyed) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      let { damage, range, fireRate } = config;
      damage *= this.state.permanentUpgrades.damageMultiplier;
      if (this.state.unlockedTech.includes('tech_range')) range *= 1.35;
      if (this.state.unlockedTech.includes('tech_speed')) fireRate *= 0.7;
      if (this.state.unlockedTech.includes('tech_tower_god')) damage *= 3;
      if (this.state.unlockedTech.includes('tech_god')) damage *= 5;

      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range, damage, fireRate, lastFired: 0, color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;

    if (!this.isPaused) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
        if (target.hp <= 0) {
           audio.playDeath();
        }
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const legacyFactor = this.state.isVictory ? 25 : 1;
      const earnedLegacy = Math.max(0, (Math.floor(this.state.code / 100) + this.state.level * 15) * legacyFactor);
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) return;

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250;
        if (this.state.unlockedSkills.includes('code_gen')) gain += 1000; 
        this.state.code += Math.max(0, gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(150, 3000 - (this.state.level * 100));
    const threatMult = 1 + (this.state.threatLevel * 0.5);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      let type: 'bug' | 'glitch' = 'bug';
      if (this.state.level >= 3 && Math.random() < 0.12) {
        type = 'glitch';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    // Strict pruning for memory safety
    if (this.state.particles.length > 200) this.state.particles.splice(0, this.state.particles.length - 200);
    if (this.state.projectiles.length > 100) this.state.projectiles.splice(0, this.state.projectiles.length - 100);
    if (this.state.ripples.length > 20) this.state.ripples.splice(0, this.state.ripples.length - 20);

    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    if (this.frameCount % 2 === 0) {
      this.onUpdate({ ...this.state });
    }
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3000 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const hp = 2000 * Math.pow(1.2, this.state.level / 5);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: 0.6 + (this.state.level * 0.02), value: 20000 + this.state.level * 5000, 
      type: 'boss', size: 300, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "BOSS DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: 'bug' | 'glitch' = 'bug') {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }

    const hpBase = type === 'glitch' ? 80 : 40;
    const hp = hpBase * Math.pow(1.08, this.state.level);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp, maxHp: hp, 
      speed: (type === 'glitch' ? 1.8 : 1.4) + (this.state.level * 0.04), value: (type === 'glitch' ? 1000 : 200) + this.state.level * 80, 
      type, size: (type === 'glitch' ? 60 : 45) + (this.state.level * 0.8), angle: 0 
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        this.state.code = 1200 + (this.state.permanentUpgrades.startingCode || 0);
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 200) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

import React, { useEffect, useRef, useState } from 'react';
import { GameEngine } from './engine/GameEngine';
import { GameState, PermanentUpgrades } from './types';
import UIOverlay from './components/UIOverlay';
import SkillTree from './components/SkillTree';
import { TOWER_TYPES } from './constants';
import { Target } from 'lucide-react';
import { audio } from './engine/AudioManager';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<GameEngine | null>(null);
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [isSkillTreeOpen, setIsSkillTreeOpen] = useState(false);
  const [buildingType, setBuildingType] = useState<keyof typeof TOWER_TYPES | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;

    const engine = new GameEngine(canvasRef.current, (state) => {
      setGameState(state);
    });
    engineRef.current = engine;

    return () => {
      if (engineRef.current) {
        engineRef.current.destroy();
        engineRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (engineRef.current) {
      engineRef.current.setPaused(isSkillTreeOpen);
    }
  }, [isSkillTreeOpen]);

  const handleClick = (e: React.MouseEvent) => {
    audio.enable();

    if (!engineRef.current || isSkillTreeOpen || (gameState && gameState.isGameOver)) return;

    const rect = canvasRef.current!.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    if (buildingType) {
      const success = engineRef.current.buyTower(buildingType, x, y);
      if (success) setBuildingType(null);
    } else {
      engineRef.current.handleClick(x, y);
    }
  };

  const handleBuildTower = (type: keyof typeof TOWER_TYPES) => {
    audio.enable();
    setBuildingType(type);
  };

  const handleUpgrade = (skillId: string) => {
    if (engineRef.current) {
      const onUnlock = (s: GameState) => {
        if (skillId === 'click_1') s.clickPower *= 2;
        if (skillId === 'massive_click') s.clickPower *= 6;
        if (skillId === 'tower_range_1') s.towers.forEach((t: any) => t.range *= 1.2);
        if (skillId === 'tower_dmg_1') s.towers.forEach((t: any) => t.damage *= 1.4);
        if (skillId === 'core_plating') {
           s.maxCoreHp += 1000;
           s.coreHp += 1000;
        }

        if (skillId === 'tech_range') s.towers.forEach((t: any) => t.range *= 1.35);
        if (skillId === 'tech_speed') s.towers.forEach((t: any) => t.fireRate *= 0.7);
        if (skillId === 'tech_click_god') s.clickPower *= 10;
        if (skillId === 'tech_tower_god') s.towers.forEach((t: any) => t.damage *= 3);
        if (skillId === 'tech_god') {
            s.clickPower *= 5;
            s.towers.forEach((t: any) => t.damage *= 5);
        }
      };
      engineRef.current.applySkill(skillId, onUnlock);
    }
  };

  const handleReroll = () => {
    if (engineRef.current) {
      engineRef.current.rerollSkills();
    }
  };

  const handleRestart = () => {
    if (engineRef.current) {
      engineRef.current.reset();
    }
  };

  const handleBuyPermanent = (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => {
    if (engineRef.current) {
      engineRef.current.buyPermanentUpgrade(type);
    }
  };

  return (
    <div className="relative w-screen h-screen bg-slate-950 overflow-hidden select-none cursor-crosshair">
      <canvas
        ref={canvasRef}
        onClick={handleClick}
        className="block w-full h-full"
      />

      {gameState && (
        <>
          <UIOverlay 
            state={gameState} 
            onBuildTower={handleBuildTower}
            onOpenSkills={() => {
              audio.enable();
              setIsSkillTreeOpen(true);
            }}
            onRestart={handleRestart}
            onBuyPermanent={handleBuyPermanent}
          />
          <SkillTree 
            state={gameState}
            isOpen={isSkillTreeOpen}
            onClose={() => setIsSkillTreeOpen(false)}
            onUpgrade={handleUpgrade}
            onReroll={handleReroll}
          />
        </>
      )}

      {buildingType && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-sky-500 text-slate-900 px-6 py-2 rounded-full font-bold shadow-[0_0_30px_rgba(56,189,248,0.5)] animate-pulse pointer-events-none z-40 flex items-center gap-2">
          <Target className="w-5 h-5" /> 
          PLACING {TOWER_TYPES[buildingType].name} - CLICK TO DEPLOY
        </div>
      )}

      <div className="fixed inset-0 pointer-events-none opacity-30 bg-[radial-gradient(circle_at_center,_transparent_0%,_#020617_100%)]" />
    </div>
  );
};

export default App;

