              <div className="text-[8px] sm:text-[10px] text-slate-400 font-black uppercase tracking-widest">RESEARCH HUB</div>
              <div className="text-xs sm:text-sm text-white font-bold uppercase italic">TECH STACK</div>
            </div>
          </div>
        </button>
      </div>

      {/* CENTER HINT */}
      {state.level === 1 && state.towers.length === 0 && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 translate-y-36 pointer-events-none text-center">
          <div className="text-sky-400 font-black text-xs uppercase tracking-[0.4em] animate-pulse">Defend the Mainframe</div>
          <div className="text-slate-500 text-[9px] font-bold uppercase tracking-widest mt-2">Build towers to generate XP & Click enemies for SP shards</div>
        </div>
      )}

      {/* BUILDER */}
      <div className="flex justify-center gap-2 sm:gap-4 pointer-events-auto mb-2 overflow-x-auto no-scrollbar pb-2 px-2">
        {(Object.entries(TOWER_TYPES) as [keyof typeof TOWER_TYPES, any][]).map(([key, config]) => {
          const towerCount = state.towers.filter(t => t.type === key).length;
          const currentCost = Math.floor(config.cost * Math.pow(1.2, towerCount));
          const isUnlocked = !config.requires || state.unlockedTech.includes(config.requires);
          const canAfford = state.code >= currentCost;
          const isActive = activeBuildingType === key;

          return (
            <button
              key={key}
              onClick={() => isUnlocked && onBuildTower(key)}
              disabled={!isUnlocked}
              className={`group relative bg-slate-900/95 backdrop-blur-lg border p-3 sm:p-4 rounded-2xl flex flex-col items-center gap-1.5 transition-all flex-shrink-0 min-w-[110px] sm:min-w-[150px] ${isUnlocked ? 'border-slate-700 hover:border-sky-400 hover:-translate-y-2' : 'opacity-30 grayscale cursor-not-allowed'} ${isActive ? 'border-sky-400 ring-2 ring-sky-400 bg-sky-950/40 -translate-y-2' : ''}`}
            >
              <div className={`w-12 h-12 sm:w-14 sm:h-14 rounded-xl flex items-center justify-center relative transition-transform ${isActive ? 'scale-110' : ''}`} style={{ backgroundColor: config.color + (isActive ? '40' : '20') }}>
                {key === 'BASIC' && <Shield className="text-sky-400 w-6 h-6 sm:w-7 sm:h-7" />}
                {key === 'SNIPER' && <Terminal className="text-pink-400 w-6 h-6 sm:w-7 sm:h-7" />}
                {key === 'RAPID' && <Layers className="text-amber-400 w-6 h-6 sm:w-7 sm:h-7" />}
                {key === 'AOE' && <Rocket className="text-purple-400 w-6 h-6 sm:w-7 sm:h-7" />}
                {!isUnlocked && <Lock className="absolute inset-0 m-auto text-white w-5 h-5" />}
              </div>
              <div className="text-center">
                <div className={`text-[10px] sm:text-xs font-black uppercase ${isActive ? 'text-sky-400' : 'text-white'}`}>{isUnlocked ? config.name : 'LOCKED'}</div>
                <div className={`text-[10px] font-black ${canAfford ? 'text-sky-400' : 'text-red-500'}`}>{currentCost.toLocaleString()} LOC</div>
              </div>
            </button>
          );
        })}
      </div>

      {/* GAME OVER */}
      {state.isGameOver && (
        <div className="fixed inset-0 bg-red-950/98 backdrop-blur-3xl flex items-center justify-center pointer-events-auto p-4 z-50">
          <div className="bg-slate-900 border border-slate-700 p-12 rounded-[2.5rem] shadow-2xl max-w-4xl w-full">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="text-center md:text-left md:pr-12">
                <h1 className="text-6xl font-black text-white mb-2 italic uppercase tracking-tighter">System Exit</h1>
                <p className="text-slate-400 mb-8 text-sm font-bold uppercase tracking-widest">Cluster failed at Level {state.level}.</p>
                <div className="bg-purple-500/10 border border-purple-500/30 p-8 rounded-2xl mb-8 text-center">
                  <div className="text-[10px] text-purple-400 mb-2 uppercase font-black tracking-widest">AVAILABLE CAPITAL</div>
                  <div className="text-5xl font-black text-white tabular-nums">{totalLegacyPool.toLocaleString()} LP</div>
                </div>
                <button onClick={onRestart} className="w-full bg-sky-500 hover:bg-sky-400 text-slate-900 font-black py-5 rounded-2xl text-2xl transition-all active:scale-95 shadow-xl shadow-sky-500/20">HARD REBOOT</button>
              </div>
              <div className="flex flex-col justify-center bg-slate-800/20 p-6 rounded-3xl border border-slate-800">
                <h3 className="text-xl font-black text-white mb-6 flex items-center gap-2 italic"><Star className="text-amber-400 w-6 h-6 fill-amber-400" />ANGEL INVESTMENTS</h3>
                <div className="space-y-4">
                  {[
                    { id: 'startingCode', name: 'Seed Round', desc: '+2.5k Start LOC', icon: <Award className="text-sky-400" /> },
                    { id: 'damageMultiplier', name: 'Optimized Kernels', desc: '+80% Total Power', icon: <Zap className="text-amber-400" /> },
                    { id: 'xpMultiplier', name: 'Neural Training', desc: '+100% XP Learning', icon: <Code className="text-purple-400" /> },
                  ].map(upg => (
                    <button 
                      key={upg.id} 
                      onClick={() => onBuyPermanent(upg.id as any)} 
                      disabled={state.permanentUpgrades.legacyPoints < 100} 
                      className="w-full p-4 bg-slate-900/60 border border-slate-700 rounded-2xl hover:border-sky-400 flex justify-between items-center group disabled:opacity-30 transition-all active:scale-95"
                    >
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-800 rounded-lg group-hover:scale-110 transition-transform">{upg.icon}</div>
                        <div className="text-left">
                          <div className="text-white font-bold text-sm uppercase">{upg.name}</div>
                          <div className="text-slate-500 text-[10px] font-black">{upg.desc}</div>
                        </div>
                      </div>
                      <div className="bg-purple-600 text-white text-[11px] px-3 py-1.5 rounded-full font-black shadow-lg shadow-purple-900/40">100 LP</div>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UIOverlay;

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;

    // 1. Base Passive Trickle
    state.code = Math.max(0, state.code + (5 + state.level) * (dt / 1000));

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied & Enemy)
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;

      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        // Enemy virus projectiles target the core
        targetPos = { x: cx, y: cy };
      }

      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 60) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code += Math.max(0, proj.damage * 0.05); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          // Virus hit core
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id && e1.hp > 0 && e2.hp > 0 && e1.type === e2.type) {
        e1.hp += e2.hp;
        e1.maxHp += e2.maxHp;
        e1.size = Math.min(e1.type === 'boss' ? 400 : 150, e1.size + 15);
        e1.value += e2.value;
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 2500 : 0) / cameraScale;
      const vacuumSpeed = 30;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Specialized Behaviors
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dx = cx - enemy.x;
      const dy = cy - enemy.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Core collision
      if (dist < (enemy.type === 'boss' ? 150 : 85)) {
        state.coreHp -= (enemy.type === 'boss' ? 500 : 25) + (state.level * 2);
        enemy.hp = -1;
        if (state.coreHp <= 0) {
          state.coreHp = 0;
          state.isGameOver = true;
        }
        return;
      }

      // Behavior: Glitch (Disables nearby towers)
      if (enemy.type === 'glitch') {
        const glitchAura = 250; // Reduced radius
        state.towers.forEach(t => {
          const tDist = Math.sqrt((t.x - enemy.x) ** 2 + (t.y - enemy.y) ** 2);
          if (tDist < glitchAura) {
            t.disabledUntil = now + 500; // Shorter disable
          }
        });
      }

      // Behavior: Boss (Fires projectiles)
      if (enemy.type === 'boss') {
        if (!enemy.nextAttackTime) enemy.nextAttackTime = now + 2000;
        if (now > enemy.nextAttackTime) {
          state.projectiles.push({
            id: Math.random().toString(36),
            targetId: 'core',
            x: enemy.x,
            y: enemy.y,
            speed: 3.5, // Even slower for readability
            damage: 20 + (state.level * 3), 
            color: COLORS.BOSS,
            type: 'enemy'
          });
          enemy.nextAttackTime = now + (5000 - Math.min(3000, state.level * 100));
        }
      }

      enemy.x += (dx / dist) * enemy.speed;
      enemy.y += (dy / dist) * enemy.speed;
      enemy.angle = Math.atan2(dy, dx);
    });

    // Clean up dead
    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory) return false;
    let hitSomething = false;
    const now = Date.now();

    // 1. Intercept Enemy Projectiles (Purple Balls)
    // Generous hitbox for projectiles
    const projInterceptRadius = 80 / cameraScale;
    state.projectiles = state.projectiles.filter(p => {
      if (p.type !== 'enemy') return true;
      const dist = Math.sqrt((p.x - worldX) ** 2 + (p.y - worldY) ** 2);
      if (dist < projInterceptRadius) {
        state.code += 500; // High reward for active defense
        state.experience += 50;
        hitSomething = true;
        return false;
      }
      return true;
    });

    // 2. Collect Drops
    const dropCollectionRadius = 100 / cameraScale; // Larger drop pickup on click
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    // 3. Hit Enemies
    // Massive splash radius to help clear glitch/boss mobs
    const splashRadius = 180 + (state.level * 5);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        // Linear falloff but higher floor (0.5 minimum damage if in splash)
        const damageMult = dist < 80 ? 1.0 : Math.max(0.5, (1 - (dist / splashRadius)));
        enemy.hp -= state.clickPower * damageMult;
        enemy.lastHit = now;
        state.code += 5;

        hitSomething = true;
        onEnemyHit(enemy);

        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory) return;
    const now = Date.now();

    const { damageMult, rangeMult, fireRateMult } = state.towerModifiers;

    // Cache tower counts for synergy bonus (each tower of same type boosts all of that type by 10%)
    const typeCounts: Record<string, number> = {};
    state.towers.forEach(t => {
      typeCounts[t.type] = (typeCounts[t.type] || 0) + 1;
    });

    state.towers.forEach(tower => {
      if (tower.disabledUntil && now < tower.disabledUntil) return;

      const synergyBonus = 1 + ((typeCounts[tower.type] || 1) - 1) * 0.10;

      // Apply modifiers dynamically to every existing tower
      const effectiveRange = tower.range * rangeMult;
      const effectiveDamage = tower.damage * damageMult * synergyBonus;
      const effectiveFireRate = tower.fireRate * fireRateMult;

      if (now - tower.lastFired > effectiveFireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (e.hp > 0 && Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < effectiveRange) targets.push(e);
          });
        } else {
          let minDist = effectiveRange;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            if (e.hp <= 0) return;
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            const actualDmg = Math.max(0, Math.min(target.hp, effectiveDamage));
            target.hp -= effectiveDamage;

            state.code += actualDmg * 0.05;
            state.experience += Math.max(0, effectiveDamage * 0.15 * state.permanentUpgrades.xpMultiplier);

            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);

            if (target.hp <= 0) {
              const isEnemy = 'type' in target;
              const isPlanet = 'isCaptured' in target;

              if (isEnemy && !(target as any)._processed) {
                this.processEnemyDeath(state, target as Enemy, false);
                this.checkLevelUp(state, onLevelUp);
              } else if (isPlanet && !(target as Planet).isCaptured) {
                this.capturePlanet(state, target as Planet, onLevelUp);
              }
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += 2500 * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
      }
    } else if (d.type === 'loc') {
      state.code += Math.max(0, 500 + (state.level * 100));
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;

    if (enemy.type === 'boss') rewardMult *= 10;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code += Math.max(0, Math.floor(enemy.value * rewardMult));

    if (!isManual) {
        state.spProgress += 0.2;
    } else {
        state.spProgress += 0.1;
    }

    if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress -= state.spGoal;
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
    }

    const rand = Math.random();
    let shardChance = isManual ? 0.6 : 0.4;
    if (state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    if (enemy.type === 'boss') {
      for (let i = 0; i < 8; i++) {
        state.drops.push({ 
          id: Math.random().toString(36), 
          name: 'Core Shard', 
          type: 'shard', 
          rarity: 'rare', 
          effect: 'SP', 
          x: enemy.x + (Math.random() - 0.5) * 150, 
          y: enemy.y + (Math.random() - 0.5) * 150, 
          life: 3.0 
        });
      }
    } else if (rand < shardChance) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Shard', 
        type: 'shard', 
        rarity: 'common', 
        effect: 'SP', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.5 
      });
    } else if (rand < 0.65) {
      state.drops.push({ 
        id: Math.random().toString(36), 
        name: 'Data', 
        type: 'loc', 
        rarity: 'common', 
        effect: 'LOC', 
        x: enemy.x, 
        y: enemy.y, 
        life: 1.5 
      });
    }

    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

import React, { useEffect, useRef, useState } from 'react';
import { GameEngine } from './engine/GameEngine';
import { GameState, PermanentUpgrades } from './types';
import UIOverlay from './components/UIOverlay';
import SkillTree from './components/SkillTree';
import { TOWER_TYPES } from './constants';
import { Target } from 'lucide-react';
import { audio } from './engine/AudioManager';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<GameEngine | null>(null);
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [isSkillTreeOpen, setIsSkillTreeOpen] = useState(false);
  const [buildingType, setBuildingType] = useState<keyof typeof TOWER_TYPES | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;

    const engine = new GameEngine(canvasRef.current, (state) => {
      setGameState(state);
    });
    engineRef.current = engine;

    return () => {
      if (engineRef.current) {
        engineRef.current.destroy();
        engineRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (engineRef.current) {
      engineRef.current.setPaused(isSkillTreeOpen);
    }
  }, [isSkillTreeOpen]);

  const handleClick = (e: React.MouseEvent) => {
    audio.enable();

    if (!engineRef.current || isSkillTreeOpen || (gameState && gameState.isGameOver)) return;

    const rect = canvasRef.current!.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    if (buildingType) {
      // Try to build a tower
      engineRef.current.buyTower(buildingType, x, y);
    }

    // ALWAYS perform a click interaction to maintain DPS and collection flow
    engineRef.current.handleClick(x, y);
  };

  const handleBuildTower = (type: keyof typeof TOWER_TYPES) => {
    audio.enable();
    // Toggle logic: if same type, turn off. Otherwise, switch to new type.
    if (buildingType === type) {
      setBuildingType(null);
    } else {
      setBuildingType(type);
    }
  };

  const handleUpgrade = (skillId: string) => {
    if (engineRef.current) {
      const onUnlock = (s: GameState) => {
        // Global Click Modifiers
        if (skillId === 'click_1') s.clickPower *= 2.5; // Buffed from 2
        if (skillId === 'massive_click') s.clickPower *= 8; // Buffed from 6
        if (skillId === 'tech_click_god') s.clickPower *= 12; // Buffed from 10

        // Global Tower Modifiers (Persistent)
        if (skillId === 'tower_range_1') s.towerModifiers.rangeMult *= 1.3; // Buffed from 1.2
        if (skillId === 'tech_range') s.towerModifiers.rangeMult *= 1.5; // Buffed from 1.35

        if (skillId === 'tower_dmg_1') s.towerModifiers.damageMult *= 1.6; // Buffed from 1.4
        if (skillId === 'tech_tower_god') s.towerModifiers.damageMult *= 4; // Buffed from 3

        if (skillId === 'tech_speed') s.towerModifiers.fireRateMult *= 0.6; // Buffed from 0.7

        if (skillId === 'tech_god') {
            s.clickPower *= 10; // Buffed from 5
            s.towerModifiers.damageMult *= 10; // Buffed from 5
        }

        // Defensive stats
        if (skillId === 'core_plating') {
           s.maxCoreHp += 2000; // Buffed from 1000
           s.coreHp += 2000;
        }
      };
      engineRef.current.applySkill(skillId, onUnlock);
    }
  };

  const handleReroll = () => {
    if (engineRef.current) {
      engineRef.current.rerollSkills();
    }
  };

  const handleRestart = () => {
    if (engineRef.current) {
      engineRef.current.reset();
    }
  };

  const handleBuyPermanent = (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => {
    if (engineRef.current) {
      engineRef.current.buyPermanentUpgrade(type);
    }
  };

  return (
    <div className="relative w-screen h-screen bg-slate-950 overflow-hidden select-none cursor-crosshair">
      <canvas
        ref={canvasRef}
        onClick={handleClick}
        className="block w-full h-full"
      />

      {gameState && (
        <>
          <UIOverlay 
            state={gameState} 
            activeBuildingType={buildingType}
            onBuildTower={handleBuildTower}
            onOpenSkills={() => {
              audio.enable();
              setIsSkillTreeOpen(true);
            }}
            onRestart={handleRestart}
            onBuyPermanent={handleBuyPermanent}
          />
          <SkillTree 
            state={gameState}
            isOpen={isSkillTreeOpen}
            onClose={() => setIsSkillTreeOpen(false)}
            onUpgrade={handleUpgrade}
            onReroll={handleReroll}
          />
        </>
      )}

      {buildingType && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-sky-500 text-slate-900 px-6 py-2 rounded-full font-bold shadow-[0_0_30px_rgba(56,189,248,0.5)] animate-bounce pointer-events-auto z-40 flex items-center gap-2 cursor-pointer" onClick={(e) => { e.stopPropagation(); setBuildingType(null); }}>
          <Target className="w-5 h-5" /> 
          PLACING {TOWER_TYPES[buildingType].name} (TAP TO DISMISS)
        </div>
      )}

      <div className="fixed inset-0 pointer-events-none opacity-30 bg-[radial-gradient(circle_at_center,_transparent_0%,_#020617_100%)]" />
    </div>
  );
};

export default App;

export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private bgmGain: GainNode | null = null;
  private lastPlayTimes: Map<string, number> = new Map();
  private enabled: boolean = false;

  // Sequencer state
  private currentBpm: number = 128;
  private nextNoteTime: number = 0;
  private currentStep: number = 0;
  private lookahead: number = 25.0; // ms
  private scheduleAheadTime: number = 0.1; // seconds
  private timerId: number | null = null;

  // Scales & Patterns (8-bit C minor / Pentatonic vibes)
  private bassScale = [65.41, 77.78, 98.00, 116.54]; // C2, Eb2, G2, Bb2
  private leadScale = [261.63, 311.13, 392.00, 466.16, 523.25]; // C4, Eb4, G4, Bb4, C5

  private bassPattern = [0, 0, 2, 2, 3, 3, 1, 1];
  private leadPattern = [0, -1, 1, -1, 2, 4, 3, -1, 0, 2, 1, -1, 3, -1, 2, -1];

  private COOLDOWNS = {
    fire_basic: 80,
    fire_rapid: 40,
    fire_sniper: 150,
    fire_aoe: 200,
    death: 30,
    click: 50,
    shard: 100,
    level_up: 60, // Added cooldown for level_up to handle rapid spending
  };

  constructor() {}

  private init() {
    if (this.ctx) return;
    this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = 0.3;
    this.masterGain.connect(this.ctx.destination);

    this.bgmGain = this.ctx.createGain();
    this.bgmGain.gain.value = 0.08;
    this.bgmGain.connect(this.masterGain);

    this.enabled = true;
    this.scheduler();
  }

  public enable() {
    if (!this.ctx) this.init();
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume();
    }
  }

  public stop() {
    this.enabled = false;
    if (this.timerId !== null) {
      window.clearTimeout(this.timerId);
      this.timerId = null;
    }
    if (this.ctx) {
      this.ctx.close();
      this.ctx = null;
    }
  }

  public updateBPM(level: number) {
    this.currentBpm = Math.min(220, 128 + (level * 1.5));
  }

  private scheduler = () => {
    if (!this.ctx || !this.enabled) return;

    while (this.nextNoteTime < this.ctx.currentTime + this.scheduleAheadTime) {
      this.scheduleNote(this.currentStep, this.nextNoteTime);
      this.advanceNote();
    }
    this.timerId = window.setTimeout(this.scheduler, this.lookahead);
  }

  private advanceNote() {
    const secondsPerBeat = 60.0 / this.currentBpm;
    this.nextNoteTime += 0.25 * secondsPerBeat; // 16th notes
    this.currentStep = (this.currentStep + 1) % 16;
  }

  private scheduleNote(step: number, time: number) {
    if (!this.ctx || !this.bgmGain) return;

    if (step % 2 === 0) {
      const bassIndex = this.bassPattern[(step / 2) % 8];
      if (bassIndex !== -1) {
        this.playPluck(this.bassScale[bassIndex], time, 0.15, 'triangle', 0.4);
      }
    }

    const leadIndex = this.leadPattern[step % 16];
    if (leadIndex !== -1) {
      this.playPluck(this.leadScale[leadIndex], time, 0.1, 'square', 0.2);
    }
  }

  private playPluck(freq: number, time: number, duration: number, type: OscillatorType, volume: number) {
    if (!this.ctx || !this.bgmGain) return;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, time);

    g.gain.setValueAtTime(0, time);
    g.gain.linearRampToValueAtTime(volume, time + 0.01);
    g.gain.exponentialRampToValueAtTime(0.001, time + duration);

    osc.connect(g);
    g.connect(this.bgmGain);

    osc.start(time);
    osc.stop(time + duration);
  }

  private canPlay(key: string): boolean {
    if (!this.enabled) return false;
    const now = Date.now();
    const last = this.lastPlayTimes.get(key) || 0;
    const cooldown = (this.COOLDOWNS as any)[key] || 0;
    if (now - last > cooldown) {
      this.lastPlayTimes.set(key, now);
      return true;
    }
    return false;
  }

  public playFire(type: string) {
    if (!this.ctx || !this.masterGain) return;
    const key = `fire_${type.toLowerCase()}`;
    if (!this.canPlay(key)) return;

    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.connect(g);
    g.connect(this.masterGain);

    const now = this.ctx.currentTime;

    if (type === 'SNIPER') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(800, now);
      osc.frequency.exponentialRampToValueAtTime(40, now + 0.5);
      g.gain.setValueAtTime(0.3, now);
      g.gain.linearRampToValueAtTime(0, now + 0.5);
      osc.start(now);
      osc.stop(now + 0.5);
    } else if (type === 'RAPID') {
      osc.type = 'square';
      osc.frequency.setValueAtTime(1200, now);
      osc.frequency.linearRampToValueAtTime(400, now + 0.05);
      g.gain.setValueAtTime(0.1, now);
      g.gain.linearRampToValueAtTime(0, now + 0.05);
      osc.start(now);
      osc.stop(now + 0.05);
    } else if (type === 'AOE') {
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(100, now);
      osc.frequency.exponentialRampToValueAtTime(400, now + 0.2);
      g.gain.setValueAtTime(0.4, now);
      g.gain.linearRampToValueAtTime(0, now + 0.2);
      osc.start(now);
      osc.stop(now + 0.2);
    } else {
      osc.type = 'square';
      osc.frequency.setValueAtTime(440, now);
      osc.frequency.exponentialRampToValueAtTime(110, now + 0.1);
      g.gain.setValueAtTime(0.2, now);
      g.gain.linearRampToValueAtTime(0, now + 0.1);
      osc.start(now);
      osc.stop(now + 0.1);
    }
  }

  public playDeath() {
    if (!this.ctx || !this.masterGain || !this.canPlay('death')) return;

    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();

    osc.type = 'square';
    osc.frequency.setValueAtTime(100, now);
    osc.frequency.linearRampToValueAtTime(20, now + 0.15);

    g.gain.setValueAtTime(0.15, now);
    g.gain.exponentialRampToValueAtTime(0.01, now + 0.15);

    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.15);
  }

  public playClick() {
    if (!this.ctx || !this.masterGain || !this.canPlay('click')) return;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sine';
    const now = this.ctx.currentTime;
    osc.frequency.setValueAtTime(1200, now);
    osc.frequency.exponentialRampToValueAtTime(1500, now + 0.02);
    g.gain.setValueAtTime(0.1, now);
    g.gain.linearRampToValueAtTime(0, now + 0.02);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.02);
  }

  public playLevelUp() {
    if (!this.ctx || !this.masterGain || !this.canPlay('level_up')) return;
    const now = this.ctx.currentTime;
    [440, 554, 659, 880].forEach((f, i) => {
      const osc = this.ctx!.createOscillator();
      const g = this.ctx!.createGain();
      osc.type = 'square';
      osc.frequency.setValueAtTime(f, now + i * 0.1);
      g.gain.setValueAtTime(0.1, now + i * 0.1);
      g.gain.exponentialRampToValueAtTime(0.01, now + i * 0.1 + 0.3);
      osc.connect(g);
      g.connect(this.masterGain!);
      osc.start(now + i * 0.1);
      osc.stop(now + i * 0.1 + 0.3);
    });
  }

  public playGameOver() {
    if (!this.ctx || !this.masterGain) return;
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(220, now);
    osc.frequency.linearRampToValueAtTime(55, now + 1.5);
    g.gain.setValueAtTime(0.3, now);
    g.gain.linearRampToValueAtTime(0, now + 1.5);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 1.5);
  }

  public playShard() {
    if (!this.ctx || !this.masterGain || !this.canPlay('shard')) return;
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(2000, now);
    osc.frequency.exponentialRampToValueAtTime(3000, now + 0.05);
    g.gain.setValueAtTime(0.15, now);
    g.gain.linearRampToValueAtTime(0, now + 0.05);
    osc.connect(g);
    g.connect(this.masterGain);
    osc.start(now);
    osc.stop(now + 0.05);
  }
}

export const audio = new AudioManager();

import React, { useState, useRef, useEffect } from 'react';
import { GameState, TechNode } from '../types';
import { ALL_SKILLS, TECH_TREE } from '../constants';
import { Cpu, X, Zap, Target, MousePointer2, Shield, Code, Award, Sparkles, RefreshCcw, LayoutGrid, Share2 } from 'lucide-react';

interface Props {
  state: GameState;
  isOpen: boolean;
  onClose: () => void;
  onUpgrade: (skillId: string) => void;
  onReroll: () => void;
}

const SkillTree: React.FC<Props> = ({ state, isOpen, onClose, onUpgrade, onReroll }) => {
  const [activeTab, setActiveTab] = useState<'shop' | 'tree'>('tree');
  const scrollRef = useRef<HTMLDivElement>(null);
  const repeatTimerRef = useRef<number | null>(null);
  const accelerationRef = useRef<number>(0);

  // Cleanup on unmount or tab change
  useEffect(() => {
    return () => stopRepeating();
  }, [activeTab]);

  if (!isOpen) return null;

  const stopRepeating = () => {
    if (repeatTimerRef.current !== null) {
      window.clearTimeout(repeatTimerRef.current);
      repeatTimerRef.current = null;
    }
    accelerationRef.current = 0;
  };

  const startRepeating = (skillId: string, canAfford: boolean) => {
    if (!canAfford) return;

    // First trigger
    onUpgrade(skillId);

    const repeat = () => {
      // Check again if we can afford after state update (not perfect with stale state but works well enough for feel)
      // The real check happens inside the onUpgrade handler anyway.
      onUpgrade(skillId);

      // Accelerate: 100ms -> 30ms floor
      accelerationRef.current = Math.min(accelerationRef.current + 1, 10);
      const nextInterval = Math.max(30, 100 - accelerationRef.current * 7);

      repeatTimerRef.current = window.setTimeout(repeat, nextInterval);
    };

    // Initial delay before rapid fire
    repeatTimerRef.current = window.setTimeout(repeat, 250);
  };

  // Filter skills: only show if not oneTime or not already unlocked
  const currentShopSkills = ALL_SKILLS.filter(s => 
    state.availableSkills.includes(s.id) && 
    (!s.oneTime || !state.unlockedSkills.includes(s.id))
  );

  const getIcon = (id: string) => {
    if (id.includes('click')) return <MousePointer2 className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('range')) return <Target className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('dmg')) return <Zap className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('collect')) return <Cpu className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('code_gen')) return <Code className="w-5 h-5 sm:w-6 sm:h-6" />;
    if (id.includes('shield')) return <Shield className="w-5 h-5 sm:w-6 sm:h-6" />;
    return <Award className="w-5 h-5 sm:w-6 sm:h-6" />;
  };

  const isTechUnlocked = (id: string) => state.unlockedTech.includes(id);
  const canUnlockTech = (tech: TechNode) => {
    if (isTechUnlocked(tech.id)) return false;
    if (tech.dependsOn && !isTechUnlocked(tech.dependsOn)) return false;
    return state.skillPoints >= tech.cost;
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-2 sm:p-6 bg-slate-950/90 backdrop-blur-xl pointer-events-auto">
      <div className="bg-slate-900 border border-slate-700 rounded-3xl w-full max-w-5xl max-h-[90vh] flex flex-col overflow-hidden shadow-2xl relative">

        {/* Tabs */}
        <div className="flex bg-slate-800/50 p-1 rounded-t-3xl border-b border-slate-700">
          <button 
            onClick={() => setActiveTab('tree')}
            className={`flex-1 py-3 px-4 flex items-center justify-center gap-2 font-black uppercase text-xs sm:text-sm tracking-widest transition-all rounded-t-2xl
              ${activeTab === 'tree' ? 'bg-slate-900 text-sky-400 shadow-[0_-4px_0_0_#38bdf8]' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <Share2 size={16} /> Tech Stack
          </button>
          <button 
            onClick={() => setActiveTab('shop')}
            className={`flex-1 py-3 px-4 flex items-center justify-center gap-2 font-black uppercase text-xs sm:text-sm tracking-widest transition-all rounded-t-2xl
              ${activeTab === 'shop' ? 'bg-slate-900 text-pink-400 shadow-[0_-4px_0_0_#f472b6]' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <LayoutGrid size={16} /> Dependencies
          </button>
        </div>

        {/* Header */}
        <div className="p-4 sm:p-6 flex justify-between items-center bg-slate-900/50 flex-shrink-0">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-white italic leading-tight uppercase">
              {activeTab === 'tree' ? 'Global Infrastructure' : 'External Modules'}
            </h2>
            <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
              {state.skillPoints} Skill Points Available
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 transition-all border border-slate-700">
            <X size={20} />
          </button>
        </div>

        {/* Content Area */}
        <div ref={scrollRef} className="flex-grow overflow-auto p-4 sm:p-8 no-scrollbar bg-slate-950/30">

          {/* TECH TREE TAB */}
          {activeTab === 'tree' && (
            <div className="relative min-h-[700px] w-full min-w-[600px] flex justify-center">
              <svg className="absolute inset-0 w-full h-full pointer-events-none z-0">
                {TECH_TREE.map(node => {
                  if (!node.dependsOn) return null;
                  const parent = TECH_TREE.find(p => p.id === node.dependsOn);
                  if (!parent) return null;
                  const isLinkActive = isTechUnlocked(node.id);
                  const isLinkAvailable = isTechUnlocked(parent.id);
                  return (
                    <line
                      key={`${parent.id}-${node.id}`}
                      x1={`${parent.position.x}%`}
                      y1={`${parent.position.y}px`}
                      x2={`${node.position.x}%`}
                      y2={`${node.position.y}px`}
                      stroke={isLinkActive ? '#38bdf8' : isLinkAvailable ? '#334155' : '#0f172a'}
                      strokeWidth={isLinkActive ? "4" : "2"}
                      strokeDasharray={isLinkActive ? "0" : "5,5"}
                      className="transition-all duration-500"
                    />
                  );
                })}
              </svg>

              {TECH_TREE.map(node => {
                const unlocked = isTechUnlocked(node.id);
                const available = canUnlockTech(node);
                return (
                  <div
                    key={node.id}
                    className="absolute z-10 -translate-x-1/2 -translate-y-1/2"
                    style={{ left: `${node.position.x}%`, top: `${node.position.y}px` }}
                  >
                    <button
                      disabled={!available || unlocked}
                      onPointerDown={() => available && !unlocked && startRepeating(node.id, true)}
                      onPointerUp={stopRepeating}
                      onPointerLeave={stopRepeating}
                      className={`
                        w-14 h-14 sm:w-20 sm:h-20 rounded-full border-2 flex flex-col items-center justify-center transition-all group relative
                        ${unlocked ? 'bg-sky-500 border-sky-300 shadow-[0_0_30px_rgba(56,189,248,0.4)]' : 
                          available ? 'bg-slate-800 border-slate-600 hover:border-sky-400 hover:scale-110 active:scale-95 active:bg-slate-700' : 
                          'bg-slate-900 border-slate-800 opacity-40 cursor-not-allowed'}
                      `}
                    >
                      <Cpu size={unlocked ? 28 : 24} className={unlocked ? 'text-white' : 'text-slate-400'} />
                      <div className="absolute top-full mt-3 left-1/2 -translate-x-1/2 w-48 bg-slate-800 border border-slate-700 p-3 rounded-xl pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity z-20 shadow-2xl">
                        <div className="text-[11px] font-black text-sky-400 uppercase mb-1">{node.name}</div>
                        <div className="text-[10px] text-slate-300 leading-tight font-medium">{node.description}</div>
                        {!unlocked && <div className="mt-2 text-[9px] font-black text-amber-500">REQUIREMENT: {node.cost} SP</div>}
                        {unlocked && <div className="mt-2 text-[9px] font-black text-green-400">STATUS: DEPLOYED</div>}
                      </div>
                      {!unlocked && node.cost > 0 && (
                        <span className="absolute -top-1 -right-1 bg-amber-500 text-slate-900 text-[10px] font-black w-6 h-6 flex items-center justify-center rounded-full border-2 border-slate-900 shadow-lg">
                          {node.cost}
                        </span>
                      )}
                    </button>
                  </div>
                );
              })}
            </div>
          )}

          {/* SHOP TAB */}
          {activeTab === 'shop' && (
            <div className="flex flex-col gap-6">
              {currentShopSkills.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-slate-500">
                  <LayoutGrid size={48} className="mb-4 opacity-20" />
                  <div className="text-sm font-bold uppercase tracking-widest">No dependencies found</div>
                  <div className="text-xs opacity-60">Reroll to fetch new versions</div>
                </div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {currentShopSkills.map((skill) => {
                    const canAfford = state.skillPoints >= skill.cost;
                    return (
                      <button
                        key={skill.id}
                        onPointerDown={() => canAfford && startRepeating(skill.id, true)}
                        onPointerUp={stopRepeating}
                        onPointerLeave={stopRepeating}
                        disabled={!canAfford}
                        className={`
                          text-left p-6 rounded-2xl border transition-all relative group flex flex-col justify-between h-52
                          ${canAfford 
                            ? 'border-slate-700 bg-slate-800/40 hover:border-pink-400 hover:-translate-y-2 active:scale-95 active:bg-slate-700/60 shadow-lg hover:shadow-pink-500/10' 
                            : 'border-slate-800 bg-slate-900/50 opacity-40 cursor-not-allowed'}
                        `}
                      >
                        <div>
                          <div className={`w-12 h-12 rounded-xl flex items-center justify-center mb-4 
                            ${skill.rarity === 'epic' ? 'bg-purple-500/20 text-purple-400' : 
                              skill.rarity === 'rare' ? 'bg-amber-500/20 text-amber-400' : 'bg-pink-500/20 text-pink-400'}`}>
                            {getIcon(skill.id)}
                          </div>
                          <h3 className="text-sm font-black text-white leading-tight mb-1 uppercase tracking-tight">{skill.name}</h3>
                          <p className="text-[11px] text-slate-400 leading-relaxed font-medium">{skill.description}</p>
                        </div>
                        <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-700/50">
                          <span className="text-[9px] font-black px-2 py-0.5 rounded uppercase tracking-tighter bg-slate-700 text-slate-300">
                            {skill.rarity}
                          </span>
                          <div className="font-black text-white text-xs uppercase flex items-center gap-1">
                            <Sparkles size={12} className="text-amber-400" /> {skill.cost} SP
                          </div>
                        </div>
                      </button>
                    );
                  })}
                </div>
              )}

              <div className="mt-8 flex flex-col items-center gap-4">
                <button
                  onClick={onReroll}
                  disabled={state.code < state.rerollCost}
                  className={`
                    flex items-center gap-3 px-8 py-4 rounded-2xl font-black uppercase text-[11px] tracking-[0.2em] transition-all shadow-2xl
                    ${state.code >= state.rerollCost
                      ? 'bg-slate-800 hover:bg-slate-700 border-2 border-slate-700 text-pink-400 hover:border-pink-500 shadow-pink-500/5'
                      : 'bg-slate-900/50 text-slate-700 cursor-not-allowed opacity-50 border-2 border-transparent'}
                  `}
                >
                  <RefreshCcw className="w-5 h-5" />
                  <span>Update Dependencies</span>
                  <span className="opacity-60">({state.rerollCost} LOC)</span>
                </button>
              </div>
            </div>
          )}
        </div>

        <div className="p-4 bg-slate-950/80 text-center text-[9px] text-slate-600 font-bold uppercase tracking-[0.4em] border-t border-slate-800 flex-shrink-0">
          HOLD TO AUTO-INJECT SKILL POINTS. ACCELERATION ACTIVE.
        </div>
      </div>
    </div>
  );
};

