              <div className="text-center md:text-left">
                <div className="flex items-center gap-3 mb-2 justify-center md:justify-start">
                  <div className="w-12 h-1 bg-red-500 rounded-full" />
                  <span className="text-red-500 font-black uppercase tracking-[0.3em] text-xs">Runtime Error</span>
                </div>
                <h1 className="text-5xl font-black text-white mb-2 italic uppercase tracking-tighter">System Exit</h1>
                <p className="text-slate-500 mb-8 text-sm font-bold uppercase tracking-widest">Codebase failed at Level {state.level}.</p>

                <div className="bg-purple-500/5 border border-purple-500/20 p-8 rounded-3xl mb-8">
                  <div className="text-[10px] text-purple-400 mb-2 uppercase font-black tracking-widest">Legacy Capital</div>
                  <div className="text-4xl font-black text-white tabular-nums flex items-baseline gap-2">
                    {formatLarge(totalLegacyPool)} <span className="text-base text-purple-500">LP</span>
                  </div>
                </div>

                <button onClick={onRestart} className="w-full bg-sky-500 hover:bg-sky-400 text-slate-900 font-black py-4 rounded-2xl text-xl transition-all active:scale-95 shadow-xl shadow-sky-500/20 uppercase italic">Hard Reboot</button>
              </div>

              <div className="flex flex-col justify-center bg-slate-800/20 p-6 rounded-[2rem] border border-slate-800">
                <h3 className="text-lg font-black text-white mb-6 flex items-center gap-3 italic uppercase tracking-wider">
                  <Star className="text-amber-400 w-5 h-5 fill-amber-400" /> Angel Investments
                </h3>
                <div className="space-y-3">
                  {[
                    { id: 'startingCode', name: 'Seed Round', desc: '+2.5k LOC', icon: <Award className="text-sky-400 w-4 h-4" /> },
                    { id: 'damageMultiplier', name: 'Optimized Kernels', desc: '+80% Power', icon: <Zap className="text-amber-400 w-4 h-4" /> },
                    { id: 'xpMultiplier', name: 'Neural Training', desc: '+100% XP', icon: <Code className="text-purple-400 w-4 h-4" /> },
                  ].map(upg => (
                    <button 
                      key={upg.id} 
                      onClick={() => onBuyPermanent(upg.id as any)} 
                      disabled={state.permanentUpgrades.legacyPoints < 100} 
                      className="w-full p-4 bg-slate-900/60 border border-slate-800 rounded-2xl hover:border-sky-400/50 flex justify-between items-center group disabled:opacity-30 transition-all"
                    >
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-800 rounded-xl group-hover:scale-110 transition-transform">{upg.icon}</div>
                        <div className="text-left">
                          <div className="text-white font-bold text-xs uppercase">{upg.name}</div>
                          <div className="text-slate-500 text-[10px] font-bold">{upg.desc}</div>
                        </div>
                      </div>
                      <div className="bg-slate-800 text-purple-400 text-[10px] px-3 py-1.5 rounded-full font-black border border-purple-500/20">100 LP</div>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UIOverlay;

export interface Point {
  x: number;
  y: number;
}

export interface Particle extends Point {
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
  text?: string;
}

export interface Projectile extends Point {
  id: string;
  targetId: string;
  speed: number;
  damage: number;
  color: string;
  type: 'allied' | 'enemy';
}

export interface Planet extends Point {
  id: string;
  hp: number;
  maxHp: number;
  isCaptured: boolean;
  size: number;
  color: string;
  name: string;
  sector: number;
}

export interface ClickRipple extends Point {
  radius: number;
  maxRadius: number;
  life: number;
}

export interface Enemy extends Point {
  id: string;
  hp: number;
  maxHp: number;
  speed: number;
  value: number;
  type: 'bug' | 'boss' | 'glitch' | 'null_pointer' | 'memory_leak' | 'shielded' | 'worm';
  size: number;
  angle: number;
  lastHit?: number;
  sourcePlanetId?: string;
  nextAttackTime?: number;

  // Behavior stats
  shield?: number;
  hasBlinked?: boolean;
  isChild?: boolean;
  sinOffset?: number; // For worm movement
  isFriendly?: boolean; // New conversion mechanic
}

export interface Tower extends Point {
  id: string;
  type: string;
  level: number;
  range: number;
  damage: number;
  fireRate: number;
  lastFired: number;
  color: string;
  disabledUntil?: number;
}

export interface LibraryDrop extends Point {
  id: string;
  name: string;
  type: 'loc' | 'shard' | 'library';
  rarity: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
  effect: string;
  life: number;
}

export interface PermanentUpgrades {
  startingCode: number;
  damageMultiplier: number;
  xpMultiplier: number;
  legacyPoints: number;
  version: number; // The global evolution level
}

export interface TechNode {
  id: string;
  name: string;
  description: string;
  cost: number;
  position: { x: number; y: number };
  dependsOn?: string;
}

export interface TowerModifiers {
  damageMult: number;
  rangeMult: number;
  fireRateMult: number;
}

export interface GameState {
  code: number;
  experience: number;
  level: number;
  skillPoints: number;
  spProgress: number;
  spGoal: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  planets: Planet[];
  projectiles: Projectile[];
  isGameOver: boolean;
  isVictory: boolean;
  permanentUpgrades: PermanentUpgrades;
  lastRunCode: number;
  availableSkills: string[];
  unlockedTech: string[];
  unlockedSkills: string[]; 
  rerollCost: number;
  combo: number;
  threatLevel: number;
  coreHp: number;
  maxCoreHp: number;
  towerModifiers: TowerModifiers;
  currentSector: number;
  isCompiling?: boolean; // For "Ship to Production" effect
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

// Safeguard against JS floating point limits
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private resizeHandler: () => void;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    this.resizeHandler = () => this.resize();
    this.resize();
    window.addEventListener('resize', this.resizeHandler);
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  public destroy() {
    this.isDestroyed = true;
    window.removeEventListener('resize', this.resizeHandler);
    audio.stop();
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 2600 + (sector * 3500); 
    const count = PLANET_COUNT + (sector * 2);
    const names = ["NPM", "PYPI", "Maven", "Cargo", "Go-Get", "NuGet", "RubyGems", "Composer"];
    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);

    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 0.5);
      const baseHp = (3000 + (this.state.level * 200)) * Math.pow(1.5, sector);
      const cappedHp = Math.min(MAX_VAL, baseHp * versionBoost);

      this.state.planets.push({
        id: `planet_${sector}_${i}`, 
        name: `${names[i % names.length]}-${sector}`,
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: cappedHp,
        maxHp: cappedHp,
        isCaptured: false, size: 350 + (sector * 100), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    const versionMult = Math.pow(5, perms.version - 1);
    this.state.code = (1200 + (perms.startingCode || 0)) * versionMult;
    this.state.clickPower = 35 * perms.damageMultiplier * versionMult;

    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(0); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;

    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    // Calculate Legacy Points reward
    const earnedLegacy = Math.floor(Math.log10(this.state.code + 1) * this.state.level / 10);
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.state.permanentUpgrades.version++;

    // Aesthetic delay for "Shipping"
    await new Promise(r => setTimeout(r, 2000));

    this.state.isCompiling = false;
    this.reset();
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused || this.isDestroyed || this.state.isCompiling) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        if (e.isFriendly) {
           this.createParticles(e.x, e.y, 10, COLORS.PRIMARY);
        } else {
           this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        }
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const versionMult = Math.pow(2, this.state.permanentUpgrades.version - 1);
      const missReward = (50 + (this.state.level * 5)) * versionMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + missReward);
      this.createFloatingText(worldX, worldY, `+${this.formatNumber(missReward)}`, COLORS.PRIMARY);
      audio.playClick();
    }

    if (this.state.ripples.length < 15) {
      this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    }

    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);

    const uncapturedInSector = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncapturedInSector.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "SYNCING NEW SECTOR...", COLORS.ACCENT);
    }

    if (this.state.level % 5 === 0) {
      this.state.maxCoreHp = Math.min(MAX_VAL, this.state.maxCoreHp + (500 * this.state.permanentUpgrades.version)); 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  private formatNumber(num: number): string {
    if (num < 1000) return num.toFixed(0);
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const suffix = suffixes[tier];
    const scale = Math.pow(10, tier * 3);
    const scaled = num / scale;
    return scaled.toFixed(2) + suffix;
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused || this.isDestroyed || this.state.isCompiling) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range: config.range, 
        damage: config.damage, 
        fireRate: config.fireRate, 
        lastFired: 0, 
        color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;

    if (!this.isPaused && !this.state.isCompiling) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused || !!this.state.isCompiling);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;

    // --- ENHANCED DYNAMIC ZOOM ALGORITHM ---
    // Instead of just mapping dist, we use a logarithmic curve that ensures we zoom out much further
    // while keeping the action centered.
    let maxDist = 1200;
    this.state.enemies.forEach(e => {
        const d = Math.sqrt((e.x - this.canvas.width/2)**2 + (e.y - this.canvas.height/2)**2);
        if (d > maxDist) maxDist = d;
    });
    this.state.planets.forEach(p => {
        // Only zoom out for uncaptured planets in active or next sector
        if (!p.isCaptured && p.sector <= this.state.currentSector + 1) {
           const d = Math.sqrt((p.x - this.canvas.width/2)**2 + (p.y - this.canvas.height/2)**2);
           if (d > maxDist) maxDist = d;
        }
    });

    // Scale target becomes progressively more "intimate" or "grand" based on level
    const baseView = 900;
    // Lower the floor of camera scale as level/sector increases (infinite zoom-out)
    const scaleFloor = Math.max(0.0001, 0.04 / (1 + this.state.currentSector * 0.5));
    this.targetCameraScale = Math.max(scaleFloor, baseView / (maxDist * 1.1));
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.02;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
        if (target.hp <= 0) {
           audio.playDeath();
        }
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const earnedLegacy = Math.max(0, Math.floor(Math.log10(this.state.code + 1)));
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) return;

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 250 * Math.pow(2, this.state.permanentUpgrades.version - 1);
        if (this.state.unlockedSkills.includes('code_gen')) gain *= 10; 
        this.state.code = Math.min(MAX_VAL, this.state.code + gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(100, 3000 - (this.state.level * 150));
    const threatMult = 1 + (this.state.threatLevel * 0.5) + (this.state.currentSector * 0.4);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      let type: Enemy['type'] = 'bug';
      const r = Math.random();
      if (this.state.level >= 20 || this.state.currentSector > 0) {
          if (r < 0.1) type = 'glitch';
          else if (r < 0.2) type = 'null_pointer';
          else if (r < 0.3) type = 'memory_leak';
          else if (r < 0.4) type = 'shielded';
          else if (r < 0.45) type = 'worm';
      } else {
          if (r < 0.1) type = 'glitch';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    // Pruning
    if (this.state.particles.length > 300) this.state.particles.splice(0, this.state.particles.length - 300);
    if (this.state.projectiles.length > 150) this.state.projectiles.splice(0, this.state.projectiles.length - 150);

    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.1; return r.life > 0; });

    if (this.frameCount % 2 === 0) {
      this.onUpdate({ ...this.state });
    }
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3000 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const hp = 2000 * Math.pow(1.3, (this.state.level / 5) + this.state.currentSector) * Math.pow(10, this.state.permanentUpgrades.version - 1);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed: 0.6 + (this.state.level * 0.02), value: 20000 * this.state.permanentUpgrades.version, 
      type: 'boss', size: 300, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "CRITICAL ERROR DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: Enemy['type'] = 'bug') {
    const dist = 3600 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }

    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);
    const hpMult = Math.pow(1.12, Math.min(this.state.level, 1000) + (this.state.currentSector * 5));
    let hp = 40 * hpMult * versionBoost;
    let speed = 1.4 + (Math.min(this.state.level, 500) * 0.04);
    let size = 45 + (Math.min(this.state.level, 2000) * 0.5);
    let shield = 0;

    if (type === 'glitch') { hp *= 2; speed += 0.4; }
    if (type === 'shielded') { shield = hp * 0.5; hp *= 1.5; speed *= 0.7; size += 20; }
    if (type === 'null_pointer') { hp *= 0.8; speed += 1.0; }
    if (type === 'memory_leak') { hp *= 1.2; speed *= 0.8; size += 15; }
    if (type === 'worm') { hp *= 0.5; speed += 0.8; size *= 0.7; }

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed, value: (hp * 2), type, size, angle: 0,
      shield: Math.min(MAX_VAL, shield), sinOffset: Math.random() * 1000
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
        const versionMult = Math.pow(5, this.state.permanentUpgrades.version - 1);
        this.state.code = (1200 + (this.state.permanentUpgrades.startingCode || 0)) * versionMult;
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 2500;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 0.8;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 1.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 400) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*10, vy: (Math.random()-0.5)*10, size: Math.random()*5+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 30, life: 1.0, color, text });
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 60;
const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);

    // 1. Base Passive Trickle
    state.code = Math.min(MAX_VAL, state.code + (5 + state.level) * (dt / 1000) * versionMult);

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied & Enemy)
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;
      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        targetPos = { x: cx, y: cy };
      }
      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 60) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code = Math.min(MAX_VAL, state.code + proj.damage * 0.05); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const e1 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      const e2 = state.enemies[Math.floor(Math.random() * state.enemies.length)];
      if (e1 && e2 && e1.id !== e2.id && e1.hp > 0 && e2.hp > 0 && e1.type === e2.type && e1.isFriendly === e2.isFriendly) {
        e1.hp = Math.min(MAX_VAL, e1.hp + e2.hp);
        e1.maxHp = Math.min(MAX_VAL, e1.maxHp + e2.maxHp);
        e1.size = Math.min(e1.type === 'boss' ? 400 : 150, e1.size + 15);
        e1.value = Math.min(MAX_VAL, e1.value + e2.value);
        e2.hp = -999;
      }
    }

    // 5. Drops & Collection
    state.drops = state.drops.filter(d => {
      d.life -= 0.0015;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 2500 : 0) / cameraScale;
      const vacuumSpeed = 30;

      if (dist < 80 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Conversion Logic
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;

      if (enemy.isFriendly) {
         // Converted enemies move towards uncaptured planets and "capture" them
         const uncaptured = state.planets.filter(p => !p.isCaptured);
         if (uncaptured.length > 0) {
             // Find nearest planet
             let nearest = uncaptured[0];
             let minD = Infinity;
             uncaptured.forEach(p => {
                 const d = Math.sqrt((p.x - enemy.x)**2 + (p.y - enemy.y)**2);
                 if (d < minD) { minD = d; nearest = p; }
             });

             const dx = nearest.x - enemy.x;
             const dy = nearest.y - enemy.y;
             const dist = Math.sqrt(dx * dx + dy * dy);

             if (dist < 100) {
                 nearest.hp -= enemy.hp * 0.1; // Deal damage to planet
                 enemy.hp -= nearest.maxHp * 0.005; // Take some fatigue
                 if (nearest.hp <= 0) this.capturePlanet(state, nearest, onLevelUp);
             }

             enemy.x += (dx / dist) * enemy.speed * 0.7;
             enemy.y += (dy / dist) * enemy.speed * 0.7;
             enemy.angle = Math.atan2(dy, dx);
         } else {
             // Move away from core if nothing left
             const dx = enemy.x - cx;
             const dy = enemy.y - cy;
             const dist = Math.sqrt(dx * dx + dy * dy);
             enemy.x += (dx / dist) * enemy.speed;
             enemy.y += (dy / dist) * enemy.speed;
             enemy.angle = Math.atan2(dy, dx);
         }
      } else {
         const dx = cx - enemy.x;
         const dy = cy - enemy.y;
         const dist = Math.sqrt(dx * dx + dy * dy);

         if (dist < (enemy.type === 'boss' ? 150 : 85)) {
           state.coreHp -= (enemy.type === 'boss' ? 500 : 25) + (state.level * 2);
           enemy.hp = -1;
           if (state.coreHp <= 0) {
             state.coreHp = 0;
             state.isGameOver = true;
           }
           return;
         }

         if (enemy.type === 'null_pointer' && !enemy.hasBlinked && enemy.hp < enemy.maxHp * 0.5) {
            enemy.hasBlinked = true;
            enemy.x += (dx / dist) * 600;
            enemy.y += (dy / dist) * 600;
         }

         let finalSpeed = enemy.speed;
         if (enemy.type === 'worm') {
             const sin = Math.sin((now + (enemy.sinOffset || 0)) * 0.005) * 50;
             const perpX = -dy / dist;
             const perpY = dx / dist;
             enemy.x += perpX * sin * 0.05;
             enemy.y += perpY * sin * 0.05;
         }

         enemy.x += (dx / dist) * finalSpeed;
         enemy.y += (dy / dist) * finalSpeed;
         enemy.angle = Math.atan2(dy, dx);
      }
    });

    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory || state.isCompiling) return false;
    let hitSomething = false;
    const now = Date.now();
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);

    const projInterceptRadius = 80 / cameraScale;
    state.projectiles = state.projectiles.filter(p => {
      if (p.type !== 'enemy') return true;
      const dist = Math.sqrt((p.x - worldX) ** 2 + (p.y - worldY) ** 2);
      if (dist < projInterceptRadius) {
        state.code = Math.min(MAX_VAL, state.code + (500 * versionMult));
        state.experience += 50;
        hitSomething = true;
        return false;
      }
      return true;
    });

    const dropCollectionRadius = 100 / cameraScale;
    state.drops = state.drops.filter(d => {
      const dist = Math.sqrt((d.x - worldX) ** 2 + (d.y - worldY) ** 2);
      if (dist < dropCollectionRadius) {
        this.collectDrop(state, d);
        onItemCollected(d);
        hitSomething = true;
        return false;
      }
      return true;
    });

    const splashRadius = 180 + (state.level * 5);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0 || enemy.isFriendly) return; // Don't hurt friends
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 80 ? 1.0 : Math.max(0.5, (1 - (dist / splashRadius)));
        let actualDmg = state.clickPower * damageMult;

        // --- OVERWHELMING FORCE CONVERSION ---
        // If hit deals > 25% of current HP and level is high, chance to convert.
        // If hit > 200% of Max HP, instant conversion!
        if (actualDmg > enemy.maxHp * 1.5 && state.level > 100) {
            enemy.isFriendly = true;
            enemy.hp = enemy.maxHp * 0.5; // Re-initialize as healthy ally
            hitSomething = true;
            onEnemyHit(enemy);
            return;
        }

        enemy.hp -= actualDmg;
        enemy.lastHit = now;
        state.code = Math.min(MAX_VAL, state.code + (5 * versionMult));
        hitSomething = true;
        onEnemyHit(enemy);

        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const { damageMult, rangeMult, fireRateMult } = state.towerModifiers;
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);

    const typeCounts: Record<string, number> = {};
    state.towers.forEach(t => {
      typeCounts[t.type] = (typeCounts[t.type] || 0) + 1;
    });

    state.towers.forEach(tower => {
      if (tower.disabledUntil && now < tower.disabledUntil) return;
      const synergyBonus = 1 + ((typeCounts[tower.type] || 1) - 1) * 0.12;
      const effectiveRange = tower.range * rangeMult;
      const effectiveDamage = tower.damage * damageMult * synergyBonus;
      const effectiveFireRate = tower.fireRate * fireRateMult;

      if (now - tower.lastFired > effectiveFireRate) {
        let targets: (Enemy | Planet)[] = [];
        if (tower.type === 'AOE') {
          state.enemies.forEach(e => {
            if (e.hp > 0 && !e.isFriendly && Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2) < effectiveRange) targets.push(e);
          });
        } else {
          let minDist = effectiveRange;
          let nearest: (Enemy | Planet) | null = null;
          state.enemies.forEach(e => {
            if (e.hp <= 0 || e.isFriendly) return;
            const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = e; }
          });
          if (!nearest) {
            state.planets.filter(p => !p.isCaptured).forEach(p => {
              const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
              if (dist < minDist) { minDist = dist; nearest = p; }
            });
          }
          if (nearest) targets.push(nearest);
        }

        if (targets.length > 0) {
          targets.forEach(target => {
            let towerDmg = effectiveDamage;
            if ('shield' in target && (target as Enemy).shield && (target as Enemy).shield! > 0) {
                const absorbed = Math.min((target as Enemy).shield!, towerDmg);
                (target as Enemy).shield! -= absorbed;
                towerDmg -= absorbed;
            }
            target.hp -= towerDmg;
            state.code = Math.min(MAX_VAL, state.code + towerDmg * 0.05);
            state.experience += Math.max(0, towerDmg * 0.15 * state.permanentUpgrades.xpMultiplier);
            if ('lastHit' in target) (target as Enemy).lastHit = now;
            onFire(tower, target);

            if (target.hp <= 0) {
              const isEnemy = 'type' in target;
              const isPlanet = 'isCaptured' in target;
              if (isEnemy && !(target as any)._processed) {
                this.processEnemyDeath(state, target as Enemy, false);
                this.checkLevelUp(state, onLevelUp);
              } else if (isPlanet && !(target as Planet).isCaptured) {
                this.capturePlanet(state, target as Planet, onLevelUp);
              }
            }
          });
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += (2500 * (planet.sector + 1)) * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);
    if (d.type === 'shard') {
      state.spProgress += 1;
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
      }
    } else if (d.type === 'loc') {
      state.code = Math.min(MAX_VAL, state.code + (500 + (state.level * 100)) * (state.currentSector + 1) * versionMult);
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);

    if (enemy.type === 'memory_leak' && !enemy.isChild) {
        for (let i = 0; i < 3; i++) {
            const angle = Math.random() * Math.PI * 2;
            state.enemies.push({
                ...enemy,
                id: Math.random().toString(36),
                hp: enemy.maxHp * 0.3,
                maxHp: enemy.maxHp * 0.3,
                speed: enemy.speed * 1.5,
                size: enemy.size * 0.5,
                isChild: true,
                x: enemy.x + Math.cos(angle) * 20,
                y: enemy.y + Math.sin(angle) * 20,
                isFriendly: enemy.isFriendly // Children inherit allegiance
            } as any);
        }
    }

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.15) * state.permanentUpgrades.xpMultiplier;
    if (state.unlockedTech.includes('tech_efficiency')) rewardMult *= 1.2;
    if (state.unlockedTech.includes('tech_xp_boost')) rewardMult *= 1.5;
    if (enemy.type === 'boss') rewardMult *= 10;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code = Math.min(MAX_VAL, state.code + Math.floor(enemy.value * rewardMult * versionMult));

    state.spProgress += isManual ? 0.1 : 0.2;
    if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress -= state.spGoal;
        state.spGoal = Math.floor(state.spGoal * 1.05) + 1;
    }

    const rand = Math.random();
    let shardChance = isManual ? 0.6 : 0.4;
    if (state.unlockedSkills.includes('fast_shards')) shardChance *= 1.5;

    if (enemy.type === 'boss') {
      for (let i = 0; i < 8; i++) {
        state.drops.push({ 
          id: Math.random().toString(36), name: 'Core Shard', type: 'shard', rarity: 'rare', effect: 'SP', 
          x: enemy.x + (Math.random() - 0.5) * 150, y: enemy.y + (Math.random() - 0.5) * 150, life: 3.0 
        });
      }
    } else if (rand < shardChance) {
      state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP', x: enemy.x, y: enemy.y, life: 1.5 });
    } else if (rand < 0.65) {
      state.drops.push({ id: Math.random().toString(36), name: 'Data', type: 'loc', rarity: 'common', effect: 'LOC', x: enemy.x, y: enemy.y, life: 1.5 });
    }
    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 200 + (state.level * 250);
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15;
      state.skillPoints += 1;
      onLevelUp();
    }
  }
}

import { GameState, Enemy } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 50;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.9;
    }

    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // Environment-based Grid
    const tier = Math.floor(state.currentSector / 5);
    const gridColors = ['#1e293b', '#064e3b', '#422006', '#2e1065', '#450a0a'];
    this.ctx.strokeStyle = gridColors[tier % gridColors.length];
    this.ctx.lineWidth = 1 / cameraScale;
    const gridSize = 1000 / (1 + (version * 0.1));
    const gridLimit = 20000 + (state.currentSector * 5000);

    for (let x = -gridLimit; x <= gridLimit; x += gridSize) {
        this.ctx.beginPath(); this.ctx.moveTo(cx + x, cy - gridLimit); this.ctx.lineTo(cx + x, cy + gridLimit); this.ctx.stroke();
    }
    for (let y = -gridLimit; y <= gridLimit; y += gridSize) {
        this.ctx.beginPath(); this.ctx.moveTo(cx - gridLimit, cy + y); this.ctx.lineTo(cx + gridLimit, cy + y); this.ctx.stroke();
    }

    // Capture Radius Visual
    this.ctx.strokeStyle = versionColor;
    this.ctx.globalAlpha = 0.05;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, 1200 + state.level * 10, 0, Math.PI * 2); this.ctx.stroke();
    this.ctx.globalAlpha = 1.0;

    // Planets
    state.planets.forEach(p => {
      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#450a0a';
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      this.ctx.strokeStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
      this.ctx.lineWidth = 4 / cameraScale;
      this.ctx.globalAlpha = 0.3;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 30, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = '#fff'; 
      this.ctx.font = `bold ${50 + p.size/5}px Space Grotesk`; 
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // Core with Evolution Rings
    const coreSize = 90 + (state.level * 0.3);
    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 40; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // Orbital Rings for Versions
    for (let i = 0; i < version; i++) {
        const radius = coreSize + 40 + (i * 30);
        const orbitAngle = (now * 0.001 * (1 + i * 0.2)) % (Math.PI * 2);
        this.ctx.strokeStyle = versionColor;
        this.ctx.lineWidth = 2;
        this.ctx.globalAlpha = 0.2;
        this.ctx.beginPath(); this.ctx.arc(cx, cy, radius, 0, Math.PI * 2); this.ctx.stroke();
        this.ctx.globalAlpha = 0.8;
        this.ctx.beginPath(); 
        this.ctx.arc(cx + Math.cos(orbitAngle) * radius, cy + Math.sin(orbitAngle) * radius, 8, 0, Math.PI * 2); 
        this.ctx.fill();
    }
    this.ctx.globalAlpha = 1.0;

    // Firing Effects
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = (ef.type === 'SNIPER' ? 6 : 2) * ef.life;
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.15;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // Enemies
    state.enemies.forEach(e => {
      const isHit = Date.now() - (e.lastHit || 0) < 100;
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));
      this.ctx.scale(isHit ? 1.2 : 1.0, isHit ? 1.2 : 1.0);

      if (e.isFriendly) {
         this.ctx.shadowBlur = 15;
         this.ctx.shadowColor = '#22d3ee';
      }

      if (e.type === 'null_pointer') {
          this.ctx.globalAlpha = 0.5;
          this.ctx.fillRect(-e.size/2, -e.size/2, e.size, e.size);
          this.ctx.globalAlpha = 1.0;
      }

      this.ctx.beginPath();
      if (e.type === 'boss') {
        this.ctx.moveTo(e.size, 0); this.ctx.lineTo(-e.size / 3, e.size / 2); this.ctx.lineTo(-e.size, 0); this.ctx.lineTo(-e.size / 3, -e.size / 2);
      } else {
        this.ctx.moveTo(e.size, 0); this.ctx.lineTo(-e.size / 2, e.size / 2); this.ctx.lineTo(-e.size / 2, -e.size / 2);
      }
      this.ctx.closePath();
      this.ctx.fill();

      if (e.shield && e.shield > 0) {
          this.ctx.strokeStyle = '#38bdf8';
          this.ctx.lineWidth = 4;
          this.ctx.beginPath(); this.ctx.arc(0, 0, e.size + 10, -Math.PI/2, Math.PI/2); this.ctx.stroke();
      }
      this.ctx.restore();
    });

    // Towers
    state.towers.forEach(t => {
      const isDisabled = t.disabledUntil && now < t.disabledUntil;
      this.ctx.fillStyle = isDisabled ? '#1e293b' : t.color;
      this.ctx.fillRect(t.x - 30, t.y - 30, 60, 60);

      this.ctx.strokeStyle = t.color; 
      this.ctx.lineWidth = 1 / cameraScale; 
      this.ctx.globalAlpha = Math.max(0.01, 0.1 * cameraScale);
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // Particles & Drops
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${p.size}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      }
    });

    state.drops.forEach(d => {
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.005);
      this.ctx.fillRect(-10, -10, 20, 20);
      this.ctx.restore();
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return COLORS.BOSS;
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

// Safeguard against JS floating point limits
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private resizeHandler: () => void;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    this.resizeHandler = () => this.resize();
    this.resize();
    window.addEventListener('resize', this.resizeHandler);
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  public destroy() {
    this.isDestroyed = true;
    window.removeEventListener('resize', this.resizeHandler);
    audio.stop();
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 2600 + (sector * 3500); 
    const count = PLANET_COUNT + (sector * 2);
    const names = ["NPM", "PYPI", "Maven", "Cargo", "Go-Get", "NuGet", "RubyGems", "Composer"];
    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);

    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 0.5);
      const baseHp = (3000 + (this.state.level * 200)) * Math.pow(1.5, sector);
      const cappedHp = Math.min(MAX_VAL, baseHp * versionBoost);

      this.state.planets.push({
        id: `planet_${sector}_${i}`, 
        name: `${names[i % names.length]}-${sector}`,
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: cappedHp,
        maxHp: cappedHp,
        isCaptured: false, size: 350 + (sector * 100), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    const versionMult = Math.pow(5, perms.version - 1);
    this.state.code = (1200 + (perms.startingCode || 0)) * versionMult;
    this.state.clickPower = 35 * perms.damageMultiplier * versionMult;

    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(0); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;

    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    const earnedLegacy = Math.floor(Math.log10(this.state.code + 1) * this.state.level / 10);
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 2000));

    this.state.isCompiling = false;
    this.reset();
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused || this.isDestroyed || this.state.isCompiling) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        if (e.isFriendly) {
           this.createParticles(e.x, e.y, 10, '#22d3ee');
        } else {
           this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        }
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const versionMult = Math.pow(2, this.state.permanentUpgrades.version - 1);
      const missReward = (50 + (this.state.level * 15)) * versionMult; // Increased base reward scaling
      this.state.code = Math.min(MAX_VAL, this.state.code + missReward);
      this.createFloatingText(worldX, worldY, `+${this.formatNumber(missReward)}`, COLORS.PRIMARY);
      audio.playClick();
    }

    if (this.state.ripples.length < 10) {
      this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150, life: 1.0 });
    }

    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+1 SKILL POINT", COLORS.SECONDARY);

    const uncapturedInSector = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncapturedInSector.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, `SECTOR ${this.state.currentSector} SYNCED`, COLORS.ACCENT);
    }

    if (this.state.level % 5 === 0) {
      this.state.maxCoreHp = Math.min(MAX_VAL, this.state.maxCoreHp + (500 * this.state.permanentUpgrades.version)); 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  private formatNumber(num: number): string {
    if (num < 1000) return num.toFixed(0);
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const suffix = suffixes[tier];
    const scale = Math.pow(10, tier * 3);
    const scaled = num / scale;
    return scaled.toFixed(2) + suffix;
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused || this.isDestroyed || this.state.isCompiling) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range: config.range, 
        damage: config.damage, 
        fireRate: config.fireRate, 
        lastFired: 0, 
        color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;

    if (!this.isPaused && !this.state.isCompiling) {
      this.update(dt);
    }

    // Performance optimization: skip frames if delta is too high or just throttle rendering
    this.renderer.draw(this.state, this.cameraScale, this.isPaused || !!this.state.isCompiling);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;

    // --- STEADY ZOOM ALGORITHM ---
    // Calculate the 'intended' distance based on the outer-most threat or planet.
    let targetDist = 1500;
    this.state.enemies.forEach(e => {
        if (e.isFriendly) return; // Converted allies don't push zoom
        const d = Math.sqrt((e.x - this.canvas.width/2)**2 + (e.y - this.canvas.height/2)**2);
        if (d > targetDist) targetDist = d;
    });
    this.state.planets.forEach(p => {
        if (!p.isCaptured && p.sector <= this.state.currentSector) {
           const d = Math.sqrt((p.x - this.canvas.width/2)**2 + (p.y - this.canvas.height/2)**2);
           if (d > targetDist) targetDist = d;
        }
    });

    // Use a 'zoom floor' that increases with sector to prevent unnerving snaps back in
    const sectorMinScale = 1.0 / (1 + this.state.currentSector * 0.8);
    const baseViewWidth = 850;
    this.targetCameraScale = Math.min(sectorMinScale, baseViewWidth / (targetDist * 1.1));

    // Interpolate camera scale smoothly
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.03;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const earnedLegacy = Math.max(0, Math.floor(Math.log10(this.state.code + 1)));
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) return;

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(10);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = this.state.level * 400 * Math.pow(2, this.state.permanentUpgrades.version - 1);
        if (this.state.unlockedSkills.includes('code_gen')) gain *= 10; 
        this.state.code = Math.min(MAX_VAL, this.state.code + gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    // Cap enemy spawn rate to prevent lag
    const baseFreq = Math.max(250, 2000 - (this.state.level * 10));
    const threatMult = 1 + (this.state.threatLevel * 0.3) + (this.state.currentSector * 0.2);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      // Prioritize spawning from planets in current sector
      const activePlanets = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      let type: Enemy['type'] = 'bug';
      const r = Math.random();
      if (this.state.level >= 20 || this.state.currentSector > 0) {
          if (r < 0.1) type = 'glitch';
          else if (r < 0.2) type = 'null_pointer';
          else if (r < 0.3) type = 'memory_leak';
          else if (r < 0.4) type = 'shielded';
          else if (r < 0.45) type = 'worm';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    // Performance Pruning
    if (this.state.particles.length > 200) this.state.particles.splice(0, 50);
    if (this.state.projectiles.length > 100) this.state.projectiles.splice(0, 20);

    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.02 : 0.08; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 10; r.life -= 0.05; return r.life > 0; });

    // Throttle React updates
    if (this.frameCount % 5 === 0) {
      this.onUpdate({ ...this.state });
    }
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3000 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const hp = 5000 * Math.pow(1.4, (this.state.level / 5) + this.state.currentSector) * Math.pow(10, this.state.permanentUpgrades.version - 1);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed: 0.8 + (this.state.level * 0.01), value: 50000 * this.state.permanentUpgrades.version, 
      type: 'boss', size: 350, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "SYSTEM COLLISION DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: Enemy['type'] = 'bug') {
    // Limits on total enemies to maintain performance
    if (this.state.enemies.length > 80) return;

    const dist = 4000 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }

    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);
    const hpMult = Math.pow(1.1, Math.min(this.state.level, 5000) + (this.state.currentSector * 8));
    let hp = 60 * hpMult * versionBoost;
    let speed = 1.2 + (Math.min(this.state.level, 1000) * 0.02);
    let size = 50 + (Math.min(this.state.level, 5000) * 0.1);
    let shield = 0;

    if (type === 'glitch') { hp *= 2; speed += 0.5; }
    if (type === 'shielded') { shield = hp * 0.8; hp *= 1.2; speed *= 0.6; size += 20; }
    if (type === 'null_pointer') { hp *= 0.7; speed += 1.5; }
    if (type === 'memory_leak') { hp *= 1.5; speed *= 0.7; size += 30; }
    if (type === 'worm') { hp *= 0.4; speed += 1.0; size *= 0.8; }

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed, value: (hp * 1.5), type, size, angle: 0,
      shield: Math.min(MAX_VAL, shield), sinOffset: Math.random() * 1000
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 10000;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 1.5;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 2.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 250) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*12, vy: (Math.random()-0.5)*12, size: Math.random()*4+1, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -4, size: 24, life: 1.0, color, text });
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 50; // Reduced for performance
const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);

    // 1. Improved Passive Trickle (Better scaling for mid-game)
    const basePassive = (10 + state.level * 2) * (dt / 1000) * versionMult;
    state.code = Math.min(MAX_VAL, state.code + basePassive);

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Allied & Enemy)
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;
      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        targetPos = { x: cx, y: cy };
      }
      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < 80) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code = Math.min(MAX_VAL, state.code + proj.damage * 0.1); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Aggressive Enemy Merging (Optimization)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      for (let i = 0; i < 5; i++) {
        const idx1 = Math.floor(Math.random() * state.enemies.length);
        const idx2 = Math.floor(Math.random() * state.enemies.length);
        const e1 = state.enemies[idx1];
        const e2 = state.enemies[idx2];
        if (e1 && e2 && idx1 !== idx2 && e1.type === e2.type && e1.isFriendly === e2.isFriendly) {
           const dist = Math.sqrt((e1.x-e2.x)**2 + (e1.y-e2.y)**2);
           if (dist < 300) {
              e1.hp = Math.min(MAX_VAL, e1.hp + e2.hp);
              e1.maxHp = Math.min(MAX_VAL, e1.maxHp + e2.maxHp);
              e1.size = Math.min(400, e1.size + 10);
              e1.value = Math.min(MAX_VAL, e1.value + e2.value);
              state.enemies.splice(idx2, 1);
              break;
           }
        }
      }
    }

    // 5. Drops & Collection
    state.drops = state.drops.filter(d => {
      d.life -= 0.002;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 4000 : 0) / cameraScale;
      const vacuumSpeed = 45;

      if (dist < 100 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Enemy Movement & Advanced Conversion Logic
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;

      if (enemy.isFriendly) {
         // Friendly units seek uncaptured planets with high efficiency
         const uncaptured = state.planets.filter(p => !p.isCaptured);
         if (uncaptured.length > 0) {
             let nearest = uncaptured[0];
             let minD = Infinity;
             uncaptured.forEach(p => {
                 const d = Math.sqrt((p.x - enemy.x)**2 + (p.y - enemy.y)**2);
                 if (d < minD) { minD = d; nearest = p; }
             });

             const dx = nearest.x - enemy.x;
             const dy = nearest.y - enemy.y;
             const dist = Math.sqrt(dx * dx + dy * dy);

             if (dist < 150) {
                 nearest.hp -= enemy.hp * 0.25; // Converted allies are much stronger
                 enemy.hp -= nearest.maxHp * 0.001; 
                 if (nearest.hp <= 0) this.capturePlanet(state, nearest, onLevelUp);
             }

             enemy.x += (dx / dist) * enemy.speed * 1.2;
             enemy.y += (dy / dist) * enemy.speed * 1.2;
             enemy.angle = Math.atan2(dy, dx);
         } else {
             // If everything captured, push outwards to future sectors
             const dx = enemy.x - cx;
             const dy = enemy.y - cy;
             const dist = Math.sqrt(dx * dx + dy * dy);
             enemy.x += (dx / dist) * enemy.speed;
             enemy.y += (dy / dist) * enemy.speed;
             enemy.angle = Math.atan2(dy, dx);
         }
      } else {
         const dx = cx - enemy.x;
         const dy = cy - enemy.y;
         const dist = Math.sqrt(dx * dx + dy * dy);

         if (dist < (enemy.type === 'boss' ? 180 : 100)) {
           state.coreHp -= (enemy.type === 'boss' ? 1000 : 40) + (state.level * 5);
           enemy.hp = -1;
           if (state.coreHp <= 0) {
             state.coreHp = 0;
             state.isGameOver = true;
           }
           return;
         }

         let finalSpeed = enemy.speed;
         enemy.x += (dx / dist) * finalSpeed;
         enemy.y += (dy / dist) * finalSpeed;
         enemy.angle = Math.atan2(dy, dx);
      }
    });

    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory || state.isCompiling) return false;
    let hitSomething = false;
    const now = Date.now();
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);

    // Hit allied projectiles to gain resources
    state.projectiles = state.projectiles.filter(p => {
      if (p.type !== 'enemy') return true;
      const dist = Math.sqrt((p.x - worldX) ** 2 + (p.y - worldY) ** 2);
      if (dist < 100 / cameraScale) {
        state.code = Math.min(MAX_VAL, state.code + (1000 * versionMult));
        state.experience += 100;
        hitSomething = true;
        return false;
      }
      return true;
    });

    const splashRadius = 220 + (state.level * 2);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0 || enemy.isFriendly) return;
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 100 ? 1.0 : Math.max(0.3, (1 - (dist / splashRadius)));
        let actualDmg = state.clickPower * damageMult;

        // --- BUFFED CONVERSION ---
        // Lower threshold: if hit > 50% max hp, or total force is overwhelming
        if (actualDmg > enemy.maxHp * 0.8 && state.level > 50) {
            enemy.isFriendly = true;
            enemy.hp = enemy.maxHp;
            enemy.speed *= 1.5;
            hitSomething = true;
            onEnemyHit(enemy);
            return;
        }

        enemy.hp -= actualDmg;
        enemy.lastHit = now;
        state.code = Math.min(MAX_VAL, state.code + (10 * versionMult));
        hitSomething = true;
        onEnemyHit(enemy);

        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const { damageMult, rangeMult, fireRateMult } = state.towerModifiers;
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);

    state.towers.forEach(tower => {
      if (tower.disabledUntil && now < tower.disabledUntil) return;

      const effectiveRange = tower.range * rangeMult;
      const effectiveDamage = tower.damage * damageMult;
      const effectiveFireRate = tower.fireRate * fireRateMult;

      if (now - tower.lastFired > effectiveFireRate) {
        let nearest: (Enemy | Planet) | null = null;
        let minDist = effectiveRange;

        // Target enemies first
        state.enemies.forEach(e => {
          if (e.hp <= 0 || e.isFriendly) return;
          const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
          if (dist < minDist) { minDist = dist; nearest = e; }
        });

        // Target planets if no enemies
        if (!nearest) {
          state.planets.filter(p => !p.isCaptured).forEach(p => {
            const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = p; }
          });
        }

        if (nearest) {
          nearest.hp -= effectiveDamage;
          state.code = Math.min(MAX_VAL, state.code + effectiveDamage * 0.1);
          state.experience += Math.max(0, effectiveDamage * 0.2 * state.permanentUpgrades.xpMultiplier);
          if ('lastHit' in nearest) (nearest as Enemy).lastHit = now;
          onFire(tower, nearest);

          if (nearest.hp <= 0) {
            const isEnemy = 'type' in nearest;
            const isPlanet = 'isCaptured' in nearest;
            if (isEnemy && !(nearest as any)._processed) {
              this.processEnemyDeath(state, nearest as Enemy, false);
              this.checkLevelUp(state, onLevelUp);
            } else if (isPlanet && !(nearest as Planet).isCaptured) {
              this.capturePlanet(state, nearest as Planet, onLevelUp);
            }
          }
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    // Massive XP boost for planet capture to combat mid-game stagnation
    state.experience += (10000 * (planet.sector + 1)) * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);
    if (d.type === 'shard') {
      state.spProgress += 2; // Buffed shard value
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.08) + 1;
      }
    } else if (d.type === 'loc') {
      state.code = Math.min(MAX_VAL, state.code + (1000 + (state.level * 250)) * (state.currentSector + 1) * versionMult);
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;
    const versionMult = Math.pow(2, state.permanentUpgrades.version - 1);

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.2) * state.permanentUpgrades.xpMultiplier;
    if (enemy.type === 'boss') rewardMult *= 20;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code = Math.min(MAX_VAL, state.code + Math.floor(enemy.value * rewardMult * versionMult));

    state.spProgress += isManual ? 0.5 : 1.0;
    if (state.spProgress >= state.spGoal) {
        state.skillPoints += 1;
        state.spProgress -= state.spGoal;
        state.spGoal = Math.floor(state.spGoal * 1.08) + 1;
    }

    // High chance of loot for satisfaction
    const rand = Math.random();
    if (enemy.type === 'boss' || rand < 0.3) {
      state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP', x: enemy.x, y: enemy.y, life: 2.5 });
    } else if (rand < 0.6) {
      state.drops.push({ id: Math.random().toString(36), name: 'Data', type: 'loc', rarity: 'common', effect: 'LOC', x: enemy.x, y: enemy.y, life: 2.0 });
    }
    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 250 + (state.level * 300); // Smoother XP curve
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.12; 
      state.skillPoints += 2; // More skill points at high level to maintain sense of power
      onLevelUp();
    }
  }
}

import { GameState, Enemy } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 40;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    // Dynamic background clearing
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.92;
    }

    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // Environment-based Grid (Infinite feel)
    const tier = Math.floor(state.currentSector / 5);
    const gridColors = ['#1e293b', '#064e3b', '#422006', '#2e1065', '#450a0a'];
    this.ctx.strokeStyle = gridColors[tier % gridColors.length];

    // Scale line width so it doesn't disappear when zoomed out
    this.ctx.lineWidth = Math.max(0.5, 1.5 / cameraScale);

    const gridSize = 1000;
    const gridLimit = 30000 + (state.currentSector * 5000);

    // Efficient grid rendering (only draw visible portion eventually, but this is simple)
    this.ctx.globalAlpha = 0.5;
    for (let x = -gridLimit; x <= gridLimit; x += gridSize) {
        this.ctx.beginPath(); this.ctx.moveTo(cx + x, cy - gridLimit); this.ctx.lineTo(cx + x, cy + gridLimit); this.ctx.stroke();
    }
    for (let y = -gridLimit; y <= gridLimit; y += gridSize) {
        this.ctx.beginPath(); this.ctx.moveTo(cx - gridLimit, cy + y); this.ctx.lineTo(cx + gridLimit, cy + y); this.ctx.stroke();
    }
    this.ctx.globalAlpha = 1.0;

    // Capture Horizon (Sphere of Influence)
    const horizonRadius = 2600 + (state.currentSector * 3500);
    this.ctx.strokeStyle = versionColor;
    this.ctx.lineWidth = 10 / cameraScale;
    this.ctx.globalAlpha = 0.1;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, horizonRadius, 0, Math.PI * 2); this.ctx.stroke();
    this.ctx.globalAlpha = 1.0;

    // Planets
    state.planets.forEach(p => {
      const isVisible = p.sector <= state.currentSector + 1;
      if (!isVisible) return;

      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#450a0a';
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();

      this.ctx.strokeStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
      this.ctx.lineWidth = 8 / cameraScale;
      this.ctx.globalAlpha = 0.3;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size + 40, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;

      this.ctx.fillStyle = '#fff'; 
      this.ctx.font = `bold ${Math.max(40, 60 / cameraScale)}px Space Grotesk`; 
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + 20);
    });

    // Core with Evolution Rings
    const coreSize = 100 + (state.level * 0.2);
    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 40 / cameraScale; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // Orbital Rings for Versions
    for (let i = 0; i < version; i++) {
        const radius = coreSize + 50 + (i * 40);
        const orbitAngle = (now * 0.001 * (1 + i * 0.2)) % (Math.PI * 2);
        this.ctx.strokeStyle = versionColor;
        this.ctx.lineWidth = 3 / cameraScale;
        this.ctx.globalAlpha = 0.15;
        this.ctx.beginPath(); this.ctx.arc(cx, cy, radius, 0, Math.PI * 2); this.ctx.stroke();
        this.ctx.globalAlpha = 0.8;
        this.ctx.beginPath(); 
        this.ctx.arc(cx + Math.cos(orbitAngle) * radius, cy + Math.sin(orbitAngle) * radius, 12, 0, Math.PI * 2); 
        this.ctx.fill();
    }
    this.ctx.globalAlpha = 1.0;

    // Firing Effects
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = (ef.type === 'SNIPER' ? 10 : 4) * ef.life / cameraScale;
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.1;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // Enemies & Allies
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = Date.now() - (e.lastHit || 0) < 100;
      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));

      if (e.isFriendly) {
         this.ctx.shadowBlur = 20 / cameraScale;
         this.ctx.shadowColor = '#22d3ee';
      }

      const drawSize = e.size;
      this.ctx.beginPath();
      if (e.type === 'boss') {
        this.ctx.moveTo(drawSize, 0); 
        this.ctx.lineTo(-drawSize / 2, drawSize / 1.5); 
        this.ctx.lineTo(-drawSize, 0); 
        this.ctx.lineTo(-drawSize / 2, -drawSize / 1.5);
      } else {
        this.ctx.moveTo(drawSize, 0); 
        this.ctx.lineTo(-drawSize / 2, drawSize / 2); 
        this.ctx.lineTo(-drawSize / 2, -drawSize / 2);
      }
      this.ctx.closePath();
      this.ctx.fill();

      if (e.shield && e.shield > 0) {
          this.ctx.strokeStyle = '#38bdf8';
          this.ctx.lineWidth = 5 / cameraScale;
          this.ctx.beginPath(); this.ctx.arc(0, 0, drawSize + 20, -Math.PI/2, Math.PI/2); this.ctx.stroke();
      }
      this.ctx.restore();
    });

    // Towers
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      this.ctx.fillRect(t.x - 35, t.y - 35, 70, 70);

      this.ctx.strokeStyle = t.color; 
      this.ctx.lineWidth = 1 / cameraScale; 
      this.ctx.globalAlpha = 0.05;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range * state.towerModifiers.rangeMult, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // Particles & Drops
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${Math.max(20, p.size / cameraScale)}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); this.ctx.fill();
      }
    });

    state.drops.forEach(d => {
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.005);
      const s = 15 / cameraScale;
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return COLORS.BOSS;
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Enemy } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 40;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    // NONLINEAR SCALE FACTOR: This is the key. 
    // It prevents units from becoming tiny dots at low cameraScale.
    const perceivedScale = 1 / Math.pow(cameraScale, 0.55);

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.92;
    }

    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // Grid (Stays subtle but visible)
    const tier = Math.floor(state.currentSector / 5);
    const gridColors = ['#1e293b', '#064e3b', '#422006', '#2e1065', '#450a0a'];
    this.ctx.strokeStyle = gridColors[tier % gridColors.length];
    this.ctx.lineWidth = 2 / cameraScale;

    const gridSize = 1500;
    const gridLimit = 50000 + (state.currentSector * 10000);

    this.ctx.globalAlpha = 0.3;
    for (let x = -gridLimit; x <= gridLimit; x += gridSize) {
        this.ctx.beginPath(); this.ctx.moveTo(cx + x, cy - gridLimit); this.ctx.lineTo(cx + x, cy + gridLimit); this.ctx.stroke();
    }
    for (let y = -gridLimit; y <= gridLimit; y += gridSize) {
        this.ctx.beginPath(); this.ctx.moveTo(cx - gridLimit, cy + y); this.ctx.lineTo(cx + gridLimit, cy + y); this.ctx.stroke();
    }
    this.ctx.globalAlpha = 1.0;

    // Capture Horizon
    const horizonRadius = 2600 + (state.currentSector * 3500);
    this.ctx.strokeStyle = versionColor;
    this.ctx.lineWidth = 15 / cameraScale;
    this.ctx.globalAlpha = 0.15;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, horizonRadius, 0, Math.PI * 2); this.ctx.stroke();
    this.ctx.globalAlpha = 1.0;

    // Planets
    state.planets.forEach(p => {
      const isVisible = p.sector <= state.currentSector + 1;
      if (!isVisible) return;

      const planetPerceivedSize = p.size * perceivedScale * 0.4;
      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#450a0a';
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, planetPerceivedSize, 0, Math.PI * 2); this.ctx.fill();

      this.ctx.strokeStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
      this.ctx.lineWidth = 12 / cameraScale;
      this.ctx.globalAlpha = 0.4;
      this.ctx.beginPath(); this.ctx.arc(p.x, p.y, planetPerceivedSize + (60 / cameraScale), 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;

      this.ctx.fillStyle = '#fff'; 
      this.ctx.font = `bold ${Math.max(30, 80 / cameraScale)}px Space Grotesk`; 
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, p.x, p.y + (20 / cameraScale));
    });

    // Core
    const coreSize = (100 + (state.level * 0.2)) * perceivedScale * 0.5;
    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 50 / cameraScale; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // Firing Effects
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = (ef.type === 'SNIPER' ? 20 : 8) * ef.life / cameraScale;
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.12;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // Enemies & Allies
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = Date.now() - (e.lastHit || 0) < 100;
      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));

      if (e.isFriendly) {
         this.ctx.shadowBlur = 30 / cameraScale;
         this.ctx.shadowColor = '#22d3ee';
      }

      // SCALE THE UNIT VISUALLY
      const drawSize = e.size * perceivedScale * 0.5;

      this.ctx.beginPath();
      if (e.type === 'boss') {
        this.ctx.moveTo(drawSize, 0); 
        this.ctx.lineTo(-drawSize / 1.5, drawSize); 
        this.ctx.lineTo(-drawSize * 1.5, 0); 
        this.ctx.lineTo(-drawSize / 1.5, -drawSize);
      } else {
        this.ctx.moveTo(drawSize, 0); 
        this.ctx.lineTo(-drawSize, drawSize / 1.2); 
        this.ctx.lineTo(-drawSize, -drawSize / 1.2);
      }
      this.ctx.closePath();
      this.ctx.fill();

      if (e.shield && e.shield > 0) {
          this.ctx.strokeStyle = '#38bdf8';
          this.ctx.lineWidth = 8 / cameraScale;
          this.ctx.beginPath(); this.ctx.arc(0, 0, drawSize + (30 / cameraScale), -Math.PI/2, Math.PI/2); this.ctx.stroke();
      }
      this.ctx.restore();
    });

    // Towers
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const tSize = 50 * perceivedScale * 0.5;
      this.ctx.fillRect(t.x - tSize, t.y - tSize, tSize * 2, tSize * 2);

      this.ctx.strokeStyle = t.color; 
      this.ctx.lineWidth = 4 / cameraScale; 
      this.ctx.globalAlpha = 0.08;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range * state.towerModifiers.rangeMult, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // Particles & Drops
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${Math.max(30, 100 / cameraScale)}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        const pSize = p.size * perceivedScale * 0.3;
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, pSize, 0, Math.PI * 2); this.ctx.fill();
      }
    });

    state.drops.forEach(d => {
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.005);
      const s = 30 * perceivedScale * 0.25;
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return COLORS.BOSS;
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 4;
const SHARDS_PER_SP_BASE = 20;

// Safeguard against JS floating point limits
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private resizeHandler: () => void;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    this.resizeHandler = () => this.resize();
    this.resize();
    window.addEventListener('resize', this.resizeHandler);
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  public destroy() {
    this.isDestroyed = true;
    window.removeEventListener('resize', this.resizeHandler);
    audio.stop();
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 2600 + (sector * 3500); 
    const count = PLANET_COUNT + (sector * 2);
    const names = ["NPM", "PYPI", "Maven", "Cargo", "Go-Get", "NuGet", "RubyGems", "Composer"];
    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);

    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 0.5);
      const baseHp = (3000 + (this.state.level * 200)) * Math.pow(1.8, sector);
      const cappedHp = Math.min(MAX_VAL, baseHp * versionBoost);

      this.state.planets.push({
        id: `planet_${sector}_${i}`, 
        name: `${names[i % names.length]}-${sector}`,
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: cappedHp,
        maxHp: cappedHp,
        isCaptured: false, size: 350 + (sector * 100), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    const versionMult = Math.pow(5, perms.version - 1);
    this.state.code = (1200 + (perms.startingCode || 0)) * versionMult;
    this.state.clickPower = 35 * perms.damageMultiplier * versionMult;

    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(0); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;

    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    const earnedLegacy = Math.floor(Math.log10(this.state.code + 1) * this.state.level / 5);
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 2000));

    this.state.isCompiling = false;
    this.reset();
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused || this.isDestroyed || this.state.isCompiling) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        if (e.isFriendly) {
           this.createParticles(e.x, e.y, 10, '#22d3ee');
        } else {
           this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        }
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const versionMult = Math.pow(2.5, this.state.permanentUpgrades.version - 1);
      const missReward = (100 + (this.state.level * 25) * (1 + this.state.currentSector)) * versionMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + missReward);
      this.createFloatingText(worldX, worldY, `+${this.formatNumber(missReward)}`, COLORS.PRIMARY);
      audio.playClick();
    }

    if (this.state.ripples.length < 8) {
      this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 150 / this.cameraScale, life: 1.0 });
    }

    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 80, "+2 SKILL POINTS", COLORS.SECONDARY);

    const uncapturedInSector = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncapturedInSector.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, `SECTOR ${this.state.currentSector} SYNCED`, COLORS.ACCENT);
    }

    if (this.state.level % 5 === 0) {
      this.state.maxCoreHp = Math.min(MAX_VAL, this.state.maxCoreHp + (1000 * this.state.permanentUpgrades.version)); 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  private formatNumber(num: number): string {
    if (num < 1000) return num.toFixed(0);
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const suffix = suffixes[tier];
    const scale = Math.pow(10, tier * 3);
    const scaled = num / scale;
    return scaled.toFixed(2) + suffix;
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused || this.isDestroyed || this.state.isCompiling) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range: config.range, 
        damage: config.damage, 
        fireRate: config.fireRate, 
        lastFired: 0, 
        color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;

    if (!this.isPaused && !this.state.isCompiling) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused || !!this.state.isCompiling);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;

    // --- SMOOTH STEADY ZOOM ---
    let targetDist = 1800;
    this.state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const d = Math.sqrt((e.x - this.canvas.width/2)**2 + (e.y - this.canvas.height/2)**2);
        if (d > targetDist) targetDist = d;
    });
    this.state.planets.forEach(p => {
        if (!p.isCaptured && p.sector <= this.state.currentSector) {
           const d = Math.sqrt((p.x - this.canvas.width/2)**2 + (p.y - this.canvas.height/2)**2);
           if (d > targetDist) targetDist = d;
        }
    });

    const sectorMinScale = 1.0 / (1 + this.state.currentSector * 0.9);
    const baseViewWidth = 900;
    // We dampen the target camera scale to prevent sudden jumps
    this.targetCameraScale = Math.min(sectorMinScale, baseViewWidth / (targetDist * 1.05));

    // Smooth lerp
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.02;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const earnedLegacy = Math.max(0, Math.floor(Math.log10(this.state.code + 1)));
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) return;

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(10);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = (this.state.level * 800) * Math.pow(2.2, this.state.permanentUpgrades.version - 1) * (1 + this.state.currentSector);
        if (this.state.unlockedSkills.includes('code_gen')) gain *= 15; 
        this.state.code = Math.min(MAX_VAL, this.state.code + gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(300, 2500 - (this.state.level * 12));
    const threatMult = 1 + (this.state.threatLevel * 0.3) + (this.state.currentSector * 0.25);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      let type: Enemy['type'] = 'bug';
      const r = Math.random();
      if (this.state.level >= 20 || this.state.currentSector > 0) {
          if (r < 0.12) type = 'glitch';
          else if (r < 0.22) type = 'null_pointer';
          else if (r < 0.32) type = 'memory_leak';
          else if (r < 0.42) type = 'shielded';
          else if (r < 0.48) type = 'worm';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    // High precision pruning
    if (this.state.particles.length > 150) this.state.particles.splice(0, 30);

    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.015 : 0.09; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 12; r.life -= 0.04; return r.life > 0; });

    if (this.frameCount % 5 === 0) {
      this.onUpdate({ ...this.state });
    }
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3500 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const sectorFactor = Math.pow(1.6, this.state.currentSector);
    const hp = 8000 * Math.pow(1.35, (this.state.level / 5)) * sectorFactor * Math.pow(10, this.state.permanentUpgrades.version - 1);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed: 1.0 + (this.state.level * 0.01), value: 100000 * this.state.permanentUpgrades.version * (1 + this.state.currentSector), 
      type: 'boss', size: 350, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "FATAL OVERFLOW DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: Enemy['type'] = 'bug') {
    if (this.state.enemies.length > 70) return;

    const dist = 4500 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle)*150; y = sy + Math.sin(angle)*150;
    }

    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);
    const sectorFactor = Math.pow(1.15, this.state.currentSector * 10);
    const hpMult = Math.pow(1.1, Math.min(this.state.level, 5000));
    let hp = 80 * hpMult * versionBoost * sectorFactor;
    let speed = 1.3 + (Math.min(this.state.level, 1000) * 0.02);
    let size = 55 + (Math.min(this.state.level, 5000) * 0.08);
    let shield = 0;

    if (type === 'glitch') { hp *= 2.5; speed += 0.6; }
    if (type === 'shielded') { shield = hp * 1.0; hp *= 1.1; speed *= 0.6; size += 25; }
    if (type === 'null_pointer') { hp *= 0.6; speed += 1.8; }
    if (type === 'memory_leak') { hp *= 1.8; speed *= 0.65; size += 40; }
    if (type === 'worm') { hp *= 0.35; speed += 1.2; size *= 0.75; }

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed, value: (hp * 2), type, size, angle: 0,
      shield: Math.min(MAX_VAL, shield), sinOffset: Math.random() * 1000
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.15);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 20000;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 2.0;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 2.5;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 200) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*15, vy: (Math.random()-0.5)*15, size: Math.random()*5+1, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -3, size: 22, life: 1.2, color, text });
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 40; 
const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    const versionMult = Math.pow(2.2, state.permanentUpgrades.version - 1);

    // 1. Hyper-scaling Passive (Mid-game boost)
    const midGameBoost = Math.max(1, state.level / 100);
    const basePassive = (15 + state.level * 4) * (dt / 1000) * versionMult * midGameBoost * (1 + state.currentSector);
    state.code = Math.min(MAX_VAL, state.code + basePassive);

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles 
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;
      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        targetPos = { x: cx, y: cy };
      }
      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Scale collision radius with zoom to feel impactful
      const hitRadius = Math.max(80, 100 / cameraScale);
      if (dist < hitRadius) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code = Math.min(MAX_VAL, state.code + proj.damage * 0.15); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Aggressive Deep-Space Merging
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      const mergeDistLimit = 500 / cameraScale;
      for (let i = 0; i < 10; i++) {
        const idx1 = Math.floor(Math.random() * state.enemies.length);
        const idx2 = Math.floor(Math.random() * state.enemies.length);
        const e1 = state.enemies[idx1];
        const e2 = state.enemies[idx2];
        if (e1 && e2 && idx1 !== idx2 && e1.type === e2.type && e1.isFriendly === e2.isFriendly) {
           const dist = Math.sqrt((e1.x-e2.x)**2 + (e1.y-e2.y)**2);
           if (dist < mergeDistLimit) {
              e1.hp = Math.min(MAX_VAL, e1.hp + e2.hp);
              e1.maxHp = Math.min(MAX_VAL, e1.maxHp + e2.maxHp);
              e1.size = Math.min(500, e1.size * 1.15);
              e1.value = Math.min(MAX_VAL, e1.value + e2.value);
              state.enemies.splice(idx2, 1);
              break;
           }
        }
      }
    }

    // 5. Collection
    state.drops = state.drops.filter(d => {
      d.life -= 0.0025;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 6000 : 0) / cameraScale;
      const vacuumSpeed = 60;

      if (dist < 120 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * vacuumSpeed;
        d.y += (dy / dist) * vacuumSpeed;
      }
      return d.life > 0;
    });

    // 6. Movement & Friendly AI
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;

      if (enemy.isFriendly) {
         const uncaptured = state.planets.filter(p => !p.isCaptured);
         if (uncaptured.length > 0) {
             let nearest = uncaptured[0];
             let minD = Infinity;
             uncaptured.forEach(p => {
                 const d = Math.sqrt((p.x - enemy.x)**2 + (p.y - enemy.y)**2);
                 if (d < minD) { minD = d; nearest = p; }
             });

             const dx = nearest.x - enemy.x;
             const dy = nearest.y - enemy.y;
             const dist = Math.sqrt(dx * dx + dy * dy);

             if (dist < 200) {
                 nearest.hp -= enemy.hp * 0.4; 
                 enemy.hp -= nearest.maxHp * 0.0005; 
                 if (nearest.hp <= 0) this.capturePlanet(state, nearest, onLevelUp);
             }

             enemy.x += (dx / dist) * enemy.speed * 1.5;
             enemy.y += (dy / dist) * enemy.speed * 1.5;
             enemy.angle = Math.atan2(dy, dx);
         } else {
             const dx = enemy.x - cx;
             const dy = enemy.y - cy;
             const dist = Math.sqrt(dx * dx + dy * dy);
             enemy.x += (dx / dist) * enemy.speed;
             enemy.y += (dy / dist) * enemy.speed;
             enemy.angle = Math.atan2(dy, dx);
         }
      } else {
         const dx = cx - enemy.x;
         const dy = cy - enemy.y;
         const dist = Math.sqrt(dx * dx + dy * dy);

         if (dist < (enemy.type === 'boss' ? 220 : 120)) {
           state.coreHp -= (enemy.type === 'boss' ? 2000 : 60) + (state.level * 8);
           enemy.hp = -1;
           if (state.coreHp <= 0) {
             state.coreHp = 0;
             state.isGameOver = true;
           }
           return;
         }

         enemy.x += (dx / dist) * enemy.speed;
         enemy.y += (dy / dist) * enemy.speed;
         enemy.angle = Math.atan2(dy, dx);
      }
    });

    state.enemies = state.enemies.filter(e => e.hp > 0);
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory || state.isCompiling) return false;
    let hitSomething = false;
    const now = Date.now();
    const versionMult = Math.pow(2.2, state.permanentUpgrades.version - 1);

    state.projectiles = state.projectiles.filter(p => {
      if (p.type !== 'enemy') return true;
      const dist = Math.sqrt((p.x - worldX) ** 2 + (p.y - worldY) ** 2);
      if (dist < 150 / cameraScale) {
        state.code = Math.min(MAX_VAL, state.code + (2000 * versionMult));
        state.experience += 200;
        hitSomething = true;
        return false;
      }
      return true;
    });

    const splashRadius = (250 + (state.level * 3)) / Math.pow(cameraScale, 0.3);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0 || enemy.isFriendly) return;
      const dist = Math.sqrt((enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2);
      if (dist < splashRadius) {
        const damageMult = dist < 120 ? 1.0 : Math.max(0.35, (1 - (dist / splashRadius)));
        let actualDmg = state.clickPower * damageMult;

        // --- MASSIVE OVERWHELMING FORCE ---
        if (actualDmg > enemy.hp * 0.7 && state.level > 40) {
            enemy.isFriendly = true;
            enemy.hp = enemy.maxHp;
            enemy.speed *= 2.0;
            hitSomething = true;
            onEnemyHit(enemy);
            return;
        }

        enemy.hp -= actualDmg;
        enemy.lastHit = now;
        state.code = Math.min(MAX_VAL, state.code + (20 * versionMult));
        hitSomething = true;
        onEnemyHit(enemy);

        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const { damageMult, rangeMult, fireRateMult } = state.towerModifiers;
    const versionMult = Math.pow(2.2, state.permanentUpgrades.version - 1);

    state.towers.forEach(tower => {
      if (tower.disabledUntil && now < tower.disabledUntil) return;

      const effectiveRange = tower.range * rangeMult;
      const effectiveDamage = tower.damage * damageMult;
      const effectiveFireRate = tower.fireRate * fireRateMult;

      if (now - tower.lastFired > effectiveFireRate) {
        let nearest: (Enemy | Planet) | null = null;
        let minDist = effectiveRange;

        state.enemies.forEach(e => {
          if (e.hp <= 0 || e.isFriendly) return;
          const dist = Math.sqrt((e.x - tower.x) ** 2 + (e.y - tower.y) ** 2);
          if (dist < minDist) { minDist = dist; nearest = e; }
        });

        if (!nearest) {
          state.planets.filter(p => !p.isCaptured).forEach(p => {
            const dist = Math.sqrt((p.x - tower.x) ** 2 + (p.y - tower.y) ** 2);
            if (dist < minDist) { minDist = dist; nearest = p; }
          });
        }

        if (nearest) {
          nearest.hp -= effectiveDamage;
          state.code = Math.min(MAX_VAL, state.code + effectiveDamage * 0.2);
          state.experience += Math.max(0, effectiveDamage * 0.3 * state.permanentUpgrades.xpMultiplier);
          if ('lastHit' in nearest) (nearest as Enemy).lastHit = now;
          onFire(tower, nearest);

          if (nearest.hp <= 0) {
            const isEnemy = 'type' in nearest;
            const isPlanet = 'isCaptured' in nearest;
            if (isEnemy && !(nearest as any)._processed) {
              this.processEnemyDeath(state, nearest as Enemy, false);
              this.checkLevelUp(state, onLevelUp);
            } else if (isPlanet && !(nearest as Planet).isCaptured) {
              this.capturePlanet(state, nearest as Planet, onLevelUp);
            }
          }
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    // CRITICAL Mid-game XP buff
    state.experience += (25000 * Math.pow(1.5, planet.sector)) * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    const versionMult = Math.pow(2.2, state.permanentUpgrades.version - 1);
    if (d.type === 'shard') {
      state.spProgress += 4; // Buffed
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 2; // Buffed
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.08) + 1;
      }
    } else if (d.type === 'loc') {
      state.code = Math.min(MAX_VAL, state.code + (2500 + (state.level * 400)) * (1 + state.currentSector) * versionMult);
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;
    const versionMult = Math.pow(2.2, state.permanentUpgrades.version - 1);

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.25) * state.permanentUpgrades.xpMultiplier * (1 + state.level / 200);
    if (enemy.type === 'boss') rewardMult *= 30;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code = Math.min(MAX_VAL, state.code + Math.floor(enemy.value * rewardMult * versionMult));

    state.spProgress += isManual ? 1.5 : 2.5;
    if (state.spProgress >= state.spGoal) {
        state.skillPoints += 2;
        state.spProgress -= state.spGoal;
        state.spGoal = Math.floor(state.spGoal * 1.08) + 1;
    }

    const rand = Math.random();
    if (enemy.type === 'boss' || rand < 0.45) {
      state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP', x: enemy.x, y: enemy.y, life: 3.5 });
    } else if (rand < 0.75) {
      state.drops.push({ id: Math.random().toString(36), name: 'Data', type: 'loc', rarity: 'common', effect: 'LOC', x: enemy.x, y: enemy.y, life: 2.5 });
    }
    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 300 + (state.level * 350); 
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.15; 
      state.skillPoints += 3; // Buffed sense of power
      onLevelUp();
    }
  }
}

import { GameState, Enemy } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 40;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    // ADAPTIVE SCALE SYSTEM: 
    // perceivedScale keeps objects visually "large" even when camera is lightyears away.
    // minObjectSize (in actual screen pixels) ensures nothing is ever just a 1px dot.
    const perceivedScale = 1 / Math.pow(cameraScale, 0.75); 
    const minObjectSize = 25; 

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.92;
    }

    // World Space Transform
    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // Deep Space Grid (Subtle but provides depth)
    const gridSize = 2000;
    const gridLimit = 80000;
    this.ctx.strokeStyle = '#1e293b';
    this.ctx.lineWidth = 1 / cameraScale;
    this.ctx.globalAlpha = 0.2;
    for (let x = -gridLimit; x <= gridLimit; x += gridSize) {
        this.ctx.beginPath(); this.ctx.moveTo(cx + x, cy - gridLimit); this.ctx.lineTo(cx + x, cy + gridLimit); this.ctx.stroke();
    }
    for (let y = -gridLimit; y <= gridLimit; y += gridSize) {
        this.ctx.beginPath(); this.ctx.moveTo(cx - gridLimit, cy + y); this.ctx.lineTo(cx + gridLimit, cy + y); this.ctx.stroke();
    }
    this.ctx.globalAlpha = 1.0;

    // Capture Radius (Sphere of Influence)
    const horizonRadius = 2600 + (state.currentSector * 3500);
    this.ctx.strokeStyle = versionColor;
    this.ctx.lineWidth = 15 / cameraScale;
    this.ctx.globalAlpha = 0.1;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, horizonRadius, 0, Math.PI * 2); this.ctx.stroke();
    this.ctx.globalAlpha = 1.0;

    // WARP GATES (Visualizing spawn points at distance)
    state.planets.forEach(p => {
      if (p.isCaptured || p.sector > state.currentSector + 1) return;

      this.ctx.save();
      this.ctx.translate(p.x, p.y);
      this.ctx.rotate(now * 0.002);

      // Outer warp ring
      const ringSize = (p.size + 100) * perceivedScale * 0.5;
      this.ctx.strokeStyle = COLORS.ENEMY;
      this.ctx.lineWidth = 20 / cameraScale;
      this.ctx.globalAlpha = 0.3 + Math.sin(now * 0.01) * 0.2;
      this.ctx.setLineDash([50 / cameraScale, 30 / cameraScale]);
      this.ctx.beginPath(); this.ctx.arc(0, 0, ringSize, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.setLineDash([]);

      // Core mass
      this.ctx.fillStyle = '#450a0a';
      this.ctx.globalAlpha = 1.0;
      this.ctx.beginPath(); this.ctx.arc(0, 0, p.size * perceivedScale * 0.5, 0, Math.PI * 2); this.ctx.fill();

      // Planet Name
      this.ctx.fillStyle = '#fff'; 
      this.ctx.font = `bold ${Math.max(40, 100 / cameraScale)}px Space Grotesk`; 
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, 0, 0);
      this.ctx.restore();
    });

    // Mainframe Core (The "Sun")
    const coreSize = Math.max(minObjectSize * 2, (100 + (state.level * 0.2)) * perceivedScale * 0.6);
    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 100 / cameraScale; 
    this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // Firing Effects (Lasers must be thick enough to see)
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = Math.max(5, (ef.type === 'SNIPER' ? 30 : 10) * ef.life / cameraScale);
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.12;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // Units (Enemies and Allies)
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = Date.now() - (e.lastHit || 0) < 100;
      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));

      // Min size constraint applied here
      const baseDrawSize = e.size * perceivedScale * 0.5;
      const finalDrawSize = Math.max(minObjectSize, baseDrawSize);

      if (e.isFriendly) {
         this.ctx.shadowBlur = 40 / cameraScale;
         this.ctx.shadowColor = '#22d3ee';
      }

      this.ctx.beginPath();
      if (e.type === 'boss') {
        this.ctx.moveTo(finalDrawSize * 1.5, 0); 
        this.ctx.lineTo(-finalDrawSize, finalDrawSize); 
        this.ctx.lineTo(-finalDrawSize * 2, 0); 
        this.ctx.lineTo(-finalDrawSize, -finalDrawSize);
      } else {
        this.ctx.moveTo(finalDrawSize, 0); 
        this.ctx.lineTo(-finalDrawSize, finalDrawSize * 0.8); 
        this.ctx.lineTo(-finalDrawSize, -finalDrawSize * 0.8);
      }
      this.ctx.closePath();
      this.ctx.fill();

      if (e.shield && e.shield > 0) {
          this.ctx.strokeStyle = '#38bdf8';
          this.ctx.lineWidth = Math.max(4, 10 / cameraScale);
          this.ctx.beginPath(); this.ctx.arc(0, 0, finalDrawSize + (20 / cameraScale), -Math.PI/2, Math.PI/2); this.ctx.stroke();
      }
      this.ctx.restore();
    });

    // Defenses (Towers)
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const tSize = Math.max(minObjectSize, 60 * perceivedScale * 0.5);
      this.ctx.fillRect(t.x - tSize, t.y - tSize, tSize * 2, tSize * 2);

      this.ctx.strokeStyle = t.color; 
      this.ctx.lineWidth = 5 / cameraScale; 
      this.ctx.globalAlpha = 0.08;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range * state.towerModifiers.rangeMult, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // Drops and Particles
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${Math.max(40, 120 / cameraScale)}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        const pSize = p.size * perceivedScale * 0.4;
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, pSize, 0, Math.PI * 2); this.ctx.fill();
      }
    });

    state.drops.forEach(d => {
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.005);
      const s = Math.max(minObjectSize * 0.6, 40 * perceivedScale * 0.2);
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return COLORS.BOSS;
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 3; // Reduced for tighter density
const SHARDS_PER_SP_BASE = 20;

// Safeguard against JS floating point limits
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private resizeHandler: () => void;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    this.resizeHandler = () => this.resize();
    this.resize();
    window.addEventListener('resize', this.resizeHandler);
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  public destroy() {
    this.isDestroyed = true;
    window.removeEventListener('resize', this.resizeHandler);
    audio.stop();
  }

  private getInitialState(): GameState {
    return {
      code: 1200, experience: 0, level: 1, skillPoints: 2, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 35, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 250, maxCoreHp: 250, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    // Tighter distances for better early-to-mid visibility
    const dist = 2200 + (sector * 2800); 
    const count = PLANET_COUNT + sector;
    const names = ["NPM", "PYPI", "Maven", "Cargo", "Go-Get", "NuGet", "RubyGems", "Composer"];
    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);

    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 0.8);
      const baseHp = (3000 + (this.state.level * 200)) * Math.pow(1.8, sector);
      const cappedHp = Math.min(MAX_VAL, baseHp * versionBoost);

      this.state.planets.push({
        id: `planet_${sector}_${i}`, 
        name: `${names[i % names.length]}-${sector}`,
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: cappedHp,
        maxHp: cappedHp,
        isCaptured: false, size: 400 + (sector * 150), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    const versionMult = Math.pow(5, perms.version - 1);
    this.state.code = (1200 + (perms.startingCode || 0)) * versionMult;
    this.state.clickPower = 35 * perms.damageMultiplier * versionMult;

    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(0); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;

    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    const earnedLegacy = Math.floor(Math.log10(this.state.code + 1) * this.state.level / 5);
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 2000));

    this.state.isCompiling = false;
    this.reset();
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused || this.isDestroyed || this.state.isCompiling) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 5, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        if (e.isFriendly) {
           this.createParticles(e.x, e.y, 10, '#22d3ee');
        } else {
           this.createParticles(e.x, e.y, 4, COLORS.PRIMARY);
        }
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const versionMult = Math.pow(2.5, this.state.permanentUpgrades.version - 1);
      const missReward = (120 + (this.state.level * 30) * (1 + this.state.currentSector)) * versionMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + missReward);
      this.createFloatingText(worldX, worldY, `+${this.formatNumber(missReward)}`, COLORS.PRIMARY);
      audio.playClick();
    }

    if (this.state.ripples.length < 8) {
      this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 200 / this.cameraScale, life: 1.0 });
    }

    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 120, "+3 SKILL POINTS", COLORS.SECONDARY);

    const uncapturedInSector = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncapturedInSector.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 250, `SECTOR ${this.state.currentSector} DISCOVERED`, COLORS.ACCENT);
    }

    if (this.state.level % 5 === 0) {
      this.state.maxCoreHp = Math.min(MAX_VAL, this.state.maxCoreHp + (1500 * this.state.permanentUpgrades.version)); 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  private formatNumber(num: number): string {
    if (num < 1000) return num.toFixed(0);
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const suffix = suffixes[tier];
    const scale = Math.pow(10, tier * 3);
    const scaled = num / scale;
    return scaled.toFixed(2) + suffix;
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused || this.isDestroyed || this.state.isCompiling) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.2, tCount));

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range: config.range, 
        damage: config.damage, 
        fireRate: config.fireRate, 
        lastFired: 0, 
        color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;

    if (!this.isPaused && !this.state.isCompiling) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused || !!this.state.isCompiling);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;

    // --- RECALIBRATED STEADY ZOOM ---
    // Instead of looking at lightyears away, we zoom based on the current sector's "working area"
    let workingDist = 2000;
    this.state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const d = Math.sqrt((e.x - this.canvas.width/2)**2 + (e.y - this.canvas.height/2)**2);
        if (d > workingDist) workingDist = d;
    });

    // Sector-based camera floor prevents the "detached dot" problem
    // Limit how far out we go relative to the active sector
    const maxZoomOutSector = Math.max(0, this.state.currentSector);
    const cameraScaleFloor = 0.8 / (1 + maxZoomOutSector * 0.4); 

    const baseViewWidth = 1000;
    this.targetCameraScale = Math.max(cameraScaleFloor, baseViewWidth / (workingDist * 1.1));

    // Smooth lerp
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.015;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const earnedLegacy = Math.max(0, Math.floor(Math.log10(this.state.code + 1)));
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) return;

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(12);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = (this.state.level * 1200) * Math.pow(2.2, this.state.permanentUpgrades.version - 1) * (1 + this.state.currentSector);
        if (this.state.unlockedSkills.includes('code_gen')) gain *= 15; 
        this.state.code = Math.min(MAX_VAL, this.state.code + gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(350, 2200 - (this.state.level * 10));
    const threatMult = 1 + (this.state.threatLevel * 0.3) + (this.state.currentSector * 0.2);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      let type: Enemy['type'] = 'bug';
      const r = Math.random();
      if (this.state.level >= 20 || this.state.currentSector > 0) {
          if (r < 0.12) type = 'glitch';
          else if (r < 0.22) type = 'null_pointer';
          else if (r < 0.32) type = 'memory_leak';
          else if (r < 0.42) type = 'shielded';
          else if (r < 0.48) type = 'worm';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    // Precision pruning for performance
    if (this.state.particles.length > 150) this.state.particles.splice(0, 20);

    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.01 : 0.08; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 15; r.life -= 0.05; return r.life > 0; });

    if (this.frameCount % 5 === 0) {
      this.onUpdate({ ...this.state });
    }
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3200 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const sectorFactor = Math.pow(1.6, this.state.currentSector);
    const hp = 12000 * Math.pow(1.35, (this.state.level / 5)) * sectorFactor * Math.pow(10, this.state.permanentUpgrades.version - 1);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed: 1.1 + (this.state.level * 0.01), value: 250000 * this.state.permanentUpgrades.version * (1 + this.state.currentSector), 
      type: 'boss', size: 400, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "FATAL OVERFLOW DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: Enemy['type'] = 'bug') {
    if (this.state.enemies.length > 60) return;

    const dist = 4200 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle) * 200; y = sy + Math.sin(angle) * 200;
    }

    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);
    const sectorFactor = Math.pow(1.2, this.state.currentSector * 8);
    const hpMult = Math.pow(1.1, Math.min(this.state.level, 5000));
    let hp = 100 * hpMult * versionBoost * sectorFactor;
    let speed = 1.4 + (Math.min(this.state.level, 1000) * 0.02);
    let size = 60 + (Math.min(this.state.level, 5000) * 0.08);
    let shield = 0;

    if (type === 'glitch') { hp *= 2.5; speed += 0.8; }
    if (type === 'shielded') { shield = hp * 1.2; hp *= 1.1; speed *= 0.7; size += 30; }
    if (type === 'null_pointer') { hp *= 0.6; speed += 2.2; }
    if (type === 'memory_leak') { hp *= 2.0; speed *= 0.7; size += 45; }
    if (type === 'worm') { hp *= 0.4; speed += 1.4; size *= 0.8; }

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed, value: (hp * 2.5), type, size, angle: 0,
      shield: Math.min(MAX_VAL, shield), sinOffset: Math.random() * 1000
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.25);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 50000;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 2.5;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 3.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 250) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*18, vy: (Math.random()-0.5)*18, size: Math.random()*6+2, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -4, size: 28, life: 1.5, color, text });
  }
}

export interface Point {
  x: number;
  y: number;
}

export interface Particle extends Point {
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
  text?: string;
}

export interface Projectile extends Point {
  id: string;
  targetId: string;
  speed: number;
  damage: number;
  color: string;
  type: 'allied' | 'enemy';
}

export interface Planet extends Point {
  id: string;
  hp: number;
  maxHp: number;
  isCaptured: boolean;
  size: number;
  color: string;
  name: string;
  sector: number;
}

export interface ClickRipple extends Point {
  radius: number;
  maxRadius: number;
  life: number;
}

export interface Enemy extends Point {
  id: string;
  hp: number;
  maxHp: number;
  speed: number;
  value: number;
  type: 'bug' | 'boss' | 'glitch' | 'null_pointer' | 'memory_leak' | 'shielded' | 'worm';
  size: number;
  angle: number;
  lastHit?: number;
  sourcePlanetId?: string;
  nextAttackTime?: number;

  // Behavior stats
  shield?: number;
  hasBlinked?: boolean;
  isChild?: boolean;
  sinOffset?: number; // For worm movement
  isFriendly?: boolean; // New conversion mechanic
}

export interface Tower extends Point {
  id: string;
  type: string;
  level: number;
  range: number;
  damage: number;
  fireRate: number;
  lastFired: number;
  color: string;
  disabledUntil?: number;
  lastTargetId?: string; // Performance: Cache target
}

export interface LibraryDrop extends Point {
  id: string;
  name: string;
  type: 'loc' | 'shard' | 'library';
  rarity: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
  effect: string;
  life: number;
}

export interface PermanentUpgrades {
  startingCode: number;
  damageMultiplier: number;
  xpMultiplier: number;
  legacyPoints: number;
  version: number; // The global evolution level
}

export interface TechNode {
  id: string;
  name: string;
  description: string;
  cost: number;
  position: { x: number; y: number };
  dependsOn?: string;
}

export interface TowerModifiers {
  damageMult: number;
  rangeMult: number;
  fireRateMult: number;
}

export interface GameState {
  code: number;
  experience: number;
  level: number;
  skillPoints: number;
  spProgress: number;
  spGoal: number;
  clickPower: number;
  towers: Tower[];
  enemies: Enemy[];
  particles: Particle[];
  ripples: ClickRipple[];
  drops: LibraryDrop[];
  planets: Planet[];
  projectiles: Projectile[];
  isGameOver: boolean;
  isVictory: boolean;
  permanentUpgrades: PermanentUpgrades;
  lastRunCode: number;
  availableSkills: string[];
  unlockedTech: string[];
  unlockedSkills: string[]; 
  rerollCost: number;
  combo: number;
  threatLevel: number;
  coreHp: number;
  maxCoreHp: number;
  towerModifiers: TowerModifiers;
  currentSector: number;
  isCompiling?: boolean; // For "Ship to Production" effect
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 45; 
const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    const versionMult = Math.pow(2.5, state.permanentUpgrades.version - 1);

    // 1. Sector-scaled Passive Trickle
    const sectorMult = Math.pow(2, state.currentSector);
    const basePassive = (20 + state.level * 5) * (dt / 1000) * versionMult * sectorMult;
    state.code = Math.min(MAX_VAL, state.code + basePassive);

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Fast collision)
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;
      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        targetPos = { x: cx, y: cy };
      }
      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const distSq = dx * dx + dy * dy;

      const hitRadius = Math.max(100, 150 / cameraScale);
      if (distSq < hitRadius * hitRadius) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code = Math.min(MAX_VAL, state.code + proj.damage * 0.2); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      const dist = Math.sqrt(distSq);
      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      for (let i = 0; i < 8; i++) {
        const idx1 = Math.floor(Math.random() * state.enemies.length);
        const idx2 = Math.floor(Math.random() * state.enemies.length);
        const e1 = state.enemies[idx1];
        const e2 = state.enemies[idx2];
        if (e1 && e2 && idx1 !== idx2 && e1.isFriendly === e2.isFriendly) {
           e1.hp = Math.min(MAX_VAL, e1.hp + e2.hp);
           e1.maxHp = Math.min(MAX_VAL, e1.maxHp + e2.maxHp);
           e1.size = Math.min(600, e1.size * 1.1);
           state.enemies.splice(idx2, 1);
           break;
        }
      }
    }

    // 5. Friendly AI - Seeking Planets
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;

      if (enemy.isFriendly) {
         const uncaptured = state.planets.filter(p => !p.isCaptured);
         if (uncaptured.length > 0) {
             let nearest = uncaptured[0];
             let minDSq = Infinity;
             uncaptured.forEach(p => {
                 const dSq = (p.x - enemy.x)**2 + (p.y - enemy.y)**2;
                 if (dSq < minDSq) { minDSq = dSq; nearest = p; }
             });

             const dx = nearest.x - enemy.x;
             const dy = nearest.y - enemy.y;
             const dist = Math.sqrt(minDSq);

             if (dist < 300) {
                 nearest.hp -= enemy.hp * 0.5; 
                 enemy.hp -= nearest.maxHp * 0.0002; 
                 if (nearest.hp <= 0) this.capturePlanet(state, nearest, onLevelUp);
             }

             enemy.x += (dx / dist) * enemy.speed * 2.0;
             enemy.y += (dy / dist) * enemy.speed * 2.0;
             enemy.angle = Math.atan2(dy, dx);
         } else {
             enemy.x += Math.cos(enemy.angle) * enemy.speed;
             enemy.y += Math.sin(enemy.angle) * enemy.speed;
         }
      } else {
         const dx = cx - enemy.x;
         const dy = cy - enemy.y;
         const dist = Math.sqrt(dx * dx + dy * dy);

         if (dist < 150) {
           state.coreHp -= (enemy.type === 'boss' ? 3000 : 100) + (state.level * 10);
           enemy.hp = -1;
           if (state.coreHp <= 0) {
             state.coreHp = 0;
             state.isGameOver = true;
           }
           return;
         }

         enemy.x += (dx / dist) * enemy.speed;
         enemy.y += (dy / dist) * enemy.speed;
         enemy.angle = Math.atan2(dy, dx);
      }
    });

    state.enemies = state.enemies.filter(e => e.hp > 0);

    // 6. Drops
    state.drops = state.drops.filter(d => {
      d.life -= 0.003;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const vacuumRadius = (hasAutoCollect ? 8000 : 0) / cameraScale;
      if (dist < 150 / cameraScale) {
        this.collectDrop(state, d);
        return false;
      }
      if (dist < vacuumRadius) {
        d.x += (dx / dist) * 75;
        d.y += (dy / dist) * 75;
      }
      return d.life > 0;
    });
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory || state.isCompiling) return false;
    let hitSomething = false;
    const now = Date.now();
    const versionMult = Math.pow(2.5, state.permanentUpgrades.version - 1);

    const splashRadius = (300 + (state.level * 5)) / Math.pow(cameraScale, 0.4);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0 || enemy.isFriendly) return;
      const dSq = (enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2;
      if (dSq < splashRadius * splashRadius) {
        const dist = Math.sqrt(dSq);
        const damageMult = dist < 150 ? 1.0 : Math.max(0.4, (1 - (dist / splashRadius)));
        let actualDmg = state.clickPower * damageMult;

        if (actualDmg > enemy.hp * 0.5 && state.level > 30) {
            enemy.isFriendly = true;
            enemy.hp = enemy.maxHp;
            enemy.speed *= 2.5;
            hitSomething = true;
            onEnemyHit(enemy);
            return;
        }

        enemy.hp -= actualDmg;
        enemy.lastHit = now;
        state.code = Math.min(MAX_VAL, state.code + (50 * versionMult));
        hitSomething = true;
        onEnemyHit(enemy);

        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const { damageMult, rangeMult, fireRateMult } = state.towerModifiers;
    const versionMult = Math.pow(2.5, state.permanentUpgrades.version - 1);

    // Automatically scale range with sector count so towers don't become useless
    const autoRangeScale = 1 + (state.currentSector * 0.5);

    state.towers.forEach(tower => {
      if (tower.disabledUntil && now < tower.disabledUntil) return;

      const effectiveRange = tower.range * rangeMult * autoRangeScale;
      const effectiveDamage = tower.damage * damageMult;
      const effectiveFireRate = tower.fireRate * fireRateMult;

      if (now - tower.lastFired > effectiveFireRate) {
        // Optimized targeting: check cached target first
        let target: (Enemy | Planet) | null = null;
        if (tower.lastTargetId) {
          target = state.enemies.find(e => e.id === tower.lastTargetId && !e.isFriendly && e.hp > 0) ||
                   state.planets.find(p => p.id === tower.lastTargetId && !p.isCaptured);

          if (target) {
            const dSq = (target.x - tower.x)**2 + (target.y - tower.y)**2;
            if (dSq > effectiveRange * effectiveRange) target = null;
          }
        }

        // Search for new target if cached is invalid
        if (!target) {
          let minDistSq = effectiveRange * effectiveRange;

          // Enemies have priority
          for (const e of state.enemies) {
            if (e.isFriendly || e.hp <= 0) continue;
            const dSq = (e.x - tower.x)**2 + (e.y - tower.y)**2;
            if (dSq < minDistSq) { minDistSq = dSq; target = e; }
          }

          // Planets if no enemies
          if (!target) {
            for (const p of state.planets) {
              if (p.isCaptured) continue;
              const dSq = (p.x - tower.x)**2 + (p.y - tower.y)**2;
              if (dSq < minDistSq) { minDistSq = dSq; target = p; }
            }
          }
        }

        if (target) {
          tower.lastTargetId = target.id;
          target.hp -= effectiveDamage;
          state.code = Math.min(MAX_VAL, state.code + effectiveDamage * 0.25);
          state.experience += Math.max(0, effectiveDamage * 0.4 * state.permanentUpgrades.xpMultiplier);
          if ('lastHit' in target) (target as Enemy).lastHit = now;
          onFire(tower, target);

          if (target.hp <= 0) {
            const isEnemy = 'type' in target;
            const isPlanet = 'isCaptured' in target;
            if (isEnemy && !(target as any)._processed) {
              this.processEnemyDeath(state, target as Enemy, false);
              this.checkLevelUp(state, onLevelUp);
            } else if (isPlanet && !(target as Planet).isCaptured) {
              this.capturePlanet(state, target as Planet, onLevelUp);
            }
            tower.lastTargetId = undefined;
          }
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += (50000 * Math.pow(1.8, planet.sector)) * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    const versionMult = Math.pow(2.5, state.permanentUpgrades.version - 1);
    if (d.type === 'shard') {
      state.spProgress += 6; 
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 3; 
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 1;
      }
    } else if (d.type === 'loc') {
      state.code = Math.min(MAX_VAL, state.code + (5000 + (state.level * 600)) * (1 + state.currentSector) * versionMult);
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;
    const versionMult = Math.pow(2.5, state.permanentUpgrades.version - 1);

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.3) * state.permanentUpgrades.xpMultiplier * (1 + state.level / 100);
    if (enemy.type === 'boss') rewardMult *= 50;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code = Math.min(MAX_VAL, state.code + Math.floor(enemy.value * rewardMult * versionMult));

    state.spProgress += isManual ? 2.5 : 5.0;
    if (state.spProgress >= state.spGoal) {
        state.skillPoints += 3;
        state.spProgress -= state.spGoal;
        state.spGoal = Math.floor(state.spGoal * 1.1) + 1;
    }

    const rand = Math.random();
    if (enemy.type === 'boss' || rand < 0.6) {
      state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP', x: enemy.x, y: enemy.y, life: 5.0 });
    } else {
      state.drops.push({ id: Math.random().toString(36), name: 'Data', type: 'loc', rarity: 'common', effect: 'LOC', x: enemy.x, y: enemy.y, life: 4.0 });
    }
    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 400 + (state.level * 400); 
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.2; 
      state.skillPoints += 5; 
      onLevelUp();
    }
  }
}

import { GameState, Enemy, Tower, Planet } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 50;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    // DEEP SPACE STRATEGIC SCALING
    // As cameraScale goes down, we keep objects visually large by increasing perceivedScale.
    const perceivedScale = 1 / Math.pow(cameraScale, 0.95); 
    const minPixelSize = 40; // Nothing is ever smaller than this in pixels

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.92;
    }

    // World Space
    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // Constellation / Grid Lines (Visualizing the Network)
    this.ctx.strokeStyle = versionColor;
    this.ctx.lineWidth = 2 / cameraScale;
    this.ctx.globalAlpha = 0.05;
    state.towers.forEach(t => {
      this.ctx.beginPath(); this.ctx.moveTo(cx, cy); this.ctx.lineTo(t.x, t.y); this.ctx.stroke();
    });

    // Sector Horizon Ring
    const horizonRadius = 2600 + (state.currentSector * 3500);
    this.ctx.strokeStyle = versionColor;
    this.ctx.lineWidth = 10 / cameraScale;
    this.ctx.globalAlpha = 0.15;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, horizonRadius, 0, Math.PI * 2); this.ctx.stroke();
    this.ctx.globalAlpha = 1.0;

    // Warp Gates (Planets)
    state.planets.forEach(p => {
      if (p.sector > state.currentSector + 1) return;

      this.ctx.save();
      this.ctx.translate(p.x, p.y);

      const pDrawSize = Math.max(minPixelSize * 3, p.size * perceivedScale * 0.4);
      const isSpawn = !p.isCaptured;

      if (isSpawn) {
        // Threat Nebula
        const pulse = 1 + Math.sin(now * 0.005) * 0.2;
        const grad = this.ctx.createRadialGradient(0, 0, 0, 0, 0, pDrawSize * 1.5);
        grad.addColorStop(0, COLORS.ENEMY);
        grad.addColorStop(1, 'transparent');
        this.ctx.fillStyle = grad;
        this.ctx.globalAlpha = 0.3;
        this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 1.5 * pulse, 0, Math.PI * 2); this.ctx.fill();

        // Spinning Rings
        this.ctx.strokeStyle = COLORS.ENEMY;
        this.ctx.lineWidth = 30 / cameraScale;
        this.ctx.rotate(now * 0.002);
        this.ctx.setLineDash([100 / cameraScale, 50 / cameraScale]);
        this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 1.2, 0, Math.PI * 2); this.ctx.stroke();
        this.ctx.setLineDash([]);
      }

      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#1e0505';
      this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize, 0, Math.PI * 2); this.ctx.fill();

      this.ctx.fillStyle = '#fff'; 
      this.ctx.font = `bold ${Math.max(60, 150 / cameraScale)}px Space Grotesk`; 
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, 0, pDrawSize + (150 / cameraScale));
      this.ctx.restore();
    });

    // Core Mainframe
    const coreSize = Math.max(minPixelSize * 4, (150 + (state.level * 0.3)) * perceivedScale * 0.5);
    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 150 / cameraScale; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // Firing Beams (Must be extremely visible)
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = Math.max(10, (ef.type === 'SNIPER' ? 50 : 20) * ef.life / cameraScale);
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.1;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // Units (Aggressive sizing)
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = now - (e.lastHit || 0) < 100;
      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));

      const uSize = Math.max(minPixelSize, e.size * perceivedScale * 0.5);

      if (e.isFriendly) {
         this.ctx.shadowBlur = 60 / cameraScale;
         this.ctx.shadowColor = '#22d3ee';
      }

      this.ctx.beginPath();
      if (e.type === 'boss') {
        this.ctx.moveTo(uSize * 2, 0); 
        this.ctx.lineTo(-uSize, uSize * 1.5); 
        this.ctx.lineTo(-uSize * 2, 0); 
        this.ctx.lineTo(-uSize, -uSize * 1.5);
      } else {
        this.ctx.moveTo(uSize, 0); 
        this.ctx.lineTo(-uSize, uSize); 
        this.ctx.lineTo(-uSize, -uSize);
      }
      this.ctx.closePath();
      this.ctx.fill();

      if (e.shield && e.shield > 0) {
          this.ctx.strokeStyle = '#38bdf8';
          this.ctx.lineWidth = 15 / cameraScale;
          this.ctx.beginPath(); this.ctx.arc(0, 0, uSize * 1.4, -Math.PI/2, Math.PI/2); this.ctx.stroke();
      }
      this.ctx.restore();
    });

    // Defense Systems
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const tSize = Math.max(minPixelSize * 1.2, 80 * perceivedScale * 0.5);
      this.ctx.fillRect(t.x - tSize, t.y - tSize, tSize * 2, tSize * 2);

      // Range Ring (Subtle)
      this.ctx.strokeStyle = t.color; 
      this.ctx.lineWidth = 5 / cameraScale; 
      this.ctx.globalAlpha = 0.05;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, t.range * state.towerModifiers.rangeMult * (1 + state.currentSector * 0.5), 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // Shards & Particles
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${Math.max(60, 200 / cameraScale)}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size * perceivedScale * 0.5, 0, Math.PI * 2); this.ctx.fill();
      }
    });

    state.drops.forEach(d => {
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      const s = Math.max(minPixelSize * 0.8, 60 * perceivedScale * 0.2);
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.005);
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return COLORS.BOSS;
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 3; 
const SHARDS_PER_SP_BASE = 20;

// Safeguard against JS floating point limits
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private resizeHandler: () => void;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    this.resizeHandler = () => this.resize();
    this.resize();
    window.addEventListener('resize', this.resizeHandler);
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  public destroy() {
    this.isDestroyed = true;
    window.removeEventListener('resize', this.resizeHandler);
    audio.stop();
  }

  private getInitialState(): GameState {
    return {
      code: 2500, experience: 0, level: 1, skillPoints: 5, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 50, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 500, maxCoreHp: 500, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 2400 + (sector * 3200); 
    const count = PLANET_COUNT + sector;
    const names = ["NPM", "PYPI", "Maven", "Cargo", "Go-Get", "NuGet", "RubyGems", "Composer"];
    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);

    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 1.2);
      const baseHp = (5000 + (this.state.level * 300)) * Math.pow(2.0, sector);
      const cappedHp = Math.min(MAX_VAL, baseHp * versionBoost);

      this.state.planets.push({
        id: `planet_${sector}_${i}`, 
        name: `${names[i % names.length]}-${sector}`,
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: cappedHp,
        maxHp: cappedHp,
        isCaptured: false, size: 500 + (sector * 200), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    const versionMult = Math.pow(5, perms.version - 1);
    this.state.code = (2500 + (perms.startingCode || 0)) * versionMult;
    this.state.clickPower = 50 * perms.damageMultiplier * versionMult;

    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(0); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;

    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    const earnedLegacy = Math.floor(Math.log10(this.state.code + 1) * this.state.level / 4);
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 2000));

    this.state.isCompiling = false;
    this.reset();
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused || this.isDestroyed || this.state.isCompiling) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 8, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        if (e.isFriendly) {
           this.createParticles(e.x, e.y, 15, '#22d3ee');
        } else {
           this.createParticles(e.x, e.y, 6, COLORS.PRIMARY);
        }
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const versionMult = Math.pow(3.0, this.state.permanentUpgrades.version - 1);
      const missReward = (200 + (this.state.level * 50) * (1 + this.state.currentSector)) * versionMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + missReward);
      this.createFloatingText(worldX, worldY, `+${this.formatNumber(missReward)}`, COLORS.PRIMARY);
      audio.playClick();
    }

    if (this.state.ripples.length < 5) {
      this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 300 / this.cameraScale, life: 1.0 });
    }

    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 150, "+5 SKILL POINTS", COLORS.SECONDARY);

    const uncapturedInSector = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncapturedInSector.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 300, `SYSTEM UPGRADED: SECTOR ${this.state.currentSector}`, COLORS.ACCENT);
    }

    if (this.state.level % 5 === 0) {
      this.state.maxCoreHp = Math.min(MAX_VAL, this.state.maxCoreHp + (2500 * this.state.permanentUpgrades.version)); 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  private formatNumber(num: number): string {
    if (num < 1000) return num.toFixed(0);
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const suffix = suffixes[tier];
    const scale = Math.pow(10, tier * 3);
    const scaled = num / scale;
    return scaled.toFixed(2) + suffix;
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused || this.isDestroyed || this.state.isCompiling) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.15, tCount)); // Lower cost curve

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range: config.range, 
        damage: config.damage, 
        fireRate: config.fireRate, 
        lastFired: 0, 
        color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;

    if (!this.isPaused && !this.state.isCompiling) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused || !!this.state.isCompiling);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;

    // --- RECALIBRATED CAMERA ---
    let targetDist = 2200;
    this.state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const d = Math.sqrt((e.x - this.canvas.width/2)**2 + (e.y - this.canvas.height/2)**2);
        if (d > targetDist) targetDist = d;
    });

    // Limits how far out we go to avoid the "dot" effect
    const cameraScaleFloor = 0.9 / (1 + this.state.currentSector * 0.35); 
    const baseViewWidth = 1200;
    this.targetCameraScale = Math.max(cameraScaleFloor, baseViewWidth / (targetDist * 1.15));
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.012;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const earnedLegacy = Math.max(0, Math.floor(Math.log10(this.state.code + 1)));
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) return;

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(15);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = (this.state.level * 2000) * Math.pow(2.5, this.state.permanentUpgrades.version - 1) * (1 + this.state.currentSector);
        if (this.state.unlockedSkills.includes('code_gen')) gain *= 15; 
        this.state.code = Math.min(MAX_VAL, this.state.code + gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(400, 2000 - (this.state.level * 8));
    const threatMult = 1 + (this.state.threatLevel * 0.4) + (this.state.currentSector * 0.2);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      let type: Enemy['type'] = 'bug';
      const r = Math.random();
      if (this.state.level >= 20 || this.state.currentSector > 0) {
          if (r < 0.15) type = 'glitch';
          else if (r < 0.25) type = 'null_pointer';
          else if (r < 0.35) type = 'memory_leak';
          else if (r < 0.45) type = 'shielded';
          else if (r < 0.5) type = 'worm';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    if (this.state.particles.length > 150) this.state.particles.splice(0, 25);
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.008 : 0.07; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 20; r.life -= 0.04; return r.life > 0; });

    if (this.frameCount % 5 === 0) {
      this.onUpdate({ ...this.state });
    }
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3500 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const sectorFactor = Math.pow(2.0, this.state.currentSector);
    const hp = 20000 * Math.pow(1.4, (this.state.level / 5)) * sectorFactor * Math.pow(10, this.state.permanentUpgrades.version - 1);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed: 1.2 + (this.state.level * 0.015), value: 500000 * this.state.permanentUpgrades.version * (1 + this.state.currentSector), 
      type: 'boss', size: 500, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 250, "CRITICAL SYSTEM BREACH", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: Enemy['type'] = 'bug') {
    if (this.state.enemies.length > 50) return;

    const dist = 4500 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle) * 250; y = sy + Math.sin(angle) * 250;
    }

    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);
    const sectorFactor = Math.pow(1.3, this.state.currentSector * 6);
    const hpMult = Math.pow(1.12, Math.min(this.state.level, 1000));
    let hp = 150 * hpMult * versionBoost * sectorFactor;
    let speed = 1.6 + (Math.min(this.state.level, 1000) * 0.03);
    let size = 70 + (Math.min(this.state.level, 5000) * 0.1);
    let shield = 0;

    if (type === 'glitch') { hp *= 3.0; speed += 1.0; }
    if (type === 'shielded') { shield = hp * 1.5; hp *= 1.2; speed *= 0.8; size += 40; }
    if (type === 'null_pointer') { hp *= 0.5; speed += 2.8; }
    if (type === 'memory_leak') { hp *= 2.5; speed *= 0.75; size += 60; }
    if (type === 'worm') { hp *= 0.4; speed += 1.8; size *= 0.9; }

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed, value: (hp * 3.0), type, size, angle: 0,
      shield: Math.min(MAX_VAL, shield), sinOffset: Math.random() * 1000
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.3);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 100000;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 3.0;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 4.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 200) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*25, vy: (Math.random()-0.5)*25, size: Math.random()*8+3, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -5, size: 36, life: 2.0, color, text });
  }
}

import { GameState, Enemy, Tower, Planet } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 60;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    // TACTICAL SCALING
    // We maintain a "Perceived Scale" to keep objects large, but also enforce a "Min Pixel Size"
    const perceivedScale = 1 / Math.pow(cameraScale, 0.9); 
    const minPixelSize = 35; 

    // Clear with Deep Space
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.9;
    }

    // World Space Transform
    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. DATA GRID & NETWORK LINES
    this.ctx.strokeStyle = versionColor;
    this.ctx.lineWidth = 1 / cameraScale;
    this.ctx.globalAlpha = 0.03;
    state.towers.forEach((t, i) => {
      if (i % 5 === 0) { // Only draw some lines for performance
        this.ctx.beginPath(); this.ctx.moveTo(cx, cy); this.ctx.lineTo(t.x, t.y); this.ctx.stroke();
      }
    });

    // 2. SECTOR WARP WELLS (Spawns)
    state.planets.forEach(p => {
      if (p.sector > state.currentSector + 1) return;

      this.ctx.save();
      this.ctx.translate(p.x, p.y);

      const pDrawSize = Math.max(minPixelSize * 4, p.size * perceivedScale * 0.5);

      if (!p.isCaptured) {
        // Massive Spawn Nebula
        const pulse = 1 + Math.sin(now * 0.003) * 0.15;
        const grad = this.ctx.createRadialGradient(0, 0, 0, 0, 0, pDrawSize * 2);
        grad.addColorStop(0, COLORS.ENEMY + '44');
        grad.addColorStop(1, 'transparent');
        this.ctx.fillStyle = grad;
        this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 2.5 * pulse, 0, Math.PI * 2); this.ctx.fill();

        // Rotating Tactical Brackets
        this.ctx.strokeStyle = COLORS.ENEMY;
        this.ctx.lineWidth = 15 / cameraScale;
        this.ctx.rotate(now * 0.001);
        for(let i=0; i<4; i++) {
          this.ctx.rotate(Math.PI / 2);
          this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 1.3, 0, Math.PI / 4); this.ctx.stroke();
        }
      } else {
        // Captured "Safe Zone"
        this.ctx.strokeStyle = versionColor;
        this.ctx.lineWidth = 5 / cameraScale;
        this.ctx.globalAlpha = 0.2;
        this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 1.1, 0, Math.PI * 2); this.ctx.stroke();
      }

      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#1e0505';
      this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize, 0, Math.PI * 2); this.ctx.fill();

      // Node Name
      this.ctx.fillStyle = '#fff'; 
      this.ctx.font = `bold ${Math.max(80, 200 / cameraScale)}px Space Grotesk`; 
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, 0, pDrawSize + (180 / cameraScale));
      this.ctx.restore();
    });

    // 3. CENTRAL MAINFRAME
    const coreSize = Math.max(minPixelSize * 5, (200 + (state.level * 0.5)) * perceivedScale * 0.4);
    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 150 / cameraScale; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 4. BEAMS (Lasers)
    this.ctx.lineCap = 'round';
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = Math.max(12, (ef.type === 'SNIPER' ? 60 : 25) * ef.life / cameraScale);
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.12;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // 5. UNITS (Tactical Icons)
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = now - (e.lastHit || 0) < 100;
      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));

      const uSize = Math.max(minPixelSize, e.size * perceivedScale * 0.45);

      if (e.isFriendly) {
         this.ctx.shadowBlur = 80 / cameraScale;
         this.ctx.shadowColor = '#22d3ee';
      }

      // Tactical Arrow shape
      this.ctx.beginPath();
      if (e.type === 'boss') {
        const bS = uSize * 1.8;
        this.ctx.moveTo(bS, 0); 
        this.ctx.lineTo(-bS/2, bS); 
        this.ctx.lineTo(-bS, 0); 
        this.ctx.lineTo(-bS/2, -bS);
      } else {
        this.ctx.moveTo(uSize, 0); 
        this.ctx.lineTo(-uSize, uSize * 0.8); 
        this.ctx.lineTo(-uSize * 0.5, 0);
        this.ctx.lineTo(-uSize, -uSize * 0.8);
      }
      this.ctx.closePath();
      this.ctx.fill();

      // Shield ring
      if (e.shield && e.shield > 0) {
          this.ctx.strokeStyle = '#38bdf8';
          this.ctx.lineWidth = 20 / cameraScale;
          this.ctx.beginPath(); this.ctx.arc(0, 0, uSize * 1.5, -Math.PI/2, Math.PI/2); this.ctx.stroke();
      }
      this.ctx.restore();
    });

    // 6. DEFENSE NODES (Towers)
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const tSize = Math.max(minPixelSize * 1.4, 90 * perceivedScale * 0.4);

      // Node box
      this.ctx.fillRect(t.x - tSize, t.y - tSize, tSize * 2, tSize * 2);

      // Pulsing active state
      this.ctx.strokeStyle = t.color;
      this.ctx.lineWidth = 5 / cameraScale;
      this.ctx.globalAlpha = 0.3 + Math.sin(now * 0.01) * 0.2;
      this.ctx.strokeRect(t.x - tSize - (10/cameraScale), t.y - tSize - (10/cameraScale), tSize * 2 + (20/cameraScale), tSize * 2 + (20/cameraScale));
      this.ctx.globalAlpha = 1.0;
    });

    // 7. DROPS & PARTICLES
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `bold ${Math.max(80, 250 / cameraScale)}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        const pSize = p.size * perceivedScale * 0.4;
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, pSize, 0, Math.PI * 2); this.ctx.fill();
      }
    });

    state.drops.forEach(d => {
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      const s = Math.max(minPixelSize, 80 * perceivedScale * 0.2);
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.005);
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return COLORS.BOSS;
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const THREAT_DECAY = 0.05;
const MAX_ENEMIES_ON_SCREEN = 50; 
const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(
    state: GameState, 
    dt: number, 
    cameraScale: number, 
    hasAutoCollect: boolean,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;

    const now = Date.now();
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;
    const versionMult = Math.pow(2.8, state.permanentUpgrades.version - 1);

    // 1. Passive LOC (Sector & Level Scaled)
    const sectorMult = Math.pow(2.2, state.currentSector);
    const basePassive = (50 + state.level * 10) * (dt / 1000) * versionMult * sectorMult;
    state.code = Math.min(MAX_VAL, state.code + basePassive);

    // 2. Threat & Combo
    state.threatLevel = Math.max(0.5, state.threatLevel - (THREAT_DECAY * dt / 1000));

    // 3. Projectiles (Collision scaling)
    state.projectiles = state.projectiles.filter(proj => {
      let targetPos: Point | null = null;
      if (proj.type === 'allied') {
        const target = state.planets.find(p => p.id === proj.targetId);
        if (target) targetPos = target;
      } else {
        targetPos = { x: cx, y: cy };
      }
      if (!targetPos) return false;

      const dx = targetPos.x - proj.x;
      const dy = targetPos.y - proj.y;
      const distSq = dx * dx + dy * dy;

      const hitRadius = Math.max(120, 200 / cameraScale);
      if (distSq < hitRadius * hitRadius) {
        if (proj.type === 'allied') {
          const target = state.planets.find(p => p.id === proj.targetId);
          if (target) {
            target.hp -= proj.damage;
            state.code = Math.min(MAX_VAL, state.code + proj.damage * 0.3); 
            if (target.hp <= 0 && !target.isCaptured) {
              this.capturePlanet(state, target, onLevelUp);
            }
          }
        } else {
          state.coreHp -= proj.damage;
          if (state.coreHp <= 0) {
            state.coreHp = 0;
            state.isGameOver = true;
          }
        }
        return false;
      }

      const dist = Math.sqrt(distSq);
      proj.x += (dx / dist) * proj.speed;
      proj.y += (dy / dist) * proj.speed;
      return true;
    });

    // 4. Enemy Merging (Maintain performance)
    if (state.enemies.length > MAX_ENEMIES_ON_SCREEN) {
      for (let i = 0; i < 10; i++) {
        const idx1 = Math.floor(Math.random() * state.enemies.length);
        const idx2 = Math.floor(Math.random() * state.enemies.length);
        const e1 = state.enemies[idx1];
        const e2 = state.enemies[idx2];
        if (e1 && e2 && idx1 !== idx2 && e1.isFriendly === e2.isFriendly) {
           e1.hp = Math.min(MAX_VAL, e1.hp + e2.hp);
           e1.maxHp = Math.min(MAX_VAL, e1.maxHp + e2.maxHp);
           e1.size = Math.min(700, e1.size * 1.15);
           state.enemies.splice(idx2, 1);
           break;
        }
      }
    }

    // 5. Enemy & Allied Movement
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0) return;

      if (enemy.isFriendly) {
         const uncaptured = state.planets.filter(p => !p.isCaptured);
         if (uncaptured.length > 0) {
             let nearest = uncaptured[0];
             let minDSq = Infinity;
             uncaptured.forEach(p => {
                 const dSq = (p.x - enemy.x)**2 + (p.y - enemy.y)**2;
                 if (dSq < minDSq) { minDSq = dSq; nearest = p; }
             });

             const dx = nearest.x - enemy.x;
             const dy = nearest.y - enemy.y;
             const dist = Math.sqrt(minDSq);

             if (dist < 400) {
                 nearest.hp -= enemy.hp * 0.75; 
                 enemy.hp -= nearest.maxHp * 0.0001; 
                 if (nearest.hp <= 0) this.capturePlanet(state, nearest, onLevelUp);
             }

             enemy.x += (dx / dist) * enemy.speed * 3.0;
             enemy.y += (dy / dist) * enemy.speed * 3.0;
             enemy.angle = Math.atan2(dy, dx);
         } else {
             enemy.x += Math.cos(enemy.angle) * enemy.speed * 3.0;
             enemy.y += Math.sin(enemy.angle) * enemy.speed * 3.0;
         }
      } else {
         const dx = cx - enemy.x;
         const dy = cy - enemy.y;
         const distSq = dx * dx + dy * dy;

         if (distSq < 22500) { // 150px
           state.coreHp -= (enemy.type === 'boss' ? 5000 : 200) + (state.level * 15);
           enemy.hp = -1;
           if (state.coreHp <= 0) {
             state.coreHp = 0;
             state.isGameOver = true;
           }
           return;
         }

         const dist = Math.sqrt(distSq);
         enemy.x += (dx / dist) * enemy.speed;
         enemy.y += (dy / dist) * enemy.speed;
         enemy.angle = Math.atan2(dy, dx);
      }
    });

    state.enemies = state.enemies.filter(e => e.hp > 0);

    // 6. Global Drop Collection
    state.drops = state.drops.filter(d => {
      d.life -= 0.0035;
      const dx = cx - d.x;
      const dy = cy - d.y;
      const distSq = dx * dx + dy * dy;
      const vacuumRadius = (hasAutoCollect ? 10000 : 0) / cameraScale;

      if (distSq < (200/cameraScale)**2) {
        this.collectDrop(state, d);
        return false;
      }
      if (distSq < vacuumRadius * vacuumRadius) {
        const dist = Math.sqrt(distSq);
        d.x += (dx / dist) * 100;
        d.y += (dy / dist) * 100;
      }
      return d.life > 0;
    });
  }

  public static handleClick(
    state: GameState, 
    worldX: number, 
    worldY: number, 
    cameraScale: number,
    onItemCollected: (d: LibraryDrop) => void,
    onEnemyHit: (e: Enemy) => void,
    onLevelUp: () => void
  ): boolean {
    if (state.isGameOver || state.isVictory || state.isCompiling) return false;
    let hitSomething = false;
    const now = Date.now();
    const versionMult = Math.pow(2.8, state.permanentUpgrades.version - 1);

    const splashRadius = (350 + (state.level * 8)) / Math.pow(cameraScale, 0.45);
    state.enemies.forEach(enemy => {
      if (enemy.hp <= 0 || enemy.isFriendly) return;
      const dSq = (enemy.x - worldX) ** 2 + (enemy.y - worldY) ** 2;
      if (dSq < splashRadius * splashRadius) {
        const dist = Math.sqrt(dSq);
        const damageMult = dist < 200 ? 1.0 : Math.max(0.45, (1 - (dist / splashRadius)));
        let actualDmg = state.clickPower * damageMult;

        if (actualDmg > enemy.hp * 0.4 && state.level > 25) {
            enemy.isFriendly = true;
            enemy.hp = enemy.maxHp;
            enemy.speed *= 3.0;
            hitSomething = true;
            onEnemyHit(enemy);
            return;
        }

        enemy.hp -= actualDmg;
        enemy.lastHit = now;
        state.code = Math.min(MAX_VAL, state.code + (100 * versionMult));
        hitSomething = true;
        onEnemyHit(enemy);

        if (enemy.hp <= 0 && !(enemy as any)._processed) {
          this.processEnemyDeath(state, enemy, true);
          this.checkLevelUp(state, onLevelUp);
        }
      }
    });

    return hitSomething;
  }

  public static updateTowers(
    state: GameState, 
    onFire: (tower: Tower, target: Enemy | Planet) => void,
    onLevelUp: () => void
  ): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const { damageMult, rangeMult, fireRateMult } = state.towerModifiers;

    // Exponential range scaling by sector
    const autoRangeScale = Math.pow(1.6, state.currentSector);

    // DISTRIBUTED TARGETING SYSTEM
    // To prevent 100 towers from shooting the same single enemy, we track assigned targets.
    const assignments: Record<string, number> = {};

    state.towers.forEach(tower => {
      if (tower.disabledUntil && now < tower.disabledUntil) return;

      const effectiveRange = tower.range * rangeMult * autoRangeScale;
      const effectiveDamage = tower.damage * damageMult;
      const effectiveFireRate = tower.fireRate * fireRateMult;

      if (now - tower.lastFired > effectiveFireRate) {
        let target: (Enemy | Planet) | null = null;
        let minDistSq = effectiveRange * effectiveRange;

        // Priority targeting with target distribution
        for (const e of state.enemies) {
          if (e.isFriendly || e.hp <= 0) continue;

          const dSq = (e.x - tower.x)**2 + (e.y - tower.y)**2;
          if (dSq < minDistSq) {
            // Check if this enemy already has too many towers shooting it
            const currentLoad = assignments[e.id] || 0;
            if (currentLoad < 3) { // Max 3 towers per small bug
                minDistSq = dSq;
                target = e;
            }
          }
        }

        // Siege Planets if no enemies
        if (!target) {
          for (const p of state.planets) {
            if (p.isCaptured) continue;
            const dSq = (p.x - tower.x)**2 + (p.y - tower.y)**2;
            if (dSq < minDistSq) { minDistSq = dSq; target = p; }
          }
        }

        if (target) {
          assignments[target.id] = (assignments[target.id] || 0) + 1;
          target.hp -= effectiveDamage;
          state.code = Math.min(MAX_VAL, state.code + effectiveDamage * 0.3);
          state.experience += Math.max(0, effectiveDamage * 0.5 * state.permanentUpgrades.xpMultiplier);
          if ('lastHit' in target) (target as Enemy).lastHit = now;
          onFire(tower, target);

          if (target.hp <= 0) {
            const isEnemy = 'type' in target;
            const isPlanet = 'isCaptured' in target;
            if (isEnemy && !(target as any)._processed) {
              this.processEnemyDeath(state, target as Enemy, false);
              this.checkLevelUp(state, onLevelUp);
            } else if (isPlanet && !(target as Planet).isCaptured) {
              this.capturePlanet(state, target as Planet, onLevelUp);
            }
          }
          tower.lastFired = now;
        }
      }
    });
  }

  private static capturePlanet(state: GameState, planet: Planet, onLevelUp: () => void) {
    planet.isCaptured = true;
    planet.color = COLORS.PRIMARY;
    planet.hp = 0;
    state.experience += (100000 * Math.pow(2.0, planet.sector)) * state.permanentUpgrades.xpMultiplier;
    this.checkLevelUp(state, onLevelUp);
  }

  public static collectDrop(state: GameState, d: LibraryDrop): void {
    const versionMult = Math.pow(2.8, state.permanentUpgrades.version - 1);
    if (d.type === 'shard') {
      state.spProgress += 10; 
      if (state.spProgress >= state.spGoal) {
        state.skillPoints += 5; 
        state.spProgress = 0;
        state.spGoal = Math.floor(state.spGoal * 1.15) + 2;
      }
    } else if (d.type === 'loc') {
      state.code = Math.min(MAX_VAL, state.code + (10000 + (state.level * 1000)) * (1 + state.currentSector) * versionMult);
    }
  }

  public static processEnemyDeath(state: GameState, enemy: Enemy, isManual: boolean): void {
    if ((enemy as any)._processed) return;
    (enemy as any)._processed = true;
    const versionMult = Math.pow(2.8, state.permanentUpgrades.version - 1);

    state.combo++;
    let rewardMult = (1 + state.threatLevel * 0.5) * state.permanentUpgrades.xpMultiplier * (1 + state.level / 80);
    if (enemy.type === 'boss') rewardMult *= 80;

    state.experience += Math.max(0, (enemy.value / 2) * rewardMult);
    state.code = Math.min(MAX_VAL, state.code + Math.floor(enemy.value * rewardMult * versionMult));

    state.spProgress += isManual ? 4 : 8;
    if (state.spProgress >= state.spGoal) {
        state.skillPoints += 5;
        state.spProgress -= state.spGoal;
        state.spGoal = Math.floor(state.spGoal * 1.15) + 2;
    }

    const rand = Math.random();
    if (enemy.type === 'boss' || rand < 0.7) {
      state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP', x: enemy.x, y: enemy.y, life: 6.0 });
    } else {
      state.drops.push({ id: Math.random().toString(36), name: 'Data', type: 'loc', rarity: 'common', effect: 'LOC', x: enemy.x, y: enemy.y, life: 5.0 });
    }
    enemy.hp = -999;
  }

  public static checkLevelUp(state: GameState, onLevelUp: () => void): void {
    const nextLevelExp = 500 + (state.level * 500); 
    if (state.experience >= nextLevelExp) {
      state.level++;
      state.experience -= nextLevelExp;
      state.clickPower *= 1.25; 
      state.skillPoints += 8; 
      onLevelUp();
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 3; 
const SHARDS_PER_SP_BASE = 30;

// Safeguard against JS floating point limits
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private resizeHandler: () => void;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    this.resizeHandler = () => this.resize();
    this.resize();
    window.addEventListener('resize', this.resizeHandler);
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  public destroy() {
    this.isDestroyed = true;
    window.removeEventListener('resize', this.resizeHandler);
    audio.stop();
  }

  private getInitialState(): GameState {
    return {
      code: 10000, experience: 0, level: 1, skillPoints: 10, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 100, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 1000, maxCoreHp: 1000, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 2600 + (sector * 3500); 
    const count = PLANET_COUNT + sector;
    const names = ["NODE", "HOST", "LINK", "CACHE", "PORT", "PIPE", "ROOT", "SHELL"];
    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);

    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 0.9);
      const baseHp = (10000 + (this.state.level * 500)) * Math.pow(2.5, sector);
      const cappedHp = Math.min(MAX_VAL, baseHp * versionBoost);

      this.state.planets.push({
        id: `planet_${sector}_${i}`, 
        name: `${names[i % names.length]}_0x${sector}`,
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: cappedHp,
        maxHp: cappedHp,
        isCaptured: false, size: 600 + (sector * 250), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    const versionMult = Math.pow(5, perms.version - 1);
    this.state.code = (10000 + (perms.startingCode || 0)) * versionMult;
    this.state.clickPower = 100 * perms.damageMultiplier * versionMult;

    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(0); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;

    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    const earnedLegacy = Math.floor(Math.log10(this.state.code + 1) * this.state.level / 3);
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 2000));

    this.state.isCompiling = false;
    this.reset();
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused || this.isDestroyed || this.state.isCompiling) return;

    audio.enable();

    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;

    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 10, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        if (e.isFriendly) {
           this.createParticles(e.x, e.y, 20, '#22d3ee');
        } else {
           this.createParticles(e.x, e.y, 8, COLORS.PRIMARY);
        }
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const versionMult = Math.pow(3.5, this.state.permanentUpgrades.version - 1);
      const missReward = (300 + (this.state.level * 100) * (1 + this.state.currentSector)) * versionMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + missReward);
      this.createFloatingText(worldX, worldY, `+${this.formatNumber(missReward)}`, COLORS.PRIMARY);
      audio.playClick();
    }

    if (this.state.ripples.length < 5) {
      this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 400 / this.cameraScale, life: 1.0 });
    }

    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 200, "+8 SKILL POINTS", COLORS.SECONDARY);

    const uncapturedInSector = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncapturedInSector.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 400, `NETWORK EXPANDED: SECTOR ${this.state.currentSector}`, COLORS.ACCENT);
    }

    if (this.state.level % 5 === 0) {
      this.state.maxCoreHp = Math.min(MAX_VAL, this.state.maxCoreHp + (5000 * this.state.permanentUpgrades.version)); 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  private formatNumber(num: number): string {
    if (num < 1000) return num.toFixed(0);
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const suffix = suffixes[tier];
    const scale = Math.pow(10, tier * 3);
    const scaled = num / scale;
    return scaled.toFixed(2) + suffix;
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused || this.isDestroyed || this.state.isCompiling) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const safeType: string = type;
    const tCount = this.state.towers.filter(t => t.type === safeType).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.1, tCount)); 

    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;

    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36), type: safeType, level: 1, x: worldX, y: worldY,
        range: config.range, 
        damage: config.damage, 
        fireRate: config.fireRate, 
        lastFired: 0, 
        color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;

    if (!this.isPaused && !this.state.isCompiling) {
      this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused || !!this.state.isCompiling);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const wasVictory = this.state.isVictory;
    const prevCoreHp = this.state.coreHp;

    // --- RECALIBRATED CAMERA FLOOR ---
    let targetDist = 2800;
    this.state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const d = Math.sqrt((e.x - this.canvas.width/2)**2 + (e.y - this.canvas.height/2)**2);
        if (d > targetDist) targetDist = d;
    });

    const cameraScaleFloor = 0.95 / (1 + this.state.currentSector * 0.3); 
    const baseViewWidth = 1400;
    this.targetCameraScale = Math.max(cameraScaleFloor, baseViewWidth / (targetDist * 1.2));
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.01;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
      },
      () => this.onLevelUp()
    );

    if ((this.state.isGameOver && !wasGameOver) || (this.state.isVictory && !wasVictory)) {
      audio.playGameOver();
      const earnedLegacy = Math.max(0, Math.floor(Math.log10(this.state.code + 1)));
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.isGameOver || this.state.isVictory) return;

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(20);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = (this.state.level * 3000) * Math.pow(2.5, this.state.permanentUpgrades.version - 1) * (1 + this.state.currentSector);
        if (this.state.unlockedSkills.includes('code_gen')) gain *= 15; 
        this.state.code = Math.min(MAX_VAL, this.state.code + gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(450, 2000 - (this.state.level * 6));
    const threatMult = 1 + (this.state.threatLevel * 0.5) + (this.state.currentSector * 0.25);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;

      let type: Enemy['type'] = 'bug';
      const r = Math.random();
      if (this.state.level >= 20 || this.state.currentSector > 0) {
          if (r < 0.18) type = 'glitch';
          else if (r < 0.28) type = 'null_pointer';
          else if (r < 0.38) type = 'memory_leak';
          else if (r < 0.48) type = 'shielded';
          else if (r < 0.55) type = 'worm';
      }

      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    if (this.state.particles.length > 150) this.state.particles.splice(0, 30);
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.007 : 0.06; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 25; r.life -= 0.04; return r.life > 0; });

    if (this.frameCount % 5 === 0) {
      this.onUpdate({ ...this.state });
    }
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 3800 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const sectorFactor = Math.pow(2.2, this.state.currentSector);
    const hp = 30000 * Math.pow(1.4, (this.state.level / 5)) * sectorFactor * Math.pow(10, this.state.permanentUpgrades.version - 1);

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed: 1.4 + (this.state.level * 0.02), value: 1000000 * this.state.permanentUpgrades.version * (1 + this.state.currentSector), 
      type: 'boss', size: 600, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 300, "FATAL OVERFLOW DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: Enemy['type'] = 'bug') {
    if (this.state.enemies.length > 60) return;

    const dist = 4800 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle) * 300; y = sy + Math.sin(angle) * 300;
    }

    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);
    const sectorFactor = Math.pow(1.4, this.state.currentSector * 5);
    const hpMult = Math.pow(1.15, Math.min(this.state.level, 1000));
    let hp = 200 * hpMult * versionBoost * sectorFactor;
    let speed = 1.8 + (Math.min(this.state.level, 1000) * 0.04);
    let size = 80 + (Math.min(this.state.level, 5000) * 0.12);
    let shield = 0;

    if (type === 'glitch') { hp *= 3.5; speed += 1.2; }
    if (type === 'shielded') { shield = hp * 2.0; hp *= 1.3; speed *= 0.8; size += 50; }
    if (type === 'null_pointer') { hp *= 0.5; speed += 3.2; }
    if (type === 'memory_leak') { hp *= 3.0; speed *= 0.8; size += 80; }
    if (type === 'worm') { hp *= 0.45; speed += 2.0; size *= 1.0; }

    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed, value: (hp * 4.0), type, size, angle: 0,
      shield: Math.min(MAX_VAL, shield), sinOffset: Math.random() * 1000
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;

      if (this.state.skillPoints < cost) return false;

      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);

      if (skillId === 'auto_collect') this.hasAutoCollect = true;

      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.35);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 250000;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 4.0;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 5.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 250) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*35, vy: (Math.random()-0.5)*35, size: Math.random()*10+4, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -6, size: 48, life: 2.2, color, text });
  }
}

import { GameState, Enemy, Tower, Planet } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 80;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    // DYNAMIC VISUAL SCALING
    // perceivedScale keeps objects visually "present" at extreme distances.
    const perceivedScale = 1 / Math.pow(cameraScale, 0.92); 
    const isStrategicView = cameraScale < 0.3;
    const minPixelSize = isStrategicView ? 25 : 15;

    // Background Clear
    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.9;
    }

    // World Space
    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. NEBULA & FIELD EFFECTS (Atmosphere)
    this.ctx.globalCompositeOperation = 'lighter';
    state.planets.forEach(p => {
        if (p.isCaptured) {
            this.ctx.globalAlpha = 0.05 * perceivedScale;
            const grad = this.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size * 3 * perceivedScale);
            grad.addColorStop(0, versionColor);
            grad.addColorStop(1, 'transparent');
            this.ctx.fillStyle = grad;
            this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size * 3 * perceivedScale, 0, Math.PI * 2); this.ctx.fill();
        }
    });
    this.ctx.globalCompositeOperation = 'source-over';
    this.ctx.globalAlpha = 1.0;

    // 2. NETWORK INFLUENCE BEAMS
    this.ctx.lineCap = 'round';
    state.planets.forEach(p => {
        if (!p.isCaptured) return;
        this.ctx.beginPath();
        this.ctx.moveTo(cx, cy);
        this.ctx.lineTo(p.x, p.y);
        this.ctx.strokeStyle = versionColor;
        this.ctx.lineWidth = (10 + Math.sin(now * 0.002) * 5) / cameraScale;
        this.ctx.globalAlpha = 0.08;
        this.ctx.stroke();
    });

    // 3. WARP WELLS (Spawns)
    state.planets.forEach(p => {
      if (p.sector > state.currentSector + 1) return;
      this.ctx.save();
      this.ctx.translate(p.x, p.y);

      const pDrawSize = Math.max(minPixelSize * 5, p.size * perceivedScale * 0.4);

      if (!p.isCaptured) {
        // Threat Alert Beam (Visible from distance)
        this.ctx.globalAlpha = 0.15 + Math.sin(now * 0.01) * 0.1;
        this.ctx.fillStyle = COLORS.ENEMY;
        this.ctx.fillRect(-pDrawSize * 0.2, -50000, pDrawSize * 0.4, 100000);

        // Core Mass
        this.ctx.globalAlpha = 1.0;
        this.ctx.fillStyle = '#1a0303';
        this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize, 0, Math.PI * 2); this.ctx.fill();

        // Pulsing Event Horizon
        this.ctx.strokeStyle = COLORS.ENEMY;
        this.ctx.lineWidth = 15 / cameraScale;
        this.ctx.rotate(now * 0.001);
        this.ctx.setLineDash([150 / cameraScale, 100 / cameraScale]);
        this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 1.4, 0, Math.PI * 2); this.ctx.stroke();
        this.ctx.setLineDash([]);
      } else {
        this.ctx.fillStyle = '#0c4a6e';
        this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize, 0, Math.PI * 2); this.ctx.fill();
      }

      // Node Text
      this.ctx.fillStyle = '#fff';
      this.ctx.font = `bold ${Math.max(100, 300 / cameraScale)}px Space Grotesk`;
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, 0, pDrawSize + (250 / cameraScale));
      this.ctx.restore();
    });

    // 4. THE MAINFRAME CORE
    const coreSize = Math.max(minPixelSize * 8, (250 + (state.level * 0.5)) * perceivedScale * 0.4);
    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 200 / cameraScale; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 5. COMBAT EFFECTS
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = Math.max(15, (ef.type === 'SNIPER' ? 80 : 30) * ef.life / cameraScale);
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.15;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // 6. UNITS (LOD System)
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = now - (e.lastHit || 0) < 100;
      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));

      const uSize = Math.max(minPixelSize, e.size * perceivedScale * 0.4);

      if (e.isFriendly) {
         this.ctx.shadowBlur = 100 / cameraScale;
         this.ctx.shadowColor = '#22d3ee';
      }

      this.ctx.beginPath();
      if (isStrategicView) {
        // TACTICAL ICON MODE
        this.ctx.moveTo(uSize * 2, 0); 
        this.ctx.lineTo(-uSize, uSize * 1.5); 
        this.ctx.lineTo(-uSize, -uSize * 1.5);
      } else {
        // DETAILED MODE
        if (e.type === 'boss') {
            this.ctx.moveTo(uSize * 2, 0); 
            this.ctx.lineTo(-uSize, uSize); 
            this.ctx.lineTo(-uSize * 1.5, 0); 
            this.ctx.lineTo(-uSize, -uSize);
        } else {
            this.ctx.moveTo(uSize, 0); 
            this.ctx.lineTo(-uSize, uSize * 0.8); 
            this.ctx.lineTo(-uSize * 0.5, 0);
            this.ctx.lineTo(-uSize, -uSize * 0.8);
        }
      }
      this.ctx.closePath();
      this.ctx.fill();

      // Strategic Direction Tail
      if (isStrategicView) {
          this.ctx.globalAlpha = 0.2;
          this.ctx.fillRect(-uSize * 4, -uSize * 0.2, uSize * 3, uSize * 0.4);
          this.ctx.globalAlpha = 1.0;
      }

      if (e.shield && e.shield > 0) {
          this.ctx.strokeStyle = '#38bdf8';
          this.ctx.lineWidth = 20 / cameraScale;
          this.ctx.beginPath(); this.ctx.arc(0, 0, uSize * 1.6, -Math.PI/2, Math.PI/2); this.ctx.stroke();
      }
      this.ctx.restore();
    });

    // 7. TOWERS
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const tSize = Math.max(minPixelSize * 1.5, 100 * perceivedScale * 0.4);
      this.ctx.fillRect(t.x - tSize, t.y - tSize, tSize * 2, tSize * 2);

      // Node Pulse
      this.ctx.strokeStyle = t.color;
      this.ctx.lineWidth = 10 / cameraScale;
      this.ctx.globalAlpha = 0.2 + Math.sin(now * 0.005) * 0.1;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, tSize * 1.5, 0, Math.PI * 2); this.ctx.stroke();
    });

    // 8. DROPS
    state.drops.forEach(d => {
      this.ctx.globalAlpha = d.life;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      const s = Math.max(minPixelSize * 1.2, 120 * perceivedScale * 0.2);
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.005);
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return COLORS.BOSS;
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save_v2';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 3; 
const SHARDS_PER_SP_BASE = 35;

// Safeguard against JS floating point limits
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private resizeHandler: () => void;

  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    this.resizeHandler = () => this.resize();
    this.resize();
    window.addEventListener('resize', this.resizeHandler);
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  public destroy() {
    this.isDestroyed = true;
    window.removeEventListener('resize', this.resizeHandler);
    audio.stop();
  }

  private getInitialState(): GameState {
    return {
      code: 15000, experience: 0, level: 1, skillPoints: 12, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 150, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 1500, maxCoreHp: 1500, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 3000 + (sector * 4500); 
    const count = PLANET_COUNT + sector;
    const names = ["NODE", "HOST", "LINK", "CACHE", "PORT", "PIPE", "ROOT", "SHELL", "KERN", "DAEMON"];
    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);

    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 1.3);
      const baseHp = (15000 + (this.state.level * 600)) * Math.pow(2.8, sector);
      const cappedHp = Math.min(MAX_VAL, baseHp * versionBoost);

      this.state.planets.push({
        id: `planet_${sector}_${i}`, 
        name: `${names[i % names.length]}_${sector}`,
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: cappedHp,
        maxHp: cappedHp,
        isCaptured: false, size: 700 + (sector * 300), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    const versionMult = Math.pow(6, perms.version - 1);
    this.state.code = (15000 + (perms.startingCode || 0)) * versionMult;
    this.state.clickPower = 150 * perms.damageMultiplier * versionMult;

    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(0); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;
    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();
    const earnedLegacy = Math.floor(Math.log10(this.state.code + 1) * this.state.level / 2.5);
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.state.permanentUpgrades.version++;
    await new Promise(r => setTimeout(r, 2000));
    this.state.isCompiling = false;
    this.reset();
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused || this.isDestroyed || this.state.isCompiling) return;
    audio.enable();
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const hit = LogicHandler.handleClick(
      this.state, 
      worldX, 
      worldY, 
      this.cameraScale,
      (d) => {
        this.createParticles(d.x, d.y, 12, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        this.createParticles(e.x, e.y, e.isFriendly ? 25 : 10, e.isFriendly ? '#22d3ee' : COLORS.PRIMARY);
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const versionMult = Math.pow(4.0, this.state.permanentUpgrades.version - 1);
      const missReward = (500 + (this.state.level * 150) * (1 + this.state.currentSector)) * versionMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + missReward);
      this.createFloatingText(worldX, worldY, `+${this.formatNumber(missReward)}`, COLORS.PRIMARY);
      audio.playClick();
    }

    if (this.state.ripples.length < 5) {
      this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 500 / this.cameraScale, life: 1.0 });
    }
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 250, "+12 SKILL POINTS", COLORS.SECONDARY);
    const uncapturedInSector = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncapturedInSector.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 450, `EXPANDING TO SECTOR ${this.state.currentSector}`, COLORS.ACCENT);
    }
    if (this.state.level % 5 === 0) {
      this.state.maxCoreHp = Math.min(MAX_VAL, this.state.maxCoreHp + (8000 * this.state.permanentUpgrades.version)); 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  private formatNumber(num: number): string {
    if (num < 1000) return num.toFixed(0);
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const suffix = suffixes[tier];
    const scale = Math.pow(10, tier * 3);
    const scaled = num / scale;
    return scaled.toFixed(1) + suffix;
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused || this.isDestroyed || this.state.isCompiling) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const tCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.08, tCount)); 
    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;
    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY,
        range: config.range, damage: config.damage, fireRate: config.fireRate, lastFired: 0, color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;
    if (!this.isPaused && !this.state.isCompiling) {
      this.update(dt);
    }
    this.renderer.draw(this.state, this.cameraScale, this.isPaused || !!this.state.isCompiling);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const prevCoreHp = this.state.coreHp;

    // --- GALACTIC CAMERA SYSTEM ---
    let maxDist = 3000;
    this.state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const d = Math.sqrt((e.x - this.canvas.width/2)**2 + (e.y - this.canvas.height/2)**2);
        if (d > maxDist) maxDist = d;
    });
    this.state.planets.forEach(p => {
        if (!p.isCaptured && p.sector <= this.state.currentSector) {
           const d = Math.sqrt((p.x - this.canvas.width/2)**2 + (p.y - this.canvas.height/2)**2);
           if (d > maxDist) maxDist = d;
        }
    });

    // We allow zooming out much further now by lowering the floor.
    const cameraScaleFloor = 0.8 / (1 + this.state.currentSector * 0.8); 
    const baseViewWidth = 1600;
    this.targetCameraScale = Math.max(cameraScaleFloor, baseViewWidth / (maxDist * 1.3));
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.008; // Slower, smoother zoom

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, 
      (tower, target) => {
        this.renderer.addFiringEffect(tower.x, tower.y, target.x, target.y, tower.color, tower.type);
        audio.playFire(tower.type);
      },
      () => this.onLevelUp()
    );

    if (this.state.isGameOver && !wasGameOver) {
      audio.playGameOver();
      const earnedLegacy = Math.max(0, Math.floor(Math.log10(this.state.code + 1)));
      this.state.permanentUpgrades.legacyPoints += earnedLegacy;
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return; 
    }

    if (this.state.coreHp < prevCoreHp) {
      this.renderer.triggerShake(25);
    }

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = (this.state.level * 5000) * Math.pow(2.8, this.state.permanentUpgrades.version - 1) * (1 + this.state.currentSector);
        if (this.state.unlockedSkills.includes('code_gen')) gain *= 15; 
        this.state.code = Math.min(MAX_VAL, this.state.code + gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const baseFreq = Math.max(500, 2000 - (this.state.level * 4));
    const threatMult = 1 + (this.state.threatLevel * 0.6) + (this.state.currentSector * 0.3);
    if (this.enemySpawnTimer > (baseFreq / threatMult)) {
      const activePlanets = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
      const source = activePlanets.length > 0 ? activePlanets[Math.floor(Math.random() * activePlanets.length)] : null;
      let type: Enemy['type'] = 'bug';
      const r = Math.random();
      if (this.state.level >= 20 || this.state.currentSector > 0) {
          if (r < 0.2) type = 'glitch';
          else if (r < 0.3) type = 'null_pointer';
          else if (r < 0.4) type = 'memory_leak';
          else if (r < 0.5) type = 'shielded';
          else if (r < 0.6) type = 'worm';
      }
      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, type);
      this.enemySpawnTimer = 0;
    }

    if (this.state.particles.length > 150) this.state.particles.splice(0, 40);
    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; 
      p.life -= p.text ? 0.005 : 0.05; 
      return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 30; r.life -= 0.03; return r.life > 0; });
    if (this.frameCount % 5 === 0) this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 4500 / this.cameraScale;
    const x = this.canvas.width/2 + Math.cos(angle)*dist;
    const y = this.canvas.height/2 + Math.sin(angle)*dist;
    const sectorFactor = Math.pow(2.5, this.state.currentSector);
    const hp = 50000 * Math.pow(1.5, (this.state.level / 5)) * sectorFactor * Math.pow(10, this.state.permanentUpgrades.version - 1);
    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed: 1.8 + (this.state.level * 0.03), value: 2000000 * this.state.permanentUpgrades.version * (1 + this.state.currentSector), 
      type: 'boss', size: 700, angle: 0 
    });
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 400, "FATAL OVERFLOW DETECTED", COLORS.BOSS);
  }

  private spawnEnemyAt(sx: number, sy: number, type: Enemy['type'] = 'bug') {
    if (this.state.enemies.length > 70) return;
    const dist = 5500 / this.cameraScale;
    let x, y;
    if (sx === -999) {
      const angle = Math.random() * Math.PI * 2;
      x = this.canvas.width/2 + Math.cos(angle)*dist; y = this.canvas.height/2 + Math.sin(angle)*dist;
    } else {
      const angle = Math.random() * Math.PI * 2; x = sx + Math.cos(angle) * 400; y = sy + Math.sin(angle) * 400;
    }
    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);
    const sectorFactor = Math.pow(1.5, this.state.currentSector * 4);
    const hpMult = Math.pow(1.18, Math.min(this.state.level, 1000));
    let hp = 300 * hpMult * versionBoost * sectorFactor;
    let speed = 2.0 + (Math.min(this.state.level, 1000) * 0.05);
    let size = 90 + (Math.min(this.state.level, 5000) * 0.15);
    let shield = 0;
    if (type === 'glitch') { hp *= 4.0; speed += 1.5; }
    if (type === 'shielded') { shield = hp * 3.0; hp *= 1.4; speed *= 0.9; size += 60; }
    if (type === 'null_pointer') { hp *= 0.4; speed += 4.0; }
    if (type === 'memory_leak') { hp *= 4.0; speed *= 0.8; size += 100; }
    if (type === 'worm') { hp *= 0.5; speed += 2.5; size *= 1.2; }
    this.state.enemies.push({ 
      id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), 
      speed, value: (hp * 5.0), type, size, angle: 0,
      shield: Math.min(MAX_VAL, shield), sinOffset: Math.random() * 1000
    });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    if (this.state.skillPoints > 0) {
      const skillDef = ALL_SKILLS.find(s => s.id === skillId);
      const techDef = TECH_TREE.find(s => s.id === skillId);
      const cost = skillDef?.cost || techDef?.cost || 1;
      if (this.state.skillPoints < cost) return false;
      this.state.skillPoints -= cost;
      if (skillId.startsWith('tech_') && !this.state.unlockedTech.includes(skillId)) this.state.unlockedTech.push(skillId);
      else if (!this.state.unlockedSkills.includes(skillId)) this.state.unlockedSkills.push(skillId);
      if (skillId === 'auto_collect') this.hasAutoCollect = true;
      onUnlock(this.state); 
      audio.playLevelUp(); 
      this.refreshSkillShop(); 
      this.onUpdate({ ...this.state }); 
      return true;
    }
    return false;
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...parsed };
      } catch (e) {}
    }
  }

  private savePermanentUpgrades() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades));
  }

  private refreshSkillShop() {
    const availablePool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    const shuffled = [...availablePool].sort(() => 0.5 - Math.random());
    this.state.availableSkills = shuffled.slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost;
      this.state.rerollCost = Math.floor(this.state.rerollCost * 1.4);
      audio.playClick();
      this.refreshSkillShop();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private resize() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    const cost = 100;
    if (this.state.permanentUpgrades.legacyPoints >= cost) {
      this.state.permanentUpgrades.legacyPoints -= cost;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 500000;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 5.0;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 6.0;
      audio.playShard();
      this.savePermanentUpgrades();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    if (this.state.particles.length > 300) return; 
    for (let i = 0; i < count; i++) {
      this.state.particles.push({ x, y, vx: (Math.random()-0.5)*40, vy: (Math.random()-0.5)*40, size: Math.random()*12+6, life: 1.0, color });
    }
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: (Math.random()-0.5)*2, vy: -7, size: 56, life: 2.5, color, text });
  }
}

import { GameState, Enemy, Tower, Planet } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 120; // Increased for massive battles

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  private drawStarfield(cx: number, cy: number, cameraScale: number) {
    const { canvas } = this.ctx;
    const now = Date.now();
    // Use the camera scale to drive parallax layers
    const layers = [
        { count: 100, size: 1, speed: 0.1, color: '#1e293b' },
        { count: 50, size: 2, speed: 0.3, color: '#334155' },
        { count: 20, size: 3, speed: 0.6, color: '#475569' }
    ];

    layers.forEach(layer => {
        this.ctx.fillStyle = layer.color;
        for (let i = 0; i < layer.count; i++) {
            const x = (Math.sin(i * 133.7) * 0.5 + 0.5) * canvas.width;
            const y = (Math.cos(i * 99.1) * 0.5 + 0.5) * canvas.height;
            // Simple static stars for background reference
            this.ctx.beginPath();
            this.ctx.arc(x, y, layer.size, 0, Math.PI * 2);
            this.ctx.fill();
        }
    });
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    // GALAXY-VIEW SCALING
    const perceivedScale = 1 / Math.pow(cameraScale, 0.94); 
    const minPixelSize = cameraScale < 0.1 ? 30 : 12;

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.drawStarfield(cx, cy, cameraScale);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.9;
    }

    // World Space
    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. GALAXY NETWORK (Dependency Graph)
    this.ctx.lineWidth = 4 / cameraScale;
    this.ctx.globalAlpha = 0.05 * perceivedScale;
    state.planets.forEach((p, idx) => {
        if (!p.isCaptured && p.sector > state.currentSector) return;

        // Link to Core
        this.ctx.beginPath();
        this.ctx.moveTo(cx, cy);
        this.ctx.lineTo(p.x, p.y);
        this.ctx.strokeStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
        this.ctx.stroke();

        // Link to other planets in sector to form a graph
        const siblings = state.planets.filter(s => s.sector === p.sector && s.id !== p.id);
        siblings.forEach(s => {
            this.ctx.beginPath();
            this.ctx.moveTo(p.x, p.y);
            this.ctx.lineTo(s.x, s.y);
            this.ctx.stroke();
        });
    });
    this.ctx.globalAlpha = 1.0;

    // 2. SECTOR WARP WELLS
    state.planets.forEach(p => {
      if (p.sector > state.currentSector + 2) return; // Hide distant future sectors

      this.ctx.save();
      this.ctx.translate(p.x, p.y);
      const pDrawSize = Math.max(minPixelSize * 6, p.size * perceivedScale * 0.4);

      if (!p.isCaptured) {
        // Massive Tactical HUD Circle
        this.ctx.strokeStyle = COLORS.ENEMY;
        this.ctx.lineWidth = 10 / cameraScale;
        this.ctx.globalAlpha = 0.2;
        this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 2, 0, Math.PI * 2); this.ctx.stroke();

        // Spinning Hazard Brackets
        this.ctx.rotate(now * 0.0015);
        this.ctx.globalAlpha = 0.6;
        for(let i=0; i<4; i++) {
            this.ctx.rotate(Math.PI / 2);
            this.ctx.beginPath(); this.ctx.moveTo(pDrawSize * 1.5, -pDrawSize * 0.5); this.ctx.lineTo(pDrawSize * 1.5, pDrawSize * 0.5); this.ctx.stroke();
        }
      }

      this.ctx.globalAlpha = 1.0;
      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#1e0505';
      this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize, 0, Math.PI * 2); this.ctx.fill();

      this.ctx.fillStyle = '#fff';
      this.ctx.font = `bold ${Math.max(120, 350 / cameraScale)}px Space Grotesk`;
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, 0, pDrawSize + (300 / cameraScale));
      this.ctx.restore();
    });

    // 3. THE CORE
    const coreSize = Math.max(minPixelSize * 10, (300 + (state.level * 0.8)) * perceivedScale * 0.3);
    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 200 / cameraScale; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 4. COMBAT FX (Glow Beams)
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = Math.max(20, (ef.type === 'SNIPER' ? 100 : 40) * ef.life / cameraScale);
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.15;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // 5. UNITS
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = now - (e.lastHit || 0) < 100;
      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));

      const uSize = Math.max(minPixelSize, e.size * perceivedScale * 0.35);

      this.ctx.beginPath();
      if (cameraScale < 0.2) {
        // High-Contrast Strategic Arrow
        this.ctx.moveTo(uSize * 3, 0);
        this.ctx.lineTo(-uSize * 1.5, uSize * 2);
        this.ctx.lineTo(-uSize, 0);
        this.ctx.lineTo(-uSize * 1.5, -uSize * 2);
      } else {
        this.ctx.moveTo(uSize, 0);
        this.ctx.lineTo(-uSize, uSize);
        this.ctx.lineTo(-uSize * 0.5, 0);
        this.ctx.lineTo(-uSize, -uSize);
      }
      this.ctx.closePath();
      this.ctx.fill();

      if (e.isFriendly) {
          this.ctx.strokeStyle = '#22d3ee';
          this.ctx.lineWidth = 10 / cameraScale;
          this.ctx.stroke();
      }
      this.ctx.restore();
    });

    // 6. TOWERS
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const tSize = Math.max(minPixelSize * 2, 120 * perceivedScale * 0.35);
      this.ctx.fillRect(t.x - tSize, t.y - tSize, tSize * 2, tSize * 2);

      // Data Flux pulses
      this.ctx.strokeStyle = t.color;
      this.ctx.lineWidth = 15 / cameraScale;
      this.ctx.globalAlpha = 0.2;
      this.ctx.beginPath(); this.ctx.arc(t.x, t.y, tSize * 2, 0, Math.PI * 2); this.ctx.stroke();
      this.ctx.globalAlpha = 1.0;
    });

    // 7. DROPS (High visibility shards)
    state.drops.forEach(d => {
      this.ctx.globalAlpha = d.life;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      const s = Math.max(minPixelSize * 2, 150 * perceivedScale * 0.15);
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.01);
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return COLORS.BOSS;
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_save_galactic';
const BASE_REROLL_COST = 50; 
const PLANET_COUNT = 3; 
const SHARDS_PER_SP_BASE = 40;
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private passiveCodeTimer: number = 0;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private resizeHandler: () => void;
  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    this.resizeHandler = () => this.resize();
    this.resize();
    window.addEventListener('resize', this.resizeHandler);
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) {
    this.isPaused = paused;
  }

  public destroy() {
    this.isDestroyed = true;
    window.removeEventListener('resize', this.resizeHandler);
    audio.stop();
  }

  private getInitialState(): GameState {
    return {
      code: 20000, experience: 0, level: 1, skillPoints: 15, spProgress: 0, spGoal: SHARDS_PER_SP_BASE,
      clickPower: 200, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: BASE_REROLL_COST, combo: 0,
      threatLevel: 0.5, coreHp: 2000, maxCoreHp: 2000, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 3500 + (sector * 5500); 
    const count = PLANET_COUNT + sector;
    const names = ["CENTRAL", "LOCAL", "WIFI", "DOCKER", "SLACK", "TRELLO", "JIRA", "CONFLUENCE"];
    const versionBoost = Math.pow(10, this.state.permanentUpgrades.version - 1);

    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 1.5);
      const baseHp = (20000 + (this.state.level * 800)) * Math.pow(3.0, sector);
      const cappedHp = Math.min(MAX_VAL, baseHp * versionBoost);

      this.state.planets.push({
        id: `planet_${sector}_${i}`, 
        name: `${names[i % names.length]}_${sector}`,
        x: this.canvas.width / 2 + Math.cos(angle) * dist,
        y: this.canvas.height / 2 + Math.sin(angle) * dist,
        hp: cappedHp,
        maxHp: cappedHp,
        isCaptured: false, size: 800 + (sector * 400), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public reset() {
    this.savePermanentUpgrades();
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    const versionMult = Math.pow(7, perms.version - 1);
    this.state.code = (20000 + (perms.startingCode || 0)) * versionMult;
    this.state.clickPower = 200 * perms.damageMultiplier * versionMult;
    this.cameraScale = 1.0; this.targetCameraScale = 1.0;
    this.generatePlanets(0); this.refreshSkillShop();
    audio.updateBPM(this.state.level);
    this.onUpdate({ ...this.state });
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;
    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();
    const earnedLegacy = Math.floor(Math.log10(this.state.code + 1) * this.state.level / 2);
    this.state.permanentUpgrades.legacyPoints += earnedLegacy;
    this.state.permanentUpgrades.version++;
    await new Promise(r => setTimeout(r, 2000));
    this.state.isCompiling = false;
    this.reset();
  }

  public handleClick(rawX: number, rawY: number) {
    if (this.state.isGameOver || this.state.isVictory || this.isPaused || this.isDestroyed || this.state.isCompiling) return;
    audio.enable();
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const hit = LogicHandler.handleClick(this.state, worldX, worldY, this.cameraScale, 
      (d) => {
        this.createParticles(d.x, d.y, 15, d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY);
        if (d.type === 'shard') audio.playShard();
        else audio.playClick();
      },
      (e) => {
        this.createParticles(e.x, e.y, 15, e.isFriendly ? '#22d3ee' : COLORS.PRIMARY);
        audio.playClick();
      },
      () => this.onLevelUp()
    );

    if (!hit) {
      const vMult = Math.pow(4.5, this.state.permanentUpgrades.version - 1);
      const reward = (1000 + (this.state.level * 200) * (1 + this.state.currentSector)) * vMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + reward);
      this.createFloatingText(worldX, worldY, `+${this.formatNumber(reward)}`, COLORS.PRIMARY);
      audio.playClick();
    }

    if (this.state.ripples.length < 5) {
      this.state.ripples.push({ x: worldX, y: worldY, radius: 0, maxRadius: 600 / this.cameraScale, life: 1.0 });
    }
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    audio.updateBPM(this.state.level);
    this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 250, "+15 SKILL POINTS", COLORS.SECONDARY);
    const uncaptured = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncaptured.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.createFloatingText(this.canvas.width/2, this.canvas.height/2 - 500, `SECTOR ${this.state.currentSector} UNLOCKED`, COLORS.ACCENT);
    }
    if (this.state.level % 5 === 0) {
      this.state.maxCoreHp = Math.min(MAX_VAL, this.state.maxCoreHp + (10000 * this.state.permanentUpgrades.version)); 
      this.state.coreHp = this.state.maxCoreHp;
      this.spawnBoss();
    }
    this.refreshSkillShop();
  }

  private formatNumber(num: number): string {
    if (num < 1000) return num.toFixed(0);
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const scale = Math.pow(10, tier * 3);
    return (num / scale).toFixed(1) + suffixes[tier];
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number) {
    if (this.isPaused || this.isDestroyed || this.state.isCompiling) return false;
    const cx = this.canvas.width / 2; const cy = this.canvas.height / 2;
    const worldX = (rawX - cx) / this.cameraScale + cx;
    const worldY = (rawY - cy) / this.cameraScale + cy;
    const config = TOWER_TYPES[type];
    const tCount = this.state.towers.filter(t => t.type === type).length;
    const currentCost = Math.floor(config.cost * Math.pow(1.05, tCount)); 
    if (config.requires && !this.state.unlockedTech.includes(config.requires)) return false;
    if (this.state.code >= currentCost) {
      this.state.code -= currentCost;
      this.state.towers.push({
        id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY,
        range: config.range, damage: config.damage, fireRate: config.fireRate, lastFired: 0, color: config.color
      });
      audio.playClick();
      this.onUpdate({ ...this.state });
      return true;
    }
    return false;
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;
    if (!this.isPaused && !this.state.isCompiling) this.update(dt);
    this.renderer.draw(this.state, this.cameraScale, this.isPaused || !!this.state.isCompiling);
    requestAnimationFrame(this.animate);
  };

  private update(dt: number) {
    const wasGameOver = this.state.isGameOver;
    const prevCoreHp = this.state.coreHp;

    // --- GALACTIC BOUNDING CAMERA ---
    let bounds = { minX: this.canvas.width/2 - 1000, maxX: this.canvas.width/2 + 1000, minY: this.canvas.height/2 - 1000, maxY: this.canvas.height/2 + 1000 };
    this.state.planets.forEach(p => {
        if (!p.isCaptured && p.sector <= this.state.currentSector + 1) {
            bounds.minX = Math.min(bounds.minX, p.x); bounds.maxX = Math.max(bounds.maxX, p.x);
            bounds.minY = Math.min(bounds.minY, p.y); bounds.maxY = Math.max(bounds.maxY, p.y);
        }
    });
    this.state.enemies.forEach(e => {
        bounds.minX = Math.min(bounds.minX, e.x); bounds.maxX = Math.max(bounds.maxX, e.x);
        bounds.minY = Math.min(bounds.minY, e.y); bounds.maxY = Math.max(bounds.maxY, e.y);
    });

    const viewW = bounds.maxX - bounds.minX;
    const viewH = bounds.maxY - bounds.minY;
    const margin = 1.4;
    const scaleX = this.canvas.width / (viewW * margin);
    const scaleY = this.canvas.height / (viewH * margin);

    this.targetCameraScale = Math.min(scaleX, scaleY, 1.2);
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.005;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, (t, tar) => {
        this.renderer.addFiringEffect(t.x, t.y, tar.x, tar.y, t.color, t.type);
        audio.playFire(t.type);
    }, () => this.onLevelUp());

    if (this.state.isGameOver && !wasGameOver) audio.playGameOver();
    if (this.state.coreHp < prevCoreHp) this.renderer.triggerShake(30);

    const hasPassive = this.state.unlockedTech.includes('tech_passive') || this.state.unlockedSkills.includes('code_gen');
    if (hasPassive) {
      this.passiveCodeTimer += dt;
      if (this.passiveCodeTimer > 1000) { 
        let gain = (this.state.level * 8000) * Math.pow(3, this.state.permanentUpgrades.version - 1) * (1 + this.state.currentSector);
        if (this.state.unlockedSkills.includes('code_gen')) gain *= 20; 
        this.state.code = Math.min(MAX_VAL, this.state.code + gain); 
        this.passiveCodeTimer = 0; 
      }
    }

    this.enemySpawnTimer += dt;
    const freq = Math.max(600, 2000 - (this.state.level * 5));
    if (this.enemySpawnTimer > (freq / (1 + this.state.currentSector * 0.5))) {
      const active = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
      const source = active[Math.floor(Math.random() * active.length)];
      this.spawnEnemyAt(source ? source.x : -999, source ? source.y : -999, 'bug');
      this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { 
      p.x += p.vx; p.y += p.vy; p.life -= 0.04; return p.life > 0; 
    });
    this.state.ripples = this.state.ripples.filter(r => { r.radius += 35; r.life -= 0.03; return r.life > 0; });
    if (this.frameCount % 5 === 0) this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const x = this.canvas.width/2 + (Math.random()-0.5)*8000;
    const y = this.canvas.height/2 + (Math.random()-0.5)*8000;
    const hp = 80000 * Math.pow(1.6, (this.state.level / 5)) * Math.pow(3.0, this.state.currentSector);
    this.state.enemies.push({ id: Math.random().toString(36), x, y, hp: Math.min(MAX_VAL, hp), maxHp: Math.min(MAX_VAL, hp), speed: 2.0, value: 5000000, type: 'boss', size: 1000, angle: 0 });
  }

  private spawnEnemyAt(sx: number, sy: number, type: Enemy['type']) {
    if (this.state.enemies.length > 80) return;
    const x = sx === -999 ? this.canvas.width/2 + 3000 : sx + (Math.random()-0.5)*500;
    const y = sy === -999 ? this.canvas.height/2 + 3000 : sy + (Math.random()-0.5)*500;
    let hp = 500 * Math.pow(1.2, this.state.level) * Math.pow(2.0, this.state.currentSector);
    this.state.enemies.push({ id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 2.5, value: hp * 5, type, size: 120, angle: 0 });
  }

  private loadPermanentUpgrades() {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) try { this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...JSON.parse(saved) }; } catch(e){}
  }

  private savePermanentUpgrades() { localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades)); }

  private refreshSkillShop() {
    const pool = ALL_SKILLS.filter(s => !s.oneTime || !this.state.unlockedSkills.includes(s.id));
    this.state.availableSkills = [...pool].sort(() => 0.5 - Math.random()).slice(0, 3).map(s => s.id);
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
      this.state.code -= this.state.rerollCost; this.state.rerollCost = Math.floor(this.state.rerollCost * 1.5);
      this.refreshSkillShop(); this.onUpdate({ ...this.state }); return true;
    }
    return false;
  }

  private resize() { this.canvas.width = window.innerWidth; this.canvas.height = window.innerHeight; }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    if (this.state.permanentUpgrades.legacyPoints >= 100) {
      this.state.permanentUpgrades.legacyPoints -= 100;
      if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 1000000;
      if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 6.0;
      if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 8.0;
      this.savePermanentUpgrades(); this.onUpdate({ ...this.state }); return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i = 0; i < count; i++) this.state.particles.push({ x, y, vx: (Math.random()-0.5)*50, vy: (Math.random()-0.5)*50, size: Math.random()*15+8, life: 1.0, color });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: 0, vy: -10, size: 64, life: 3.0, color, text });
  }

  public applySkill(skillId: string, onUnlock: (s: GameState) => void) {
    const s = ALL_SKILLS.find(x => x.id === skillId) || TECH_TREE.find(x => x.id === skillId);
    if (s && this.state.skillPoints >= s.cost) {
        this.state.skillPoints -= s.cost;
        if (skillId.startsWith('tech_')) this.state.unlockedTech.push(skillId);
        else this.state.unlockedSkills.push(skillId);
        if (skillId === 'auto_collect') this.hasAutoCollect = true;
        onUnlock(this.state);
        this.refreshSkillShop();
        this.onUpdate({ ...this.state });
        return true;
    }
    return false;
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(state: GameState, dt: number, cameraScale: number, auto: boolean, onLv: () => void): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const cx = window.innerWidth / 2; const cy = window.innerHeight / 2;
    const vMult = Math.pow(3, state.permanentUpgrades.version - 1);

    // 1. Massive Passive Growth
    state.code = Math.min(MAX_VAL, state.code + (100 + state.level * 20) * (dt/1000) * vMult * Math.pow(2.5, state.currentSector));

    // 2. Units (Armada Logic)
    state.enemies.forEach(e => {
        const dx = e.isFriendly ? 0 : cx - e.x;
        const dy = e.isFriendly ? 0 : cy - e.y;

        if (e.isFriendly) {
            const targets = state.planets.filter(p => !p.isCaptured);
            if (targets.length > 0) {
                const t = targets[0];
                const dX = t.x - e.x; const dY = t.y - e.y; const dist = Math.sqrt(dX*dX + dY*dY);
                if (dist < 500) { t.hp -= e.hp * 0.1; e.hp -= 100; if (t.hp <= 0) this.capturePlanet(state, t, onLv); }
                e.x += (dX/dist) * e.speed * 4; e.y += (dY/dist) * e.speed * 4; e.angle = Math.atan2(dY, dX);
            }
        } else {
            const dist = Math.sqrt(dx*dx + dy*dy);
            if (dist < 150) { state.coreHp -= 200; e.hp = -1; if (state.coreHp <= 0) state.isGameOver = true; }
            e.x += (dx/dist) * e.speed; e.y += (dy/dist) * e.speed; e.angle = Math.atan2(dy, dx);
        }
    });
    state.enemies = state.enemies.filter(e => e.hp > 0);

    // 3. Drops (Vacuum)
    state.drops = state.drops.filter(d => {
        d.life -= 0.003;
        const dist = Math.sqrt((cx - d.x)**2 + (cy - d.y)**2);
        if (dist < 300 / cameraScale) { this.collectDrop(state, d); return false; }
        if (auto || dist < 15000) {
            const dirX = cx - d.x; const dirY = cy - d.y; const dM = Math.sqrt(dirX*dirX + dirY*dirY);
            d.x += (dirX/dM) * 150; d.y += (dirY/dM) * 150;
        }
        return d.life > 0;
    });
  }

  public static handleClick(state: GameState, x: number, y: number, scale: number, onCol: (d: any)=>void, onHit: (e: any)=>void, onLv: ()=>void): boolean {
    const splash = (400 + state.level * 10) / Math.pow(scale, 0.5);
    let hit = false;
    state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const d = Math.sqrt((e.x - x)**2 + (e.y - y)**2);
        if (d < splash) {
            e.hp -= state.clickPower * (1 - d/splash); e.lastHit = Date.now(); hit = true; onHit(e);
            if (e.hp <= 0) { this.processEnemyDeath(state, e, true); this.checkLevelUp(state, onLv); }
        }
    });
    return hit;
  }

  public static updateTowers(state: GameState, onFire: (t: any, tar: any)=>void, onLv: ()=>void): void {
    const now = Date.now();
    const rScale = Math.pow(2.2, state.currentSector);
    state.towers.forEach(t => {
        const range = t.range * state.towerModifiers.rangeMult * rScale;
        if (now - t.lastFired > t.fireRate * state.towerModifiers.fireRateMult) {
            let tar = state.enemies.find(e => !e.isFriendly && Math.sqrt((e.x - t.x)**2 + (e.y - t.y)**2) < range);
            if (!tar) tar = state.planets.find(p => !p.isCaptured && Math.sqrt((p.x - t.x)**2 + (p.y - t.y)**2) < range) as any;

            if (tar) {
                tar.hp -= t.damage * state.towerModifiers.damageMult;
                state.code = Math.min(MAX_VAL, state.code + 50);
                onFire(t, tar);
                if (tar.hp <= 0) {
                    if ('isCaptured' in tar) this.capturePlanet(state, tar as any, onLv);
                    else { this.processEnemyDeath(state, tar as any, false); this.checkLevelUp(state, onLv); }
                }
                t.lastFired = now;
            }
        }
    });
  }

  private static capturePlanet(state: GameState, p: Planet, onLv: ()=>void) {
    p.isCaptured = true; p.color = COLORS.PRIMARY;
    state.experience += 200000 * Math.pow(3.5, p.sector); this.checkLevelUp(state, onLv);
  }

  public static collectDrop(state: GameState, d: LibraryDrop) {
    if (d.type === 'shard') { state.spProgress += 15; if (state.spProgress >= state.spGoal) { state.skillPoints += 10; state.spProgress = 0; state.spGoal = Math.floor(state.spGoal * 1.2); } }
    else state.code = Math.min(MAX_VAL, state.code + 20000);
  }

  public static processEnemyDeath(state: GameState, e: Enemy, manual: boolean) {
    state.experience += (e.value / 4) * state.permanentUpgrades.xpMultiplier;
    state.code = Math.min(MAX_VAL, state.code + e.value * state.permanentUpgrades.version);
    state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP', x: e.x, y: e.y, life: 7.0 });
  }

  public static checkLevelUp(state: GameState, onLv: ()=>void) {
    const req = 500 + (state.level * 600);
    if (state.experience >= req) { state.level++; state.experience -= req; state.skillPoints += 10; state.clickPower *= 1.3; onLv(); }
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(state: GameState, dt: number, cameraScale: number, auto: boolean, onLv: () => void): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const cx = window.innerWidth / 2; const cy = window.innerHeight / 2;
    const vMult = Math.pow(3, state.permanentUpgrades.version - 1);

    // 1. Balanced Passive Growth
    const passiveBase = (50 + state.level * 10) * (dt/1000) * vMult * Math.pow(2.0, state.currentSector);
    state.code = Math.min(MAX_VAL, state.code + passiveBase);

    // 2. Optimized Unit Armada Logic
    state.enemies.forEach(e => {
        if (e.isFriendly) {
            const targets = state.planets.filter(p => !p.isCaptured);
            if (targets.length > 0) {
                const t = targets[0];
                const dX = t.x - e.x; const dY = t.y - e.y; 
                const dist = Math.sqrt(dX*dX + dY*dY) || 1;
                if (dist < 500) { 
                    t.hp -= e.hp * 0.05; 
                    e.hp -= 50; 
                    if (t.hp <= 0) this.capturePlanet(state, t, onLv); 
                }
                e.x += (dX/dist) * e.speed * 3; 
                e.y += (dY/dist) * e.speed * 3; 
                e.angle = Math.atan2(dY, dX);
            }
        } else {
            const dx = cx - e.x; const dy = cy - e.y;
            const dist = Math.sqrt(dx*dx + dy*dy) || 1;
            if (dist < 150) { 
                state.coreHp -= (e.type === 'boss' ? 1000 : 100); 
                e.hp = -1; 
                if (state.coreHp <= 0) state.isGameOver = true; 
            } else {
                e.x += (dx/dist) * e.speed; 
                e.y += (dy/dist) * e.speed; 
                e.angle = Math.atan2(dy, dx);
            }
        }
    });
    state.enemies = state.enemies.filter(e => e.hp > 0);

    // 3. Drop Collection (Vacuum Scaling)
    state.drops = state.drops.filter(d => {
        d.life -= 0.003;
        const dx = cx - d.x; const dy = cy - d.y;
        const dist = Math.sqrt(dx*dx + dy*dy) || 1;
        const collectRadius = 300 / cameraScale;
        if (dist < collectRadius) { this.collectDrop(state, d); return false; }
        if (auto || dist < 5000) {
            d.x += (dx/dist) * 120; 
            d.y += (dy/dist) * 120;
        }
        return d.life > 0;
    });
  }

  public static handleClick(state: GameState, x: number, y: number, scale: number, onHit: (e: any)=>void, onLv: ()=>void): boolean {
    const splash = (300 + state.level * 5) / Math.pow(scale, 0.4);
    let hit = false;
    state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const d = Math.sqrt((e.x - x)**2 + (e.y - y)**2);
        if (d < splash) {
            const damage = state.clickPower * (1 - d/splash);
            e.hp -= damage; 
            e.lastHit = Date.now(); 
            hit = true; 
            onHit(e);
            if (e.hp <= 0) { 
                this.processEnemyDeath(state, e, true); 
                this.checkLevelUp(state, onLv); 
            }
        }
    });
    return hit;
  }

  public static updateTowers(state: GameState, onFire: (t: any, tar: any)=>void, onLv: ()=>void): void {
    const now = Date.now();
    const rScale = Math.pow(1.8, state.currentSector);
    state.towers.forEach(t => {
        const range = t.range * state.towerModifiers.rangeMult * rScale;
        if (now - t.lastFired > t.fireRate * state.towerModifiers.fireRateMult) {
            // Priority targeting: Enemies first
            let tar = state.enemies.find(e => !e.isFriendly && Math.sqrt((e.x - t.x)**2 + (e.y - t.y)**2) < range);
            if (!tar) tar = state.planets.find(p => !p.isCaptured && Math.sqrt((p.x - t.x)**2 + (p.y - t.y)**2) < range) as any;

            if (tar) {
                tar.hp -= t.damage * state.towerModifiers.damageMult;
                state.code = Math.min(MAX_VAL, state.code + (t.damage * 0.1));
                onFire(t, tar);
                if (tar.hp <= 0) {
                    if ('isCaptured' in tar) this.capturePlanet(state, tar as any, onLv);
                    else { this.processEnemyDeath(state, tar as any, false); this.checkLevelUp(state, onLv); }
                }
                t.lastFired = now;
            }
        }
    });
  }

  private static capturePlanet(state: GameState, p: Planet, onLv: ()=>void) {
    p.isCaptured = true; p.color = COLORS.PRIMARY;
    state.experience += 100000 * Math.pow(3, p.sector); 
    this.checkLevelUp(state, onLv);
  }

  public static collectDrop(state: GameState, d: LibraryDrop) {
    if (d.type === 'shard') { 
        state.spProgress += 10; 
        if (state.spProgress >= state.spGoal) { 
            state.skillPoints += 5; 
            state.spProgress = 0; 
            state.spGoal = Math.floor(state.spGoal * 1.15) + 2; 
        } 
    } else {
        state.code = Math.min(MAX_VAL, state.code + (1000 + state.level * 100));
    }
  }

  public static processEnemyDeath(state: GameState, e: Enemy, manual: boolean) {
    state.experience += (e.value / 5) * state.permanentUpgrades.xpMultiplier;
    state.code = Math.min(MAX_VAL, state.code + e.value * 0.5 * state.permanentUpgrades.version);
    state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', effect: 'SP', x: e.x, y: e.y, life: 6.0 });
  }

  public static checkLevelUp(state: GameState, onLv: ()=>void) {
    const req = 500 + (state.level * 500);
    if (state.experience >= req) { 
        state.level++; 
        state.experience -= req; 
        state.skillPoints += 5; 
        state.clickPower *= 1.2; 
        onLv(); 
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_v3';
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    window.addEventListener('resize', this.resize.bind(this));
    this.resize();
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) { this.isPaused = paused; }
  public destroy() { this.isDestroyed = true; audio.stop(); }

  private getInitialState(): GameState {
    return {
      code: 1000, experience: 0, level: 1, skillPoints: 5, spProgress: 0, spGoal: 20,
      clickPower: 50, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: 50, combo: 0,
      threatLevel: 0.5, coreHp: 1000, maxCoreHp: 1000, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 3000 + (sector * 5000); 
    const count = 3 + sector;
    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 1.5);
      const hp = (10000 + (this.state.level * 500)) * Math.pow(3, sector);
      this.state.planets.push({
        id: `p_${sector}_${i}`, 
        name: `NODE_0x${sector}${i}`,
        x: this.canvas.width/2 + Math.cos(angle) * dist,
        y: this.canvas.height/2 + Math.sin(angle) * dist,
        hp, maxHp: hp, isCaptured: false, size: 600 + (sector * 200), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;
    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();
    this.state.permanentUpgrades.legacyPoints += Math.floor(Math.log10(this.state.code + 1) * 10);
    this.state.permanentUpgrades.version++;
    await new Promise(r => setTimeout(r, 1500));
    this.state.isCompiling = false;
    this.reset();
  }

  public reset() {
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1000 + perms.startingCode;
    this.state.clickPower = 50 * perms.damageMultiplier;
    this.generatePlanets(0);
    this.onUpdate({ ...this.state });
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number): boolean {
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;
    const config = TOWER_TYPES[type];
    const tCount = this.state.towers.filter(t => t.type === type).length;
    const cost = Math.floor(config.cost * Math.pow(1.1, tCount));

    if (this.state.code >= cost && (!config.requires || this.state.unlockedTech.includes(config.requires))) {
      this.state.code -= cost;
      this.state.towers.push({ id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY, range: config.range, damage: config.damage, fireRate: config.fireRate, lastFired: 0, color: config.color });
      audio.playClick();
      return true;
    }
    return false;
  }

  public handleClick(rawX: number, rawY: number, wasPlacement: boolean) {
    if (this.state.isGameOver || this.isPaused || this.state.isCompiling) return;
    audio.enable();
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;

    // If we just placed a tower, do not trigger click rewards or splash
    if (wasPlacement) return;

    const hit = LogicHandler.handleClick(this.state, worldX, worldY, this.cameraScale, (e) => {
        this.createParticles(e.x, e.y, 10, COLORS.PRIMARY);
        audio.playClick();
    }, () => this.onLevelUp());

    if (!hit) {
      const reward = (50 + (this.state.level * 10)) * (1 + this.state.currentSector);
      state.code = Math.min(MAX_VAL, state.code + reward);
      this.createFloatingText(worldX, worldY, `+${Math.floor(reward)}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    const uncaptured = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncaptured.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
    }
    if (this.state.level % 5 === 0) this.spawnBoss();
    this.refreshSkillShop();
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;
    if (!this.isPaused && !this.state.isCompiling) this.update(dt);
    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  }

  private update(dt: number) {
    // 1. Dynamic Galactic Bounding Box
    let bounds = { minX: this.canvas.width/2 - 1000, maxX: this.canvas.width/2 + 1000, minY: this.canvas.height/2 - 1000, maxY: this.canvas.height/2 + 1000 };
    this.state.planets.forEach(p => {
        if (p.sector <= this.state.currentSector + 1) {
            bounds.minX = Math.min(bounds.minX, p.x); bounds.maxX = Math.max(bounds.maxX, p.x);
            bounds.minY = Math.min(bounds.minY, p.y); bounds.maxY = Math.max(bounds.maxY, p.y);
        }
    });
    const viewW = bounds.maxX - bounds.minX;
    const viewH = bounds.maxY - bounds.minY;
    const scaleX = this.canvas.width / (viewW * 1.3);
    const scaleY = this.canvas.height / (viewH * 1.3);

    // Snappy Camera Interpolation
    this.targetCameraScale = Math.min(scaleX, scaleY, 1.0);
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, (t, tar) => {
        this.renderer.addFiringEffect(t.x, t.y, tar.x, tar.y, t.color, t.type);
        audio.playFire(t.type);
    }, () => this.onLevelUp());

    this.enemySpawnTimer += dt;
    if (this.enemySpawnTimer > 1500 / (1 + this.state.currentSector * 0.5)) {
        const active = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
        const s = active[Math.floor(Math.random() * active.length)];
        this.spawnEnemyAt(s ? s.x : -999, s ? s.y : -999);
        this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { p.x += p.vx; p.y += p.vy; p.life -= 0.04; return p.life > 0; });
    if (this.frameCount % 5 === 0) this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const x = this.canvas.width/2 + (Math.random()-0.5)*5000;
    const y = this.canvas.height/2 + (Math.random()-0.5)*5000;
    this.state.enemies.push({ id: Math.random().toString(36), x, y, hp: 50000 * Math.pow(2, this.state.currentSector), maxHp: 50000, speed: 1.5, value: 10000, type: 'boss', size: 800, angle: 0 });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    if (this.state.enemies.length > 60) return;
    const x = sx === -999 ? this.canvas.width/2 + 2000 : sx + (Math.random()-0.5)*400;
    const y = sy === -999 ? this.canvas.height/2 + 2000 : sy + (Math.random()-0.5)*400;
    const hp = 200 * Math.pow(1.2, this.state.level);
    this.state.enemies.push({ id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 2, value: hp, type: 'bug', size: 100, angle: 0 });
  }

  private resize() { this.canvas.width = window.innerWidth; this.canvas.height = window.innerHeight; }
  private loadPermanentUpgrades() { const s = localStorage.getItem(STORAGE_KEY); if (s) try { this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...JSON.parse(s) }; } catch(e){} }
  private savePermanentUpgrades() { localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades)); }
  private refreshSkillShop() { this.state.availableSkills = [...ALL_SKILLS].sort(()=>0.5-Math.random()).slice(0,3).map(s=>s.id); }

  public applySkill(id: string, cb: (s: any)=>void) {
    const s = ALL_SKILLS.find(x=>x.id===id) || TECH_TREE.find(x=>x.id===id);
    if (s && this.state.skillPoints >= s.cost) {
        this.state.skillPoints -= s.cost;
        if (id.startsWith('tech_')) this.state.unlockedTech.push(id); else this.state.unlockedSkills.push(id);
        if (id === 'auto_collect') this.hasAutoCollect = true;
        cb(this.state); this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
        this.state.code -= this.state.rerollCost; this.state.rerollCost = Math.floor(this.state.rerollCost * 1.3);
        this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    if (this.state.permanentUpgrades.legacyPoints >= 100) {
        this.state.permanentUpgrades.legacyPoints -= 100;
        if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 5000;
        if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 2.0;
        if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 2.0;
        this.savePermanentUpgrades(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i=0; i<count; i++) this.state.particles.push({ x, y, vx: (Math.random()-0.5)*30, vy: (Math.random()-0.5)*30, size: Math.random()*10+5, life: 1.0, color });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: 0, vy: -5, size: 40, life: 2.0, color, text });
  }
}

import React, { useEffect, useRef, useState } from 'react';
import { GameEngine } from './engine/GameEngine';
import { GameState, PermanentUpgrades } from './types';
import UIOverlay from './components/UIOverlay';
import SkillTree from './components/SkillTree';
import { TOWER_TYPES } from './constants';
import { Target } from 'lucide-react';
import { audio } from './engine/AudioManager';

const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<GameEngine | null>(null);
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [isSkillTreeOpen, setIsSkillTreeOpen] = useState(false);
  const [buildingType, setBuildingType] = useState<keyof typeof TOWER_TYPES | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;
    const engine = new GameEngine(canvasRef.current, (state) => setGameState(state));
    engineRef.current = engine;
    return () => engineRef.current?.destroy();
  }, []);

  useEffect(() => {
    engineRef.current?.setPaused(isSkillTreeOpen);
  }, [isSkillTreeOpen]);

  const handleClick = (e: React.MouseEvent) => {
    audio.enable();
    if (!engineRef.current || isSkillTreeOpen || gameState?.isGameOver || gameState?.isCompiling) return;

    const rect = canvasRef.current!.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    let wasPlacement = false;
    if (buildingType) {
      wasPlacement = engineRef.current.buyTower(buildingType, x, y);
      if (wasPlacement) setBuildingType(null); // Auto-dismiss builder after placement
    }

    engineRef.current.handleClick(x, y, wasPlacement);
  };

  const handleUpgrade = (skillId: string) => {
    engineRef.current?.applySkill(skillId, (s) => {
      if (skillId === 'click_1') s.clickPower *= 2.0; 
      if (skillId === 'massive_click') s.clickPower *= 5.0; 
      if (skillId === 'tower_range_1') s.towerModifiers.rangeMult *= 1.2; 
      if (skillId === 'tower_dmg_1') s.towerModifiers.damageMult *= 1.5; 
      if (skillId === 'tech_god') { s.clickPower *= 5; s.towerModifiers.damageMult *= 5; }
    });
  };

  return (
    <div className="relative w-screen h-screen bg-slate-950 overflow-hidden select-none cursor-crosshair">
      <canvas ref={canvasRef} onClick={handleClick} className="block w-full h-full" />
      {gameState && (
        <>
          <UIOverlay 
            state={gameState} 
            activeBuildingType={buildingType}
            onBuildTower={(t) => setBuildingType(buildingType === t ? null : t)}
            onOpenSkills={() => setIsSkillTreeOpen(true)}
            onRestart={() => engineRef.current?.reset()}
            onBuyPermanent={(p) => engineRef.current?.buyPermanentUpgrade(p)}
            onShipToProduction={() => engineRef.current?.shipToProduction()}
          />
          <SkillTree 
            state={gameState}
            isOpen={isSkillTreeOpen}
            onClose={() => setIsSkillTreeOpen(false)}
            onUpgrade={handleUpgrade}
            onReroll={() => engineRef.current?.rerollSkills()}
          />
        </>
      )}
      {buildingType && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-sky-500 text-slate-900 px-6 py-2 rounded-full font-bold shadow-lg animate-bounce pointer-events-auto z-40 flex items-center gap-2 cursor-pointer" onClick={() => setBuildingType(null)}>
          <Target className="w-5 h-5" /> PLACING {TOWER_TYPES[buildingType].name} (TAP TO CANCEL)
        </div>
      )}
      <div className="fixed inset-0 pointer-events-none opacity-30 bg-[radial-gradient(circle_at_center,_transparent_0%,_#020617_100%)]" />
    </div>
  );
};

export default App;

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_v3';
const MAX_VAL = 1e300;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    window.addEventListener('resize', this.resize.bind(this));
    this.resize();
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) { this.isPaused = paused; }
  public destroy() { this.isDestroyed = true; audio.stop(); }

  private getInitialState(): GameState {
    return {
      code: 1000, experience: 0, level: 1, skillPoints: 5, spProgress: 0, spGoal: 20,
      clickPower: 50, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: 50, combo: 0,
      threatLevel: 0.5, coreHp: 1000, maxCoreHp: 1000, currentSector: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 3000 + (sector * 5000); 
    const count = 3 + sector;
    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 1.5);
      const hp = (10000 + (this.state.level * 500)) * Math.pow(3, sector);
      this.state.planets.push({
        id: `p_${sector}_${i}`, 
        name: `NODE_0x${sector}${i}`,
        x: this.canvas.width/2 + Math.cos(angle) * dist,
        y: this.canvas.height/2 + Math.sin(angle) * dist,
        hp, maxHp: hp, isCaptured: false, size: 600 + (sector * 200), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public async shipToProduction() {
    if (this.state.level < 50) return;
    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();
    this.state.permanentUpgrades.legacyPoints += Math.floor(Math.log10(this.state.code + 1) * 10);
    this.state.permanentUpgrades.version++;
    await new Promise(r => setTimeout(r, 1500));
    this.state.isCompiling = false;
    this.reset();
  }

  public reset() {
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.state.code = 1000 + perms.startingCode;
    this.state.clickPower = 50 * perms.damageMultiplier;
    this.generatePlanets(0);
    this.onUpdate({ ...this.state });
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number): boolean {
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;
    const config = TOWER_TYPES[type];
    const tCount = this.state.towers.filter(t => t.type === type).length;
    const cost = Math.floor(config.cost * Math.pow(1.1, tCount));

    if (this.state.code >= cost && (!config.requires || this.state.unlockedTech.includes(config.requires))) {
      this.state.code -= cost;
      this.state.towers.push({ id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY, range: config.range, damage: config.damage, fireRate: config.fireRate, lastFired: 0, color: config.color });
      audio.playClick();
      return true;
    }
    return false;
  }

  public handleClick(rawX: number, rawY: number, wasPlacement: boolean) {
    if (this.state.isGameOver || this.isPaused || this.state.isCompiling) return;
    audio.enable();
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;

    // If we just placed a tower, do not trigger click rewards or splash
    if (wasPlacement) return;

    const hit = LogicHandler.handleClick(this.state, worldX, worldY, this.cameraScale, (e) => {
        this.createParticles(e.x, e.y, 10, COLORS.PRIMARY);
        audio.playClick();
    }, () => this.onLevelUp());

    if (!hit) {
      const reward = (50 + (this.state.level * 10)) * (1 + this.state.currentSector);
      // Fixed: 'state' changed to 'this.state' below
      this.state.code = Math.min(MAX_VAL, this.state.code + reward);
      this.createFloatingText(worldX, worldY, `+${Math.floor(reward)}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    const uncaptured = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncaptured.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
    }
    if (this.state.level % 5 === 0) this.spawnBoss();
    this.refreshSkillShop();
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;
    if (!this.isPaused && !this.state.isCompiling) this.update(dt);
    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  }

  private update(dt: number) {
    // 1. Dynamic Galactic Bounding Box
    let bounds = { minX: this.canvas.width/2 - 1000, maxX: this.canvas.width/2 + 1000, minY: this.canvas.height/2 - 1000, maxY: this.canvas.height/2 + 1000 };
    this.state.planets.forEach(p => {
        if (p.sector <= this.state.currentSector + 1) {
            bounds.minX = Math.min(bounds.minX, p.x); bounds.maxX = Math.max(bounds.maxX, p.x);
            bounds.minY = Math.min(bounds.minY, p.y); bounds.maxY = Math.max(bounds.maxY, p.y);
        }
    });
    const viewW = bounds.maxX - bounds.minX;
    const viewH = bounds.maxY - bounds.minY;
    const scaleX = this.canvas.width / (viewW * 1.3);
    const scaleY = this.canvas.height / (viewH * 1.3);

    // Snappy Camera Interpolation
    this.targetCameraScale = Math.min(scaleX, scaleY, 1.0);
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, (t, tar) => {
        this.renderer.addFiringEffect(t.x, t.y, tar.x, tar.y, t.color, t.type);
        audio.playFire(t.type);
    }, () => this.onLevelUp());

    this.enemySpawnTimer += dt;
    if (this.enemySpawnTimer > 1500 / (1 + this.state.currentSector * 0.5)) {
        const active = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
        const s = active[Math.floor(Math.random() * active.length)];
        this.spawnEnemyAt(s ? s.x : -999, s ? s.y : -999);
        this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { p.x += p.vx; p.y += p.vy; p.life -= 0.04; return p.life > 0; });
    if (this.frameCount % 5 === 0) this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const x = this.canvas.width/2 + (Math.random()-0.5)*5000;
    const y = this.canvas.height/2 + (Math.random()-0.5)*5000;
    this.state.enemies.push({ id: Math.random().toString(36), x, y, hp: 50000 * Math.pow(2, this.state.currentSector), maxHp: 50000, speed: 1.5, value: 10000, type: 'boss', size: 800, angle: 0 });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    if (this.state.enemies.length > 60) return;
    const x = sx === -999 ? this.canvas.width/2 + 2000 : sx + (Math.random()-0.5)*400;
    const y = sy === -999 ? this.canvas.height/2 + 2000 : sy + (Math.random()-0.5)*400;
    const hp = 200 * Math.pow(1.2, this.state.level);
    this.state.enemies.push({ id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 2, value: hp, type: 'bug', size: 100, angle: 0 });
  }

  private resize() { this.canvas.width = window.innerWidth; this.canvas.height = window.innerHeight; }
  private loadPermanentUpgrades() { const s = localStorage.getItem(STORAGE_KEY); if (s) try { this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...JSON.parse(s) }; } catch(e){} }
  private savePermanentUpgrades() { localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades)); }
  private refreshSkillShop() { this.state.availableSkills = [...ALL_SKILLS].sort(()=>0.5-Math.random()).slice(0,3).map(s=>s.id); }

  public applySkill(id: string, cb: (s: any)=>void) {
    const s = ALL_SKILLS.find(x=>x.id===id) || TECH_TREE.find(x=>x.id===id);
    if (s && this.state.skillPoints >= s.cost) {
        this.state.skillPoints -= s.cost;
        if (id.startsWith('tech_')) this.state.unlockedTech.push(id); else this.state.unlockedSkills.push(id);
        if (id === 'auto_collect') this.hasAutoCollect = true;
        cb(this.state); this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
        this.state.code -= this.state.rerollCost; this.state.rerollCost = Math.floor(this.state.rerollCost * 1.3);
        this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    if (this.state.permanentUpgrades.legacyPoints >= 100) {
        this.state.permanentUpgrades.legacyPoints -= 100;
        if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 5000;
        if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 2.0;
        if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 2.0;
        this.savePermanentUpgrades(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i=0; i<count; i++) this.state.particles.push({ x, y, vx: (Math.random()-0.5)*30, vy: (Math.random()-0.5)*30, size: Math.random()*10+5, life: 1.0, color });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: 0, vy: -5, size: 40, life: 2.0, color, text });
  }
}

