import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_v4_stable';
const MAX_VAL = 1e308;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    window.addEventListener('resize', this.resize.bind(this));
    this.resize();
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) { this.isPaused = paused; }
  public destroy() { this.isDestroyed = true; audio.stop(); }

  private getInitialState(): GameState {
    return {
      code: 1000, experience: 0, level: 1, skillPoints: 5, spProgress: 0, spGoal: 20,
      clickPower: 50, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: 50, combo: 0,
      threatLevel: 0.5, coreHp: 1000, maxCoreHp: 1000, currentSector: 0,
      buildProgress: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 3500 + (sector * 6000); 
    const count = 3 + sector;
    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 1.8);
      const versionMult = Math.pow(10, this.state.permanentUpgrades.version - 1);
      const hp = (15000 + (this.state.level * 800)) * Math.pow(3.5, sector) * versionMult;
      this.state.planets.push({
        id: `p_${sector}_${i}`, 
        name: `NODE_0x${sector}${i}`,
        x: this.canvas.width/2 + Math.cos(angle) * dist,
        y: this.canvas.height/2 + Math.sin(angle) * dist,
        hp, maxHp: hp, isCaptured: false, size: 700 + (sector * 250), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public async shipToProduction() {
    if (this.state.buildProgress < 100) return;
    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    // Massive Legacy Gain
    const legacyGain = Math.max(10, Math.floor(Math.log10(this.state.code + 1) * this.state.level));
    this.state.permanentUpgrades.legacyPoints += legacyGain;
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 1800));
    this.state.isCompiling = false;
    this.reset();
  }

  public reset() {
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    // Scale starting resources based on Version
    const vMult = Math.pow(8, perms.version - 1);
    this.state.code = (1000 + perms.startingCode) * vMult;
    this.state.clickPower = 50 * perms.damageMultiplier * vMult;

    this.generatePlanets(0);
    this.onUpdate({ ...this.state });
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number): boolean {
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;
    const config = TOWER_TYPES[type];
    const tCount = this.state.towers.filter(t => t.type === type).length;
    const cost = Math.floor(config.cost * Math.pow(1.12, tCount));

    if (this.state.code >= cost && (!config.requires || this.state.unlockedTech.includes(config.requires))) {
      this.state.code -= cost;
      this.state.towers.push({ 
        id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY, 
        range: config.range, damage: config.damage, fireRate: config.fireRate, 
        lastFired: 0, color: config.color 
      });
      audio.playClick();
      return true;
    }
    return false;
  }

  public handleClick(rawX: number, rawY: number, wasPlacement: boolean) {
    if (this.state.isGameOver || this.isPaused || this.state.isCompiling) return;
    audio.enable();
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;

    if (wasPlacement) return;

    const hit = LogicHandler.handleClick(this.state, worldX, worldY, this.cameraScale, (e) => {
        this.createParticles(e.x, e.y, 12, COLORS.PRIMARY);
        audio.playClick();
        // Clicks boost build progress
        this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.1);
    }, () => this.onLevelUp());

    if (!hit) {
      const vMult = Math.pow(4, this.state.permanentUpgrades.version - 1);
      const reward = (100 + (this.state.level * 25)) * (1 + this.state.currentSector) * vMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + reward);
      this.createFloatingText(worldX, worldY, `+${Math.floor(reward)}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    const uncaptured = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncaptured.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 15); // Big boost for clearing sector
    }
    if (this.state.level % 5 === 0) this.spawnBoss();
    this.refreshSkillShop();
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;
    if (!this.isPaused && !this.state.isCompiling) this.update(dt);
    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  }

  private update(dt: number) {
    // 1. Dynamic Galactic Bounding Box
    let bounds = { 
      minX: this.canvas.width/2 - 2000, maxX: this.canvas.width/2 + 2000, 
      minY: this.canvas.height/2 - 2000, maxY: this.canvas.height/2 + 2000 
    };

    this.state.planets.forEach(p => {
        if (p.sector <= this.state.currentSector + 1) {
            bounds.minX = Math.min(bounds.minX, p.x); bounds.maxX = Math.max(bounds.maxX, p.x);
            bounds.minY = Math.min(bounds.minY, p.y); bounds.maxY = Math.max(bounds.maxY, p.y);
        }
    });

    // Also zoom for enemies at the edge
    this.state.enemies.forEach(e => {
        bounds.minX = Math.min(bounds.minX, e.x); bounds.maxX = Math.max(bounds.maxX, e.x);
        bounds.minY = Math.min(bounds.minY, e.y); bounds.maxY = Math.max(bounds.maxY, e.y);
    });

    const viewW = bounds.maxX - bounds.minX;
    const viewH = bounds.maxY - bounds.minY;
    const scaleX = this.canvas.width / (viewW * 1.4);
    const scaleY = this.canvas.height / (viewH * 1.4);

    this.targetCameraScale = Math.min(scaleX, scaleY, 1.0);
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.08;

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, (t, tar) => {
        this.renderer.addFiringEffect(t.x, t.y, tar.x, tar.y, t.color, t.type);
        audio.playFire(t.type);
        // Defense boosts build progress slowly
        this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.001);
    }, () => this.onLevelUp());

    this.enemySpawnTimer += dt;
    if (this.enemySpawnTimer > 1800 / (1 + this.state.currentSector * 0.5)) {
        const active = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
        const s = active[Math.floor(Math.random() * active.length)];
        this.spawnEnemyAt(s ? s.x : -999, s ? s.y : -999);
        this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { 
        p.x += p.vx; p.y += p.vy; p.life -= 0.04; return p.life > 0; 
    });

    if (this.frameCount % 5 === 0) this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 6000;
    const x = this.canvas.width/2 + Math.cos(angle) * dist;
    const y = this.canvas.height/2 + Math.sin(angle) * dist;
    const vMult = Math.pow(10, this.state.permanentUpgrades.version - 1);
    const hp = 100000 * Math.pow(2.2, this.state.currentSector) * vMult;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.8, 
        value: hp * 5, type: 'boss', size: 1000, angle: 0 
    });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    if (this.state.enemies.length > 80) return;
    const x = sx === -999 ? this.canvas.width/2 + 3000 : sx + (Math.random()-0.5)*600;
    const y = sy === -999 ? this.canvas.height/2 + 3000 : sy + (Math.random()-0.5)*600;
    const vMult = Math.pow(8, this.state.permanentUpgrades.version - 1);
    const hp = 350 * Math.pow(1.25, this.state.level) * vMult;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 2.2 + (this.state.level * 0.02), 
        value: hp * 2, type: 'bug', size: 120, angle: 0 
    });
  }

  private resize() { this.canvas.width = window.innerWidth; this.canvas.height = window.innerHeight; }
  private loadPermanentUpgrades() { const s = localStorage.getItem(STORAGE_KEY); if (s) try { this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...JSON.parse(s) }; } catch(e){} }
  private savePermanentUpgrades() { localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades)); }
  private refreshSkillShop() { this.state.availableSkills = [...ALL_SKILLS].sort(()=>0.5-Math.random()).slice(0,3).map(s=>s.id); }

  public applySkill(id: string, cb: (s: any)=>void) {
    const s = ALL_SKILLS.find(x=>x.id===id) || TECH_TREE.find(x=>x.id===id);
    if (s && this.state.skillPoints >= s.cost) {
        this.state.skillPoints -= s.cost;
        if (id.startsWith('tech_')) this.state.unlockedTech.push(id); else this.state.unlockedSkills.push(id);
        if (id === 'auto_collect') this.hasAutoCollect = true;
        cb(this.state); this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
        this.state.code -= this.state.rerollCost; this.state.rerollCost = Math.floor(this.state.rerollCost * 1.4);
        this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    if (this.state.permanentUpgrades.legacyPoints >= 100) {
        this.state.permanentUpgrades.legacyPoints -= 100;
        if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 10000;
        if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 3.0;
        if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 3.0;
        this.savePermanentUpgrades(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i=0; i<count; i++) this.state.particles.push({ x, y, vx: (Math.random()-0.5)*40, vy: (Math.random()-0.5)*40, size: Math.random()*12+6, life: 1.0, color });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: 0, vy: -12, size: 50, life: 2.5, color, text });
  }
}

import { GameState, Enemy, Tower, Planet } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 150;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  private drawStarfield(cx: number, cy: number, cameraScale: number) {
    const { canvas } = this.ctx;
    const now = Date.now();
    const layers = [
        { count: 120, size: 1, color: '#1e293b' },
        { count: 60, size: 2, color: '#334155' },
        { count: 30, size: 3, color: '#475569' }
    ];

    layers.forEach(layer => {
        this.ctx.fillStyle = layer.color;
        for (let i = 0; i < layer.count; i++) {
            const x = (Math.sin(i * 157.7) * 0.5 + 0.5) * canvas.width;
            const y = (Math.cos(i * 89.1) * 0.5 + 0.5) * canvas.height;
            this.ctx.beginPath();
            this.ctx.arc(x, y, layer.size, 0, Math.PI * 2);
            this.ctx.fill();
        }
    });
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    // GALAXY-VIEW SCALING
    const perceivedScale = 1 / Math.pow(cameraScale, 0.95); 
    const minPixelSize = cameraScale < 0.15 ? 40 : 15;

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.drawStarfield(cx, cy, cameraScale);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.85;
    }

    // World Space
    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. GALAXY NETWORK
    this.ctx.lineWidth = 5 / cameraScale;
    this.ctx.globalAlpha = 0.08 * perceivedScale;
    state.planets.forEach(p => {
        if (!p.isCaptured && p.sector > state.currentSector) return;
        this.ctx.beginPath();
        this.ctx.moveTo(cx, cy);
        this.ctx.lineTo(p.x, p.y);
        this.ctx.strokeStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
        this.ctx.stroke();

        // Linked Pulse
        const progress = (now * 0.002) % 1;
        const pulseX = cx + (p.x - cx) * progress;
        const pulseY = cy + (p.y - cy) * progress;
        this.ctx.globalAlpha = 0.2;
        this.ctx.fillStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
        this.ctx.beginPath(); this.ctx.arc(pulseX, pulseY, 50 / cameraScale, 0, Math.PI * 2); this.ctx.fill();
        this.ctx.globalAlpha = 0.08 * perceivedScale;
    });
    this.ctx.globalAlpha = 1.0;

    // 2. PLANETS
    state.planets.forEach(p => {
      if (p.sector > state.currentSector + 2) return;

      this.ctx.save();
      this.ctx.translate(p.x, p.y);
      const pDrawSize = Math.max(minPixelSize * 5, p.size * perceivedScale * 0.4);

      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#1e0505';
      this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize, 0, Math.PI * 2); this.ctx.fill();

      if (!p.isCaptured) {
          this.ctx.strokeStyle = COLORS.ENEMY;
          this.ctx.lineWidth = 15 / cameraScale;
          this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 1.2, 0, Math.PI * 2); this.ctx.stroke();
      }

      this.ctx.fillStyle = '#fff';
      this.ctx.font = `bold ${Math.max(150, 400 / cameraScale)}px Space Grotesk`;
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, 0, pDrawSize + (400 / cameraScale));
      this.ctx.restore();
    });

    // 3. THE CORE + BUILD RING
    const coreSize = Math.max(minPixelSize * 12, (350 + (state.level * 1.5)) * perceivedScale * 0.3);

    // BUILD RING (Visual CI/CD Pipeline)
    this.ctx.save();
    this.ctx.translate(cx, cy);
    this.ctx.lineWidth = 40 / cameraScale;
    this.ctx.lineCap = 'round';

    // Background Ring
    this.ctx.strokeStyle = '#1e293b';
    this.ctx.beginPath(); this.ctx.arc(0, 0, coreSize * 1.4, 0, Math.PI * 2); this.ctx.stroke();

    // Progress Ring
    const buildColor = state.buildProgress >= 100 ? '#10b981' : state.buildProgress > 50 ? '#f59e0b' : '#ef4444';
    this.ctx.strokeStyle = buildColor;
    this.ctx.beginPath(); this.ctx.arc(0, 0, coreSize * 1.4, -Math.PI/2, -Math.PI/2 + (Math.PI * 2 * (state.buildProgress/100))); this.ctx.stroke();
    this.ctx.restore();

    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 300 / cameraScale; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 4. COMBAT FX
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = Math.max(25, (ef.type === 'SNIPER' ? 120 : 50) * ef.life / cameraScale);
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.12;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // 5. UNITS
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = now - (e.lastHit || 0) < 100;
      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));
      const uSize = Math.max(minPixelSize, e.size * perceivedScale * 0.35);

      this.ctx.beginPath();
      if (cameraScale < 0.25) {
        this.ctx.moveTo(uSize * 3, 0);
        this.ctx.lineTo(-uSize * 1.5, uSize * 2);
        this.ctx.lineTo(-uSize, 0);
        this.ctx.lineTo(-uSize * 1.5, -uSize * 2);
      } else {
        this.ctx.moveTo(uSize * 1.5, 0);
        this.ctx.lineTo(-uSize, uSize);
        this.ctx.lineTo(-uSize * 0.5, 0);
        this.ctx.lineTo(-uSize, -uSize);
      }
      this.ctx.closePath();
      this.ctx.fill();
      this.ctx.restore();
    });

    // 6. TOWERS
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const tSize = Math.max(minPixelSize * 2.5, 140 * perceivedScale * 0.35);
      this.ctx.fillRect(t.x - tSize, t.y - tSize, tSize * 2, tSize * 2);
    });

    // 7. DROPS
    state.drops.forEach(d => {
      this.ctx.globalAlpha = d.life;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      const s = Math.max(minPixelSize * 2.5, 180 * perceivedScale * 0.15);
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.015);
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return COLORS.BOSS;
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import React from 'react';
import { GameState, PermanentUpgrades } from '../types';
import { TOWER_TYPES, COLORS } from '../constants';
import { Terminal, Cpu, Zap, Code, Shield, Layers, Award, Star, Heart, Rocket, Lock, Database, Send, CheckCircle2 } from 'lucide-react';

interface Props {
  state: GameState;
  activeBuildingType: keyof typeof TOWER_TYPES | null;
  onBuildTower: (type: keyof typeof TOWER_TYPES) => void;
  onOpenSkills: () => void;
  onRestart: () => void;
  onBuyPermanent: (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => void;
  onShipToProduction: () => void;
}

const UIOverlay: React.FC<Props> = ({ state, activeBuildingType, onBuildTower, onOpenSkills, onRestart, onBuyPermanent, onShipToProduction }) => {
  const nextLevelExp = 500 + (state.level * 500);
  const expProgress = (state.experience / nextLevelExp) * 100;
  const coreHpPercent = (state.coreHp / state.maxCoreHp) * 100;
  const buildProgress = state.buildProgress;

  const totalLegacyPool = Math.floor(state.permanentUpgrades.legacyPoints);
  const currentVersion = state.permanentUpgrades.version;

  const formatLarge = (num: number): string => {
    if (num === Infinity || isNaN(num)) return "MAXED";
    if (num < 1000) return num.toFixed(0);
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const suffix = suffixes[tier];
    const scale = Math.pow(10, tier * 3);
    const scaled = num / scale;
    return scaled.toFixed(1) + suffix;
  };

  return (
    <div className="fixed inset-0 pointer-events-none flex flex-col items-center justify-between p-4">

      {/* TOP HUD */}
      <div className="flex flex-col items-center gap-2 pointer-events-auto">
        <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-700/50 rounded-full px-6 py-2 flex items-center gap-8 shadow-2xl relative overflow-hidden">
          {/* Health Bar */}
          <div className="absolute top-0 left-0 h-[3px] bg-red-500/20 w-full">
            <div className="h-full bg-red-500 shadow-[0_0_12px_#ef4444] transition-all duration-500" style={{ width: `${coreHpPercent}%` }} />
          </div>

          <div className="flex items-center gap-2">
            <Code className="text-sky-400 w-4 h-4" />
            <span className="text-white font-black tabular-nums text-sm">
              {formatLarge(state.code)}
            </span>
          </div>

          <div className="flex items-center gap-2 border-x border-slate-700/30 px-8">
            <Database className="text-pink-400 w-4 h-4" />
            <span className="text-white font-black tabular-nums text-sm">
              {state.spProgress.toFixed(0)}<span className="text-slate-500 mx-1">/</span>{state.spGoal}
            </span>
          </div>

          <div className="flex items-center gap-2">
            <Zap className="text-amber-400 w-4 h-4" />
            <span className="text-white font-black text-sm tabular-nums">LV.{state.level}</span>
          </div>

          {/* XP Bar */}
          <div className="absolute bottom-0 left-0 h-[3px] bg-amber-500/10 w-full">
            <div className="h-full bg-amber-400 shadow-[0_0_12px_#fbbf24] transition-all duration-300" style={{ width: `${expProgress}%` }} />
          </div>
        </div>

        <div className="flex gap-4 items-center mt-2">
          {/* BUILD STATUS */}
          <div className="bg-slate-900/80 border border-slate-700 rounded-xl px-4 py-2 flex items-center gap-3">
             <div className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Build Status:</div>
             <div className="w-32 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                <div 
                    className={`h-full transition-all duration-500 ${buildProgress >= 100 ? 'bg-emerald-500' : buildProgress > 50 ? 'bg-amber-500' : 'bg-red-500'}`} 
                    style={{ width: `${buildProgress}%` }} 
                />
             </div>
             <div className={`text-[11px] font-black uppercase ${buildProgress >= 100 ? 'text-emerald-400' : 'text-slate-400'}`}>
                {buildProgress >= 100 ? 'Stable' : `${buildProgress.toFixed(0)}%`}
             </div>
          </div>

          <button 
            onClick={onOpenSkills}
            className="w-12 h-12 bg-slate-900 border border-slate-700 rounded-xl flex items-center justify-center hover:border-pink-500 transition-all shadow-xl group active:scale-95 pointer-events-auto"
          >
            <Cpu className="text-pink-400 w-6 h-6 group-hover:scale-110 transition-transform" />
          </button>

          {buildProgress >= 100 && (
            <button 
                onClick={onShipToProduction}
                className="bg-emerald-500 hover:bg-emerald-400 text-slate-900 px-6 py-2.5 rounded-xl font-black uppercase italic tracking-tighter flex items-center gap-2 shadow-[0_0_30px_rgba(16,185,129,0.3)] transition-all hover:-translate-y-1 active:scale-95 pointer-events-auto animate-bounce"
            >
                <Send className="w-5 h-5" /> Ship v{currentVersion + 1}.0
            </button>
          )}
        </div>
      </div>

      {/* COMPILING OVERLAY */}
      {state.isCompiling && (
          <div className="fixed inset-0 bg-slate-950/95 backdrop-blur-3xl flex flex-col items-center justify-center z-[500] pointer-events-auto">
             <div className="text-emerald-400 font-black text-6xl mb-12 animate-pulse italic uppercase tracking-tighter">Shipping Production Build...</div>
             <div className="flex flex-col gap-4 items-center">
                <div className="text-slate-400 font-mono text-sm uppercase tracking-[0.4em] flex items-center gap-3">
                    <CheckCircle2 className="w-5 h-5" /> Migrating Legacy Data
                </div>
                <div className="text-slate-400 font-mono text-sm uppercase tracking-[0.4em] flex items-center gap-3">
                    <CheckCircle2 className="w-5 h-5" /> Upgrading Mainframe Infrastructure
                </div>
                <div className="text-slate-400 font-mono text-sm uppercase tracking-[0.4em] flex items-center gap-3">
                    <CheckCircle2 className="w-5 h-5" /> Deploying Version {currentVersion + 1}.0
                </div>
             </div>
             <div className="mt-16 w-96 h-2 bg-slate-900 rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500 animate-[loading_2s_ease-in-out_infinite]" />
             </div>
             <style>{`
                @keyframes loading {
                    0% { width: 0%; left: 0%; }
                    50% { width: 100%; left: 0%; }
                    100% { width: 0%; left: 100%; }
                }
             `}</style>
          </div>
      )}

      {/* BUILDER (BOTTOM) */}
      <div className="flex justify-center gap-4 pointer-events-auto mb-6">
        {(Object.entries(TOWER_TYPES) as [keyof typeof TOWER_TYPES, any][]).map(([key, config]) => {
          const towerCount = state.towers.filter(t => t.type === key).length;
          const currentCost = Math.floor(config.cost * Math.pow(1.15, towerCount));
          const isUnlocked = !config.requires || state.unlockedTech.includes(config.requires);
          const canAfford = state.code >= currentCost;
          const isActive = activeBuildingType === key;

          return (
            <button
              key={key}
              onClick={() => isUnlocked && onBuildTower(key)}
              disabled={!isUnlocked}
              className={`group relative bg-slate-900/90 backdrop-blur-xl border p-3 rounded-[1.5rem] flex flex-col items-center gap-1.5 transition-all min-w-[100px] 
                ${isUnlocked ? 'border-slate-700 hover:border-sky-400 hover:-translate-y-2' : 'opacity-30 grayscale cursor-not-allowed'} 
                ${isActive ? 'border-sky-400 ring-2 ring-sky-400 bg-sky-950/50 -translate-y-2' : ''}`}
            >
              <div className="w-12 h-12 rounded-2xl flex items-center justify-center relative transition-transform" style={{ backgroundColor: config.color + '20' }}>
                {key === 'BASIC' && <Shield className="text-sky-400 w-6 h-6" />}
                {key === 'SNIPER' && <Terminal className="text-pink-400 w-6 h-6" />}
                {key === 'RAPID' && <Layers className="text-amber-400 w-6 h-6" />}
                {key === 'AOE' && <Rocket className="text-purple-400 w-6 h-6" />}
                {!isUnlocked && <Lock className="absolute inset-0 m-auto text-white w-4 h-4 opacity-50" />}
              </div>
              <div className="text-center px-1">
                <div className={`text-[9px] font-black uppercase tracking-tight truncate w-full ${isActive ? 'text-sky-400' : 'text-slate-400'}`}>
                  {isUnlocked ? config.name : 'Locked'}
                </div>
                <div className={`text-[12px] font-black tabular-nums ${canAfford ? 'text-white' : 'text-red-500'}`}>
                  {formatLarge(currentCost)}
                </div>
              </div>
            </button>
          );
        })}
      </div>

      {/* GAME OVER SCREEN */}
      {state.isGameOver && (
        <div className="fixed inset-0 bg-slate-950/98 backdrop-blur-3xl flex items-center justify-center pointer-events-auto z-[1000]">
