  }

  public async shipToProduction() {
    if (this.state.buildProgress < 100) return;
    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    const legacyGain = Math.max(20, Math.floor(Math.log10(this.state.code + 1) * this.state.level * 2));
    this.state.permanentUpgrades.legacyPoints += legacyGain;
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 2000));
    this.state.isCompiling = false;
    this.reset();
  }

  public reset() {
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    const vMult = Math.pow(10, perms.version - 1);
    this.state.code = (1000 + perms.startingCode) * vMult;
    this.state.clickPower = 60 * perms.damageMultiplier * vMult;

    this.generatePlanets(0);
    this.onUpdate({ ...this.state });
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number): boolean {
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;
    const config = TOWER_TYPES[type];
    const tCount = this.state.towers.filter(t => t.type === type).length;
    const cost = Math.floor(config.cost * Math.pow(1.15, tCount));

    if (this.state.code >= cost && (!config.requires || this.state.unlockedTech.includes(config.requires))) {
      this.state.code -= cost;
      this.state.towers.push({ 
        id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY, 
        range: config.range, damage: config.damage, fireRate: config.fireRate, 
        lastFired: 0, color: config.color 
      });
      audio.playClick();
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 1);
      return true;
    }
    return false;
  }

  public handleClick(rawX: number, rawY: number, wasPlacement: boolean) {
    if (this.state.isGameOver || this.isPaused || this.state.isCompiling) return;
    audio.enable();
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;

    const hit = LogicHandler.handleClick(this.state, worldX, worldY, this.cameraScale, (e) => {
        this.createParticles(e.x, e.y, 12, COLORS.PRIMARY);
        audio.playClick();
        this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.2);
    }, () => this.onLevelUp());

    if (!hit && !wasPlacement) {
      const vMult = Math.pow(5, this.state.permanentUpgrades.version - 1);
      const reward = (120 + (this.state.level * 30)) * (1 + this.state.currentSector) * vMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + reward);
      this.createFloatingText(worldX, worldY, `+${Math.floor(reward)}`, COLORS.PRIMARY);
      audio.playClick();
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.05);
    }
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    const uncaptured = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncaptured.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 20); 
    }
    if (this.state.level % 5 === 0) this.spawnBoss();
    this.refreshSkillShop();
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;
    if (!this.isPaused && !this.state.isCompiling) this.update(dt);
    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  }

  private update(dt: number) {
    // Dynamic Bounding Box must include EVERYTHING the player needs to see
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;
    let bounds = { 
      minX: cx - 2000, maxX: cx + 2000, 
      minY: cy - 2000, maxY: cy + 2000 
    };

    // Include Planets
    this.state.planets.forEach(p => {
        if (p.sector <= this.state.currentSector + 1) {
            bounds.minX = Math.min(bounds.minX, p.x); bounds.maxX = Math.max(bounds.maxX, p.x);
            bounds.minY = Math.min(bounds.minY, p.y); bounds.maxY = Math.max(bounds.maxY, p.y);
        }
    });

    // CRITICAL: Include Enemies (Bosses) in zoom logic
    this.state.enemies.forEach(e => {
        bounds.minX = Math.min(bounds.minX, e.x); bounds.maxX = Math.max(bounds.maxX, e.x);
        bounds.minY = Math.min(bounds.minY, e.y); bounds.maxY = Math.max(bounds.maxY, e.y);
    });

    const viewW = bounds.maxX - bounds.minX;
    const viewH = bounds.maxY - bounds.minY;

    // Zoom out enough to give 20% margin
    const scaleX = this.canvas.width / (viewW * 1.3);
    const scaleY = this.canvas.height / (viewH * 1.3);

    this.targetCameraScale = Math.min(scaleX, scaleY, 1.0);
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.05; 

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, (t, tar) => {
        this.renderer.addFiringEffect(t.x, t.y, tar.x, tar.y, t.color, t.type);
        audio.playFire(t.type);
        this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.002);
    }, () => this.onLevelUp());

    this.enemySpawnTimer += dt;
    if (this.enemySpawnTimer > 2000 / (1 + this.state.currentSector * 0.5)) {
        const active = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
        const s = active[Math.floor(Math.random() * active.length)];
        this.spawnEnemyAt(s ? s.x : -999, s ? s.y : -999);
        this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { 
        p.x += p.vx; p.y += p.vy; p.life -= 0.04; return p.life > 0; 
    });

    if (this.frameCount % 5 === 0) this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 8000 + (this.state.currentSector * 2000); // Push bosses further as galaxy grows
    const x = this.canvas.width/2 + Math.cos(angle) * dist;
    const y = this.canvas.height/2 + Math.sin(angle) * dist;
    const vMult = Math.pow(15, this.state.permanentUpgrades.version - 1);
    const hp = 250000 * Math.pow(3.0, this.state.currentSector) * vMult;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.4, 
        value: hp * 8, type: 'boss', size: 1500, angle: 0 
    });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    if (this.state.enemies.length > 100) return;
    const x = sx === -999 ? this.canvas.width/2 + 4000 : sx + (Math.random()-0.5)*1000;
    const y = sy === -999 ? this.canvas.height/2 + 4000 : sy + (Math.random()-0.5)*1000;
    const vMult = Math.pow(10, this.state.permanentUpgrades.version - 1);
    const hp = 500 * Math.pow(1.35, this.state.level) * vMult;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.8 + (this.state.level * 0.04), 
        value: hp * 4, type: 'bug', size: 160, angle: 0 
    });
  }

  private resize() { this.canvas.width = window.innerWidth; this.canvas.height = window.innerHeight; }
  private loadPermanentUpgrades() { const s = localStorage.getItem(STORAGE_KEY); if (s) try { this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...JSON.parse(s) }; } catch(e){} }
  private savePermanentUpgrades() { localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades)); }
  private refreshSkillShop() { this.state.availableSkills = [...ALL_SKILLS].sort(()=>0.5-Math.random()).slice(0,3).map(s=>s.id); }

  public applySkill(id: string, cb: (s: any)=>void) {
    const s = ALL_SKILLS.find(x=>x.id===id) || TECH_TREE.find(x=>x.id===id);
    if (s && this.state.skillPoints >= s.cost) {
        this.state.skillPoints -= s.cost;
        if (id.startsWith('tech_')) this.state.unlockedTech.push(id); else this.state.unlockedSkills.push(id);
        if (id === 'auto_collect') this.hasAutoCollect = true;
        cb(this.state); this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
        this.state.code -= this.state.rerollCost; this.state.rerollCost = Math.floor(this.state.rerollCost * 1.5);
        this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    if (this.state.permanentUpgrades.legacyPoints >= 100) {
        this.state.permanentUpgrades.legacyPoints -= 100;
        if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 30000;
        if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 5.0;
        if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 5.0;
        this.savePermanentUpgrades(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i=0; i<count; i++) this.state.particles.push({ x, y, vx: (Math.random()-0.5)*50, vy: (Math.random()-0.5)*50, size: Math.random()*16+8, life: 1.0, color });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: 0, vy: -15, size: 60, life: 3.0, color, text });
  }
}

import { GameState, Enemy, Tower, Planet } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 200;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  private drawStarfield(cx: number, cy: number, cameraScale: number) {
    const { canvas } = this.ctx;
    const layers = [
        { count: 150, size: 1, color: '#1e293b' },
        { count: 80, size: 2, color: '#334155' },
        { count: 40, size: 3, color: '#475569' }
    ];

    layers.forEach(layer => {
        this.ctx.fillStyle = layer.color;
        for (let i = 0; i < layer.count; i++) {
            const x = (Math.sin(i * 157.7) * 0.5 + 0.5) * canvas.width;
            const y = (Math.cos(i * 89.1) * 0.5 + 0.5) * canvas.height;
            this.ctx.beginPath();
            this.ctx.arc(x, y, layer.size, 0, Math.PI * 2);
            this.ctx.fill();
        }
    });
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    // Keep units and nodes legible when zoomed out
    const iconBaseScale = cameraScale < 0.2 ? 1.5 : 1.0;

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.drawStarfield(cx, cy, cameraScale);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.85;
    }

    // World Space Transformation
    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. GALAXY NETWORK
    this.ctx.lineWidth = 10 / cameraScale;
    state.planets.forEach(p => {
        if (!p.isCaptured && p.sector > state.currentSector) return;
        this.ctx.globalAlpha = 0.1 / (cameraScale * 0.5);
        this.ctx.beginPath();
        this.ctx.moveTo(cx, cy);
        this.ctx.lineTo(p.x, p.y);
        this.ctx.strokeStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
        this.ctx.stroke();

        const progress = (now * 0.001) % 1;
        const pulseX = cx + (p.x - cx) * progress;
        const pulseY = cy + (p.y - cy) * progress;
        this.ctx.globalAlpha = 0.3;
        this.ctx.fillStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
        this.ctx.beginPath(); this.ctx.arc(pulseX, pulseY, 60 / cameraScale, 0, Math.PI * 2); this.ctx.fill();
    });
    this.ctx.globalAlpha = 1.0;

    // 2. PLANETS
    state.planets.forEach(p => {
      if (p.sector > state.currentSector + 2) return;
      this.ctx.save();
      this.ctx.translate(p.x, p.y);
      const pDrawSize = p.size;

      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#1e0505';
      this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize, 0, Math.PI * 2); this.ctx.fill();

      this.ctx.strokeStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
      this.ctx.lineWidth = 20 / cameraScale;
      this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 1.1, 0, Math.PI * 2); this.ctx.stroke();

      this.ctx.fillStyle = '#fff';
      this.ctx.font = `bold ${Math.max(160, 450 / cameraScale)}px Space Grotesk`;
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, 0, pDrawSize + (600 / cameraScale));
      this.ctx.restore();
    });

    // 3. THE CORE + BUILD RING
    const coreSize = 350 + (state.level * 1.5);
    this.ctx.save();
    this.ctx.translate(cx, cy);
    this.ctx.lineWidth = 50 / cameraScale;
    this.ctx.lineCap = 'round';

    this.ctx.strokeStyle = '#1e293b';
    this.ctx.beginPath(); this.ctx.arc(0, 0, coreSize * 1.4, 0, Math.PI * 2); this.ctx.stroke();

    const buildColor = state.buildProgress >= 100 ? '#10b981' : state.buildProgress > 50 ? '#f59e0b' : '#ef4444';
    this.ctx.strokeStyle = buildColor;
    this.ctx.beginPath(); this.ctx.arc(0, 0, coreSize * 1.4, -Math.PI/2, -Math.PI/2 + (Math.PI * 2 * (state.buildProgress/100))); this.ctx.stroke();
    this.ctx.restore();

    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 400 / cameraScale; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 4. COMBAT FX
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = (ef.type === 'SNIPER' ? 140 : 60) * ef.life / cameraScale;
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.1;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // 5. ENEMIES (INCLUDING THE BIG PURPLE SHIPS)
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = now - (e.lastHit || 0) < 100;
      this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));

      const uSize = e.size * iconBaseScale;

      if (e.type === 'boss') {
        // Draw Large Capital Ship (Purple Boss)
        this.ctx.beginPath();
        this.ctx.moveTo(uSize, 0);
        this.ctx.lineTo(-uSize * 0.5, uSize * 0.8);
        this.ctx.lineTo(-uSize * 0.2, 0);
        this.ctx.lineTo(-uSize * 0.5, -uSize * 0.8);
        this.ctx.closePath();
        this.ctx.fill();

        // Engine Glow
        this.ctx.fillStyle = '#a855f7';
        this.ctx.globalAlpha = 0.4 + Math.sin(now * 0.02) * 0.2;
        this.ctx.beginPath(); this.ctx.arc(-uSize * 0.4, 0, uSize * 0.6, 0, Math.PI * 2); this.ctx.fill();

        // Boss Status
        this.ctx.globalAlpha = 1.0;
        this.ctx.fillStyle = '#fff';
        this.ctx.font = `bold ${500 / cameraScale}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText("CRITICAL THREAT", 0, -uSize * 1.5);
      } else {
        // Normal Bug
        this.ctx.beginPath();
        this.ctx.moveTo(uSize, 0);
        this.ctx.lineTo(-uSize * 0.6, uSize * 0.6);
        this.ctx.lineTo(-uSize * 0.3, 0);
        this.ctx.lineTo(-uSize * 0.6, -uSize * 0.6);
        this.ctx.closePath();
        this.ctx.fill();
      }
      this.ctx.restore();
    });

    // 6. TOWERS
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const tSize = 140;
      this.ctx.fillRect(t.x - tSize, t.y - tSize, tSize * 2, tSize * 2);
    });

    // 7. DROPS
    state.drops.forEach(d => {
      this.ctx.globalAlpha = d.life;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      const s = 180;
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.02);
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    // 8. PARTICLES / TEXT
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `black ${p.size / cameraScale}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size / cameraScale, 0, Math.PI * 2); this.ctx.fill();
      }
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return '#a855f7'; // Bright Purple for bosses
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(state: GameState, dt: number, cameraScale: number, auto: boolean, onLv: () => void): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const cx = window.innerWidth / 2; const cy = window.innerHeight / 2;
    const vMult = Math.pow(4, state.permanentUpgrades.version - 1);

    // 1. Passive LOC Generation
    const passiveBase = (100 + state.level * 20) * (dt/1000) * vMult * Math.pow(2.5, state.currentSector);
    state.code = Math.min(MAX_VAL, state.code + passiveBase);

    // 2. Unit Behavior
    state.enemies.forEach(e => {
        if (e.isFriendly) {
            // Friendly units attack uncaptured planets
            const targets = state.planets.filter(p => !p.isCaptured);
            if (targets.length > 0) {
                const t = targets[0];
                const dX = t.x - e.x; const dY = t.y - e.y; 
                const dist = Math.sqrt(dX*dX + dY*dY) || 1;
                if (dist < 800) { 
                    t.hp -= e.hp * 0.1; 
                    e.hp -= 100; // Converted units exhaust themselves
                    if (t.hp <= 0) this.capturePlanet(state, t, onLv); 
                }
                e.x += (dX/dist) * e.speed * 4; 
                e.y += (dY/dist) * e.speed * 4; 
                e.angle = Math.atan2(dY, dX);
            } else {
                // Return to core if no planets to capture
                const dX = cx - e.x; const dY = cy - e.y;
                const dist = Math.sqrt(dX*dX + dY*dY) || 1;
                e.x += (dX/dist) * e.speed * 2;
                e.y += (dY/dist) * e.speed * 2;
                e.angle = Math.atan2(dY, dX);
            }
        } else {
            // Boss Logic: Fire at core from distance
            if (e.type === 'boss') {
                const dx = cx - e.x; const dy = cy - e.y;
                const dist = Math.sqrt(dx*dx + dy*dy) || 1;

                // Bosses stop at a distance to fire beams
                if (dist < 1500) {
                    if (!e.nextAttackTime || now > e.nextAttackTime) {
                        state.coreHp -= 200; 
                        e.nextAttackTime = now + 2000;
                    }
                } else {
                    e.x += (dx/dist) * e.speed; 
                    e.y += (dy/dist) * e.speed; 
                }
                e.angle = Math.atan2(dy, dx);
            } else {
                // Normal bugs swarm the core
                const dx = cx - e.x; const dy = cy - e.y;
                const dist = Math.sqrt(dx*dx + dy*dy) || 1;
                if (dist < 150) { 
                    state.coreHp -= 100; 
                    e.hp = -1; 
                } else {
                    e.x += (dx/dist) * e.speed; 
                    e.y += (dy/dist) * e.speed; 
                    e.angle = Math.atan2(dy, dx);
                }
            }
        }

        if (state.coreHp <= 0) state.isGameOver = true;
    });
    state.enemies = state.enemies.filter(e => e.hp > 0);

    // 3. Drop Collection
    state.drops = state.drops.filter(d => {
        d.life -= 0.003;
        const dx = cx - d.x; const dy = cy - d.y;
        const dist = Math.sqrt(dx*dx + dy*dy) || 1;
        const collectRadius = 400 / cameraScale;

        if (dist < collectRadius) { this.collectDrop(state, d); return false; }

        // Vacuum logic
        if (auto || dist < 6000) {
            const pull = auto ? 200 : 100;
            d.x += (dx/dist) * pull; 
            d.y += (dy/dist) * pull;
        }
        return d.life > 0;
    });
  }

  public static handleClick(state: GameState, x: number, y: number, scale: number, onHit: (e: any)=>void, onLv: ()=>void): boolean {
    const splash = (400 + state.level * 8) / Math.pow(scale, 0.5);
    let hit = false;

    state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const d = Math.sqrt((e.x - x)**2 + (e.y - y)**2);
        if (d < splash) {
            const damage = state.clickPower * (1 - d/splash);
            e.hp -= damage; 
            e.lastHit = Date.now(); 
            hit = true; 
            onHit(e);

            // Special: clicking a Boss has a chance to "convert" its subsystems
            if (e.type === 'boss' && Math.random() < 0.05) {
               e.isFriendly = true;
               e.hp = e.maxHp * 0.5;
            }

            if (e.hp <= 0) { 
                this.processEnemyDeath(state, e, true); 
                this.checkLevelUp(state, onLv); 
            }
        }
    });
    return hit;
  }

  public static updateTowers(state: GameState, onFire: (t: any, tar: any)=>void, onLv: ()=>void): void {
    const now = Date.now();
    const rScale = Math.pow(2.0, state.currentSector);
    state.towers.forEach(t => {
        const range = t.range * state.towerModifiers.rangeMult * rScale;
        if (now - t.lastFired > t.fireRate * state.towerModifiers.fireRateMult) {
            // Target Bosses first if in range
            let tar = state.enemies.find(e => !e.isFriendly && e.type === 'boss' && Math.sqrt((e.x - t.x)**2 + (e.y - t.y)**2) < range);
            if (!tar) tar = state.enemies.find(e => !e.isFriendly && Math.sqrt((e.x - t.x)**2 + (e.y - t.y)**2) < range);
            if (!tar) tar = state.planets.find(p => !p.isCaptured && Math.sqrt((p.x - t.x)**2 + (p.y - t.y)**2) < range) as any;

            if (tar) {
                tar.hp -= t.damage * state.towerModifiers.damageMult;
                state.code = Math.min(MAX_VAL, state.code + (t.damage * 0.1));
                onFire(t, tar);
                if (tar.hp <= 0) {
                    if ('isCaptured' in tar) this.capturePlanet(state, tar as any, onLv);
                    else { this.processEnemyDeath(state, tar as any, false); this.checkLevelUp(state, onLv); }
                }
                t.lastFired = now;
            }
        }
    });
  }

  private static capturePlanet(state: GameState, p: Planet, onLv: ()=>void) {
    p.isCaptured = true; p.color = COLORS.PRIMARY;
    state.experience += 200000 * Math.pow(4, p.sector); 
    this.checkLevelUp(state, onLv);
  }

  public static collectDrop(state: GameState, d: LibraryDrop) {
    if (d.type === 'shard') { 
        state.spProgress += 12; 
        if (state.spProgress >= state.spGoal) { 
            state.skillPoints += 6; 
            state.spProgress = 0; 
            state.spGoal = Math.floor(state.spGoal * 1.2) + 2; 
        } 
    } else {
        state.code = Math.min(MAX_VAL, state.code + (1500 + state.level * 150));
    }
  }

  public static processEnemyDeath(state: GameState, e: Enemy, manual: boolean) {
    state.experience += (e.value / 4) * state.permanentUpgrades.xpMultiplier;
    state.code = Math.min(MAX_VAL, state.code + e.value * 0.6 * state.permanentUpgrades.version);
    state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', x: e.x, y: e.y, effect: 'SP', life: 8.0 });
  }

  public static checkLevelUp(state: GameState, onLv: ()=>void) {
    const req = 500 + (state.level * 500);
    if (state.experience >= req) { 
        state.level++; 
        state.experience -= req; 
        state.skillPoints += 5; 
        state.clickPower *= 1.25; 
        onLv(); 
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_v5_stable';
const MAX_VAL = 1e308;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    window.addEventListener('resize', this.resize.bind(this));
    this.resize();
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) { this.isPaused = paused; }
  public destroy() { this.isDestroyed = true; audio.stop(); }

  private getInitialState(): GameState {
    return {
      code: 1000, experience: 0, level: 1, skillPoints: 5, spProgress: 0, spGoal: 20,
      clickPower: 75, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: 50, combo: 0,
      threatLevel: 0.5, coreHp: 1500, maxCoreHp: 1500, currentSector: 0,
      buildProgress: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    // Increase distance significantly to force zoom-out behavior
    const dist = 4000 + (sector * 8000); 
    const count = 3 + sector;
    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 2.5);
      const versionMult = Math.pow(15, this.state.permanentUpgrades.version - 1);
      const hp = (25000 + (this.state.level * 1200)) * Math.pow(4.5, sector) * versionMult;
      this.state.planets.push({
        id: `p_${sector}_${i}`, 
        name: `CLUSTER_0x${sector}${i}`,
        x: this.canvas.width/2 + Math.cos(angle) * dist,
        y: this.canvas.height/2 + Math.sin(angle) * dist,
        hp, maxHp: hp, isCaptured: false, size: 900 + (sector * 350), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public async shipToProduction() {
    if (this.state.buildProgress < 100) return;
    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    const legacyGain = Math.max(30, Math.floor(Math.log10(this.state.code + 1) * this.state.level * 3));
    this.state.permanentUpgrades.legacyPoints += legacyGain;
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 2200));
    this.state.isCompiling = false;
    this.reset();
  }

  public reset() {
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    const vMult = Math.pow(12, perms.version - 1);
    this.state.code = (1000 + perms.startingCode) * vMult;
    this.state.clickPower = 75 * perms.damageMultiplier * vMult;

    this.generatePlanets(0);
    this.onUpdate({ ...this.state });
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number): boolean {
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;
    const config = TOWER_TYPES[type];
    const tCount = this.state.towers.filter(t => t.type === type).length;
    const cost = Math.floor(config.cost * Math.pow(1.15, tCount));

    if (this.state.code >= cost && (!config.requires || this.state.unlockedTech.includes(config.requires))) {
      this.state.code -= cost;
      this.state.towers.push({ 
        id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY, 
        range: config.range, damage: config.damage, fireRate: config.fireRate, 
        lastFired: 0, color: config.color 
      });
      audio.playClick();
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 1.2);
      return true;
    }
    return false;
  }

  public handleClick(rawX: number, rawY: number, wasPlacement: boolean) {
    if (this.state.isGameOver || this.isPaused || this.state.isCompiling) return;
    audio.enable();
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;

    // Always apply interaction logic (damage/collection)
    const hit = LogicHandler.handleClick(this.state, worldX, worldY, this.cameraScale, (e) => {
        this.createParticles(e.x, e.y, 14, COLORS.PRIMARY);
        audio.playClick();
        this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.25);
    }, () => this.onLevelUp());

    // Only grant the "miss" bonus if nothing was hit AND no placement happened
    if (!hit && !wasPlacement) {
      const vMult = Math.pow(6, this.state.permanentUpgrades.version - 1);
      const reward = (150 + (this.state.level * 35)) * (1 + this.state.currentSector) * vMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + reward);
      this.createFloatingText(worldX, worldY, `+${Math.floor(reward)}`, COLORS.PRIMARY);
      audio.playClick();
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.08);
    }
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    const uncaptured = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncaptured.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 25); 
    }
    if (this.state.level % 5 === 0) this.spawnBoss();
    this.refreshSkillShop();
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;
    if (!this.isPaused && !this.state.isCompiling) this.update(dt);
    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  }

  private update(dt: number) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;

    // EXTREME CAMERA STABILITY: Force zoom bounds to contain Core, Planets, and Bosses
    let bounds = { 
      minX: cx - 1800, maxX: cx + 1800, 
      minY: cy - 1800, maxY: cy + 1800 
    };

    // Contain relevant planets
    this.state.planets.forEach(p => {
        if (p.sector <= this.state.currentSector) {
            bounds.minX = Math.min(bounds.minX, p.x); bounds.maxX = Math.max(bounds.maxX, p.x);
            bounds.minY = Math.min(bounds.minY, p.y); bounds.maxY = Math.max(bounds.maxY, p.y);
        }
    });

    // Aggressively contain Bosses (Purple Ships)
    this.state.enemies.forEach(e => {
        if (e.type === 'boss') {
            bounds.minX = Math.min(bounds.minX, e.x); bounds.maxX = Math.max(bounds.maxX, e.x);
            bounds.minY = Math.min(bounds.minY, e.y); bounds.maxY = Math.max(bounds.maxY, e.y);
        }
    });

    const viewW = bounds.maxX - bounds.minX;
    const viewH = bounds.maxY - bounds.minY;
    const scaleX = this.canvas.width / (viewW * 1.5);
    const scaleY = this.canvas.height / (viewH * 1.5);

    // Zoom floor is 0.05 to ensure massive sectors are visible
    this.targetCameraScale = Math.max(0.05, Math.min(scaleX, scaleY, 1.0));
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.08; 

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, (t, tar) => {
        this.renderer.addFiringEffect(t.x, t.y, tar.x, tar.y, t.color, t.type);
        audio.playFire(t.type);
        this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.003);
    }, () => this.onLevelUp());

    this.enemySpawnTimer += dt;
    if (this.enemySpawnTimer > 2500 / (1 + this.state.currentSector * 0.6)) {
        const active = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
        const s = active[Math.floor(Math.random() * active.length)];
        this.spawnEnemyAt(s ? s.x : -999, s ? s.y : -999);
        this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { 
        p.x += p.vx; p.y += p.vy; p.life -= 0.04; return p.life > 0; 
    });

    if (this.frameCount % 5 === 0) this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 10000 + (this.state.currentSector * 3000); 
    const x = this.canvas.width/2 + Math.cos(angle) * dist;
    const y = this.canvas.height/2 + Math.sin(angle) * dist;
    const vMult = Math.pow(18, this.state.permanentUpgrades.version - 1);
    const hp = 350000 * Math.pow(3.5, this.state.currentSector) * vMult;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.2, 
        value: hp * 10, type: 'boss', size: 1800, angle: 0 
    });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    if (this.state.enemies.length > 120) return;
    const x = sx === -999 ? this.canvas.width/2 + 4500 : sx + (Math.random()-0.5)*1200;
    const y = sy === -999 ? this.canvas.height/2 + 4500 : sy + (Math.random()-0.5)*1200;
    const vMult = Math.pow(12, this.state.permanentUpgrades.version - 1);
    const hp = 600 * Math.pow(1.35, this.state.level) * vMult;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.6 + (this.state.level * 0.05), 
        value: hp * 5, type: 'bug', size: 180, angle: 0 
    });
  }

  private resize() { this.canvas.width = window.innerWidth; this.canvas.height = window.innerHeight; }
  private loadPermanentUpgrades() { const s = localStorage.getItem(STORAGE_KEY); if (s) try { this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...JSON.parse(s) }; } catch(e){} }
  private savePermanentUpgrades() { localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades)); }
  private refreshSkillShop() { this.state.availableSkills = [...ALL_SKILLS].sort(()=>0.5-Math.random()).slice(0,3).map(s=>s.id); }

  public applySkill(id: string, cb: (s: any)=>void) {
    const s = ALL_SKILLS.find(x=>x.id===id) || TECH_TREE.find(x=>x.id===id);
    if (s && this.state.skillPoints >= s.cost) {
        this.state.skillPoints -= s.cost;
        if (id.startsWith('tech_')) this.state.unlockedTech.push(id); else this.state.unlockedSkills.push(id);
        if (id === 'auto_collect') this.hasAutoCollect = true;
        cb(this.state); this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
        this.state.code -= this.state.rerollCost; this.state.rerollCost = Math.floor(this.state.rerollCost * 1.6);
        this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    if (this.state.permanentUpgrades.legacyPoints >= 100) {
        this.state.permanentUpgrades.legacyPoints -= 100;
        if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 40000;
        if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 6.0;
        if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 6.0;
        this.savePermanentUpgrades(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i=0; i<count; i++) this.state.particles.push({ x, y, vx: (Math.random()-0.5)*60, vy: (Math.random()-0.5)*60, size: Math.random()*20+10, life: 1.0, color });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: 0, vy: -18, size: 70, life: 3.2, color, text });
  }
}

import { GameState, Enemy, Tower, Planet } from '../types';
import { COLORS } from '../constants';

export class RenderHandler {
  private ctx: CanvasRenderingContext2D;
  private firingEffects: Array<{x1: number, y1: number, x2: number, y2: number, life: number, color: string, type: string}> = [];
  private screenShake: number = 0;
  private MAX_FIRING_EFFECTS = 250;

  constructor(ctx: CanvasRenderingContext2D) {
    this.ctx = ctx;
  }

  public addFiringEffect(x1: number, y1: number, x2: number, y2: number, color: string, type: string) {
    if (this.firingEffects.length < this.MAX_FIRING_EFFECTS) {
      this.firingEffects.push({ x1, y1, x2, y2, life: 1.0, color, type });
    }
  }

  public triggerShake(intensity: number = 10) {
    this.screenShake = intensity;
  }

  private getVersionColor(version: number): string {
    const palette = [COLORS.PRIMARY, '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#06b6d4'];
    return palette[(version - 1) % palette.length];
  }

  private drawStarfield(cx: number, cy: number, cameraScale: number) {
    const { canvas } = this.ctx;
    const layers = [
        { count: 180, size: 1, color: '#1e293b' },
        { count: 100, size: 2, color: '#334155' },
        { count: 50, size: 3, color: '#475569' }
    ];

    layers.forEach(layer => {
        this.ctx.fillStyle = layer.color;
        for (let i = 0; i < layer.count; i++) {
            const x = (Math.sin(i * 157.7) * 0.5 + 0.5) * canvas.width;
            const y = (Math.cos(i * 89.1) * 0.5 + 0.5) * canvas.height;
            this.ctx.beginPath();
            this.ctx.arc(x, y, layer.size, 0, Math.PI * 2);
            this.ctx.fill();
        }
    });
  }

  public draw(state: GameState, cameraScale: number, isPaused: boolean) {
    const { canvas } = this.ctx;
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const now = Date.now();
    const version = state.permanentUpgrades.version;
    const versionColor = this.getVersionColor(version);

    this.ctx.fillStyle = COLORS.BG;
    this.ctx.fillRect(0, 0, canvas.width, canvas.height);

    this.drawStarfield(cx, cy, cameraScale);

    this.ctx.save();
    if (this.screenShake > 0) {
      this.ctx.translate((Math.random() - 0.5) * this.screenShake, (Math.random() - 0.5) * this.screenShake);
      this.screenShake *= 0.85;
    }

    // World Space
    this.ctx.translate(cx, cy);
    this.ctx.scale(cameraScale, cameraScale);
    this.ctx.translate(-cx, -cy);

    // 1. GALAXY NETWORK
    this.ctx.lineWidth = 15 / cameraScale;
    state.planets.forEach(p => {
        if (!p.isCaptured && p.sector > state.currentSector) return;
        this.ctx.globalAlpha = 0.08 / (cameraScale * 0.4);
        this.ctx.beginPath();
        this.ctx.moveTo(cx, cy);
        this.ctx.lineTo(p.x, p.y);
        this.ctx.strokeStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
        this.ctx.stroke();

        const progress = (now * 0.0008) % 1;
        const pulseX = cx + (p.x - cx) * progress;
        const pulseY = cy + (p.y - cy) * progress;
        this.ctx.globalAlpha = 0.25;
        this.ctx.fillStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
        this.ctx.beginPath(); this.ctx.arc(pulseX, pulseY, 80 / cameraScale, 0, Math.PI * 2); this.ctx.fill();
    });
    this.ctx.globalAlpha = 1.0;

    // 2. BOSS ATTACK BEAMS (Rendering these BEFORE bosses for layering)
    state.enemies.forEach(e => {
        if (e.type === 'boss' && !e.isFriendly) {
            const dx = cx - e.x; const dy = cy - e.y;
            const dist = Math.sqrt(dx*dx + dy*dy);
            if (dist < 4000) { // Beam becomes visible as they approach
                this.ctx.save();
                this.ctx.strokeStyle = '#a855f7';
                this.ctx.lineWidth = (20 + Math.sin(now * 0.1) * 10) / cameraScale;
                this.ctx.globalAlpha = 0.4;
                this.ctx.setLineDash([100 / cameraScale, 50 / cameraScale]);
                this.ctx.lineDashOffset = -now * 0.2;
                this.ctx.beginPath();
                this.ctx.moveTo(e.x, e.y);
                this.ctx.lineTo(cx, cy);
                this.ctx.stroke();
                this.ctx.restore();
            }
        }
    });

    // 3. PLANETS
    state.planets.forEach(p => {
      if (p.sector > state.currentSector + 1) return;
      this.ctx.save();
      this.ctx.translate(p.x, p.y);
      const pDrawSize = p.size;

      this.ctx.fillStyle = p.isCaptured ? '#0c4a6e' : '#1e0505';
      this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize, 0, Math.PI * 2); this.ctx.fill();

      this.ctx.strokeStyle = p.isCaptured ? versionColor : COLORS.ENEMY;
      this.ctx.lineWidth = 25 / cameraScale;
      this.ctx.beginPath(); this.ctx.arc(0, 0, pDrawSize * 1.1, 0, Math.PI * 2); this.ctx.stroke();

      this.ctx.fillStyle = '#fff';
      this.ctx.font = `bold ${Math.max(200, 600 / cameraScale)}px Space Grotesk`;
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.name, 0, pDrawSize + (800 / cameraScale));
      this.ctx.restore();
    });

    // 4. THE CORE + BUILD RING
    const coreSize = 350 + (state.level * 2);
    this.ctx.save();
    this.ctx.translate(cx, cy);
    this.ctx.lineWidth = 60 / cameraScale;

    this.ctx.strokeStyle = '#1e293b';
    this.ctx.beginPath(); this.ctx.arc(0, 0, coreSize * 1.4, 0, Math.PI * 2); this.ctx.stroke();

    const buildColor = state.buildProgress >= 100 ? '#10b981' : state.buildProgress > 50 ? '#f59e0b' : '#ef4444';
    this.ctx.strokeStyle = buildColor;
    this.ctx.beginPath(); this.ctx.arc(0, 0, coreSize * 1.4, -Math.PI/2, -Math.PI/2 + (Math.PI * 2 * (state.buildProgress/100))); this.ctx.stroke();
    this.ctx.restore();

    this.ctx.fillStyle = versionColor;
    this.ctx.shadowBlur = 500 / cameraScale; this.ctx.shadowColor = versionColor;
    this.ctx.beginPath(); this.ctx.arc(cx, cy, coreSize, 0, Math.PI * 2); this.ctx.fill();
    this.ctx.shadowBlur = 0;

    // 5. COMBAT FX
    this.firingEffects = this.firingEffects.filter(ef => {
      this.ctx.globalAlpha = ef.life;
      this.ctx.strokeStyle = ef.color;
      this.ctx.lineWidth = (ef.type === 'SNIPER' ? 180 : 80) * ef.life / cameraScale;
      this.ctx.beginPath(); this.ctx.moveTo(ef.x1, ef.y1); this.ctx.lineTo(ef.x2, ef.y2); this.ctx.stroke();
      ef.life -= 0.08;
      return ef.life > 0;
    });
    this.ctx.globalAlpha = 1.0;

    // 6. ENTITIES
    state.enemies.forEach(e => {
      this.ctx.save();
      this.ctx.translate(e.x, e.y);
      this.ctx.rotate(e.angle);

      const isHit = now - (e.lastHit || 0) < 100;
      const uSize = e.size;

      if (e.type === 'boss') {
        // High-legibility Boss Ship (Absolute thickness lines)
        const bossColor = e.isFriendly ? '#22d3ee' : '#a855f7';
        this.ctx.fillStyle = isHit ? '#fff' : bossColor;
        this.ctx.strokeStyle = '#fff';
        this.ctx.lineWidth = 40 / cameraScale;

        this.ctx.beginPath();
        this.ctx.moveTo(uSize, 0);
        this.ctx.lineTo(-uSize * 0.5, uSize * 0.9);
        this.ctx.lineTo(-uSize * 0.1, 0);
        this.ctx.lineTo(-uSize * 0.5, -uSize * 0.9);
        this.ctx.closePath();
        this.ctx.fill();
        this.ctx.stroke();

        // Huge Engine Pulse
        this.ctx.fillStyle = bossColor;
        this.ctx.globalAlpha = 0.5 + Math.sin(now * 0.01) * 0.3;
        this.ctx.beginPath(); this.ctx.arc(-uSize * 0.6, 0, uSize * 0.8, 0, Math.PI * 2); this.ctx.fill();

        // Text Alert
        this.ctx.globalAlpha = 1.0;
        this.ctx.fillStyle = '#fff';
        this.ctx.font = `black ${Math.max(400, 700 / cameraScale)}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(e.isFriendly ? "CONVERTED" : "BOSS DETECTED", 0, -uSize * 1.5);
      } else {
        this.ctx.fillStyle = isHit ? '#fff' : (e.isFriendly ? '#22d3ee' : this.getEnemyColor(e));
        this.ctx.beginPath();
        this.ctx.moveTo(uSize, 0);
        this.ctx.lineTo(-uSize * 0.7, uSize * 0.7);
        this.ctx.lineTo(-uSize * 0.3, 0);
        this.ctx.lineTo(-uSize * 0.7, -uSize * 0.7);
        this.ctx.closePath();
        this.ctx.fill();
      }
      this.ctx.restore();
    });

    // 7. TOWERS & DROPS
    state.towers.forEach(t => {
      this.ctx.fillStyle = t.color;
      const tSize = 160;
      this.ctx.fillRect(t.x - tSize, t.y - tSize, tSize * 2, tSize * 2);
    });

    state.drops.forEach(d => {
      this.ctx.globalAlpha = d.life;
      this.ctx.fillStyle = d.type === 'shard' ? COLORS.SECONDARY : COLORS.PRIMARY;
      const s = 220;
      this.ctx.save();
      this.ctx.translate(d.x, d.y);
      this.ctx.rotate(now * 0.015);
      this.ctx.fillRect(-s, -s, s*2, s*2);
      this.ctx.restore();
    });

    // 8. PARTICLES
    state.particles.forEach(p => {
      this.ctx.globalAlpha = p.life;
      this.ctx.fillStyle = p.color;
      if (p.text) {
        this.ctx.font = `black ${p.size / cameraScale}px Space Grotesk`;
        this.ctx.textAlign = 'center';
        this.ctx.fillText(p.text, p.x, p.y);
      } else {
        this.ctx.beginPath(); this.ctx.arc(p.x, p.y, p.size / cameraScale, 0, Math.PI * 2); this.ctx.fill();
      }
    });

    this.ctx.restore();
  }

  private getEnemyColor(e: Enemy): string {
      switch(e.type) {
          case 'boss': return '#a855f7';
          case 'glitch': return '#00ffcc';
          case 'null_pointer': return '#ffffff';
          case 'memory_leak': return '#fbbf24';
          case 'shielded': return '#38bdf8';
          case 'worm': return '#f472b6';
          default: return COLORS.ENEMY;
      }
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(state: GameState, dt: number, cameraScale: number, auto: boolean, onLv: () => void): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const cx = window.innerWidth / 2; const cy = window.innerHeight / 2;
    const vMult = Math.pow(5, state.permanentUpgrades.version - 1);

    // 1. Passive Code Generation
    const passiveBase = (120 + state.level * 25) * (dt/1000) * vMult * Math.pow(2.8, state.currentSector);
    state.code = Math.min(MAX_VAL, state.code + passiveBase);

    // 2. Unit AI
    state.enemies.forEach(e => {
        if (e.isFriendly) {
            // Seek uncaptured planets
            const targets = state.planets.filter(p => !p.isCaptured);
            if (targets.length > 0) {
                const t = targets[0];
                const dX = t.x - e.x; const dY = t.y - e.y; 
                const dist = Math.sqrt(dX*dX + dY*dY) || 1;
                if (dist < 1000) { 
                    t.hp -= e.hp * 0.05; 
                    e.hp -= 80; 
                    if (t.hp <= 0) this.capturePlanet(state, t, onLv); 
                }
                e.x += (dX/dist) * e.speed * 4.5; 
                e.y += (dY/dist) * e.speed * 4.5; 
                e.angle = Math.atan2(dY, dX);
            } else {
                const dX = cx - e.x; const dY = cy - e.y;
                const dist = Math.sqrt(dX*dX + dY*dY) || 1;
                e.x += (dX/dist) * e.speed * 3;
                e.y += (dY/dist) * e.speed * 3;
                e.angle = Math.atan2(dY, dX);
            }
        } else {
            const dx = cx - e.x; const dy = cy - e.y;
            const dist = Math.sqrt(dx*dx + dy*dy) || 1;

            if (e.type === 'boss') {
                // Artillery Boss
                if (dist < 2200) {
                    if (!e.nextAttackTime || now > e.nextAttackTime) {
                        state.coreHp -= 300; 
                        e.nextAttackTime = now + 1800;
                    }
                } else {
                    e.x += (dx/dist) * e.speed * 1.5; 
                    e.y += (dy/dist) * e.speed * 1.5; 
                }
                e.angle = Math.atan2(dy, dx);
            } else {
                // Swarm Bug
                if (dist < 200) { 
                    state.coreHp -= 150; 
                    e.hp = -1; 
                } else {
                    e.x += (dx/dist) * e.speed; 
                    e.y += (dy/dist) * e.speed; 
                    e.angle = Math.atan2(dy, dx);
                }
            }
        }

        if (state.coreHp <= 0) state.isGameOver = true;
    });
    state.enemies = state.enemies.filter(e => e.hp > 0);

    // 3. Collection
    state.drops = state.drops.filter(d => {
        d.life -= 0.003;
        const dx = cx - d.x; const dy = cy - d.y;
        const dist = Math.sqrt(dx*dx + dy*dy) || 1;
        const collectRadius = 500 / cameraScale;

        if (dist < collectRadius) { this.collectDrop(state, d); return false; }

        if (auto || dist < 8000) {
            const pull = auto ? 250 : 150;
            d.x += (dx/dist) * pull; 
            d.y += (dy/dist) * pull;
        }
        return d.life > 0;
    });
  }

  public static handleClick(state: GameState, x: number, y: number, scale: number, onHit: (e: any)=>void, onLv: ()=>void): boolean {
    // Aggressive splash that grows with level and scales inversely with zoom to stay useful
    const splash = (500 + state.level * 10) / Math.pow(scale, 0.4);
    let hitSomething = false;

    state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const dist = Math.sqrt((e.x - x)**2 + (e.y - y)**2);
        if (dist < splash) {
            const damage = state.clickPower * (1 - dist/splash);
            e.hp -= damage; 
            e.lastHit = Date.now(); 
            hitSomething = true; 
            onHit(e);

            // Higher conversion chance for bosses to improve engagement
            if (e.type === 'boss' && Math.random() < 0.10) {
               e.isFriendly = true;
               e.hp = e.maxHp * 0.4;
               state.experience += 50000;
            }

            if (e.hp <= 0) { 
                this.processEnemyDeath(state, e, true); 
                this.checkLevelUp(state, onLv); 
            }
        }
    });
    return hitSomething;
  }

  public static updateTowers(state: GameState, onFire: (t: any, tar: any)=>void, onLv: ()=>void): void {
    const now = Date.now();
    const rScale = Math.pow(2.2, state.currentSector);
    state.towers.forEach(t => {
        const range = t.range * state.towerModifiers.rangeMult * rScale;
        if (now - t.lastFired > t.fireRate * state.towerModifiers.fireRateMult) {
            let tar = state.enemies.find(e => !e.isFriendly && e.type === 'boss' && Math.sqrt((e.x - t.x)**2 + (e.y - t.y)**2) < range);
            if (!tar) tar = state.enemies.find(e => !e.isFriendly && Math.sqrt((e.x - t.x)**2 + (e.y - t.y)**2) < range);
            if (!tar) tar = state.planets.find(p => !p.isCaptured && Math.sqrt((p.x - t.x)**2 + (p.y - t.y)**2) < range) as any;

            if (tar) {
                tar.hp -= t.damage * state.towerModifiers.damageMult;
                state.code = Math.min(MAX_VAL, state.code + (t.damage * 0.15));
                onFire(t, tar);
                if (tar.hp <= 0) {
                    if ('isCaptured' in tar) this.capturePlanet(state, tar as any, onLv);
                    else { this.processEnemyDeath(state, tar as any, false); this.checkLevelUp(state, onLv); }
                }
                t.lastFired = now;
            }
        }
    });
  }

  private static capturePlanet(state: GameState, p: Planet, onLv: ()=>void) {
    p.isCaptured = true; p.color = COLORS.PRIMARY;
    state.experience += 250000 * Math.pow(5, p.sector); 
    this.checkLevelUp(state, onLv);
  }

  public static collectDrop(state: GameState, d: LibraryDrop) {
    if (d.type === 'shard') { 
        state.spProgress += 15; 
        if (state.spProgress >= state.spGoal) { 
            state.skillPoints += 8; 
            state.spProgress = 0; 
            state.spGoal = Math.floor(state.spGoal * 1.25) + 5; 
        } 
    } else {
        state.code = Math.min(MAX_VAL, state.code + (2000 + state.level * 200));
    }
  }

  public static processEnemyDeath(state: GameState, e: Enemy, manual: boolean) {
    state.experience += (e.value / 3) * state.permanentUpgrades.xpMultiplier;
    state.code = Math.min(MAX_VAL, state.code + e.value * 0.8 * state.permanentUpgrades.version);
    state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', x: e.x, y: e.y, effect: 'SP', life: 10.0 });
  }

  public static checkLevelUp(state: GameState, onLv: ()=>void) {
    const req = 600 + (state.level * 600);
    if (state.experience >= req) { 
        state.level++; 
        state.experience -= req; 
        state.skillPoints += 5; 
        state.clickPower *= 1.3; 
        onLv(); 
    }
  }
}

import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE, COST_MULTIPLIER } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_v6_tactical';
const MAX_VAL = 1e308;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    window.addEventListener('resize', this.resize.bind(this));
    this.resize();
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) { this.isPaused = paused; }
  public destroy() { this.isDestroyed = true; audio.stop(); }

  private getInitialState(): GameState {
    return {
      code: 1000, experience: 0, level: 1, skillPoints: 5, spProgress: 0, spGoal: 20,
      clickPower: 120, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: 100, combo: 0,
      threatLevel: 0.5, coreHp: 2000, maxCoreHp: 2000, currentSector: 0,
      buildProgress: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 5000 + (sector * 9000); 
    const count = 3 + sector;
    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 2.5);
      // Enemies scale based on Version to keep them challenging
      const versionScaling = Math.pow(1.8, this.state.permanentUpgrades.version - 1);
      const hp = (30000 + (this.state.level * 1500)) * Math.pow(4.5, sector) * versionScaling;
      this.state.planets.push({
        id: `p_${sector}_${i}`, 
        name: `CLUSTER_0x${sector}${i}`,
        x: this.canvas.width/2 + Math.cos(angle) * dist,
        y: this.canvas.height/2 + Math.sin(angle) * dist,
        hp, maxHp: hp, isCaptured: false, size: 900 + (sector * 350), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public async shipToProduction() {
    if (this.state.buildProgress < 100) return;
    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    // Legacy gain is now much more generous and scales with Sectors and Versions
    const legacyGain = Math.floor((this.state.currentSector + 1) * 150 * Math.pow(1.2, this.state.permanentUpgrades.version));
    this.state.permanentUpgrades.legacyPoints += legacyGain;
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 2200));
    this.state.isCompiling = false;
    this.reset();
  }

  public reset() {
    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;

    // Resetting Version gives a massive base stat multiplier
    const vMult = Math.pow(1.5, perms.version - 1);
    this.state.code = (1000 + perms.startingCode) * vMult * 5;
    this.state.clickPower = 120 * perms.damageMultiplier * vMult;

    this.generatePlanets(0);
    this.onUpdate({ ...this.state });
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number): boolean {
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;
    const config = TOWER_TYPES[type];
    const tCount = this.state.towers.filter(t => t.type === type).length;

    // Brutal exponential cost scaling
    const cost = Math.floor(config.cost * Math.pow(COST_MULTIPLIER, tCount));

    if (this.state.code >= cost && (!config.requires || this.state.unlockedTech.includes(config.requires))) {
      this.state.code -= cost;
      this.state.towers.push({ 
        id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY, 
        range: config.range, damage: config.damage, fireRate: config.fireRate, 
        lastFired: 0, color: config.color 
      });
      audio.playClick();
      // Building a high-value tower stabilizes the system significantly
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 5);
      return true;
    }
    return false;
  }

  public handleClick(rawX: number, rawY: number, wasPlacement: boolean) {
    if (this.state.isGameOver || this.isPaused || this.state.isCompiling) return;
    audio.enable();
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;

    const hit = LogicHandler.handleClick(this.state, worldX, worldY, this.cameraScale, (e) => {
        this.createParticles(e.x, e.y, 14, COLORS.PRIMARY);
        audio.playClick();
        this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.1);
    }, () => this.onLevelUp());

    if (!hit && !wasPlacement) {
      const vMult = Math.pow(1.4, this.state.permanentUpgrades.version - 1);
      const reward = (250 + (this.state.level * 50)) * (1 + this.state.currentSector) * vMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + reward);
      this.createFloatingText(worldX, worldY, `+${Math.floor(reward)}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    const uncaptured = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncaptured.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      // Clearing a sector provides a massive stability boost
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 35); 
    }
    if (this.state.level % 5 === 0) this.spawnBoss();
    this.refreshSkillShop();
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;
    if (!this.isPaused && !this.state.isCompiling) this.update(dt);
    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  }

  private update(dt: number) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;

    let bounds = { 
      minX: cx - 2000, maxX: cx + 2000, 
      minY: cy - 2000, maxY: cy + 2000 
    };

    this.state.planets.forEach(p => {
        if (p.sector <= this.state.currentSector) {
            bounds.minX = Math.min(bounds.minX, p.x); bounds.maxX = Math.max(bounds.maxX, p.x);
            bounds.minY = Math.min(bounds.minY, p.y); bounds.maxY = Math.max(bounds.maxY, p.y);
        }
    });

    this.state.enemies.forEach(e => {
        if (e.type === 'boss') {
            bounds.minX = Math.min(bounds.minX, e.x); bounds.maxX = Math.max(bounds.maxX, e.x);
            bounds.minY = Math.min(bounds.minY, e.y); bounds.maxY = Math.max(bounds.maxY, e.y);
        }
    });

    const viewW = bounds.maxX - bounds.minX;
    const viewH = bounds.maxY - bounds.minY;
    const scaleX = this.canvas.width / (viewW * 1.5);
    const scaleY = this.canvas.height / (viewH * 1.5);

    this.targetCameraScale = Math.max(0.04, Math.min(scaleX, scaleY, 1.0));
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.08; 

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, (t, tar) => {
        this.renderer.addFiringEffect(t.x, t.y, tar.x, tar.y, t.color, t.type);
        audio.playFire(t.type);
    }, () => this.onLevelUp());

    this.enemySpawnTimer += dt;
    if (this.enemySpawnTimer > 2500 / (1 + this.state.currentSector * 0.7)) {
        const active = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
        const s = active[Math.floor(Math.random() * active.length)];
        this.spawnEnemyAt(s ? s.x : -999, s ? s.y : -999);
        this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { 
        p.x += p.vx; p.y += p.vy; p.life -= 0.04; return p.life > 0; 
    });

    if (this.frameCount % 5 === 0) this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 12000 + (this.state.currentSector * 4000); 
    const x = this.canvas.width/2 + Math.cos(angle) * dist;
    const y = this.canvas.height/2 + Math.sin(angle) * dist;
    const versionScaling = Math.pow(2.0, this.state.permanentUpgrades.version - 1);
    const hp = 500000 * Math.pow(3.5, this.state.currentSector) * versionScaling;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.1, 
        value: hp * 12, type: 'boss', size: 1800, angle: 0 
    });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    if (this.state.enemies.length > 100) return;
    const x = sx === -999 ? this.canvas.width/2 + 5000 : sx + (Math.random()-0.5)*1500;
    const y = sy === -999 ? this.canvas.height/2 + 5000 : sy + (Math.random()-0.5)*1500;
    const versionScaling = Math.pow(1.5, this.state.permanentUpgrades.version - 1);
    const hp = 800 * Math.pow(1.35, this.state.level) * versionScaling;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.5 + (this.state.level * 0.05), 
        value: hp * 6, type: 'bug', size: 200, angle: 0 
    });
  }

  private resize() { this.canvas.width = window.innerWidth; this.canvas.height = window.innerHeight; }
  private loadPermanentUpgrades() { const s = localStorage.getItem(STORAGE_KEY); if (s) try { this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...JSON.parse(s) }; } catch(e){} }
  private savePermanentUpgrades() { localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades)); }
  private refreshSkillShop() { this.state.availableSkills = [...ALL_SKILLS].sort(()=>0.5-Math.random()).slice(0,3).map(s=>s.id); }

  public applySkill(id: string, cb: (s: any)=>void) {
    const s = ALL_SKILLS.find(x=>x.id===id) || TECH_TREE.find(x=>x.id===id);
    if (s && this.state.skillPoints >= s.cost) {
        this.state.skillPoints -= s.cost;
        if (id.startsWith('tech_')) this.state.unlockedTech.push(id); else this.state.unlockedSkills.push(id);
        if (id === 'auto_collect') this.hasAutoCollect = true;
        cb(this.state); this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
        this.state.code -= this.state.rerollCost; this.state.rerollCost = Math.floor(this.state.rerollCost * 1.8);
        this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    if (this.state.permanentUpgrades.legacyPoints >= 100) {
        this.state.permanentUpgrades.legacyPoints -= 100;
        if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 50000;
        if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 8.0;
        if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 8.0;
        this.savePermanentUpgrades(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i=0; i<count; i++) this.state.particles.push({ x, y, vx: (Math.random()-0.5)*60, vy: (Math.random()-0.5)*60, size: Math.random()*20+10, life: 1.0, color });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: 0, vy: -18, size: 70, life: 3.2, color, text });
  }
}

