import { GameState, Tower, PermanentUpgrades, Planet, LibraryDrop, Point, Enemy } from '../types';
import { COLORS, TOWER_TYPES, ALL_SKILLS, TECH_TREE, COST_MULTIPLIER } from '../constants';
import { LogicHandler } from './LogicHandler';
import { RenderHandler } from './RenderHandler';
import { audio } from './AudioManager';

const STORAGE_KEY = 'library_legend_v7_final';
const MAX_VAL = 1e308;

export class GameEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private state: GameState;
  private lastTime: number = 0;
  private enemySpawnTimer: number = 0;
  private onUpdate: (state: GameState) => void;
  private hasAutoCollect: boolean = false;
  private cameraScale: number = 1.0;
  private targetCameraScale: number = 1.0;
  private isPaused: boolean = false;
  private frameCount: number = 0;
  private isDestroyed: boolean = false;
  private renderer: RenderHandler;

  constructor(canvas: HTMLCanvasElement, onUpdate: (state: GameState) => void) {
    this.canvas = canvas;
    const context = canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error('Canvas context not available');
    this.ctx = context;
    this.onUpdate = onUpdate;
    this.renderer = new RenderHandler(this.ctx);

    this.state = this.getInitialState();
    this.loadPermanentUpgrades();
    this.refreshSkillShop();
    this.generatePlanets(0);

    window.addEventListener('resize', this.resize.bind(this));
    this.resize();
    requestAnimationFrame(this.animate);
  }

  public setPaused(paused: boolean) { this.isPaused = paused; }
  public destroy() { this.isDestroyed = true; audio.stop(); }

  private getInitialState(): GameState {
    return {
      code: 1000, experience: 0, level: 1, skillPoints: 5, spProgress: 0, spGoal: 20,
      clickPower: 200, towers: [], enemies: [], particles: [], ripples: [], drops: [], planets: [],
      projectiles: [], isGameOver: false, isVictory: false, lastRunCode: 0, availableSkills: [],
      unlockedTech: ['root'], unlockedSkills: [], rerollCost: 100, combo: 0,
      threatLevel: 0.5, coreHp: 2500, maxCoreHp: 2500, currentSector: 0,
      buildProgress: 0, unclaimedLP: 0,
      towerModifiers: { damageMult: 1.0, rangeMult: 1.0, fireRateMult: 1.0 },
      permanentUpgrades: { startingCode: 0, damageMultiplier: 1.0, xpMultiplier: 1.0, legacyPoints: 0, version: 1 }
    };
  }

  private generatePlanets(sector: number) {
    const dist = 5000 + (sector * 10000); 
    const count = 3 + sector;
    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + (sector * 2.5);
      const vScale = Math.pow(1.8, this.state.permanentUpgrades.version - 1);
      const hp = (40000 + (this.state.level * 2000)) * Math.pow(5.0, sector) * vScale;
      this.state.planets.push({
        id: `p_${sector}_${i}`, 
        name: `NODE_CLUSTER_0x${sector}${i}`,
        x: this.canvas.width/2 + Math.cos(angle) * dist,
        y: this.canvas.height/2 + Math.sin(angle) * dist,
        hp, maxHp: hp, isCaptured: false, size: 1000 + (sector * 400), color: COLORS.ENEMY,
        sector
      });
    }
  }

  public async shipToProduction() {
    if (this.state.buildProgress < 100) return;
    this.state.isCompiling = true;
    this.onUpdate({ ...this.state });
    audio.playLevelUp();

    // Distribute 100% of unclaimed LP plus stability bonus
    const stabilityBonus = Math.floor(this.state.unclaimedLP * 0.25);
    this.state.permanentUpgrades.legacyPoints += (this.state.unclaimedLP + stabilityBonus);
    this.state.permanentUpgrades.version++;

    await new Promise(r => setTimeout(r, 2200));
    this.state.isCompiling = false;
    this.reset();
  }

  public reset() {
    // If we're coming from a GameOver, distribute 50% consolation LP
    if (this.state.isGameOver) {
      this.state.permanentUpgrades.legacyPoints += Math.floor(this.state.unclaimedLP * 0.5);
    }

    const perms = { ...this.state.permanentUpgrades };
    this.state = this.getInitialState();
    this.state.permanentUpgrades = perms;
    this.savePermanentUpgrades();

    const vMult = Math.pow(2.0, perms.version - 1);
    this.state.code = (1000 + perms.startingCode) * vMult * 10;
    this.state.clickPower = 200 * perms.damageMultiplier * vMult;

    this.generatePlanets(0);
    this.onUpdate({ ...this.state });
  }

  public buyTower(type: keyof typeof TOWER_TYPES, rawX: number, rawY: number): boolean {
    if (this.state.isGameOver || this.state.isCompiling) return false;
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;
    const config = TOWER_TYPES[type];
    const tCount = this.state.towers.filter(t => t.type === type).length;
    const cost = Math.floor(config.cost * Math.pow(COST_MULTIPLIER, tCount));

    if (this.state.code >= cost && (!config.requires || this.state.unlockedTech.includes(config.requires))) {
      this.state.code -= cost;
      this.state.towers.push({ 
        id: Math.random().toString(36), type, level: 1, x: worldX, y: worldY, 
        range: config.range, damage: config.damage, fireRate: config.fireRate, 
        lastFired: 0, color: config.color 
      });
      audio.playClick();
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 8);
      return true;
    }
    return false;
  }

  public handleClick(rawX: number, rawY: number, wasPlacement: boolean) {
    if (this.state.isGameOver || this.isPaused || this.state.isCompiling) return;
    audio.enable();
    const worldX = (rawX - this.canvas.width/2) / this.cameraScale + this.canvas.width/2;
    const worldY = (rawY - this.canvas.height/2) / this.cameraScale + this.canvas.height/2;

    const hit = LogicHandler.handleClick(this.state, worldX, worldY, this.cameraScale, (e) => {
        this.createParticles(e.x, e.y, 14, COLORS.PRIMARY);
        audio.playClick();
        this.state.buildProgress = Math.min(100, this.state.buildProgress + 0.15);
    }, () => this.onLevelUp());

    if (!hit && !wasPlacement) {
      const vMult = Math.pow(1.5, this.state.permanentUpgrades.version - 1);
      const reward = (300 + (this.state.level * 60)) * (1 + this.state.currentSector) * vMult;
      this.state.code = Math.min(MAX_VAL, this.state.code + reward);
      this.createFloatingText(worldX, worldY, `+${Math.floor(reward)}`, COLORS.PRIMARY);
      audio.playClick();
    }
    this.onUpdate({ ...this.state });
  }

  private onLevelUp() {
    audio.playLevelUp();
    const uncaptured = this.state.planets.filter(p => !p.isCaptured && p.sector === this.state.currentSector);
    if (uncaptured.length === 0) {
      this.state.currentSector++;
      this.generatePlanets(this.state.currentSector);
      this.state.buildProgress = Math.min(100, this.state.buildProgress + 40); 
    }
    if (this.state.level % 5 === 0) this.spawnBoss();
    this.refreshSkillShop();
  }

  private animate = (time: number) => {
    if (this.isDestroyed) return;
    const dt = Math.min(time - this.lastTime, 33);
    this.lastTime = time;
    this.frameCount++;

    // CRITICAL: Hard pause logic
    const canUpdate = !this.isPaused && !this.state.isGameOver && !this.state.isCompiling;
    if (canUpdate) {
        this.update(dt);
    }

    this.renderer.draw(this.state, this.cameraScale, this.isPaused);
    requestAnimationFrame(this.animate);
  }

  private update(dt: number) {
    const cx = this.canvas.width / 2;
    const cy = this.canvas.height / 2;

    let bounds = { 
      minX: cx - 2500, maxX: cx + 2500, 
      minY: cy - 2500, maxY: cy + 2500 
    };

    this.state.planets.forEach(p => {
        if (p.sector <= this.state.currentSector) {
            bounds.minX = Math.min(bounds.minX, p.x); bounds.maxX = Math.max(bounds.maxX, p.x);
            bounds.minY = Math.min(bounds.minY, p.y); bounds.maxY = Math.max(bounds.maxY, p.y);
        }
    });

    this.state.enemies.forEach(e => {
        if (e.type === 'boss') {
            bounds.minX = Math.min(bounds.minX, e.x); bounds.maxX = Math.max(bounds.maxX, e.x);
            bounds.minY = Math.min(bounds.minY, e.y); bounds.maxY = Math.max(bounds.maxY, e.y);
        }
    });

    const viewW = bounds.maxX - bounds.minX;
    const viewH = bounds.maxY - bounds.minY;
    const scaleX = this.canvas.width / (viewW * 1.5);
    const scaleY = this.canvas.height / (viewH * 1.5);

    this.targetCameraScale = Math.max(0.04, Math.min(scaleX, scaleY, 1.0));
    this.cameraScale += (this.targetCameraScale - this.cameraScale) * 0.08; 

    LogicHandler.update(this.state, dt, this.cameraScale, this.hasAutoCollect, () => this.onLevelUp());
    LogicHandler.updateTowers(this.state, (t, tar) => {
        this.renderer.addFiringEffect(t.x, t.y, tar.x, tar.y, t.color, t.type);
        audio.playFire(t.type);
    }, () => this.onLevelUp());

    this.enemySpawnTimer += dt;
    if (this.enemySpawnTimer > 3000 / (1 + this.state.currentSector * 0.8)) {
        const active = this.state.planets.filter(p => !p.isCaptured && p.sector <= this.state.currentSector);
        const s = active[Math.floor(Math.random() * active.length)];
        this.spawnEnemyAt(s ? s.x : -999, s ? s.y : -999);
        this.enemySpawnTimer = 0;
    }

    this.state.particles = this.state.particles.filter(p => { 
        p.x += p.vx; p.y += p.vy; p.life -= 0.04; return p.life > 0; 
    });

    if (this.frameCount % 5 === 0) this.onUpdate({ ...this.state });
  }

  private spawnBoss() {
    const angle = Math.random() * Math.PI * 2;
    const dist = 14000 + (this.state.currentSector * 5000); 
    const x = this.canvas.width/2 + Math.cos(angle) * dist;
    const y = this.canvas.height/2 + Math.sin(angle) * dist;
    const vScale = Math.pow(2.2, this.state.permanentUpgrades.version - 1);
    const hp = 800000 * Math.pow(4.0, this.state.currentSector) * vScale;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.05, 
        value: hp * 15, type: 'boss', size: 2000, angle: 0 
    });
  }

  private spawnEnemyAt(sx: number, sy: number) {
    if (this.state.enemies.length > 100) return;
    const x = sx === -999 ? this.canvas.width/2 + 6000 : sx + (Math.random()-0.5)*1800;
    const y = sy === -999 ? this.canvas.height/2 + 6000 : sy + (Math.random()-0.5)*1800;
    const vScale = Math.pow(1.6, this.state.permanentUpgrades.version - 1);
    const hp = 1000 * Math.pow(1.4, this.state.level) * vScale;
    this.state.enemies.push({ 
        id: Math.random().toString(36), x, y, hp, maxHp: hp, speed: 1.4 + (this.state.level * 0.06), 
        value: hp * 8, type: 'bug', size: 220, angle: 0 
    });
  }

  private resize() { this.canvas.width = window.innerWidth; this.canvas.height = window.innerHeight; }
  private loadPermanentUpgrades() { const s = localStorage.getItem(STORAGE_KEY); if (s) try { this.state.permanentUpgrades = { ...this.state.permanentUpgrades, ...JSON.parse(s) }; } catch(e){} }
  private savePermanentUpgrades() { localStorage.setItem(STORAGE_KEY, JSON.stringify(this.state.permanentUpgrades)); }
  private refreshSkillShop() { this.state.availableSkills = [...ALL_SKILLS].sort(()=>0.5-Math.random()).slice(0,3).map(s=>s.id); }

  public applySkill(id: string, cb: (s: any)=>void) {
    const s = ALL_SKILLS.find(x=>x.id===id) || TECH_TREE.find(x=>x.id===id);
    if (s && this.state.skillPoints >= s.cost) {
        this.state.skillPoints -= s.cost;
        if (id.startsWith('tech_')) this.state.unlockedTech.push(id); else this.state.unlockedSkills.push(id);
        if (id === 'auto_collect') this.hasAutoCollect = true;
        cb(this.state); this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public rerollSkills() {
    if (this.state.code >= this.state.rerollCost) {
        this.state.code -= this.state.rerollCost; this.state.rerollCost = Math.floor(this.state.rerollCost * 1.8);
        this.refreshSkillShop(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  public buyPermanentUpgrade(type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) {
    if (this.state.permanentUpgrades.legacyPoints >= 100) {
        this.state.permanentUpgrades.legacyPoints -= 100;
        if (type === 'startingCode') this.state.permanentUpgrades.startingCode += 100000;
        if (type === 'damageMultiplier') this.state.permanentUpgrades.damageMultiplier += 10.0;
        if (type === 'xpMultiplier') this.state.permanentUpgrades.xpMultiplier += 10.0;
        this.savePermanentUpgrades(); this.onUpdate({...this.state}); return true;
    }
    return false;
  }

  private createParticles(x: number, y: number, count: number, color: string) {
    for (let i=0; i<count; i++) this.state.particles.push({ x, y, vx: (Math.random()-0.5)*60, vy: (Math.random()-0.5)*60, size: Math.random()*20+10, life: 1.0, color });
  }

  private createFloatingText(x: number, y: number, text: string, color: string) {
    this.state.particles.push({ x, y, vx: 0, vy: -18, size: 70, life: 3.2, color, text });
  }
}

import { GameState, Enemy, Planet, LibraryDrop, Tower, Point } from '../types';
import { COLORS, TOWER_TYPES } from '../constants';

const MAX_VAL = 1e300;

export class LogicHandler {
  public static update(state: GameState, dt: number, cameraScale: number, auto: boolean, onLv: () => void): void {
    if (state.isGameOver || state.isVictory || state.isCompiling) return;
    const now = Date.now();
    const cx = window.innerWidth / 2; const cy = window.innerHeight / 2;
    const vMult = Math.pow(6, state.permanentUpgrades.version - 1);

    // 1. Passive Code Generation
    const passiveBase = (150 + state.level * 30) * (dt/1000) * vMult * Math.pow(3.0, state.currentSector);
    state.code = Math.min(MAX_VAL, state.code + passiveBase);

    // 2. Unit AI
    state.enemies.forEach(e => {
        if (e.isFriendly) {
            const targets = state.planets.filter(p => !p.isCaptured);
            if (targets.length > 0) {
                const t = targets[0];
                const dX = t.x - e.x; const dY = t.y - e.y; 
                const dist = Math.sqrt(dX*dX + dY*dY) || 1;
                if (dist < 1000) { 
                    t.hp -= e.hp * 0.05; 
                    e.hp -= 100; 
                    if (t.hp <= 0) this.capturePlanet(state, t, onLv); 
                }
                e.x += (dX/dist) * e.speed * 4.5; 
                e.y += (dY/dist) * e.speed * 4.5; 
                e.angle = Math.atan2(dY, dX);
            } else {
                const dX = cx - e.x; const dY = cy - e.y;
                const dist = Math.sqrt(dX*dX + dY*dY) || 1;
                e.x += (dX/dist) * e.speed * 3;
                e.y += (dY/dist) * e.speed * 3;
                e.angle = Math.atan2(dY, dX);
            }
        } else {
            const dx = cx - e.x; const dy = cy - e.y;
            const dist = Math.sqrt(dx*dx + dy*dy) || 1;

            if (e.type === 'boss') {
                if (dist < 2200) {
                    if (!e.nextAttackTime || now > e.nextAttackTime) {
                        state.coreHp -= 400; 
                        e.nextAttackTime = now + 1800;
                    }
                } else {
                    e.x += (dx/dist) * e.speed * 1.5; 
                    e.y += (dy/dist) * e.speed * 1.5; 
                }
                e.angle = Math.atan2(dy, dx);
            } else {
                if (dist < 200) { 
                    state.coreHp -= 200; 
                    e.hp = -1; 
                } else {
                    e.x += (dx/dist) * e.speed; 
                    e.y += (dy/dist) * e.speed; 
                    e.angle = Math.atan2(dy, dx);
                }
            }
        }

        if (state.coreHp <= 0) state.isGameOver = true;
    });
    state.enemies = state.enemies.filter(e => e.hp > 0);

    // 3. Collection
    state.drops = state.drops.filter(d => {
        d.life -= 0.003;
        const dx = cx - d.x; const dy = cy - d.y;
        const dist = Math.sqrt(dx*dx + dy*dy) || 1;
        const collectRadius = 500 / cameraScale;

        if (dist < collectRadius) { this.collectDrop(state, d); return false; }

        if (auto || dist < 8000) {
            const pull = auto ? 300 : 180;
            d.x += (dx/dist) * pull; 
            d.y += (dy/dist) * pull;
        }
        return d.life > 0;
    });
  }

  public static handleClick(state: GameState, x: number, y: number, scale: number, onHit: (e: any)=>void, onLv: ()=>void): boolean {
    const splash = (500 + state.level * 15) / Math.pow(scale, 0.4);
    let hitSomething = false;

    state.enemies.forEach(e => {
        if (e.isFriendly) return;
        const dist = Math.sqrt((e.x - x)**2 + (e.y - y)**2);
        if (dist < splash) {
            const damage = state.clickPower * (1 - dist/splash);
            e.hp -= damage; 
            e.lastHit = Date.now(); 
            hitSomething = true; 
            onHit(e);

            if (e.type === 'boss' && Math.random() < 0.12) {
               e.isFriendly = true;
               e.hp = e.maxHp * 0.5;
               state.experience += 100000;
            }

            if (e.hp <= 0) { 
                this.processEnemyDeath(state, e, true); 
                this.checkLevelUp(state, onLv); 
            }
        }
    });
    return hitSomething;
  }

  public static updateTowers(state: GameState, onFire: (t: any, tar: any)=>void, onLv: ()=>void): void {
    const now = Date.now();
    const rScale = Math.pow(2.5, state.currentSector);
    state.towers.forEach(t => {
        const range = t.range * state.towerModifiers.rangeMult * rScale;
        if (now - t.lastFired > t.fireRate * state.towerModifiers.fireRateMult) {
            let tar = state.enemies.find(e => !e.isFriendly && e.type === 'boss' && Math.sqrt((e.x - t.x)**2 + (e.y - t.y)**2) < range);
            if (!tar) tar = state.enemies.find(e => !e.isFriendly && Math.sqrt((e.x - t.x)**2 + (e.y - t.y)**2) < range);
            if (!tar) tar = state.planets.find(p => !p.isCaptured && Math.sqrt((p.x - t.x)**2 + (p.y - t.y)**2) < range) as any;

            if (tar) {
                tar.hp -= t.damage * state.towerModifiers.damageMult;
                state.code = Math.min(MAX_VAL, state.code + (t.damage * 0.2));
                onFire(t, tar);
                if (tar.hp <= 0) {
                    if ('isCaptured' in tar) this.capturePlanet(state, tar as any, onLv);
                    else { this.processEnemyDeath(state, tar as any, false); this.checkLevelUp(state, onLv); }
                }
                t.lastFired = now;
            }
        }
    });
  }

  private static capturePlanet(state: GameState, p: Planet, onLv: ()=>void) {
    p.isCaptured = true; p.color = COLORS.PRIMARY;
    state.experience += 300000 * Math.pow(5, p.sector); 
    // Capturing a planet grants significant unclaimed LP
    state.unclaimedLP += Math.floor(100 * Math.pow(1.5, p.sector));
    this.checkLevelUp(state, onLv);
  }

  public static collectDrop(state: GameState, d: LibraryDrop) {
    if (d.type === 'shard') { 
        state.spProgress += 15; 
        if (state.spProgress >= state.spGoal) { 
            state.skillPoints += 10; 
            state.spProgress = 0; 
            state.spGoal = Math.floor(state.spGoal * 1.3) + 10; 
        } 
    } else {
        state.code = Math.min(MAX_VAL, state.code + (3000 + state.level * 300));
    }
  }

  public static processEnemyDeath(state: GameState, e: Enemy, manual: boolean) {
    state.experience += (e.value / 2.5) * state.permanentUpgrades.xpMultiplier;
    state.code = Math.min(MAX_VAL, state.code + e.value * 1.0 * state.permanentUpgrades.version);
    state.drops.push({ id: Math.random().toString(36), name: 'Shard', type: 'shard', rarity: 'common', x: e.x, y: e.y, effect: 'SP', life: 12.0 });

    // Bosses grant LP directly
    if (e.type === 'boss') {
        state.unclaimedLP += Math.floor(50 * Math.pow(1.5, state.currentSector));
    }
  }

  public static checkLevelUp(state: GameState, onLv: ()=>void) {
    const req = 600 + (state.level * 600);
    if (state.experience >= req) { 
        state.level++; 
        state.experience -= req; 
        state.skillPoints += 5; 
        state.clickPower *= 1.35; 
        // Leveling up grants small LP
        state.unclaimedLP += 5 + Math.floor(state.level * 0.5);
        onLv(); 
    }
  }
}

import React from 'react';
import { GameState, PermanentUpgrades } from '../types';
import { TOWER_TYPES, COLORS, COST_MULTIPLIER } from '../constants';
import { Terminal, Cpu, Zap, Code, Shield, Layers, Award, Star, Heart, Rocket, Lock, Database, Send, CheckCircle2, TrendingUp, AlertTriangle } from 'lucide-react';

interface Props {
  state: GameState;
  activeBuildingType: keyof typeof TOWER_TYPES | null;
  onBuildTower: (type: keyof typeof TOWER_TYPES) => void;
  onOpenSkills: () => void;
  onRestart: () => void;
  onBuyPermanent: (type: keyof Omit<PermanentUpgrades, 'legacyPoints'>) => void;
  onShipToProduction: () => void;
}

const UIOverlay: React.FC<Props> = ({ state, activeBuildingType, onBuildTower, onOpenSkills, onRestart, onBuyPermanent, onShipToProduction }) => {
  const nextLevelExp = 600 + (state.level * 600);
  const expProgress = (state.experience / nextLevelExp) * 100;
  const coreHpPercent = (state.coreHp / state.maxCoreHp) * 100;
  const buildProgress = state.buildProgress;

  const totalLegacyPool = Math.floor(state.permanentUpgrades.legacyPoints);
  const currentVersion = state.permanentUpgrades.version;
  const unclaimedLP = state.unclaimedLP;

  const formatLarge = (num: number): string => {
    if (num === Infinity || isNaN(num)) return "MAXED";
    if (num < 1000) return Math.floor(num).toString();
    const suffixes = ["", "K", "M", "B", "T", "Q", "Qi", "Sx", "Sp", "Oc", "No", "Dc"];
    const tier = Math.floor(Math.log10(num) / 3);
    if (tier >= suffixes.length) return num.toExponential(2);
    const suffix = suffixes[tier];
    const scale = Math.pow(10, tier * 3);
    const scaled = num / scale;
    return scaled.toFixed(1) + suffix;
  };

  return (
    <div className="fixed inset-0 pointer-events-none flex flex-col items-center justify-between p-4">

      {/* TOP HUD */}
      <div className="flex flex-col items-center gap-2 pointer-events-auto">
        <div className="bg-slate-900/95 backdrop-blur-2xl border border-slate-700/50 rounded-full px-6 py-2.5 flex items-center gap-8 shadow-2xl relative overflow-hidden">
          {/* Health Bar */}
          <div className="absolute top-0 left-0 h-[3px] bg-red-500/20 w-full">
            <div className="h-full bg-red-500 shadow-[0_0_12px_#ef4444] transition-all duration-500" style={{ width: `${coreHpPercent}%` }} />
          </div>

          <div className="flex items-center gap-2">
            <Code className="text-sky-400 w-4 h-4" />
            <span className="text-white font-black tabular-nums text-sm">
              {formatLarge(state.code)}
            </span>
          </div>

          <div className="flex items-center gap-2 border-x border-slate-700/30 px-8">
            <TrendingUp className="text-purple-400 w-4 h-4" />
            <span className="text-white font-black tabular-nums text-sm flex items-center gap-1">
              {totalLegacyPool} 
              <span className="text-purple-400 text-[10px] animate-pulse">
                (+{unclaimedLP})
              </span>
            </span>
          </div>

          <div className="flex items-center gap-2">
            <Zap className="text-amber-400 w-4 h-4" />
            <span className="text-white font-black text-sm tabular-nums">LV.{state.level}</span>
          </div>

          {/* XP Bar */}
          <div className="absolute bottom-0 left-0 h-[3px] bg-amber-500/10 w-full">
            <div className="h-full bg-amber-400 shadow-[0_0_12px_#fbbf24] transition-all duration-300" style={{ width: `${expProgress}%` }} />
          </div>
        </div>

        <div className="flex gap-4 items-center mt-2">
          {/* BUILD STATUS */}
          <div className="bg-slate-900/90 border border-slate-700 rounded-xl px-4 py-2 flex items-center gap-3">
             <div className="text-[10px] font-black uppercase text-slate-500 tracking-widest italic">Prod Stability:</div>
             <div className="w-32 h-2 bg-slate-800 rounded-full overflow-hidden">
                <div 
                    className={`h-full transition-all duration-500 ${buildProgress >= 100 ? 'bg-emerald-500 shadow-[0_0_10px_#10b981]' : buildProgress > 50 ? 'bg-amber-500' : 'bg-red-500'}`} 
                    style={{ width: `${buildProgress}%` }} 
                />
             </div>
             <div className={`text-[11px] font-black uppercase ${buildProgress >= 100 ? 'text-emerald-400' : 'text-slate-400'}`}>
                {buildProgress >= 100 ? 'STABLE' : `${buildProgress.toFixed(0)}%`}
             </div>
          </div>

          <button 
            onClick={onOpenSkills}
            className="w-12 h-12 bg-slate-900 border border-slate-700 rounded-xl flex items-center justify-center hover:border-pink-500 transition-all shadow-xl group active:scale-95 pointer-events-auto"
          >
            <Cpu className="text-pink-400 w-6 h-6 group-hover:scale-110 transition-transform" />
          </button>

          {buildProgress >= 100 && (
            <button 
                onClick={onShipToProduction}
                className="bg-emerald-500 hover:bg-emerald-400 text-slate-900 px-6 py-2.5 rounded-xl font-black uppercase italic tracking-tighter flex flex-col items-center gap-0 shadow-[0_0_35px_rgba(16,185,129,0.4)] transition-all hover:-translate-y-1 active:scale-95 pointer-events-auto animate-bounce border-2 border-emerald-300"
            >
                <div className="flex items-center gap-2 text-sm"><Send className="w-4 h-4" /> Ship v{currentVersion + 1}.0</div>
                <div className="text-[9px] opacity-80 font-bold">BONUS: +{Math.floor(unclaimedLP * 0.25)} LP</div>
            </button>
          )}
        </div>
      </div>

      {/* COMPILING OVERLAY */}
      {state.isCompiling && (
          <div className="fixed inset-0 bg-slate-950/95 backdrop-blur-3xl flex flex-col items-center justify-center z-[500] pointer-events-auto">
             <div className="text-emerald-400 font-black text-6xl mb-12 animate-pulse italic uppercase tracking-tighter">Deploying v{currentVersion + 1}.0</div>
             <div className="flex flex-col gap-4 items-center">
                <div className="text-slate-400 font-mono text-sm uppercase tracking-[0.4em] flex items-center gap-3">
                    <CheckCircle2 className="w-5 h-5" /> Distributing {unclaimedLP} Legacy Points
                </div>
                <div className="text-slate-400 font-mono text-sm uppercase tracking-[0.4em] flex items-center gap-3 text-emerald-300">
                    <CheckCircle2 className="w-5 h-5" /> Scaling Infrastructure x2.0
                </div>
             </div>
             <div className="mt-16 w-96 h-2 bg-slate-900 rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500 animate-[loading_2s_ease-in-out_infinite]" />
             </div>
          </div>
      )}

      {/* BUILDER (BOTTOM) */}
      <div className="flex justify-center gap-4 pointer-events-auto mb-6">
        {(Object.entries(TOWER_TYPES) as [keyof typeof TOWER_TYPES, any][]).map(([key, config]) => {
          const towerCount = state.towers.filter(t => t.type === key).length;
          const currentCost = Math.floor(config.cost * Math.pow(COST_MULTIPLIER, towerCount));
          const isUnlocked = !config.requires || state.unlockedTech.includes(config.requires);
          const canAfford = state.code >= currentCost;
          const isActive = activeBuildingType === key;

          return (
            <button
              key={key}
              onClick={() => isUnlocked && onBuildTower(key)}
              disabled={!isUnlocked}
              className={`group relative bg-slate-900/90 backdrop-blur-xl border p-4 rounded-[1.8rem] flex flex-col items-center gap-2 transition-all min-w-[120px] 
                ${isUnlocked ? 'border-slate-700 hover:border-sky-400 hover:-translate-y-2' : 'opacity-30 grayscale cursor-not-allowed'} 
                ${isActive ? 'border-sky-400 ring-4 ring-sky-400/20 bg-sky-950/50 -translate-y-2 shadow-[0_0_30px_rgba(56,189,248,0.2)]' : ''}`}
            >
              <div className="w-14 h-14 rounded-2xl flex items-center justify-center relative transition-transform" style={{ backgroundColor: config.color + '20' }}>
                {key === 'BASIC' && <Shield className="text-sky-400 w-7 h-7" />}
                {key === 'SNIPER' && <Terminal className="text-pink-400 w-7 h-7" />}
