                <div className="bg-purple-500/10 border border-purple-500/30 p-10 rounded-[3rem] mb-10 shadow-2xl group">
                  <div className="text-sm text-purple-400 mb-2 uppercase font-black tracking-[0.4em]">Recovered Assets (Consolation)</div>
                  <div className="text-6xl font-black text-white tabular-nums flex items-baseline gap-4">
