              </div>

              <div className="flex flex-col justify-center bg-slate-950/40 p-10 rounded-[3rem] border border-slate-800/50 shadow-inner overflow-auto max-h-[600px] no-scrollbar">
                <h3 className="text-2xl font-black text-white mb-8 flex items-center gap-4 italic uppercase tracking-wider">
                  <Star className="text-amber-400 w-7 h-7 fill-amber-400" /> Mastery Shop
                </h3>
                <div className="space-y-4">
