                    { id: 'startingCode', name: 'Seed Capital', desc: '+100K Starting LOC', icon: <Database className="text-sky-400 w-5 h-5" /> },
                    { id: 'damageMultiplier', name: 'Overclocked CPUs', desc: 'Global Damage x10', icon: <Zap className="text-amber-400 w-5 h-5" /> },
                    { id: 'xpMultiplier', name: 'AI Optimization', desc: 'Global XP x10', icon: <TrendingUp className="text-purple-400 w-5 h-5" /> },
