                    <button 
                      key={upg.id} 
                      onClick={() => onBuyPermanent(upg.id as any)} 
                      disabled={state.permanentUpgrades.legacyPoints < 100} 
                      className="w-full p-6 bg-slate-900/90 border border-slate-700/50 rounded-2xl hover:border-sky-400 flex justify-between items-center group disabled:opacity-25 transition-all hover:scale-[1.03]"
                    >
                      <div className="flex items-center gap-6">
                        <div className="p-4 bg-slate-800 rounded-xl group-hover:bg-slate-700 transition-colors shadow-lg">{upg.icon}</div>
                        <div className="text-left">
                          <div className="text-white font-black text-base uppercase tracking-tight">{upg.name}</div>
                          <div className="text-slate-500 text-[12px] font-bold tracking-wide italic">{upg.desc}</div>
                        </div>
                      </div>
                      <div className="bg-slate-950 text-purple-400 text-xs px-5 py-2.5 rounded-full font-black border border-purple-500/40 shadow-inner">100 LP</div>
                    </button>
                  ))}
